import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ElementType = 'text' | 'image' | 'shape' | 'button';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  styles: {
    backgroundColor?: string;
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
  };
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateContentIdeas = async (prompt: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest a few elements for an interactive lesson about: ${prompt}. 
    Provide the response in JSON format.
    Include a title, a brief description, and 3 key interactive points.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          points: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                info: { type: Type.STRING }
              },
              required: ["label", "info"]
            }
          }
        },
        required: ["title", "description", "points"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateImage = async (prompt: string): Promise<string | null> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `High quality flat illustration, educational style, clean background for: ${prompt}` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

import React from 'react';
import { CanvasElement, InteractivityType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  isPreview?: boolean;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ element, isSelected, onSelect, isPreview }) => {
  const style: React.CSSProperties = {
    position: 'absolute',
    left: element.x,
    top: element.y,
    width: element.width,
    height: element.height,
    zIndex: element.styles.zIndex,
    cursor: isPreview && element.interactivity.type !== InteractivityType.NONE ? 'pointer' : 'move',
    backgroundColor: element.styles.backgroundColor,
    color: element.styles.color,
    fontSize: element.styles.fontSize,
    borderRadius: element.styles.borderRadius,
    fontWeight: element.styles.fontWeight as any,
    textAlign: element.styles.textAlign,
    opacity: element.styles.opacity,
    display: 'flex',
    alignItems: 'center',
    justifyContent: element.styles.textAlign === 'center' ? 'center' : (element.styles.textAlign === 'right' ? 'flex-end' : 'flex-start'),
    padding: '8px',
    boxShadow: isSelected ? '0 0 0 2px #3b82f6' : 'none',
    overflow: 'hidden',
    transition: 'transform 0.2s',
  };

  const handleInteraction = () => {
    if (!isPreview) return;

    switch (element.interactivity.type) {
      case InteractivityType.EXTERNAL_LINK:
        window.open(element.interactivity.value, '_blank');
        break;
      case InteractivityType.TOOLTIP:
        alert(`${element.interactivity.title || 'Info'}: ${element.interactivity.value}`);
        break;
      case InteractivityType.MODAL:
        // Could implement a better modal system
        alert(`Modal: ${element.interactivity.value}`);
        break;
      default:
        break;
    }
  };

  return (
    <div
      style={style}
      onMouseDown={onSelect}
      onClick={handleInteraction}
      className={`${isSelected ? 'ring-2 ring-blue-500' : ''} ${isPreview && element.interactivity.type !== InteractivityType.NONE ? 'hover:scale-105' : ''}`}
    >
      {element.type === 'image' ? (
        <img src={element.content} alt="Element" className="w-full h-full object-contain pointer-events-none" />
      ) : element.type === 'shape' ? (
        <div className="w-full h-full" style={{ backgroundColor: element.styles.backgroundColor }} />
      ) : (
        <span className="w-full pointer-events-none">{element.content}</span>
      )}

      {/* Interactivity indicators */}
      {!isPreview && element.interactivity.type !== InteractivityType.NONE && (
        <div className="absolute top-0 right-0 p-1 bg-yellow-400 rounded-bl text-[8px] font-bold">
          <i className="fas fa-hand-pointer"></i>
        </div>
      )}

      {/* Resize handles when selected */}
      {isSelected && !isPreview && (
        <>
          <div className="resizable-handle -top-1 -left-1" />
          <div className="resizable-handle -top-1 -right-1" />
          <div className="resizable-handle -bottom-1 -left-1" />
          <div className="resizable-handle -bottom-1 -right-1" />
        </>
      )}
    </div>
  );
};

export default ElementRenderer;

import React, { useState } from 'react';
import { generateImage, generateContentIdeas } from '../services/geminiService';
import { ElementType } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ onAddElement, onBulkAdd }) => {
  const [activeTab, setActiveTab] = useState<'elements' | 'ai'>('elements');
  const [aiPrompt, setAiPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleAiGeneration = async () => {
    if (!aiPrompt) return;
    setIsLoading(true);
    try {
      const ideas = await generateContentIdeas(aiPrompt);
      onBulkAdd(ideas);
      setAiPrompt('');
    } catch (error) {
      console.error(error);
      alert("Error generating content");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAiImage = async () => {
    if (!aiPrompt) return;
    setIsLoading(true);
    try {
      const url = await generateImage(aiPrompt);
      if (url) onAddElement('image', url);
      setAiPrompt('');
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-64 bg-slate-900 text-white flex flex-col h-full border-r border-slate-700">
      <div className="flex border-b border-slate-700">
        <button 
          onClick={() => setActiveTab('elements')}
          className={`flex-1 p-4 text-sm font-medium ${activeTab === 'elements' ? 'bg-slate-800 border-b-2 border-blue-500' : 'hover:bg-slate-800'}`}
        >
          <i className="fas fa-plus mr-2"></i> Assets
        </button>
        <button 
          onClick={() => setActiveTab('ai')}
          className={`flex-1 p-4 text-sm font-medium ${activeTab === 'ai' ? 'bg-slate-800 border-b-2 border-blue-500' : 'hover:bg-slate-800'}`}
        >
          <i className="fas fa-magic mr-2"></i> AI Creator
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {activeTab === 'elements' ? (
          <>
            <section>
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Basic</h3>
              <div className="grid grid-cols-2 gap-2">
                <button onClick={() => onAddElement('text')} className="flex flex-col items-center justify-center p-3 bg-slate-800 rounded-lg hover:bg-slate-700 border border-slate-700 transition">
                  <i className="fas fa-font text-xl mb-1"></i>
                  <span className="text-xs">Text</span>
                </button>
                <button onClick={() => onAddElement('button')} className="flex flex-col items-center justify-center p-3 bg-slate-800 rounded-lg hover:bg-slate-700 border border-slate-700 transition">
                  <i className="fas fa-square text-xl mb-1"></i>
                  <span className="text-xs">Button</span>
                </button>
                <button onClick={() => onAddElement('shape')} className="flex flex-col items-center justify-center p-3 bg-slate-800 rounded-lg hover:bg-slate-700 border border-slate-700 transition">
                  <i className="fas fa-shapes text-xl mb-1"></i>
                  <span className="text-xs">Shape</span>
                </button>
                <label className="flex flex-col items-center justify-center p-3 bg-slate-800 rounded-lg hover:bg-slate-700 border border-slate-700 transition cursor-pointer">
                  <i className="fas fa-upload text-xl mb-1"></i>
                  <span className="text-xs">Upload</span>
                  <input type="file" className="hidden" onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                      const reader = new FileReader();
                      reader.onload = (re) => onAddElement('image', re.target?.result as string);
                      reader.readAsDataURL(file);
                    }
                  }} />
                </label>
              </div>
            </section>

            <section>
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Templates</h3>
              <div className="space-y-2">
                <div className="p-3 bg-slate-800 rounded-lg border border-slate-700 text-xs text-slate-300">
                  Select a template to start quickly. (Coming Soon)
                </div>
              </div>
            </section>
          </>
        ) : (
          <div className="space-y-4">
            <h3 className="text-sm font-bold text-blue-400">Ask Gemini to design</h3>
            <textarea
              value={aiPrompt}
              onChange={(e) => setAiPrompt(e.target.value)}
              placeholder="e.g., 'An interactive lesson about black holes'"
              className="w-full p-3 bg-slate-800 border border-slate-700 rounded-lg text-sm h-32 focus:ring-1 focus:ring-blue-500 focus:outline-none"
            />
            <div className="flex flex-col gap-2">
              <button 
                disabled={isLoading || !aiPrompt}
                onClick={handleAiGeneration}
                className="w-full py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-sm font-bold rounded-lg transition"
              >
                {isLoading ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-sparkles mr-1"></i>}
                Generate Slide
              </button>
              <button 
                disabled={isLoading || !aiPrompt}
                onClick={handleAiImage}
                className="w-full py-2 bg-purple-600 hover:bg-purple-500 disabled:opacity-50 text-sm font-bold rounded-lg transition"
              >
                {isLoading ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-image mr-1"></i>}
                Generate Illustration
              </button>
            </div>
            <p className="text-[10px] text-slate-500 leading-tight">
              AI can create structural content or custom illustrations based on your description.
            </p>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-950 text-slate-500 text-[10px] flex items-center justify-between">
        <span>v1.0.4 - BETA</span>
        <i className="fas fa-bolt text-yellow-500"></i>
      </div>
    </div>
  );
};

export default Sidebar;

import React from 'react';
import { CanvasElement, InteractivityType } from '../types';

interface ToolbarProps {
  selectedElement: CanvasElement | null;
  onUpdateElement: (id: string, updates: Partial<CanvasElement>) => void;
  onDeleteElement: (id: string) => void;
  onPreview: () => void;
  isPreview: boolean;
}

const Toolbar: React.FC<ToolbarProps> = ({ 
  selectedElement, 
  onUpdateElement, 
  onDeleteElement,
  onPreview,
  isPreview
}) => {
  if (isPreview) {
    return (
      <div className="h-16 bg-slate-900 border-b border-slate-700 flex items-center justify-between px-6 shadow-md">
        <div className="flex items-center gap-2">
           <div className="w-8 h-8 bg-blue-600 rounded flex items-center justify-center">
             <i className="fas fa-eye text-white text-sm"></i>
           </div>
           <span className="text-white font-bold">PREVIEW MODE</span>
        </div>
        <button 
          onClick={onPreview}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-blue-500 transition"
        >
          Exit Preview
        </button>
      </div>
    );
  }

  return (
    <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shadow-sm">
      <div className="flex items-center gap-6">
        <div className="flex items-center gap-2">
           <div className="w-8 h-8 bg-blue-600 rounded flex items-center justify-center">
             <i className="fas fa-rocket text-white text-sm"></i>
           </div>
           <span className="font-bold text-slate-800">GenialAI</span>
        </div>

        {selectedElement ? (
          <div className="flex items-center gap-3 border-l border-slate-200 pl-6 animate-fade-in">
            <input 
              type="color" 
              value={selectedElement.styles.backgroundColor || '#ffffff'}
              onChange={(e) => onUpdateElement(selectedElement.id, { 
                styles: { ...selectedElement.styles, backgroundColor: e.target.value } 
              })}
              className="w-8 h-8 p-0 border-0 cursor-pointer"
              title="Background Color"
            />

            {(selectedElement.type === 'text' || selectedElement.type === 'button') && (
              <>
                <input 
                  type="color" 
                  value={selectedElement.styles.color || '#000000'}
                  onChange={(e) => onUpdateElement(selectedElement.id, { 
                    styles: { ...selectedElement.styles, color: e.target.value } 
                  })}
                  className="w-8 h-8 p-0 border-0 cursor-pointer"
                  title="Text Color"
                />
                <input 
                  type="number"
                  value={selectedElement.styles.fontSize}
                  onChange={(e) => onUpdateElement(selectedElement.id, { 
                    styles: { ...selectedElement.styles, fontSize: parseInt(e.target.value) } 
                  })}
                  className="w-16 p-1 border border-slate-200 rounded text-sm"
                  title="Font Size"
                />
              </>
            )}

            <div className="h-8 w-px bg-slate-200 mx-2" />

            {/* Interactivity Tool */}
            <select
              value={selectedElement.interactivity.type}
              onChange={(e) => onUpdateElement(selectedElement.id, {
                interactivity: { ...selectedElement.interactivity, type: e.target.value as InteractivityType }
              })}
              className="p-1 border border-slate-200 rounded text-sm bg-slate-50 font-medium"
            >
              <option value={InteractivityType.NONE}>No Action</option>
              <option value={InteractivityType.TOOLTIP}>Tooltip</option>
              <option value={InteractivityType.MODAL}>Modal Window</option>
              <option value={InteractivityType.EXTERNAL_LINK}>Go to Link</option>
            </select>

            {selectedElement.interactivity.type !== InteractivityType.NONE && (
              <input 
                type="text"
                placeholder="Action value (URL, Info, etc)"
                value={selectedElement.interactivity.value}
                onChange={(e) => onUpdateElement(selectedElement.id, {
                  interactivity: { ...selectedElement.interactivity, value: e.target.value }
                })}
                className="w-40 p-1 border border-slate-200 rounded text-sm focus:ring-1 focus:ring-blue-500"
              />
            )}

            <button 
              onClick={() => onDeleteElement(selectedElement.id)}
              className="text-slate-400 hover:text-red-500 transition p-2"
              title="Delete Element"
            >
              <i className="fas fa-trash"></i>
            </button>
          </div>
        ) : (
          <div className="text-sm text-slate-400 font-medium">Select an element to edit properties</div>
        )}
      </div>

      <div className="flex items-center gap-3">
        <button 
          onClick={onPreview}
          className="flex items-center gap-2 px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition text-sm font-semibold"
        >
          <i className="fas fa-eye"></i>
          Preview
        </button>
        <button 
          className="bg-blue-600 text-white px-5 py-2 rounded-lg text-sm font-bold hover:bg-blue-500 shadow-sm shadow-blue-200 transition"
        >
          Share
        </button>
      </div>
    </div>
  );
};

export default Toolbar;

import React, { useState, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import { CanvasElement, Project, ElementType, InteractivityType } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'My Interactive Lesson',
  pages: [
    {
      id: 'page-1',
      name: 'Introduction',
      elements: []
    }
  ]
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageId, setCurrentPageId] = useState('page-1');
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [dragging, setDragging] = useState<{ id: string; startX: number; startY: number; initialX: number; initialY: number } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages.find(p => p.id === currentPageId)!;

  const handleAddElement = (type: ElementType, content?: string) => {
    const newElement: CanvasElement = {
      id: `el-${Date.now()}`,
      type,
      x: 100,
      y: 100,
      width: type === 'text' ? 200 : 150,
      height: type === 'text' ? 50 : 150,
      content: content || (type === 'text' ? 'Double click to edit text' : (type === 'button' ? 'Click Me' : '')),
      styles: {
        backgroundColor: type === 'button' ? '#3b82f6' : (type === 'shape' ? '#e2e8f0' : 'transparent'),
        color: type === 'button' ? '#ffffff' : '#000000',
        fontSize: 16,
        borderRadius: type === 'button' ? 8 : 0,
        zIndex: currentPage.elements.length,
        opacity: 1,
        textAlign: 'center'
      },
      interactivity: {
        type: InteractivityType.NONE,
        value: ''
      }
    };

    const updatedPages = project.pages.map(p => {
      if (p.id === currentPageId) {
        return { ...p, elements: [...p.elements, newElement] };
      }
      return p;
    });

    setProject({ ...project, pages: updatedPages });
    setSelectedElementId(newElement.id);
  };

  const handleBulkAdd = (aiData: any) => {
    const newElements: CanvasElement[] = [];

    // Title
    newElements.push({
      id: `ai-title-${Date.now()}`,
      type: 'text',
      x: 50, y: 30, width: 700, height: 60,
      content: aiData.title,
      styles: { fontSize: 32, fontWeight: 'bold', zIndex: 0, textAlign: 'left', opacity: 1 },
      interactivity: { type: InteractivityType.NONE, value: '' }
    });

    // Description
    newElements.push({
      id: `ai-desc-${Date.now()}`,
      type: 'text',
      x: 50, y: 100, width: 400, height: 100,
      content: aiData.description,
      styles: { fontSize: 16, zIndex: 1, textAlign: 'left', opacity: 1 },
      interactivity: { type: InteractivityType.NONE, value: '' }
    });

    // Interactive points
    aiData.points.forEach((p: any, i: number) => {
      newElements.push({
        id: `ai-point-${Date.now()}-${i}`,
        type: 'button',
        x: 50 + (i * 160), y: 350, width: 140, height: 60,
        content: p.label,
        styles: { backgroundColor: '#3b82f6', color: '#fff', fontSize: 14, borderRadius: 30, zIndex: 2+i, textAlign: 'center', opacity: 1 },
        interactivity: { type: InteractivityType.TOOLTIP, value: p.info, title: p.label }
      });
    });

    const updatedPages = project.pages.map(page => {
      if (page.id === currentPageId) {
        return { ...page, elements: [...page.elements, ...newElements] };
      }
      return page;
    });

    setProject({ ...project, pages: updatedPages });
  };

  const handleUpdateElement = (id: string, updates: Partial<CanvasElement>) => {
    const updatedPages = project.pages.map(p => {
      if (p.id === currentPageId) {
        const updatedElements = p.elements.map(el => el.id === id ? { ...el, ...updates } : el);
        return { ...p, elements: updatedElements };
      }
      return p;
    });
    setProject({ ...project, pages: updatedPages });
  };

  const handleDeleteElement = (id: string) => {
    const updatedPages = project.pages.map(p => {
      if (p.id === currentPageId) {
        return { ...p, elements: p.elements.filter(el => el.id !== id) };
      }
      return p;
    });
    setProject({ ...project, pages: updatedPages });
    setSelectedElementId(null);
  };

  const onMouseDown = useCallback((e: React.MouseEvent, element: CanvasElement) => {
    if (isPreview) return;
    setSelectedElementId(element.id);
    setDragging({
      id: element.id,
      startX: e.clientX,
      startY: e.clientY,
      initialX: element.x,
      initialY: element.y
    });
  }, [isPreview]);

  const onMouseMove = useCallback((e: React.MouseEvent) => {
    if (!dragging) return;
    const dx = e.clientX - dragging.startX;
    const dy = e.clientY - dragging.startY;
    handleUpdateElement(dragging.id, {
      x: dragging.initialX + dx,
      y: dragging.initialY + dy
    });
  }, [dragging]);

  const onMouseUp = useCallback(() => {
    setDragging(null);
  }, []);

  const handleCanvasClick = (e: React.MouseEvent) => {
    if (e.target === canvasRef.current) {
      setSelectedElementId(null);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 overflow-hidden">
      <Toolbar 
        selectedElement={currentPage.elements.find(el => el.id === selectedElementId) || null}
        onUpdateElement={handleUpdateElement}
        onDeleteElement={handleDeleteElement}
        onPreview={() => {
          setIsPreview(!isPreview);
          setSelectedElementId(null);
        }}
        isPreview={isPreview}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={handleAddElement} 
            onBulkAdd={handleBulkAdd}
          />
        )}

        <main 
          className="flex-1 overflow-auto p-8 flex justify-center items-start bg-slate-100"
          onMouseMove={onMouseMove}
          onMouseUp={onMouseUp}
          onMouseLeave={onMouseUp}
        >
          <div 
            ref={canvasRef}
            onClick={handleCanvasClick}
            className={`canvas-container bg-white shadow-2xl relative flex-shrink-0 transition-all duration-300 ${isPreview ? 'w-full h-full max-w-full rounded-none' : 'w-[800px] h-[500px] rounded-lg'}`}
            style={{ 
              transform: !isPreview ? 'scale(1)' : 'none',
              transformOrigin: 'top center'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => onMouseDown(e, el)}
                isPreview={isPreview}
              />
            ))}

            {!isPreview && (
              <div className="absolute -top-10 left-0 text-slate-400 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
                <i className="fas fa-expand"></i> 800 x 500 px
              </div>
            )}
          </div>
        </main>

        {!isPreview && (
          <aside className="w-64 bg-white border-l border-slate-200 p-4">
             <h3 className="text-sm font-bold text-slate-800 mb-4">Layers</h3>
             <div className="space-y-1">
               {[...currentPage.elements].reverse().map(el => (
                 <div 
                  key={el.id}
                  onClick={() => setSelectedElementId(el.id)}
