                 >
                   <i className={`fas ${el.type === 'text' ? 'fa-font' : el.type === 'image' ? 'fa-image' : 'fa-square'} w-4 text-center`}></i>
                   <span className="truncate flex-1">{el.type === 'text' ? (el.content.length > 20 ? el.content.substring(0, 20) + '...' : el.content) : el.type}</span>
                   {el.interactivity.type !== InteractivityType.NONE && <i className="fas fa-hand-pointer text-[10px] text-yellow-500"></i>}
                 </div>
               ))}
               {currentPage.elements.length === 0 && (
                 <div className="text-center py-10">
                   <i className="fas fa-layer-group text-slate-200 text-3xl mb-2"></i>
