import React, { useState } from 'react';
import { generateImage, generateContentIdeas } from '../services/geminiService';
import { ElementType, CanvasPreset, CANVAS_PRESETS } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ onAddElement, onBulkAdd, canvasPreset, onUpdatePreset }) => {
  const [activeTab, setActiveTab] = useState<'assets' | 'settings'>('assets');
  const [aiPrompt, setAiPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleAiGeneration = async () => {
    if (!aiPrompt) return;
    setIsLoading(true);
    try {
      const ideas = await generateContentIdeas(aiPrompt);
      onBulkAdd(ideas);
      setAiPrompt('');
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-56 bg-white flex flex-col h-full border-r border-slate-100">
      <div className="flex p-3 gap-1">
        <button 
          onClick={() => setActiveTab('assets')}
          className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-md transition ${activeTab === 'assets' ? 'bg-indigo-50 text-indigo-600' : 'text-slate-400 hover:bg-slate-50'}`}
        >
          Assets
        </button>
        <button 
          onClick={() => setActiveTab('settings')}
          className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-md transition ${activeTab === 'settings' ? 'bg-indigo-50 text-indigo-600' : 'text-slate-400 hover:bg-slate-50'}`}
        >
          Layout
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-4 py-2 space-y-8">
        {activeTab === 'assets' ? (
          <>
            <section>
              <h3 className="text-[10px] font-bold text-slate-300 uppercase tracking-widest mb-4">Core elements</h3>
              <div className="grid grid-cols-2 gap-3">
                <AssetButton icon="fa-heading" label="Text" onClick={() => onAddElement('text')} />
                <AssetButton icon="fa-square" label="Button" onClick={() => onAddElement('button')} />
                <AssetButton icon="fa-circle" label="Shape" onClick={() => onAddElement('shape')} />
                <AssetButton icon="fa-image" label="Image" onClick={() => {
                   const url = prompt("Enter Image URL");
                   if(url) onAddElement('image', url);
                }} />
              </div>
            </section>

            <section className="bg-slate-50 rounded-xl p-4 border border-slate-100">
              <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-3 flex items-center gap-1.5">
                <i className="fas fa-wand-magic-sparkles"></i> AI Designer
              </h3>
              <textarea
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                placeholder="Briefly describe what you want to create..."
                className="w-full p-2 bg-white border border-slate-100 rounded-lg text-xs h-24 focus:ring-1 focus:ring-indigo-500 focus:outline-none placeholder-slate-300 resize-none shadow-sm"
              />
              <button 
                disabled={isLoading || !aiPrompt}
                onClick={handleAiGeneration}
                className="w-full mt-3 py-2 bg-slate-900 hover:bg-indigo-600 disabled:opacity-20 text-white text-[10px] font-bold rounded-lg transition-all shadow-md shadow-slate-100"
              >
                {isLoading ? <i className="fas fa-circle-notch fa-spin"></i> : 'GENERATE SLIDE'}
              </button>
            </section>
          </>
        ) : (
          <section>
             <h3 className="text-[10px] font-bold text-slate-300 uppercase tracking-widest mb-4">Canvas size</h3>
             <div className="space-y-2">
                {(Object.entries(CANVAS_PRESETS) as [CanvasPreset, any][]).map(([key, dim]) => (
                   <button 
                    key={key}
                    onClick={() => onUpdatePreset(key)}
