import React, { useState, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Untitled Design',
  pages: [
    {
      id: 'page-1',
      name: 'Slide 1',
      elements: []
    }
  ],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageId, setCurrentPageId] = useState('page-1');
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [dragging, setDragging] = useState<{ id: string; startX: number; startY: number; initialX: number; initialY: number } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages.find(p => p.id === currentPageId)!;
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const handleAddElement = (type: ElementType, content?: string) => {
    const newElement: CanvasElement = {
      id: `el-${Date.now()}`,
      type,
      x: 50,
      y: 50,
      width: type === 'text' ? 300 : (type === 'shape' ? 100 : 150),
      height: type === 'text' ? 60 : (type === 'shape' ? 100 : 150),
      content: content || (type === 'text' ? 'Start typing...' : (type === 'button' ? 'CLICK ME' : '')),
      styles: {
        backgroundColor: type === 'button' ? '#6366f1' : (type === 'shape' ? '#f1f5f9' : 'transparent'),
        color: type === 'button' ? '#ffffff' : '#1e293b',
        fontSize: type === 'text' ? 24 : 14,
        borderRadius: type === 'button' ? 50 : 0,
        zIndex: currentPage.elements.length,
        opacity: 1,
        textAlign: 'center',
        fontFamily: 'Inter',
        fontWeight: type === 'button' ? 'bold' : 'normal'
      },
      interactivity: {
        type: InteractivityType.NONE,
        value: ''
      }
    };

    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => p.id === currentPageId ? { ...p, elements: [...p.elements, newElement] } : p)
    }));
    setSelectedElementId(newElement.id);
  };

  const handleBulkAdd = (aiData: any) => {
    const newElements: CanvasElement[] = [];

    // Title
    newElements.push({
      id: `ai-title-${Date.now()}`,
      type: 'text',
      x: 40, y: 40, width: 600, height: 80,
      content: aiData.title,
      styles: { fontSize: 42, fontWeight: 'bold', zIndex: 0, textAlign: 'left', opacity: 1, fontFamily: 'Inter', color: '#111827' },
      interactivity: { type: InteractivityType.NONE, value: '' }
    });

    // Description
    newElements.push({
      id: `ai-desc-${Date.now()}`,
      type: 'text',
      x: 40, y: 140, width: 500, height: 100,
      content: aiData.description,
      styles: { fontSize: 18, zIndex: 1, textAlign: 'left', opacity: 1, fontFamily: 'Inter', color: '#4b5563' },
      interactivity: { type: InteractivityType.NONE, value: '' }
    });

    // Interactive points
    aiData.points.forEach((p: any, i: number) => {
      newElements.push({
        id: `ai-point-${Date.now()}-${i}`,
        type: 'button',
        x: 40 + (i * 180), y: 380, width: 160, height: 54,
        content: p.label,
        styles: { backgroundColor: '#6366f1', color: '#fff', fontSize: 12, borderRadius: 50, zIndex: 2+i, textAlign: 'center', opacity: 1, fontWeight: 'bold', fontFamily: 'Inter' },
        interactivity: { type: InteractivityType.TOOLTIP, value: p.info, title: p.label }
      });
    });

    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(page => page.id === currentPageId ? { ...page, elements: [...page.elements, ...newElements] } : page)
    }));
  };

  const handleUpdatePreset = (preset: CanvasPreset) => {
    setProject(prev => ({ ...prev, canvasPreset: preset }));
  };

  const handleUpdateElement = (id: string, updates: Partial<CanvasElement>) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => p.id === currentPageId ? {
        ...p, elements: p.elements.map(el => el.id === id ? { ...el, ...updates } : el)
      } : p)
    }));
  };

  const handleDeleteElement = (id: string) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => p.id === currentPageId ? { ...p, elements: p.elements.filter(el => el.id !== id) } : p)
    }));
    setSelectedElementId(null);
  };

  const onMouseDown = useCallback((e: React.MouseEvent, element: CanvasElement) => {
    if (isPreview) return;
    setSelectedElementId(element.id);
    setDragging({
      id: element.id,
      startX: e.clientX,
      startY: e.clientY,
      initialX: element.x,
      initialY: element.y
    });
  }, [isPreview]);

  const onMouseMove = useCallback((e: React.MouseEvent) => {
    if (!dragging) return;
    const dx = e.clientX - dragging.startX;
    const dy = e.clientY - dragging.startY;
    handleUpdateElement(dragging.id, {
      x: dragging.initialX + dx,
      y: dragging.initialY + dy
    });
  }, [dragging]);

  const onMouseUp = useCallback(() => {
    setDragging(null);
  }, []);

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-800 overflow-hidden select-none">
      <Toolbar 
        selectedElement={currentPage.elements.find(el => el.id === selectedElementId) || null}
        onUpdateElement={handleUpdateElement}
        onDeleteElement={handleDeleteElement}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        isPreview={isPreview}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={handleAddElement} 
            onBulkAdd={handleBulkAdd}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={handleUpdatePreset}
          />
        )}

        <main 
          className="flex-1 overflow-auto p-12 flex justify-center items-start bg-slate-50 relative"
          onMouseMove={onMouseMove}
          onMouseUp={onMouseUp}
          onMouseLeave={onMouseUp}
        >
          <div 
            ref={canvasRef}
            onClick={(e) => e.target === canvasRef.current && setSelectedElementId(null)}
            className={`bg-white shadow-xl relative flex-shrink-0 transition-all duration-300 overflow-hidden ${isPreview ? 'w-full h-full rounded-none shadow-none' : 'rounded-2xl'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => onMouseDown(e, el)}
                isPreview={isPreview}
              />
            ))}
          </div>

          {!isPreview && (
            <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-white px-3 py-1.5 rounded-full border border-slate-100 shadow-sm text-[10px] font-bold text-slate-400 uppercase tracking-widest pointer-events-none">
              Canvas: {currentDimensions.label}
            </div>
          )}
        </main>

        {!isPreview && (
          <aside className="w-60 bg-white border-l border-slate-50 p-6">
             <h3 className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-6">Objects Hierarchy</h3>
             <div className="space-y-2">
               {[...currentPage.elements].reverse().map(el => (
                 <div 
                  key={el.id}
                  onClick={() => setSelectedElementId(el.id)}
                  className={`group p-2.5 rounded-xl flex items-center gap-3 text-xs cursor-pointer transition-all ${selectedElementId === el.id ? 'bg-indigo-50 text-indigo-700 ring-1 ring-indigo-100' : 'hover:bg-slate-50 text-slate-400'}`}
                 >
                   <div className={`w-6 h-6 rounded-lg flex items-center justify-center ${selectedElementId === el.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'}`}>
                     <i className={`fas ${el.type === 'text' ? 'fa-font' : el.type === 'image' ? 'fa-image' : 'fa-square'} text-[10px]`}></i>
                   </div>
                   <span className="truncate flex-1 font-semibold">{el.type === 'text' ? el.content : el.type}</span>
                   {el.interactivity.type !== InteractivityType.NONE && <i className="fas fa-hand-pointer text-[10px] text-indigo-400"></i>}
                 </div>
               ))}
               {currentPage.elements.length === 0 && (
                 <div className="text-center py-12 border-2 border-dashed border-slate-50 rounded-2xl">
                   <p className="text-slate-300 text-[10px] font-bold uppercase tracking-widest leading-relaxed">No objects in<br/>this layout</p>
                 </div>
               )}
             </div>
          </aside>
        )}
      </div>
    </div>
  );
};

