import React, { useState, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import FloatingActionMenu from './components/FloatingActionMenu';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Global Expansion Design',
  pages: [{ id: 'page-1', name: 'Main Canvas', elements: [], groups: [] }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageId] = useState('page-1');
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [actionState, setActionState] = useState<{ id: string; startX: number; startY: number; initialX: number; initialY: number; initialW: number; initialH: number; handle?: string } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages.find(p => p.id === currentPageId)!;
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElement = currentPage.elements.find(el => el.id === selectedElementId);

  const handleUpdateElement = useCallback((id: string, updates: Partial<CanvasElement>) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => p.id === currentPageId ? {
        ...p, elements: p.elements.map(el => el.id === id ? { ...el, ...updates, styles: { ...el.styles, ...(updates.styles || {}) } } : el)
      } : p)
    }));
  }, [currentPageId]);

  const onMouseMove = useCallback((e: React.MouseEvent) => {
    if (!actionState) return;

    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      let newW = actionState.initialW;
      let newH = actionState.initialH;
      let newX = actionState.initialX;
      let newY = actionState.initialY;

      const h = actionState.handle;
      if (h.includes('r')) newW = actionState.initialW + dx;
      if (h.includes('l')) { newW = actionState.initialW - dx; newX = actionState.initialX + dx; }
      if (h.includes('b')) newH = actionState.initialH + dy;
      if (h.includes('t')) { newH = actionState.initialH - dy; newY = actionState.initialY + dy; }

      handleUpdateElement(actionState.id, { x: newX, y: newY, width: Math.max(10, newW), height: Math.max(10, newH) });
    } else {
      handleUpdateElement(actionState.id, { x: actionState.initialX + dx, y: actionState.initialY + dy });
    }
  }, [actionState, zoom, handleUpdateElement]);

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden select-none font-sans">
      <Toolbar 
        selectedElement={selectedElement || null}
        onUpdateElement={handleUpdateElement}
        onDeleteElement={(id) => {
          setProject(prev => ({ ...prev, pages: prev.pages.map(p => p.id === currentPageId ? { ...p, elements: p.elements.filter(el => el.id !== id) } : p) }));
          setSelectedElementId(null);
        }}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        isPreview={isPreview}
        zoom={zoom}
        onZoomChange={setZoom}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 100, y: 100, width: 150, height: 150,
                content: content || (type === 'text' ? 'New Text' : (type === 'button' ? 'ACTION' : '')),
                styles: { 
                  backgroundColor: type === 'button' ? '#6366f1' : '#f1f5f9', color: '#111', 
                  fontSize: 18, borderRadius: type === 'button' ? 12 : 0, zIndex: currentPage.elements.length, 
                  opacity: 1, textAlign: 'center', fontFamily: 'Inter' 
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ ...p, pages: p.pages.map(pg => pg.id === currentPageId ? { ...pg, elements: [...pg.elements, el] } : pg) }));
              setSelectedElementId(el.id);
            }} 
            onBulkAdd={(data) => {/* ... existing AI logic ... */}}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementId={selectedElementId}
            onSelectElement={setSelectedElementId}
            onGroupElements={() => {}}
          />
        )}

        <main 
          className="flex-1 overflow-auto bg-slate-800 p-24 flex justify-center items-start scrollbar-hide perspective-1000"
          onMouseMove={onMouseMove}
          onMouseUp={() => setActionState(null)}
          onMouseLeave={() => setActionState(null)}
        >
          <div 
            ref={canvasRef}
            onClick={(e) => e.target === canvasRef.current && setSelectedElementId(null)}
            className={`bg-white shadow-[0_40px_100px_rgba(0,0,0,0.5)] relative flex-shrink-0 transition-transform duration-100 ease-out overflow-visible ${isPreview ? 'w-full h-full shadow-none' : 'rounded-lg'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top center'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height })}
                onResizeStart={(e, handle) => setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height, handle })}
                isPreview={isPreview}
              />
            ))}
          </div>
        </main>
      </div>

      {selectedElement && !isPreview && (
        <FloatingActionMenu element={selectedElement} onUpdate={(u) => handleUpdateElement(selectedElement.id, u)} />
      )}
    </div>
  );
};

export default App;

