import { GoogleGenAI, Type } from "@google/genai";

// Initialize the Google GenAI client with the API key from environment variables.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateContentIdeas = async (prompt: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest a few elements for an interactive lesson about: ${prompt}. 
    Provide the response in JSON format.
    Include a title, a brief description, and 3 key interactive points.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          points: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                info: { type: Type.STRING }
              },
              required: ["label", "info"]
            }
          }
        },
        required: ["title", "description", "points"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateImage = async (prompt: string): Promise<string | null> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `High quality flat illustration, educational style, clean background for: ${prompt}` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import FloatingActionMenu from './components/FloatingActionMenu';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'GenialAI Workspace',
  pages: [{ id: 'page-1', name: 'Slide 1', elements: [], groups: [] }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [actionState, setActionState] = useState<{ 
    id: string; 
    startX: number; 
    startY: number; 
    initialX: number; 
    initialY: number; 
    initialW: number; 
    initialH: number; 
    handle?: string 
  } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElement = currentPage.elements.find(el => el.id === selectedElementId);

  const handleUpdateElement = useCallback((id: string, updates: Partial<CanvasElement>) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => ({
        ...p,
        elements: p.elements.map(el => el.id === id ? { 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } : el)
      }))
    }));
  }, []);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!actionState) return;

    // Use movement restricted by zoom factor for precision
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      let newW = actionState.initialW;
      let newH = actionState.initialH;
      let newX = actionState.initialX;
      let newY = actionState.initialY;

      const h = actionState.handle;
      // Precision snapping and boundaries
      if (h.includes('r')) newW = Math.max(20, actionState.initialW + dx);
      if (h.includes('l')) { 
        const widthDelta = actionState.initialW - 20;
        const actualDx = Math.min(dx, widthDelta);
        newW = actionState.initialW - actualDx; 
        newX = actionState.initialX + actualDx; 
      }
      if (h.includes('b')) newH = Math.max(20, actionState.initialH + dy);
      if (h.includes('t')) { 
        const heightDelta = actionState.initialH - 20;
        const actualDy = Math.min(dy, heightDelta);
        newH = actionState.initialH - actualDy; 
        newY = actionState.initialY + actualDy; 
      }

      handleUpdateElement(actionState.id, { 
        x: Math.round(newX), 
        y: Math.round(newY), 
        width: Math.round(newW), 
        height: Math.round(newH) 
      });
    } else {
      // Direct drag with precision
      handleUpdateElement(actionState.id, { 
        x: Math.round(actionState.initialX + dx), 
        y: Math.round(actionState.initialY + dy) 
      });
    }
  }, [actionState, zoom, handleUpdateElement]);

  const onMouseUp = useCallback(() => {
    setActionState(null);
  }, []);

  useEffect(() => {
    if (actionState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [actionState, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElement || null}
        onUpdateElement={handleUpdateElement}
        onDeleteElement={(id) => {
          setProject(prev => ({ 
            ...prev, 
            pages: prev.pages.map(p => ({ ...p, elements: p.elements.filter(el => el.id !== id) })) 
          }));
          setSelectedElementId(null);
        }}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        isPreview={isPreview}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, 
                x: (currentDimensions.width / 2) - 75, 
                y: (currentDimensions.height / 2) - 75, 
                width: type === 'text' ? 300 : 150, 
                height: type === 'text' ? 60 : 150,
                content: content || (type === 'text' ? 'Double click to edit' : (type === 'button' ? 'BUTTON' : '')),
                styles: { 
                  backgroundColor: type === 'button' ? '#6366f1' : (type === 'shape' ? '#cbd5e1' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#1e293b', 
                  fontSize: type === 'text' ? 24 : 16, 
                  borderRadius: type === 'button' ? 8 : 0, 
                  zIndex: currentPage.elements.length, 
                  opacity: 1, 
                  textAlign: 'center', 
                  fontFamily: 'Inter' 
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ 
                ...p, 
                pages: p.pages.map(pg => ({ ...pg, elements: [...pg.elements, el] })) 
              }));
              setSelectedElementId(el.id);
            }} 
            onBulkAdd={(data) => {
              // Simple bulk add implementation
              const newEls = data.points.map((p:any, i:number) => ({
                id: `ai-${Date.now()}-${i}`,
                type: 'button',
                x: 100 + (i * 200),
                y: 300,
                width: 160,
                height: 50,
                content: p.label,
                styles: { backgroundColor: '#6366f1', color: '#fff', fontSize: 14, borderRadius: 25, zIndex: i, textAlign: 'center', fontFamily: 'Inter' },
                interactivity: { type: InteractivityType.TOOLTIP, value: p.info, title: p.label }
              }));
              setProject(pr => ({ ...pr, pages: pr.pages.map(pg => ({ ...pg, elements: [...pg.elements, ...newEls] })) }));
            }}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementId={selectedElementId}
            onSelectElement={setSelectedElementId}
            onGroupElements={() => {}}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-slate-900 p-32 flex justify-center items-start scrollbar-hide relative transition-all ${isPreview ? 'p-0' : ''}`}
          ref={containerRef}
          onMouseDown={(e) => {
            if (e.target === containerRef.current) setSelectedElementId(null);
          }}
        >
          {/* Zoom Controller Bottom-Center */}
          {!isPreview && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-4 bg-slate-950 border border-slate-800 px-6 py-2.5 rounded-full shadow-2xl ring-1 ring-white/5">
              <button 
                onClick={() => setZoom(Math.max(0.1, zoom - 0.1))} 
                className="text-slate-400 hover:text-white transition-colors p-1"
              >
                <i className="fas fa-minus text-xs"></i>
              </button>
              <div className="flex flex-col items-center min-w-[60px]">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter mb-0.5">Zoom</span>
                <span className="text-xs font-bold text-white leading-none">{Math.round(zoom * 100)}%</span>
              </div>
              <button 
                onClick={() => setZoom(Math.min(3, zoom + 0.1))} 
                className="text-slate-400 hover:text-white transition-colors p-1"
              >
                <i className="fas fa-plus text-xs"></i>
              </button>
              <div className="w-px h-6 bg-slate-800 mx-2" />
              <button 
                onClick={() => setZoom(1)} 
                className="text-slate-500 hover:text-indigo-400 text-[10px] font-bold uppercase tracking-widest"
              >
                Reset
              </button>
            </div>
          )}

          <div 
            ref={canvasRef}
            onClick={(e) => {
              if (e.target === canvasRef.current) setSelectedElementId(null);
            }}
            className={`bg-white shadow-[0_40px_100px_rgba(0,0,0,0.6)] relative flex-shrink-0 transition-transform duration-75 ease-out overflow-visible ${isPreview ? 'w-full h-full shadow-none border-none rounded-none' : 'rounded-sm border border-slate-200'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top center'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ 
                    id: el.id, 
                    startX: e.clientX, 
                    startY: e.clientY, 
                    initialX: el.x, 
                    initialY: el.y, 
                    initialW: el.width, 
                    initialH: el.height 
                  });
                }}
                onResizeStart={(e, handle) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ 
                    id: el.id, 
                    startX: e.clientX, 
                    startY: e.clientY, 
                    initialX: el.x, 
                    initialY: el.y, 
                    initialW: el.width, 
                    initialH: el.height, 
                    handle 
                  });
                }}
                isPreview={isPreview}
              />
            ))}
          </div>
        </main>

        {selectedElement && !isPreview && (
          <aside className="w-64 bg-slate-950 border-l border-slate-800 flex flex-col z-50 animate-in slide-in-from-right duration-300">
             <div className="p-4 border-b border-slate-800 bg-slate-900/50">
               <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Properties</h3>
             </div>
             <div className="p-6 space-y-6">
               <div className="space-y-2">
                 <label className="text-[9px] font-black text-slate-500 uppercase">Typography</label>
                 <select 
                   value={selectedElement.styles.fontFamily}
                   onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontFamily: e.target.value } })}
                   className="w-full bg-slate-900 border-none rounded-lg text-xs py-2 px-3 text-slate-300 focus:ring-1 focus:ring-indigo-500"
                 >
                   <option value="Inter">Inter</option>
                   <option value="Arial">Arial</option>
                   <option value="Georgia">Georgia</option>
                   <option value="Monospace">Monospace</option>
                 </select>
               </div>

               <div className="space-y-2">
                 <label className="text-[9px] font-black text-slate-500 uppercase">Text Align</label>
                 <div className="flex bg-slate-900 rounded-lg p-1">
                   {['left', 'center', 'right'].map(align => (
                     <button 
                       key={align}
                       onClick={() => handleUpdateElement(selectedElement.id, { styles: { textAlign: align as any } })}
                       className={`flex-1 py-1.5 rounded-md text-xs ${selectedElement.styles.textAlign === align ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                     >
                       <i className={`fas fa-align-${align}`}></i>
