import React, { useState, useCallback, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import FloatingActionMenu from './components/FloatingActionMenu';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'GenialAI Workspace',
  pages: [{ id: 'page-1', name: 'Slide 1', elements: [], groups: [] }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [actionState, setActionState] = useState<{ 
    id: string; 
    startX: number; 
    startY: number; 
    initialX: number; 
    initialY: number; 
    initialW: number; 
    initialH: number; 
    handle?: string 
  } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElement = currentPage.elements.find(el => el.id === selectedElementId);

  // Fix: Updated handleUpdateElement signature to allow partial styles updates.
  // This avoids TS errors when updating individual style properties without spreading full styles object.
  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }))
    }));
  }, []);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!actionState) return;

    // Movement calculation adjusted by current zoom level for pixel-perfect precision
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      let newW = actionState.initialW;
      let newH = actionState.initialH;
      let newX = actionState.initialX;
      let newY = actionState.initialY;

      const h = actionState.handle;

      // Precision resizing with constraints
      if (h.includes('r')) newW = Math.max(10, actionState.initialW + dx);
      if (h.includes('l')) { 
        const maxDx = actionState.initialW - 10;
        const clampedDx = Math.min(dx, maxDx);
        newW = actionState.initialW - clampedDx; 
        newX = actionState.initialX + clampedDx; 
      }
      if (h.includes('b')) newH = Math.max(10, actionState.initialH + dy);
      if (h.includes('t')) { 
        const maxDy = actionState.initialH - 10;
        const clampedDy = Math.min(dy, maxDy);
        newH = actionState.initialH - clampedDy; 
        newY = actionState.initialY + clampedDy; 
      }

      handleUpdateElement(actionState.id, { 
        x: Math.round(newX), 
        y: Math.round(newY), 
        width: Math.round(newW), 
        height: Math.round(newH) 
      });
    } else {
      // Fluid drag movement
      handleUpdateElement(actionState.id, { 
        x: Math.round(actionState.initialX + dx), 
        y: Math.round(actionState.initialY + dy) 
      });
    }
  }, [actionState, zoom, handleUpdateElement]);

  const onMouseUp = useCallback(() => {
    setActionState(null);
  }, []);

  useEffect(() => {
    if (actionState) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [actionState, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#0a0a0f] text-slate-200 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElement || null}
        onUpdateElement={handleUpdateElement}
        onDeleteElement={(id) => {
          setProject(prev => ({ 
            ...prev, 
            pages: prev.pages.map(p => ({ ...p, elements: p.elements.filter(el => el.id !== id) })) 
          }));
          setSelectedElementId(null);
        }}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        isPreview={isPreview}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, 
                x: (currentDimensions.width / 2) - 75, 
                y: (currentDimensions.height / 2) - 75, 
                width: type === 'text' ? 300 : 150, 
                height: type === 'text' ? 60 : 150,
                content: content || (type === 'text' ? 'New content' : (type === 'button' ? 'ACTION' : '')),
                styles: { 
                  backgroundColor: type === 'button' ? '#6366f1' : (type === 'shape' ? '#f8fafc' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#0f172a', 
                  fontSize: type === 'text' ? 24 : 16, 
                  borderRadius: type === 'button' ? 12 : 0, 
                  zIndex: currentPage.elements.length, 
                  opacity: 1, 
                  textAlign: 'center', 
                  fontFamily: 'Inter' 
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ 
                ...p, 
                pages: p.pages.map(pg => ({ ...pg, elements: [...pg.elements, el] })) 
              }));
              setSelectedElementId(el.id);
            }} 
            onBulkAdd={(data) => {
              // Implementation of AI bulk additions
              const newEls = data.points.map((p: any, i: number) => ({
                id: `ai-${Date.now()}-${i}`,
                type: 'button',
                x: 100 + (i * 200),
                y: 350,
                width: 160,
                height: 52,
                content: p.label,
                styles: { backgroundColor: '#6366f1', color: '#fff', fontSize: 14, borderRadius: 30, zIndex: i, textAlign: 'center', fontFamily: 'Inter', fontWeight: 'bold' },
                interactivity: { type: InteractivityType.TOOLTIP, value: p.info, title: p.label }
              }));
              setProject(pr => ({ ...pr, pages: pr.pages.map(pg => ({ ...pg, elements: [...pg.elements, ...newEls] })) }));
            }}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementId={selectedElementId}
            onSelectElement={setSelectedElementId}
            onGroupElements={() => {}}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#13131a] p-32 flex justify-center items-start scrollbar-hide relative ${isPreview ? 'p-0' : ''}`}
          ref={containerRef}
          onMouseDown={(e) => { if (e.target === containerRef.current) setSelectedElementId(null); }}
        >
          {/* Zoom Controller Fixed Bottom-Center */}
          {!isPreview && (
            <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-5 bg-slate-900/80 backdrop-blur-xl border border-white/10 px-6 py-3 rounded-2xl shadow-[0_20px_60px_-15px_rgba(0,0,0,0.7)] ring-1 ring-white/5">
              <button 
                onClick={() => setZoom(Math.max(0.1, zoom - 0.1))} 
                className="text-slate-500 hover:text-white transition-colors h-8 w-8 flex items-center justify-center rounded-lg hover:bg-white/5"
              >
                <i className="fas fa-minus text-xs"></i>
              </button>
              <div className="flex flex-col items-center min-w-[50px]">
                <span className="text-sm font-black text-white">{Math.round(zoom * 100)}%</span>
              </div>
              <button 
                onClick={() => setZoom(Math.min(3, zoom + 0.1))} 
                className="text-slate-500 hover:text-white transition-colors h-8 w-8 flex items-center justify-center rounded-lg hover:bg-white/5"
              >
                <i className="fas fa-plus text-xs"></i>
              </button>
              <div className="w-px h-6 bg-white/10 mx-2" />
              <button 
                onClick={() => setZoom(1)} 
                className="text-[10px] font-black text-indigo-400 uppercase tracking-widest hover:text-indigo-300 transition-colors"
              >
                Reset
              </button>
            </div>
          )}

          <div 
            ref={canvasRef}
            onClick={(e) => { if (e.target === canvasRef.current) setSelectedElementId(null); }}
            className={`bg-white shadow-[0_50px_120px_-20px_rgba(0,0,0,0.8)] relative flex-shrink-0 transition-transform duration-75 ease-out overflow-visible ${isPreview ? 'w-full h-full shadow-none border-none rounded-none' : 'rounded-sm border border-slate-300'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top center'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ 
                    id: el.id, 
                    startX: e.clientX, 
                    startY: e.clientY, 
                    initialX: el.x, 
                    initialY: el.y, 
                    initialW: el.width, 
                    initialH: el.height 
                  });
                }}
                onResizeStart={(e, handle) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ 
                    id: el.id, 
                    startX: e.clientX, 
                    startY: e.clientY, 
                    initialX: el.x, 
                    initialY: el.y, 
                    initialW: el.width, 
                    initialH: el.height, 
                    handle 
                  });
                }}
                isPreview={isPreview}
              />
            ))}
          </div>
        </main>

        {selectedElement && !isPreview && (
          <aside className="w-72 bg-[#0d0d12] border-l border-white/5 flex flex-col z-50 animate-in slide-in-from-right duration-300 shadow-2xl">
             <div className="p-5 border-b border-white/5 bg-white/5 flex items-center justify-between">
               <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Properties</h3>
               <span className="text-[9px] text-slate-500 font-bold uppercase">{selectedElement.type}</span>
             </div>
             <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide">
               <div className="space-y-3">
                 <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Content</label>
                 <textarea 
                    className="w-full bg-[#16161f] border border-white/5 rounded-xl text-xs py-3 px-4 text-slate-300 focus:ring-1 focus:ring-indigo-500 focus:outline-none min-h-[80px] resize-none"
                    value={selectedElement.content}
                    onChange={(e) => handleUpdateElement(selectedElement.id, { content: e.target.value })}
                 />
               </div>

               <div className="space-y-3">
                 <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Typography</label>
                 <div className="grid grid-cols-2 gap-2">
                    <select 
                      value={selectedElement.styles.fontFamily}
                      onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontFamily: e.target.value } })}
                      className="bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 focus:ring-1 focus:ring-indigo-500 outline-none"
                    >
                      <option value="Inter">Inter</option>
                      <option value="Arial">Arial</option>
                      <option value="Georgia">Georgia</option>
                      <option value="Monospace">Mono</option>
                    </select>
                    <input 
                      type="number" 
                      value={selectedElement.styles.fontSize}
                      onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontSize: parseInt(e.target.value) } })}
                      className="bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 focus:ring-1 focus:ring-indigo-500 outline-none text-center"
                    />
                 </div>
               </div>

               <div className="space-y-3">
                 <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Alignment</label>
                 <div className="flex bg-[#16161f] rounded-xl p-1 border border-white/5">
                   {['left', 'center', 'right'].map(align => (
                     <button 
                       key={align}
                       onClick={() => handleUpdateElement(selectedElement.id, { styles: { textAlign: align as any } })}
                       className={`flex-1 py-2 rounded-lg text-xs transition-all ${selectedElement.styles.textAlign === align ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
                     >
                       <i className={`fas fa-align-${align}`}></i>
                     </button>
                   ))}
                 </div>
               </div>

               <div className="space-y-3">
                 <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Interactivity</label>
                 <select 
                   value={selectedElement.interactivity.type}
                   onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, type: e.target.value as any } })}
                   className="w-full bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 outline-none"
                 >
                   <option value={InteractivityType.NONE}>None</option>
                   <option value={InteractivityType.TOOLTIP}>Tooltip</option>
                   <option value={InteractivityType.MODAL}>Modal Window</option>
                   <option value={InteractivityType.EXTERNAL_LINK}>Link</option>
                 </select>
                 {selectedElement.interactivity.type !== InteractivityType.NONE && (
                   <input 
                     type="text"
                     placeholder="Enter URL or information..."
                     value={selectedElement.interactivity.value}
                     onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, value: e.target.value } })}
                     className="w-full bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 mt-2 focus:ring-1 focus:ring-indigo-500 outline-none"
                   />
                 )}
               </div>
             </div>

             <div className="p-6 bg-white/[0.02] border-t border-white/5">
               <button 
                onClick={() => {
                   setProject(prev => ({ ...prev, pages: prev.pages.map(p => ({ ...p, elements: p.elements.filter(el => el.id !== selectedElement.id) })) }));
                   setSelectedElementId(null);
                }}
                className="w-full py-3 bg-red-500/10 hover:bg-red-500/20 text-red-400 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all border border-red-500/20 shadow-lg shadow-red-950/20"
               >
                 <i className="fas fa-trash-alt mr-2"></i> Delete Object
               </button>
             </div>
          </aside>
        )}
      </div>

      {selectedElement && !isPreview && (
        <FloatingActionMenu element={selectedElement} onUpdate={(u) => handleUpdateElement(selectedElement.id, u)} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS, AnimationType } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'GenialAI Workspace',
  pages: [{ id: 'page-1', name: 'Slide 1', elements: [], groups: [] }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [actionState, setActionState] = useState<{ 
    id: string; 
    startX: number; 
    startY: number; 
    initialX: number; 
    initialY: number; 
    initialW: number; 
    initialH: number; 
    handle?: string 
  } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElement = currentPage.elements.find(el => el.id === selectedElementId);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }))
    }));
  }, []);

  const handleDeleteElement = useCallback((id: string) => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map(p => ({ ...p, elements: p.elements.filter(el => el.id !== id) })) 
    }));
    setSelectedElementId(null);
  }, []);

  // Keyboard shortcut for Delete
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedElementId) {
        // Prevent deletion if the user is currently typing in an input/textarea
        const activeTag = document.activeElement?.tagName;
        if (activeTag !== 'INPUT' && activeTag !== 'TEXTAREA') {
          handleDeleteElement(selectedElementId);
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedElementId, handleDeleteElement]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!actionState) return;
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      let newW = actionState.initialW;
      let newH = actionState.initialH;
      let newX = actionState.initialX;
      let newY = actionState.initialY;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, actionState.initialW + dx);
      if (h.includes('l')) { 
        const maxDx = actionState.initialW - 10;
        const clampedDx = Math.min(dx, maxDx);
        newW = actionState.initialW - clampedDx; 
        newX = actionState.initialX + clampedDx; 
      }
      if (h.includes('b')) newH = Math.max(10, actionState.initialH + dy);
      if (h.includes('t')) { 
        const maxDy = actionState.initialH - 10;
        const clampedDy = Math.min(dy, maxDy);
        newH = actionState.initialH - clampedDy; 
        newY = actionState.initialY + clampedDy; 
      }

      handleUpdateElement(actionState.id, { 
        x: Math.round(newX), 
        y: Math.round(newY), 
        width: Math.round(newW), 
        height: Math.round(newH) 
      });
    } else {
      handleUpdateElement(actionState.id, { 
        x: Math.round(actionState.initialX + dx), 
        y: Math.round(actionState.initialY + dy) 
      });
    }
  }, [actionState, zoom, handleUpdateElement]);

  const onMouseUp = useCallback(() => setActionState(null), []);

  useEffect(() => {
    if (actionState) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [actionState, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#0a0a0f] text-slate-200 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElement || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        isPreview={isPreview}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, 
                x: (currentDimensions.width / 2) - 75, 
                y: (currentDimensions.height / 2) - 75, 
                width: type === 'text' ? 300 : 150, 
                height: type === 'text' ? 60 : 150,
                content: content || (type === 'text' ? 'New content' : (type === 'button' ? 'ACTION' : (type === 'shape' ? 'square' : ''))),
                styles: { 
                  backgroundColor: type === 'button' ? '#6366f1' : (type === 'shape' ? '#3b82f6' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#0f172a', 
                  fontSize: type === 'text' ? 24 : 16, 
                  borderRadius: type === 'button' ? 12 : 0, 
                  zIndex: currentPage.elements.length, 
                  opacity: 1, 
                  textAlign: 'center', 
                  fontFamily: 'Inter',
                  hoverAnimation: 'none',
                  clickAnimation: 'none'
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ 
                ...p, 
                pages: p.pages.map(pg => ({ ...pg, elements: [...pg.elements, el] })) 
              }));
              setSelectedElementId(el.id);
            }} 
            onBulkAdd={(data) => {
              const newEls = data.points.map((p: any, i: number) => ({
                id: `ai-${Date.now()}-${i}`,
                type: 'button',
                x: 100 + (i * 200),
                y: 350,
                width: 160,
                height: 52,
                content: p.label,
                styles: { backgroundColor: '#6366f1', color: '#fff', fontSize: 14, borderRadius: 30, zIndex: i, textAlign: 'center', fontFamily: 'Inter', fontWeight: 'bold' },
                interactivity: { type: InteractivityType.TOOLTIP, value: p.info, title: p.label }
              }));
              setProject(pr => ({ ...pr, pages: pr.pages.map(pg => ({ ...pg, elements: [...pg.elements, ...newEls] })) }));
            }}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementId={selectedElementId}
            onSelectElement={setSelectedElementId}
            onGroupElements={() => {}}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#13131a] p-32 flex justify-center items-start scrollbar-hide relative ${isPreview ? 'p-0' : ''}`}
          ref={containerRef}
          onMouseDown={(e) => { if (e.target === containerRef.current) setSelectedElementId(null); }}
        >
          {!isPreview && (
            <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-5 bg-slate-900/80 backdrop-blur-xl border border-white/10 px-6 py-3 rounded-2xl shadow-[0_20px_60px_-15px_rgba(0,0,0,0.7)] ring-1 ring-white/5">
              <button onClick={() => setZoom(Math.max(0.1, zoom - 0.1))} className="text-slate-500 hover:text-white transition-colors h-8 w-8 flex items-center justify-center rounded-lg hover:bg-white/5"><i className="fas fa-minus text-xs"></i></button>
              <div className="flex flex-col items-center min-w-[50px]"><span className="text-sm font-black text-white">{Math.round(zoom * 100)}%</span></div>
              <button onClick={() => setZoom(Math.min(3, zoom + 0.1))} className="text-slate-500 hover:text-white transition-colors h-8 w-8 flex items-center justify-center rounded-lg hover:bg-white/5"><i className="fas fa-plus text-xs"></i></button>
              <div className="w-px h-6 bg-white/10 mx-2" /><button onClick={() => setZoom(1)} className="text-[10px] font-black text-indigo-400 uppercase tracking-widest hover:text-indigo-300 transition-colors">Reset</button>
            </div>
          )}

          <div 
            ref={canvasRef}
            onClick={(e) => { if (e.target === canvasRef.current) setSelectedElementId(null); }}
            className={`bg-white shadow-[0_50px_120px_-20px_rgba(0,0,0,0.8)] relative flex-shrink-0 transition-transform duration-75 ease-out overflow-visible ${isPreview ? 'w-full h-full shadow-none border-none rounded-none' : 'rounded-sm border border-slate-300'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top center'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height });
                }}
                onResizeStart={(e, handle) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height, handle });
                }}
                isPreview={isPreview}
              />
            ))}
          </div>
        </main>

        {selectedElement && !isPreview && (
          <aside className="w-72 bg-[#0d0d12] border-l border-white/5 flex flex-col z-50 animate-in slide-in-from-right duration-300 shadow-2xl">
             <div className="p-5 border-b border-white/5 bg-white/5 flex items-center justify-between">
               <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Properties</h3>
               <span className="text-[9px] text-slate-500 font-bold uppercase">{selectedElement.type}</span>
             </div>
             <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide pb-24">
               {selectedElement.type !== 'shape' && (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Content</label>
                   <textarea 
                      className="w-full bg-[#16161f] border border-white/5 rounded-xl text-xs py-3 px-4 text-slate-300 focus:ring-1 focus:ring-indigo-500 focus:outline-none min-h-[80px] resize-none"
                      value={selectedElement.content}
                      onChange={(e) => handleUpdateElement(selectedElement.id, { content: e.target.value })}
                   />
                 </div>
               )}

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Design</label>
                 <div className="grid grid-cols-2 gap-3">
                   <div className="bg-[#16161f] p-3 rounded-xl border border-white/5">
                      <span className="block text-[8px] font-bold text-slate-600 uppercase mb-2">Color</span>
                      <input 
                        type="color" 
                        value={selectedElement.styles.backgroundColor || '#ffffff'}
                        onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { backgroundColor: e.target.value } })}
                        className="w-full h-8 p-0 border-0 bg-transparent cursor-pointer rounded-lg overflow-hidden"
                      />
                   </div>
                   <div className="bg-[#16161f] p-3 rounded-xl border border-white/5">
                      <span className="block text-[8px] font-bold text-slate-600 uppercase mb-2">Radius</span>
                      <input 
                        type="number" 
                        value={selectedElement.styles.borderRadius}
                        onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { borderRadius: parseInt(e.target.value) } })}
                        className="w-full bg-transparent border-none text-white text-xs font-bold outline-none"
                      />
                   </div>
                 </div>
               </div>

               {selectedElement.type === 'text' && (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Typography</label>
                   <div className="grid grid-cols-2 gap-2">
                      <select value={selectedElement.styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontFamily: e.target.value } })} className="bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 focus:ring-1 focus:ring-indigo-500 outline-none">
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Monospace">Mono</option>
                      </select>
                      <input type="number" value={selectedElement.styles.fontSize} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontSize: parseInt(e.target.value) } })} className="bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 focus:ring-1 focus:ring-indigo-500 outline-none text-center" />
                   </div>
                   <div className="flex bg-[#16161f] rounded-xl p-1 border border-white/5">
                     {['left', 'center', 'right'].map(align => (
                       <button key={align} onClick={() => handleUpdateElement(selectedElement.id, { styles: { textAlign: align as any } })} className={`flex-1 py-2 rounded-lg text-xs transition-all ${selectedElement.styles.textAlign === align ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}><i className={`fas fa-align-${align}`}></i></button>
                     ))}
                   </div>
                 </div>
               )}

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Interaction</label>
                 <div className="space-y-3">
                    <select value={selectedElement.interactivity.type} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, type: e.target.value as any } })} className="w-full bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 outline-none">
                      <option value={InteractivityType.NONE}>No Interaction</option>
                      <option value={InteractivityType.TOOLTIP}>Tooltip</option>
                      <option value={InteractivityType.MODAL}>Modal Window</option>
                      <option value={InteractivityType.EXTERNAL_LINK}>Link</option>
                    </select>
                    {selectedElement.interactivity.type !== InteractivityType.NONE && (
                      <input type="text" placeholder="Value..." value={selectedElement.interactivity.value} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, value: e.target.value } })} className="w-full bg-[#16161f] border border-white/5 rounded-xl text-xs py-2.5 px-3 text-slate-300 focus:ring-1 focus:ring-indigo-500 outline-none" />
                    )}
                 </div>
               </div>

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block">Behaviors (Animations)</label>
                 <div className="space-y-3">
                   <div className="space-y-1">
                      <span className="text-[8px] font-bold text-slate-600 uppercase">Hover</span>
                      <div className="flex flex-wrap gap-1.5">
                        {['none', 'pop', 'lift', 'fade'].map(anim => (
                          <button key={anim} onClick={() => handleUpdateElement(selectedElement.id, { styles: { hoverAnimation: anim as AnimationType } })} className={`px-2 py-1 rounded text-[9px] font-black uppercase tracking-widest transition-all ${selectedElement.styles.hoverAnimation === anim ? 'bg-indigo-600 text-white' : 'bg-[#16161f] text-slate-500 hover:text-slate-300'}`}>{anim}</button>
                        ))}
                      </div>
                   </div>
                   <div className="space-y-1">
                      <span className="text-[8px] font-bold text-slate-600 uppercase">Click</span>
                      <div className="flex flex-wrap gap-1.5">
                        {['none', 'squeeze', 'pop', 'fade'].map(anim => (
                          <button key={anim} onClick={() => handleUpdateElement(selectedElement.id, { styles: { clickAnimation: anim as AnimationType } })} className={`px-2 py-1 rounded text-[9px] font-black uppercase tracking-widest transition-all ${selectedElement.styles.clickAnimation === anim ? 'bg-indigo-600 text-white' : 'bg-[#16161f] text-slate-500 hover:text-slate-300'}`}>{anim}</button>
                        ))}
                      </div>
                   </div>
                 </div>
               </div>
             </div>

             <div className="p-6 bg-white/[0.02] border-t border-white/5 absolute bottom-0 left-0 w-full">
               <button onClick={() => handleDeleteElement(selectedElement.id)} className="w-full py-3 bg-red-500/10 hover:bg-red-500/20 text-red-400 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all border border-red-500/20 shadow-lg shadow-red-950/20"><i className="fas fa-trash-alt mr-2"></i> Delete Object</button>
             </div>
          </aside>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { generateImage, generateContentIdeas } from '../services/geminiService';
import { ElementType, CanvasPreset, CANVAS_PRESETS, ProjectPage } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
  currentPage: ProjectPage;
  selectedElementId: string | null;
  onSelectElement: (id: string | null) => void;
  onGroupElements: (elementIds: string[]) => void;
}

const PREDEFINED_SHAPES = [
  { id: 'square', icon: 'fa-square' },
  { id: 'circle', icon: 'fa-circle' },
  { id: 'triangle', icon: 'fa-play fa-rotate-270' },
  { id: 'star', icon: 'fa-star' },
  { id: 'diamond', icon: 'fa-diamond' },
  { id: 'heart', icon: 'fa-heart' }
];

const Sidebar: React.FC<SidebarProps> = ({ 
  onAddElement, onBulkAdd, canvasPreset, onUpdatePreset, 
  currentPage, selectedElementId, onSelectElement
}) => {
  const [activePanel, setActivePanel] = useState<'assets' | 'management'>('assets');
  const [managementTab, setManagementTab] = useState<'layers' | 'settings'>('layers');
