import React, { useState, useCallback, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS, AnimationType } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'GenialAI Workspace',
  pages: [{ id: 'page-1', name: 'Slide 1', elements: [], groups: [] }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [actionState, setActionState] = useState<{ 
    id: string; 
    startX: number; 
    startY: number; 
    initialX: number; 
    initialY: number; 
    initialW: number; 
    initialH: number; 
    handle?: string 
  } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElement = currentPage.elements.find(el => el.id === selectedElementId);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(p => ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }))
    }));
  }, []);

  const handleDeleteElement = useCallback((id: string) => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map(p => ({ ...p, elements: p.elements.filter(el => el.id !== id) })) 
    }));
    setSelectedElementId(null);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedElementId) {
        const activeTag = document.activeElement?.tagName;
        if (activeTag !== 'INPUT' && activeTag !== 'TEXTAREA') {
          handleDeleteElement(selectedElementId);
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedElementId, handleDeleteElement]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!actionState) return;
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      let newW = actionState.initialW;
      let newH = actionState.initialH;
      let newX = actionState.initialX;
      let newY = actionState.initialY;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, actionState.initialW + dx);
      if (h.includes('l')) { 
        const maxDx = actionState.initialW - 10;
        const clampedDx = Math.min(dx, maxDx);
        newW = actionState.initialW - clampedDx; 
        newX = actionState.initialX + clampedDx; 
      }
      if (h.includes('b')) newH = Math.max(10, actionState.initialH + dy);
      if (h.includes('t')) { 
        const maxDy = actionState.initialH - 10;
        const clampedDy = Math.min(dy, maxDy);
        newH = actionState.initialH - clampedDy; 
        newY = actionState.initialY + clampedDy; 
      }

      handleUpdateElement(actionState.id, { 
        x: Math.round(newX), 
        y: Math.round(newY), 
        width: Math.round(newW), 
        height: Math.round(newH) 
      });
    } else {
      handleUpdateElement(actionState.id, { 
        x: Math.round(actionState.initialX + dx), 
        y: Math.round(actionState.initialY + dy) 
      });
    }
  }, [actionState, zoom, handleUpdateElement]);

  const onMouseUp = useCallback(() => setActionState(null), []);

  useEffect(() => {
    if (actionState) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [actionState, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElement || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        isPreview={isPreview}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, 
                x: (currentDimensions.width / 2) - 75, 
                y: (currentDimensions.height / 2) - 75, 
                width: type === 'text' ? 300 : 150, 
                height: type === 'text' ? 60 : 150,
                content: content || (type === 'text' ? 'New content' : (type === 'button' ? 'ACTION' : (type === 'shape' ? 'square' : ''))),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#000000' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: type === 'text' ? 24 : 16, 
                  borderRadius: type === 'button' ? 4 : 0, 
                  zIndex: currentPage.elements.length, 
                  opacity: 1, 
                  textAlign: 'center', 
                  fontFamily: 'Inter',
                  hoverAnimation: 'none',
                  clickAnimation: 'none'
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ 
                ...p, 
                pages: p.pages.map(pg => ({ ...pg, elements: [...pg.elements, el] })) 
              }));
              setSelectedElementId(el.id);
            }} 
            onBulkAdd={(data) => {
              const newEls = data.points.map((p: any, i: number) => ({
                id: `ai-${Date.now()}-${i}`,
                type: 'button',
                x: 100 + (i * 200),
                y: 350,
                width: 160,
                height: 52,
                content: p.label,
                styles: { backgroundColor: '#E4002B', color: '#fff', fontSize: 14, borderRadius: 4, zIndex: i, textAlign: 'center', fontFamily: 'Inter', fontWeight: 'bold' },
                interactivity: { type: InteractivityType.TOOLTIP, value: p.info, title: p.label }
              }));
              setProject(pr => ({ ...pr, pages: pr.pages.map(pg => ({ ...pg, elements: [...pg.elements, ...newEls] })) }));
            }}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementId={selectedElementId}
            onSelectElement={setSelectedElementId}
            onGroupElements={() => {}}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#FAFAFA] p-32 flex justify-center items-start scrollbar-hide relative ${isPreview ? 'p-0' : ''}`}
          ref={containerRef}
          onMouseDown={(e) => { if (e.target === containerRef.current) setSelectedElementId(null); }}
        >
          {/* Zoom Controller Light Theme */}
          {!isPreview && (
            <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-5 bg-white border border-slate-200 px-6 py-3 rounded-full shadow-xl ring-1 ring-black/5">
              <button onClick={() => setZoom(Math.max(0.1, zoom - 0.1))} className="text-slate-400 hover:text-[#E4002B] transition-colors h-8 w-8 flex items-center justify-center rounded-lg hover:bg-slate-50"><i className="fas fa-minus text-xs"></i></button>
              <div className="flex flex-col items-center min-w-[50px]"><span className="text-sm font-black text-slate-900">{Math.round(zoom * 100)}%</span></div>
              <button onClick={() => setZoom(Math.min(3, zoom + 0.1))} className="text-slate-400 hover:text-[#E4002B] transition-colors h-8 w-8 flex items-center justify-center rounded-lg hover:bg-slate-50"><i className="fas fa-plus text-xs"></i></button>
              <div className="w-px h-6 bg-slate-200 mx-2" /><button onClick={() => setZoom(1)} className="text-[10px] font-black text-[#E4002B] uppercase tracking-widest hover:text-[#c40024] transition-colors">Reset</button>
            </div>
          )}

          <div 
            ref={canvasRef}
            onClick={(e) => { if (e.target === canvasRef.current) setSelectedElementId(null); }}
            className={`bg-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] relative flex-shrink-0 transition-transform duration-75 ease-out overflow-visible ${isPreview ? 'w-full h-full shadow-none border-none rounded-none' : 'rounded-sm border border-slate-200'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top center'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height });
                }}
                onResizeStart={(e, handle) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height, handle });
                }}
                isPreview={isPreview}
              />
            ))}
          </div>
        </main>

        {selectedElement && !isPreview && (
          <aside className="w-72 bg-white border-l border-slate-200 flex flex-col z-50 animate-in slide-in-from-right duration-300 shadow-xl overflow-hidden">
             <div className="p-5 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
               <h3 className="text-[10px] font-black text-[#E4002B] uppercase tracking-widest">Properties</h3>
               <span className="text-[9px] text-slate-400 font-bold uppercase">{selectedElement.type}</span>
             </div>
             <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide pb-32">
               {selectedElement.type !== 'shape' && (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Content</label>
                   <textarea 
                      className="w-full bg-slate-50 border border-slate-200 rounded-lg text-xs py-3 px-4 text-slate-900 focus:ring-1 focus:ring-[#E4002B] focus:outline-none min-h-[80px] resize-none"
                      value={selectedElement.content}
                      onChange={(e) => handleUpdateElement(selectedElement.id, { content: e.target.value })}
                   />
                 </div>
               )}

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Design & Fill</label>

                 {/* Fill Toggle */}
                 <div className="flex bg-slate-100 p-1 rounded-lg gap-1">
                    <button 
                      onClick={() => handleUpdateElement(selectedElement.id, { styles: { gradient: undefined } })}
                      className={`flex-1 py-1.5 rounded text-[9px] font-black uppercase transition-all ${!selectedElement.styles.gradient ? 'bg-white text-[#E4002B] shadow-sm' : 'text-slate-500'}`}
                    >Solid</button>
                    <button 
                      onClick={() => handleUpdateElement(selectedElement.id, { styles: { gradient: 'linear-gradient(135deg, #E4002B 0%, #000000 100%)' } })}
                      className={`flex-1 py-1.5 rounded text-[9px] font-black uppercase transition-all ${selectedElement.styles.gradient ? 'bg-white text-[#E4002B] shadow-sm' : 'text-slate-500'}`}
                    >Gradient</button>
                 </div>

                 <div className="grid grid-cols-2 gap-3">
                   <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                      <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Color</span>
                      <input 
                        type="color" 
                        value={selectedElement.styles.backgroundColor || '#E4002B'}
                        onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { backgroundColor: e.target.value } })}
                        className="w-full h-8 p-0 border-0 bg-transparent cursor-pointer rounded-lg overflow-hidden"
                      />
                   </div>
                   <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                      <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Radius</span>
                      <input 
                        type="number" 
                        value={selectedElement.styles.borderRadius}
                        onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { borderRadius: parseInt(e.target.value) } })}
                        className="w-full bg-transparent border-none text-slate-900 text-xs font-bold outline-none"
                      />
                   </div>
                 </div>

                 {selectedElement.styles.gradient && (
                    <div className="p-3 bg-slate-50 border border-slate-200 rounded-lg space-y-3">
                        <span className="block text-[8px] font-bold text-slate-400 uppercase">Gradient Logic</span>
                        <div className="flex items-center gap-2">
                            <div className="flex-1 h-8 rounded border border-slate-200 overflow-hidden shadow-inner" style={{ background: selectedElement.styles.gradient }}></div>
                            <button 
                                onClick={() => {
                                    const colors = ['#E4002B', '#000000', '#FFFFFF', '#FFBABA'];
                                    const c1 = colors[Math.floor(Math.random()*colors.length)];
                                    const c2 = colors[Math.floor(Math.random()*colors.length)];
                                    handleUpdateElement(selectedElement.id, { styles: { gradient: `linear-gradient(45deg, ${c1} 0%, ${c2} 100%)` } });
                                }}
                                className="text-[8px] font-bold text-[#E4002B] uppercase hover:underline"
                            >Randomize</button>
                        </div>
                    </div>
                 )}
               </div>

               {selectedElement.type === 'text' && (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Typography</label>
                   <div className="grid grid-cols-2 gap-2">
                      <select value={selectedElement.styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontFamily: e.target.value } })} className="bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 focus:ring-1 focus:ring-[#E4002B] outline-none">
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Monospace">Mono</option>
                      </select>
                      <input type="number" value={selectedElement.styles.fontSize} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontSize: parseInt(e.target.value) } })} className="bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 focus:ring-1 focus:ring-[#E4002B] outline-none text-center" />
                   </div>
                   <div className="flex bg-slate-50 rounded-lg p-1 border border-slate-200">
                     {['left', 'center', 'right'].map(align => (
                       <button key={align} onClick={() => handleUpdateElement(selectedElement.id, { styles: { textAlign: align as any } })} className={`flex-1 py-2 rounded-lg text-xs transition-all ${selectedElement.styles.textAlign === align ? 'bg-white text-[#E4002B] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><i className={`fas fa-align-${align}`}></i></button>
                     ))}
                   </div>
                 </div>
               )}

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Interaction</label>
                 <div className="space-y-3">
                    <select value={selectedElement.interactivity.type} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, type: e.target.value as any } })} className="w-full bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 outline-none">
                      <option value={InteractivityType.NONE}>No Interaction</option>
                      <option value={InteractivityType.TOOLTIP}>Tooltip</option>
                      <option value={InteractivityType.MODAL}>Modal Window</option>
                      <option value={InteractivityType.EXTERNAL_LINK}>Link</option>
                    </select>
                    {selectedElement.interactivity.type !== InteractivityType.NONE && (
                      <input type="text" placeholder="Value..." value={selectedElement.interactivity.value} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, value: e.target.value } })} className="w-full bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 focus:ring-1 focus:ring-[#E4002B] outline-none" />
                    )}
                 </div>
               </div>

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Animations</label>
                 <div className="space-y-3">
                   <div className="space-y-1">
                      <span className="text-[8px] font-bold text-slate-400 uppercase">On Hover</span>
                      <div className="flex flex-wrap gap-1.5">
                        {['none', 'pop', 'lift', 'fade'].map(anim => (
                          <button key={anim} onClick={() => handleUpdateElement(selectedElement.id, { styles: { hoverAnimation: anim as AnimationType } })} className={`px-2 py-1 rounded text-[9px] font-black uppercase transition-all ${selectedElement.styles.hoverAnimation === anim ? 'bg-[#E4002B] text-white' : 'bg-slate-100 text-slate-400 hover:text-slate-600'}`}>{anim}</button>
                        ))}
                      </div>
                   </div>
                 </div>
               </div>
             </div>

             <div className="p-6 bg-slate-50 border-t border-slate-200 absolute bottom-0 left-0 w-full">
               <button onClick={() => handleDeleteElement(selectedElement.id)} className="w-full py-3 bg-red-50 hover:bg-red-100 text-[#E4002B] text-[10px] font-black uppercase tracking-widest rounded-lg transition-all border border-red-200"><i className="fas fa-trash-alt mr-2"></i> Delete Object</button>
             </div>
          </aside>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { generateImage, generateContentIdeas } from '../services/geminiService';
import { ElementType, CanvasPreset, CANVAS_PRESETS, ProjectPage } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
  currentPage: ProjectPage;
  selectedElementId: string | null;
  onSelectElement: (id: string | null) => void;
  onGroupElements: (elementIds: string[]) => void;
}

const PREDEFINED_SHAPES = [
  { id: 'square', icon: 'fa-square' },
  { id: 'circle', icon: 'fa-circle' },
  { id: 'triangle', icon: 'fa-play fa-rotate-270' },
  { id: 'star', icon: 'fa-star' },
  { id: 'diamond', icon: 'fa-diamond' },
  { id: 'heart', icon: 'fa-heart' }
];

const Sidebar: React.FC<SidebarProps> = ({ 
  onAddElement, onBulkAdd, canvasPreset, onUpdatePreset, 
  currentPage, selectedElementId, onSelectElement
}) => {
  const [activePanel, setActivePanel] = useState<'assets' | 'management'>('assets');
  const [managementTab, setManagementTab] = useState<'layers' | 'settings'>('layers');
  const [showShapeMenu, setShowShapeMenu] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  return (
    <div className="flex h-full bg-white border-r border-slate-200 z-[100] shadow-xl">
      {/* KFC Primary Navigation Column */}
      <div className="w-16 bg-white flex flex-col items-center py-8 gap-8 border-r border-slate-100">
        <NavIcon 
          active={activePanel === 'assets'} 
          icon="fa-circle-plus" 
          onClick={() => { setActivePanel('assets'); setShowShapeMenu(false); }} 
          label="Add"
        />
        <NavIcon 
          active={activePanel === 'management'} 
          icon="fa-sliders" 
          onClick={() => { setActivePanel('management'); setShowShapeMenu(false); }} 
          label="Organize"
        />
        <div className="mt-auto opacity-20 hover:opacity-100 transition-opacity">
           <NavIcon active={false} icon="fa-life-ring" onClick={() => {}} label="Help" />
        </div>
      </div>

      {/* KFC Content Panel Column */}
      <div className="w-64 flex flex-col bg-slate-50/50">
        <div className="h-16 flex items-center px-6 border-b border-slate-100 bg-white">
          <h2 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.25em]">
            {activePanel === 'assets' ? 'Creative Studio' : 'Workspace'}
          </h2>
        </div>

        <div className="flex-1 overflow-y-auto px-6 py-8 space-y-10 scrollbar-hide">
          {activePanel === 'assets' ? (
            <div className="space-y-10">
              <section>
                <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-5">Primary Elements</h3>
                <div className="grid grid-cols-2 gap-4">
                  <AssetButton icon="fa-heading" label="Text" onClick={() => onAddElement('text')} />
                  <AssetButton icon="fa-square-check" label="Button" onClick={() => onAddElement('button')} />
                  <AssetButton 
                    icon="fa-shapes" 
                    label="Shape" 
                    onClick={() => setShowShapeMenu(!showShapeMenu)} 
                    active={showShapeMenu}
                  />
                  <AssetButton icon="fa-images" label="Image" onClick={() => {
                     const url = prompt("Paste Image URL:"); if(url) onAddElement('image', url);
                  }} />
                </div>
              </section>

              {showShapeMenu && (
                <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm animate-in zoom-in-95 duration-200">
                  <h4 className="text-[8px] font-black text-[#E4002B] uppercase tracking-widest mb-3">Geometric Shapes</h4>
                  <div className="grid grid-cols-3 gap-2">
                    {PREDEFINED_SHAPES.map(s => (
                      <button 
                        key={s.id}
                        onClick={() => { onAddElement('shape', s.id); setShowShapeMenu(false); }}
                        className="h-12 bg-slate-50 rounded-lg flex items-center justify-center border border-slate-200 hover:border-[#E4002B] hover:text-[#E4002B] text-slate-400 transition-all"
                      >
                        <i className={`fas ${s.icon} text-sm`}></i>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <section className="bg-red-50 rounded-2xl p-5 border border-red-100 shadow-sm">
                <div className="flex items-center gap-2.5 mb-4">
                  <div className="w-1.5 h-1.5 rounded-full bg-[#E4002B]" />
                  <h3 className="text-[10px] font-black text-[#E4002B] uppercase tracking-widest">AI Content</h3>
                </div>
                <textarea
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  placeholder="Ask AI for a layout..."
                  className="w-full p-4 bg-white border border-red-100 rounded-xl text-[11px] h-32 text-slate-900 focus:ring-1 focus:ring-[#E4002B] focus:outline-none placeholder-slate-300 resize-none leading-relaxed"
                />
                <button 
                  disabled={isLoading || !aiPrompt}
                  onClick={async () => {
                    setIsLoading(true);
                    try { const ideas = await generateContentIdeas(aiPrompt); onBulkAdd(ideas); setAiPrompt(''); } finally { setIsLoading(false); }
                  }}
                  className="w-full mt-4 py-3.5 bg-[#E4002B] hover:bg-[#c40024] disabled:opacity-50 text-white text-[10px] font-black rounded-xl transition-all shadow-md active:scale-95 uppercase tracking-widest"
                >
                  {isLoading ? <i className="fas fa-circle-notch fa-spin"></i> : 'Generate Interactive Slide'}
                </button>
              </section>
            </div>
          ) : (
            <div className="space-y-8">
              <div className="flex p-1 bg-white rounded-lg border border-slate-200">
                 <button onClick={() => setManagementTab('layers')} className={`flex-1 py-2 rounded text-[9px] font-black uppercase tracking-widest transition-all ${managementTab === 'layers' ? 'bg-slate-100 text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Layers</button>
                 <button onClick={() => setManagementTab('settings')} className={`flex-1 py-2 rounded text-[9px] font-black uppercase tracking-widest transition-all ${managementTab === 'settings' ? 'bg-slate-100 text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Setup</button>
              </div>

              {managementTab === 'layers' ? (
                <div className="space-y-2.5">
                  {[...currentPage.elements].reverse().map(el => (
                    <div 
                      key={el.id}
                      onClick={() => onSelectElement(el.id)}
                      className={`group p-3.5 rounded-xl flex items-center gap-4 text-xs cursor-pointer transition-all border ${selectedElementId === el.id ? 'bg-[#E4002B] border-[#E4002B] text-white shadow-lg' : 'bg-white border-slate-200 hover:border-slate-300 text-slate-600'}`}
                    >
                      <div className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${selectedElementId === el.id ? 'bg-[#c40024]' : 'bg-slate-50 text-slate-400 group-hover:text-[#E4002B]'}`}>
                        <i className={`fas ${el.type === 'text' ? 'fa-font' : el.type === 'image' ? 'fa-image' : 'fa-square'} text-xs`}></i>
                      </div>
                      <span className="truncate flex-1 font-bold text-[10px] tracking-tight uppercase">
                        {el.type === 'text' ? (el.content.length > 15 ? el.content.substring(0, 15) + '...' : el.content) : (el.type === 'shape' ? el.content : el.type)}
                      </span>
                    </div>
                  ))}
                  {currentPage.elements.length === 0 && (
                    <div className="text-center py-20 border-2 border-dashed border-slate-200 rounded-2xl opacity-40"><i className="fas fa-layer-group text-3xl mb-4 text-slate-300"></i><p className="text-[9px] font-black uppercase tracking-widest text-slate-400">Empty Canvas</p></div>
                  )}
                </div>
              ) : (
                <div className="space-y-3">
                  {(Object.entries(CANVAS_PRESETS) as [CanvasPreset, any][]).map(([key, dim]) => (
                     <button key={key} onClick={() => onUpdatePreset(key)} className={`w-full text-left p-5 rounded-xl border transition-all ${canvasPreset === key ? 'border-[#E4002B] bg-red-50 text-[#E4002B]' : 'border-slate-200 text-slate-500 hover:bg-slate-50'}`}><div className="text-[10px] uppercase font-black tracking-widest mb-1.5">{dim.label}</div><div className="text-[9px] font-bold opacity-40 tracking-wider">{dim.width} x {dim.height}px</div></button>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const NavIcon: React.FC<{ active: boolean; icon: string; onClick: () => void; label: string }> = ({ active, icon, onClick, label }) => (
  <button 
    onClick={onClick}
    className={`group flex flex-col items-center gap-2 transition-all outline-none ${active ? 'text-[#E4002B]' : 'text-slate-300 hover:text-[#E4002B]'}`}
  >
    <div className={`w-11 h-11 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-red-50 ring-1 ring-[#E4002B]' : 'bg-white hover:bg-slate-50 border border-slate-100'}`}><i className={`fas ${icon} text-lg`}></i></div>
    <span className={`text-[8px] font-black uppercase tracking-tighter transition-opacity ${active ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>{label}</span>
  </button>
);

const AssetButton: React.FC<{ icon: string; label: string; onClick: () => void; active?: boolean }> = ({ icon, label, onClick, active }) => (
  <button onClick={onClick} className={`flex flex-col items-center justify-center p-5 bg-white rounded-xl border transition-all group active:scale-95 shadow-sm ${active ? 'border-[#E4002B] bg-red-50' : 'border-slate-200 hover:border-[#E4002B]'}`}>
    <i className={`fas ${icon} mb-3 transition-colors text-lg ${active ? 'text-[#E4002B]' : 'text-slate-300 group-hover:text-[#E4002B]'}`}></i>
    <span className={`text-[9px] font-black uppercase tracking-widest ${active ? 'text-[#E4002B]' : 'text-slate-400 group-hover:text-slate-600'}`}>{label}</span>
  </button>
);

export default Sidebar;

import React from 'react';
import { CanvasElement } from '../types';

interface ToolbarProps {
  selectedElement: CanvasElement | null;
  onPreview: () => void;
  isPreview: boolean;
}

const Toolbar: React.FC<ToolbarProps> = ({ 
  selectedElement, onPreview, isPreview
}) => {
  return (
    <div className={`h-16 flex items-center justify-between px-8 transition-colors duration-300 shadow-sm z-[100] ${isPreview ? 'bg-white border-b border-slate-100' : 'bg-white border-b border-slate-200'}`}>
      <div className="flex items-center gap-8">
        <div className="flex items-center gap-3 pr-8 border-r border-slate-200">
          <div className="w-8 h-8 bg-[#E4002B] rounded-lg flex items-center justify-center shadow-md">
