          <div>
            <span className="block font-black text-slate-900 text-[11px] tracking-[0.3em] uppercase leading-none mb-1">GenialAI</span>
            <span className="block text-[8px] text-[#E4002B] font-bold tracking-widest uppercase opacity-80">Content Studio</span>
          </div>
        </div>

        {selectedElement && !isPreview && (
          <div className="flex items-center gap-2 animate-in fade-in duration-300">
