                   </div>
                 </div>

                 {selectedElement.styles.gradient && (
                    <div className="p-3 bg-slate-50 border border-slate-200 rounded-lg space-y-3">
                        <span className="block text-[8px] font-bold text-slate-400 uppercase">Gradient Logic</span>
                        <div className="flex items-center gap-2">
                            <div className="flex-1 h-8 rounded border border-slate-200 overflow-hidden shadow-inner" style={{ background: selectedElement.styles.gradient }}></div>
                            <button onClick={() => {
                                    const colors = ['#E4002B', '#000000', '#FFFFFF', '#FFBABA'];
                                    const c1 = colors[Math.floor(Math.random()*colors.length)];
                                    const c2 = colors[Math.floor(Math.random()*colors.length)];
                                    handleUpdateElement(selectedElement.id, { styles: { gradient: `linear-gradient(45deg, ${c1} 0%, ${c2} 100%)` } });
                                }} className="text-[8px] font-bold text-[#E4002B] uppercase hover:underline">Randomize</button>
                        </div>
                    </div>
                 )}
               </div>

               {selectedElement.type === 'text' && (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Typography</label>
                   <div className="grid grid-cols-2 gap-2">
