import React, { useState } from 'react';
import { CanvasElement, InteractivityType, AnimationType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onResizeStart: (e: React.MouseEvent, handle: string) => void;
  isPreview?: boolean;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ element, isSelected, onSelect, onResizeStart, isPreview }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isPressed, setIsPressed] = useState(false);

  const getAnimationClass = (type?: AnimationType, state?: 'hover' | 'click') => {
    if (!type || type === 'none') return '';
    if (state === 'hover' && !isHovered) return '';
    if (state === 'click' && !isPressed) return '';

    switch (type) {
      case 'pop': return 'scale-110';
      case 'lift': return '-translate-y-2 shadow-2xl';
      case 'squeeze': return 'scale-95';
      case 'fade': return 'opacity-60';
      default: return '';
    }
  };

  const isCircle = element.type === 'shape' && element.content === 'circle';

  const style: React.CSSProperties = {
    position: 'absolute',
    left: element.x,
    top: element.y,
    width: element.width,
    height: element.height,
    zIndex: element.styles.zIndex,
    cursor: isPreview && element.interactivity.type !== InteractivityType.NONE ? 'pointer' : 'move',

    // Support gradient vs solid background
    background: element.styles.gradient ? element.styles.gradient : element.styles.backgroundColor,
    backgroundColor: !element.styles.gradient ? element.styles.backgroundColor : undefined,

    color: element.styles.color,
    fontSize: element.styles.fontSize,
    borderRadius: isCircle ? '50%' : `${element.styles.borderRadius}px`,
    fontWeight: element.styles.fontWeight as any,
    fontFamily: element.styles.fontFamily || 'Inter, sans-serif',
    textAlign: element.styles.textAlign,
    opacity: element.styles.opacity,
    display: 'flex',
    alignItems: 'center',
    justifyContent: element.styles.textAlign === 'center' ? 'center' : (element.styles.textAlign === 'right' ? 'flex-end' : 'flex-start'),
    padding: element.type === 'text' ? '12px' : '0',
    transition: 'all 0.15s cubic-bezier(0.4, 0, 0.2, 1)',
    userSelect: 'none',
    pointerEvents: 'auto',
    clipPath: getClipPath(element.type === 'shape' ? element.content : '')
  };

  const handles = ['tl', 'tr', 'bl', 'br', 'tc', 'bc', 'ml', 'mr'];

  const handleInteraction = () => {
    if (!isPreview) return;
    switch (element.interactivity.type) {
      case InteractivityType.EXTERNAL_LINK: window.open(element.interactivity.value, '_blank'); break;
      case InteractivityType.TOOLTIP: alert(`${element.interactivity.title || 'Info'}: ${element.interactivity.value}`); break;
      case InteractivityType.MODAL: alert(`Modal Window: ${element.interactivity.value}`); break;
    }
  };

  const animationClasses = isPreview ? `
    ${getAnimationClass(element.styles.hoverAnimation, 'hover')}
    ${getAnimationClass(element.styles.clickAnimation, 'click')}
  ` : '';

  const renderContent = () => {
    switch(element.type) {
      case 'image':
        return <img src={element.content} alt="" className="w-full h-full object-contain pointer-events-none" />;
      case 'video':
        return <video src={element.content} controls={isPreview} className="w-full h-full object-cover rounded-inherit" />;
      case 'audio':
        return (
          <div className="w-full h-full flex items-center bg-slate-100 rounded-lg px-2 gap-2 overflow-hidden border border-slate-200">
             <i className="fas fa-music text-[#E4002B] text-xs shrink-0"></i>
             <audio src={element.content} controls={isPreview} className="w-full h-8 scale-75 origin-left" />
          </div>
        );
      case 'shape':
        return <div className="w-full h-full" style={{ background: 'inherit' }} />;
      default:
        return <span className="w-full pointer-events-none whitespace-pre-wrap">{element.content}</span>;
    }
  };

  return (
    <div
      style={style}
      onMouseDown={(e) => { setIsPressed(true); onSelect(e); }}
      onMouseUp={() => setIsPressed(false)}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => { setIsHovered(false); setIsPressed(false); }}
      onClick={handleInteraction}
      className={`
        ${isSelected && !isPreview ? 'ring-2 ring-[#E4002B]' : ''} 
        ${animationClasses}
        group
      `}
    >
      {renderContent()}

      {isSelected && !isPreview && handles.map(h => (
        <div
          key={h}
          onMouseDown={(e) => { e.stopPropagation(); onResizeStart(e, h); }}
          className={`absolute w-3 h-3 bg-white border-2 border-[#E4002B] rounded-full z-[120] hover:scale-125 transition-transform cursor-${getCursor(h)}`}
          style={getHandleStyle(h)}
        />
      ))}
    </div>
  );
};

function getClipPath(shape: string) {
  switch (shape) {
    case 'triangle': return 'polygon(50% 0%, 0% 100%, 100% 100%)';
    case 'star': return 'polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%)';
    case 'diamond': return 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)';
    case 'heart': return 'path("M 50 25 C 50 10, 80 10, 80 30 C 80 50, 50 75, 50 90 C 50 75, 20 50, 20 30 C 20 10, 50 10, 50 25")';
    default: return 'none';
  }
}

function getCursor(h: string) {
  if (h === 'tl' || h === 'br') return 'nwse-resize';
  if (h === 'tr' || h === 'bl') return 'nesw-resize';
  if (h === 'tc' || h === 'bc') return 'ns-resize';
  return 'ew-resize';
}

function getHandleStyle(h: string): React.CSSProperties {
  const offset = '-6px';
  switch (h) {
    case 'tl': return { top: offset, left: offset };
    case 'tr': return { top: offset, right: offset };
    case 'bl': return { bottom: offset, left: offset };
    case 'br': return { bottom: offset, right: offset };
    case 'tc': return { top: offset, left: '50%', transform: 'translateX(-50%)' };
    case 'bc': return { bottom: offset, left: '50%', transform: 'translateX(-50%)' };
    case 'ml': return { top: '50%', left: offset, transform: 'translateY(-50%)' };
    case 'mr': return { top: '50%', right: offset, transform: 'translateY(-50%)' };
    default: return {};
  }
}

export default ElementRenderer;

import JSZip from 'jszip';
import { Project } from '../types';

export const exportScorm = async (project: Project, version: '1.2' | '2004') => {
  const zip = new JSZip();
  const projectJson = JSON.stringify(project);

  // 1. Create Manifest
  const manifest = version === '1.2' ? getScorm12Manifest(project) : getScorm2004Manifest(project);
  zip.file('imsmanifest.xml', manifest);

  // 2. Create index.html (The Player)
  const playerHtml = getPlayerHtml(projectJson, version);
  zip.file('index.html', playerHtml);

  // 3. SCORM API Wrapper
  const wrapper = getScormWrapper();
  zip.file('scorm_wrapper.js', wrapper);

  // Generate ZIP
  const content = await zip.generateAsync({ type: 'blob' });
  const fileName = `${project.title.replace(/\s+/g, '_')}_SCORM_${version}.zip`;

  const link = document.createElement('a');
  link.href = URL.createObjectURL(content);
  link.download = fileName;
  link.click();
};

