const getPlayerHtml = (projectJson: string, version: string) => `
<!DOCTYPE html>
<html>
<head>
    <title>KFC SCORM Player</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <script src="scorm_wrapper.js"></script>
    <style>
        body { margin: 0; overflow: hidden; background: #eee; font-family: sans-serif; }
        #viewport { width: 100vw; height: 100vh; display: flex; align-items: center; justify-content: center; overflow: auto; }
        .canvas { position: relative; background: white; box-shadow: 0 10px 30px rgba(0,0,0,0.1); flex-shrink: 0; }
        .element { position: absolute; display: flex; align-items: center; }
    </style>
</head>
<body>
    <div id="viewport">
        <div id="canvas" class="canvas"></div>
    </div>
    <script>
        const project = ${projectJson};
        const scormVersion = "${version}";
        let currentPage = 0;

        function initScorm() {
            const success = pipwerks.SCORM.init();
            if(success) {
                pipwerks.SCORM.set("cmi.core.lesson_status", "incomplete");
                if(scormVersion === "2004") pipwerks.SCORM.set("cmi.completion_status", "incomplete");
                pipwerks.SCORM.save();
            }
        }

        function finishScorm() {
            pipwerks.SCORM.set("cmi.core.lesson_status", "completed");
            if(scormVersion === "2004") pipwerks.SCORM.set("cmi.completion_status", "completed");
            pipwerks.SCORM.save();
            pipwerks.SCORM.quit();
        }

        function renderPage(index) {
            const page = project.pages[index];
            const canvas = document.getElementById('canvas');
            const dims = {
                presentation: { w: 960, h: 540 },
                square: { w: 600, h: 600 },
                vertical: { w: 400, h: 711 },
                a4: { w: 595, h: 842 }
            }[project.canvasPreset];

            canvas.style.width = dims.w + 'px';
            canvas.style.height = dims.h + 'px';
            canvas.innerHTML = '';

            // Set Background
            if(page.background) {
                if(page.background.type === 'color') canvas.style.background = page.background.value;
                else if(page.background.type === 'gradient') canvas.style.background = page.background.value;
                else canvas.style.backgroundImage = "url(" + page.background.value + ")";
                canvas.style.backgroundSize = "cover";
            }

            page.elements.forEach(el => {
                const div = document.createElement('div');
                div.className = 'element';
                div.style.left = el.x + 'px';
                div.style.top = el.y + 'px';
                div.style.width = el.width + 'px';
                div.style.height = el.height + 'px';
                div.style.zIndex = el.styles.zIndex;
                div.style.background = el.styles.gradient || el.styles.backgroundColor;
                div.style.color = el.styles.color;
                div.style.fontSize = el.styles.fontSize + 'px';
                div.style.borderRadius = el.styles.borderRadius + 'px';
                div.style.textAlign = el.styles.textAlign;
                div.style.justifyContent = el.styles.textAlign === 'center' ? 'center' : 'flex-start';
                div.style.fontFamily = el.styles.fontFamily;

                if(el.type === 'text') div.innerText = el.content;
                else if(el.type === 'image') div.innerHTML = '<img src="' + el.content + '" style="width:100%;height:100%;object-fit:contain">';
                else if(el.type === 'button') div.innerText = el.content;

                if(el.interactivity && el.interactivity.type !== 'NONE') {
                    div.style.cursor = 'pointer';
                    div.onclick = () => {
                        if(el.interactivity.type === 'EXTERNAL_LINK') window.open(el.interactivity.value);
                        else alert(el.interactivity.value);
                    };
                }

                canvas.appendChild(div);
            });

            if(index === project.pages.length - 1) {
                finishScorm();
            }
        }

        window.onload = () => {
            initScorm();
            renderPage(0);
        };
    </script>
</body>
</html>`;

const getScormWrapper = () => `
var pipwerks = {};
pipwerks.UTILS = {
    handleError: function(msg){ console.error(msg); return false; }
};
pipwerks.SCORM = {
    version: null,
    handle: null,
    isInit: false,
    init: function(){
        this.handle = this.getAPI();
        if(this.handle){
            var success = false;
            if(this.version === "1.2") success = this.handle.LMSInitialize("");
            else if(this.version === "2004") success = this.handle.Initialize("");
            this.isInit = (success === "true" || success === true);
            return this.isInit;
        }
        return false;
    },
    getAPI: function(){
        var win = window, find = function(w){
            if(w.API) { pipwerks.SCORM.version = "1.2"; return w.API; }
            if(w.API_1484_11) { pipwerks.SCORM.version = "2004"; return w.API_1484_11; }
            return null;
        }, api = find(win);
        if(!api && win.parent && win.parent !== win) api = find(win.parent);
        if(!api && win.top && win.top !== win) api = find(win.top);
        if(!api && win.opener) api = find(win.opener);
        return api;
    },
    set: function(param, val){
        if(this.isInit){
            if(this.version === "1.2") return this.handle.LMSSetValue(param, val);
            return this.handle.SetValue(param, val);
        }
    },
    save: function(){
        if(this.isInit){
            if(this.version === "1.2") return this.handle.LMSCommit("");
            return this.handle.Commit("");
        }
    },
    quit: function(){
        if(this.isInit){
            if(this.version === "1.2") this.handle.LMSFinish("");
            else this.handle.Terminate("");
            this.isInit = false;
        }
    }
};`;

