import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS, AnimationType, PageBackground } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Untitled KFC Project',
  pages: [{ 
    id: 'page-1', 
    name: 'Page 1', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [clipboard, setClipboard] = useState<CanvasElement | null>(null);
  const [actionState, setActionState] = useState<{ 
    id: string; 
    startX: number; 
    startY: number; 
    initialX: number; 
    initialY: number; 
    initialW: number; 
    initialH: number; 
    handle?: string 
  } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPageIndex = 0; 
  const currentPage = project.pages[currentPageIndex];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElement = useMemo(() => 
    currentPage.elements.find(el => el.id === selectedElementId)
  , [currentPage.elements, selectedElementId]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleUpdateBackground = useCallback((bg: PageBackground) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p)
    }));
  }, [currentPageIndex]);

  const handleDeleteElement = useCallback((id: string) => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map(p => ({ ...p, elements: p.elements.filter(el => el.id !== id) })) 
    }));
    setSelectedElementId(null);
  }, []);

  const handleCopy = useCallback(() => {
    if (selectedElement) {
      setClipboard({ ...selectedElement });
    }
  }, [selectedElement]);

  const handleCut = useCallback(() => {
    if (selectedElement) {
      setClipboard({ ...selectedElement });
      handleDeleteElement(selectedElement.id);
    }
  }, [selectedElement, handleDeleteElement]);

  const handlePaste = useCallback(() => {
    if (clipboard) {
      const newEl: CanvasElement = {
        ...clipboard,
        id: `el-${Date.now()}`,
        x: clipboard.x + 20,
        y: clipboard.y + 20,
      };
      setProject(p => ({
        ...p,
        pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, newEl] }) : pg)
      }));
      setSelectedElementId(newEl.id);
    }
  }, [clipboard, currentPageIndex]);

  const handleResetZoom = () => {
    setZoom(1);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const activeTag = document.activeElement?.tagName;
      if (activeTag === 'INPUT' || activeTag === 'TEXTAREA') return;

      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedElementId) {
        handleDeleteElement(selectedElementId);
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'c') {
        handleCopy();
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'x') {
        handleCut();
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
        handlePaste();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedElementId, handleDeleteElement, handleCopy, handleCut, handlePaste]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!actionState) return;
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      let newW = actionState.initialW;
      let newH = actionState.initialH;
      let newX = actionState.initialX;
      let newY = actionState.initialY;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, actionState.initialW + dx);
      if (h.includes('l')) { 
        const maxDx = actionState.initialW - 10;
        const clampedDx = Math.min(dx, maxDx);
        newW = actionState.initialW - clampedDx; 
        newX = actionState.initialX + clampedDx; 
      }
      if (h.includes('b')) newH = Math.max(10, actionState.initialH + dy);
      if (h.includes('t')) { 
        const maxDy = actionState.initialH - 10;
        const clampedDy = Math.min(dy, maxDy);
        newH = actionState.initialH - clampedDy; 
        newY = actionState.initialY + clampedDy; 
      }

      handleUpdateElement(actionState.id, { 
        x: Math.round(newX), 
        y: Math.round(newY), 
        width: Math.round(newW), 
        height: Math.round(newH) 
      });
    } else {
      handleUpdateElement(actionState.id, { 
        x: Math.round(actionState.initialX + dx), 
        y: Math.round(actionState.initialY + dy) 
      });
    }
  }, [actionState, zoom, handleUpdateElement]);

  const onMouseUp = useCallback(() => setActionState(null), []);

  useEffect(() => {
    if (actionState) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [actionState, onMouseMove, onMouseUp]);

  const canvasBackgroundStyle: React.CSSProperties = useMemo(() => {
    const bg = currentPage.background;
    if (!bg) return { backgroundColor: '#FFFFFF' };
    if (bg.type === 'image') {
      return { 
        backgroundImage: `url(${bg.value})`, 
        backgroundSize: 'cover', 
        backgroundPosition: 'center' 
      };
    }
    if (bg.type === 'gradient') {
      return { background: bg.value };
    }
    return { backgroundColor: bg.value };
  }, [currentPage.background]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElement || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, 
                x: (currentDimensions.width / 2) - 100, 
                y: (currentDimensions.height / 2) - 100, 
                width: type === 'text' ? 300 : (type === 'image' || type === 'video' ? 320 : 150), 
                height: type === 'text' ? 60 : (type === 'image' || type === 'video' ? 180 : (type === 'audio' ? 50 : 150)),
                content: content || (type === 'text' ? 'New text element' : (type === 'button' ? 'ACTION' : (type === 'shape' ? 'square' : ''))),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#000000' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: type === 'text' ? 24 : 16, 
                  borderRadius: type === 'button' ? 4 : 0, 
                  zIndex: currentPage.elements.length, 
                  opacity: 1, 
                  textAlign: 'center', 
                  fontFamily: 'Inter',
                  hoverAnimation: 'none',
                  clickAnimation: 'none'
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ 
                ...p, 
                pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) 
              }));
              setSelectedElementId(el.id);
            }} 
            onBulkAdd={(data) => {
              const newEls = data.points.map((p: any, i: number) => ({
                id: `ai-${Date.now()}-${i}`,
                type: 'button',
                x: 100 + (i * 220),
                y: 350,
                width: 180,
                height: 56,
                content: p.label,
                styles: { backgroundColor: '#E4002B', color: '#fff', fontSize: 14, borderRadius: 4, zIndex: i, textAlign: 'center', fontFamily: 'Inter', fontWeight: 'bold' },
                interactivity: { type: InteractivityType.TOOLTIP, value: p.info, title: p.label }
              }));
              setProject(pr => ({ ...pr, pages: pr.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, ...newEls] }) : pg) }));
            }}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementId={selectedElementId}
            onSelectElement={setSelectedElementId}
            onUpdateBackground={handleUpdateBackground}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-center items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-12 pl-12'}`}
          ref={containerRef}
          onMouseDown={(e) => { if (e.target === containerRef.current) setSelectedElementId(null); }}
        >
          {!isPreview && (
            <>
              <div className="absolute top-0 left-12 right-0 h-6 bg-white border-b border-slate-200 z-[10]">
                 <div className="flex text-[8px] text-slate-400 font-mono h-full items-center">
                    {[0, 100, 200, 300, 400, 500, 600, 700, 800, 900, 1000, 1100].map(val => (
                       <span key={val} className="w-[100px] border-l border-slate-100 pl-1">{val}</span>
                    ))}
                 </div>
              </div>
              <div className="absolute top-6 left-0 bottom-0 w-6 bg-white border-r border-slate-200 z-[10]">
                 <div className="flex flex-col text-[8px] text-slate-400 font-mono w-full items-center">
                    {[0, 100, 200, 300, 400, 500, 600].map(val => (
                       <span key={val} className="h-[100px] border-t border-slate-100 pt-1 w-full text-center">{val}</span>
                    ))}
                 </div>
              </div>
            </>
          )}

          <div 
            ref={canvasRef}
            onClick={(e) => { if (e.target === canvasRef.current) setSelectedElementId(null); }}
            className={`shadow-[0_10px_30px_rgba(0,0,0,0.1)] relative flex-shrink-0 transition-transform duration-75 ease-out overflow-visible ${isPreview ? 'w-full h-full shadow-none border-none rounded-none' : 'border border-slate-300'}`}
            style={{ 
              ...canvasBackgroundStyle,
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height });
                }}
                onResizeStart={(e, handle) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height, handle });
                }}
                isPreview={isPreview}
              />
            ))}

            {/* Contextual Floating Menu */}
            {!isPreview && selectedElement && (
               <div 
                  className="absolute z-[200] flex bg-white rounded-lg shadow-xl border border-slate-200 overflow-hidden group/menu"
                  style={{ 
                    left: selectedElement.x, 
                    top: selectedElement.y - 45, 
                    pointerEvents: 'auto'
                  }}
               >
                  <button onClick={(e) => { e.stopPropagation(); handleCut(); }} className="px-3 py-2 hover:bg-slate-50 border-r border-slate-100 text-slate-600 hover:text-[#E4002B] transition-colors" title="Cut (Ctrl+X)">
                     <i className="fas fa-scissors text-xs"></i>
                  </button>
                  <button onClick={(e) => { e.stopPropagation(); handleCopy(); }} className="px-3 py-2 hover:bg-slate-50 border-r border-slate-100 text-slate-600 hover:text-[#E4002B] transition-colors" title="Copy (Ctrl+C)">
                     <i className="fas fa-copy text-xs"></i>
                  </button>
                  <button onClick={(e) => { e.stopPropagation(); handlePaste(); }} className={`px-3 py-2 hover:bg-slate-50 text-slate-600 hover:text-[#E4002B] transition-colors ${!clipboard ? 'opacity-30 pointer-events-none' : ''}`} title="Paste (Ctrl+V)">
                     <i className="fas fa-paste text-xs"></i>
                  </button>
               </div>
            )}
          </div>

          {!isPreview && (
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-2 bg-white/90 backdrop-blur border border-slate-200 px-4 py-2 rounded-full shadow-lg">
               <div className="flex items-center gap-1 border-r border-slate-200 pr-3">
                  <button onClick={() => setProject(p => ({ ...p, pages: [...p.pages, { id: `pg-${Date.now()}`, name: `Page ${p.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } }] }))} className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold text-slate-700 hover:bg-slate-100 rounded-md transition-colors">
                     <i className="fas fa-plus"></i> Add page
                  </button>
               </div>

               <div className="flex items-center gap-3 px-3 border-r border-slate-200">
                  <button onClick={() => setZoom(Math.max(0.1, zoom - 0.1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-search-minus"></i></button>
                  <span className="text-[10px] font-black min-w-[35px] text-center">{Math.round(zoom * 100)}%</span>
                  <button onClick={() => setZoom(Math.min(3, zoom + 0.1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-search-plus"></i></button>
                  <button onClick={handleResetZoom} className="text-[10px] font-bold text-slate-400 hover:text-[#E4002B] ml-1">Reset</button>
               </div>

               <div className="flex items-center gap-2 px-1">
                  <button className="text-slate-400 px-2 hover:text-[#E4002B] transition-colors"><i className="fas fa-chevron-left text-[10px]"></i></button>
                  <span className="text-[10px] font-black">1</span>
                  <button className="text-slate-400 px-2 hover:text-[#E4002B] transition-colors"><i className="fas fa-chevron-right text-[10px]"></i></button>
                  <button className="text-[#E4002B] px-2"><i className="fas fa-wand-magic-sparkles text-[10px]"></i></button>
               </div>
            </div>
          )}
        </main>

        {selectedElement && !isPreview && (
          <aside className="w-72 bg-white border-l border-slate-200 flex flex-col z-50 animate-in slide-in-from-right duration-300 shadow-xl overflow-hidden">
             <div className="p-5 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
               <h3 className="text-[10px] font-black text-[#E4002B] uppercase tracking-widest">Properties</h3>
               <span className="text-[9px] text-slate-400 font-bold uppercase">{selectedElement.type}</span>
             </div>
             <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide pb-32">
               {selectedElement.type !== 'shape' && (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Content</label>
                   <textarea 
                      className="w-full bg-slate-50 border border-slate-200 rounded-lg text-xs py-3 px-4 text-slate-900 focus:ring-1 focus:ring-[#E4002B] focus:outline-none min-h-[80px] resize-none"
                      value={selectedElement.content}
                      onChange={(e) => handleUpdateElement(selectedElement.id, { content: e.target.value })}
                   />
                 </div>
               )}

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Design & Fill</label>
                 <div className="flex bg-slate-100 p-1 rounded-lg gap-1">
                    <button onClick={() => handleUpdateElement(selectedElement.id, { styles: { gradient: undefined } })} className={`flex-1 py-1.5 rounded text-[9px] font-black uppercase transition-all ${!selectedElement.styles.gradient ? 'bg-white text-[#E4002B] shadow-sm' : 'text-slate-500'}`}>Solid</button>
                    <button onClick={() => handleUpdateElement(selectedElement.id, { styles: { gradient: 'linear-gradient(135deg, #E4002B 0%, #000000 100%)' } })} className={`flex-1 py-1.5 rounded text-[9px] font-black uppercase transition-all ${selectedElement.styles.gradient ? 'bg-white text-[#E4002B] shadow-sm' : 'text-slate-500'}`}>Gradient</button>
                 </div>

                 <div className="grid grid-cols-2 gap-3">
                   <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                      <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Color</span>
                      <input type="color" value={selectedElement.styles.backgroundColor || '#E4002B'} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { backgroundColor: e.target.value } })} className="w-full h-8 p-0 border-0 bg-transparent cursor-pointer rounded-lg overflow-hidden" />
                   </div>
                   <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                      <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Radius</span>
                      <input type="number" value={selectedElement.styles.borderRadius} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { borderRadius: parseInt(e.target.value) } })} className="w-full bg-transparent border-none text-slate-900 text-xs font-bold outline-none" />
                   </div>
                 </div>
               </div>

               {selectedElement.type === 'text' && (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Typography</label>
                   <div className="grid grid-cols-2 gap-2">
                      <select value={selectedElement.styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontFamily: e.target.value } })} className="bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 focus:ring-1 focus:ring-[#E4002B] outline-none">
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Monospace">Mono</option>
                      </select>
                      <input type="number" value={selectedElement.styles.fontSize} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { fontSize: parseInt(e.target.value) } })} className="bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 focus:ring-1 focus:ring-[#E4002B] outline-none text-center" />
                   </div>
                   <div className="flex bg-slate-50 rounded-lg p-1 border border-slate-200">
                     {['left', 'center', 'right'].map(align => (
                       <button key={align} onClick={() => handleUpdateElement(selectedElement.id, { styles: { textAlign: align as any } })} className={`flex-1 py-2 rounded-lg text-xs transition-all ${selectedElement.styles.textAlign === align ? 'bg-white text-[#E4002B] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><i className={`fas fa-align-${align}`}></i></button>
                     ))}
                   </div>
                 </div>
               )}

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Interaction</label>
                 <div className="space-y-3">
                    <select value={selectedElement.interactivity.type} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, type: e.target.value as any } })} className="w-full bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 outline-none">
                      <option value={InteractivityType.NONE}>No Interaction</option>
                      <option value={InteractivityType.TOOLTIP}>Tooltip</option>
                      <option value={InteractivityType.MODAL}>Modal Window</option>
                      <option value={InteractivityType.EXTERNAL_LINK}>Link</option>
                    </select>
                    {selectedElement.interactivity.type !== InteractivityType.NONE && (
                      <input type="text" placeholder="Value..." value={selectedElement.interactivity.value} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, value: e.target.value } })} className="w-full bg-slate-50 border border-slate-200 rounded-lg text-xs py-2.5 px-3 text-slate-900 focus:ring-1 focus:ring-[#E4002B] focus:outline-none" />
                    )}
                 </div>
               </div>

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Animations</label>
                 <div className="space-y-3">
                   <div className="space-y-1">
                      <span className="text-[8px] font-bold text-slate-400 uppercase">On Hover</span>
                      <div className="flex flex-wrap gap-1.5">
                        {['none', 'pop', 'lift', 'fade'].map(anim => (
                          <button key={anim} onClick={() => handleUpdateElement(selectedElement.id, { styles: { hoverAnimation: anim as AnimationType } })} className={`px-2 py-1 rounded text-[9px] font-black uppercase transition-all ${selectedElement.styles.hoverAnimation === anim ? 'bg-[#E4002B] text-white' : 'bg-slate-100 text-slate-400 hover:text-slate-600'}`}>{anim}</button>
                        ))}
                      </div>
                   </div>
                 </div>
               </div>
             </div>

             <div className="p-6 bg-slate-50 border-t border-slate-200 absolute bottom-0 left-0 w-full">
               <button onClick={() => handleDeleteElement(selectedElement.id)} className="w-full py-3 bg-red-50 hover:bg-red-100 text-[#E4002B] text-[10px] font-black uppercase tracking-widest rounded-lg transition-all border border-red-200"><i className="fas fa-trash-alt mr-2"></i> Delete Object</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && (
        <PublishModal project={project} onClose={() => setShowPublishModal(false)} />
      )}
    </div>
  );
};

export default App;

