export default Toolbar;

export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'pop' | 'fade' | 'lift' | 'squeeze';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentation (16:9)' },
  square: { width: 600, height: 600, label: 'Square (1:1)' },
  vertical: { width: 400, height: 711, label: 'Mobile (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Portrait' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string; // Used for text, URLs, or JSON-stringified data for complex types
  groupId?: string;
  styles: {
    backgroundColor?: string;
    gradient?: string;
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    hoverAnimation?: AnimationType;
    clickAnimation?: AnimationType;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
  };
}

export interface GroupFolder {
  id: string;
  name: string;
  isOpen: boolean;
}

export interface PageBackground {
  type: 'color' | 'gradient' | 'image';
  value: string;
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
  groups: GroupFolder[];
  background?: PageBackground;
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
  canvasPreset: CanvasPreset;
}

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS, AnimationType, PageBackground } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mastering KFC Culinary Arts',
  pages: [{ 
    id: 'page-1', 
    name: 'Introduction', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [clipboard, setClipboard] = useState<CanvasElement | null>(null);
  const [actionState, setActionState] = useState<{ 
    id: string; 
    startX: number; 
    startY: number; 
    initialX: number; 
    initialY: number; 
    initialW: number; 
    initialH: number; 
    handle?: string 
  } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElement = useMemo(() => 
    currentPage.elements.find(el => el.id === selectedElementId)
  , [currentPage.elements, selectedElementId]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleUpdateBackground = useCallback((bg: PageBackground) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p)
    }));
  }, [currentPageIndex]);

  const handleDeleteElement = useCallback((id: string) => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map(p => ({ ...p, elements: p.elements.filter(el => el.id !== id) })) 
    }));
    setSelectedElementId(null);
  }, []);

  const handlePageNavigation = (target: string | number) => {
    if (typeof target === 'number') {
      if (target >= 0 && target < project.pages.length) setCurrentPageIndex(target);
    } else {
      const idx = project.pages.findIndex(p => p.id === target || p.name === target);
      if (idx !== -1) setCurrentPageIndex(idx);
    }
  };

  const handleAddPage = () => {
    const newPage = { id: `pg-${Date.now()}`, name: `New Page ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
    setProject(p => ({ ...p, pages: [...p.pages, newPage] }));
    setCurrentPageIndex(project.pages.length);
  };

  const handleCopy = useCallback(() => {
    if (selectedElement) setClipboard({ ...selectedElement });
  }, [selectedElement]);

  const handleCut = useCallback(() => {
    if (selectedElement) {
      setClipboard({ ...selectedElement });
      handleDeleteElement(selectedElement.id);
    }
  }, [selectedElement, handleDeleteElement]);

  const handlePaste = useCallback(() => {
    if (clipboard) {
      const newEl: CanvasElement = { ...clipboard, id: `el-${Date.now()}`, x: clipboard.x + 20, y: clipboard.y + 20 };
      setProject(p => ({
        ...p,
        pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, newEl] }) : pg)
      }));
      setSelectedElementId(newEl.id);
    }
  }, [clipboard, currentPageIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const activeTag = document.activeElement?.tagName;
      if (activeTag === 'INPUT' || activeTag === 'TEXTAREA') return;
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedElementId) handleDeleteElement(selectedElementId);
      else if ((e.ctrlKey || e.metaKey) && e.key === 'c') handleCopy();
      else if ((e.ctrlKey || e.metaKey) && e.key === 'x') handleCut();
      else if ((e.ctrlKey || e.metaKey) && e.key === 'v') handlePaste();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedElementId, handleDeleteElement, handleCopy, handleCut, handlePaste]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!actionState) return;
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;
    if (actionState.handle) {
      let { initialX: newX, initialY: newY, initialW: newW, initialH: newH } = actionState;
      const h = actionState.handle;
      if (h.includes('r')) newW = Math.max(10, actionState.initialW + dx);
      if (h.includes('l')) { const cl = Math.min(dx, actionState.initialW - 10); newW = actionState.initialW - cl; newX = actionState.initialX + cl; }
      if (h.includes('b')) newH = Math.max(10, actionState.initialH + dy);
      if (h.includes('t')) { const cl = Math.min(dy, actionState.initialH - 10); newH = actionState.initialH - cl; newY = actionState.initialY + cl; }
      handleUpdateElement(actionState.id, { x: Math.round(newX), y: Math.round(newY), width: Math.round(newW), height: Math.round(newH) });
    } else {
      handleUpdateElement(actionState.id, { x: Math.round(actionState.initialX + dx), y: Math.round(actionState.initialY + dy) });
    }
  }, [actionState, zoom, handleUpdateElement]);

  useEffect(() => {
    if (actionState) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', () => setActionState(null));
    }
    return () => { window.removeEventListener('mousemove', onMouseMove); };
  }, [actionState, onMouseMove]);

  const canvasBackgroundStyle: React.CSSProperties = useMemo(() => {
    const bg = currentPage.background;
    if (!bg) return { backgroundColor: '#FFFFFF' };
    if (bg.type === 'image') return { backgroundImage: `url(${bg.value})`, backgroundSize: 'cover', backgroundPosition: 'center' };
    if (bg.type === 'gradient') return { background: bg.value };
    return { backgroundColor: bg.value };
  }, [currentPage.background]);

  const progressPercentage = ((currentPageIndex + 1) / project.pages.length) * 100;

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElement || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementId(null); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      {/* Global Learning Progress Bar */}
      <div className="h-1 w-full bg-slate-200 z-[300]">
         <div className="h-full bg-[#E4002B] transition-all duration-700 ease-out shadow-[0_0_10px_rgba(228,0,43,0.5)]" style={{ width: `${progressPercentage}%` }} />
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, 
                x: (currentDimensions.width / 2) - 150, 
                y: (currentDimensions.height / 2) - 100, 
                width: type === 'quiz' ? 400 : (type === 'gallery' ? 500 : 250), 
                height: type === 'quiz' ? 300 : (type === 'gallery' ? 350 : 60),
                content: content || (type === 'quiz' ? JSON.stringify({ question: 'The Golden Question?', options: ['Extra Crispy', 'Original Recipe', 'Spicy'], correct: 1 }) : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#000000' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 20, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter',
                  borderRadius: type === 'quiz' ? 16 : 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ 
                ...p, 
                pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) 
              }));
              setSelectedElementId(el.id);
            }} 
            onBulkAdd={(data) => {}}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementId={selectedElementId}
            onSelectElement={setSelectedElementId}
            onUpdateBackground={handleUpdateBackground}
            pages={project.pages}
            currentPageIndex={currentPageIndex}
            onNavigatePage={setCurrentPageIndex}
            onAddPage={handleAddPage}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-center items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef}
          onMouseDown={(e) => { if (e.target === containerRef.current) setSelectedElementId(null); }}
        >
          <div 
            ref={canvasRef}
            onClick={(e) => { if (e.target === canvasRef.current) setSelectedElementId(null); }}
            className={`shadow-[0_20px_60px_rgba(0,0,0,0.15)] relative flex-shrink-0 transition-transform duration-75 ease-out overflow-visible ${isPreview ? 'w-full h-full shadow-none' : 'border border-slate-300 rounded-sm bg-white'}`}
            style={{ 
              ...canvasBackgroundStyle,
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={el.id === selectedElementId}
                onSelect={(e) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height });
                }}
                onResizeStart={(e, handle) => {
                  e.stopPropagation();
                  setSelectedElementId(el.id);
                  setActionState({ id: el.id, startX: e.clientX, startY: e.clientY, initialX: el.x, initialY: el.y, initialW: el.width, initialH: el.height, handle });
                }}
                isPreview={isPreview}
                onNavigate={handlePageNavigation}
              />
            ))}

            {!isPreview && selectedElement && (
               <div className="absolute z-[200] flex bg-white rounded-lg shadow-xl border border-slate-200 overflow-hidden" style={{ left: selectedElement.x, top: selectedElement.y - 45 }}>
                  <button onClick={handleCut} className="px-3 py-2 hover:bg-slate-50 border-r border-slate-100 text-slate-600"><i className="fas fa-scissors text-xs"></i></button>
                  <button onClick={handleCopy} className="px-3 py-2 hover:bg-slate-50 border-r border-slate-100 text-slate-600"><i className="fas fa-copy text-xs"></i></button>
                  <button onClick={handlePaste} className="px-3 py-2 hover:bg-slate-50 text-slate-600"><i className="fas fa-paste text-xs"></i></button>
               </div>
            )}
          </div>

          {!isPreview && (
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-2 bg-white/95 backdrop-blur border border-slate-200 px-5 py-3 rounded-full shadow-2xl">
               <div className="flex items-center gap-4 px-3 border-r border-slate-200">
                  <button onClick={() => setZoom(Math.max(0.1, zoom - 0.1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-search-minus"></i></button>
                  <span className="text-[10px] font-black min-w-[35px] text-center">{Math.round(zoom * 100)}%</span>
                  <button onClick={() => setZoom(Math.min(3, zoom + 0.1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-search-plus"></i></button>
               </div>
               <div className="flex items-center gap-4 px-3">
                  <button onClick={() => setCurrentPageIndex(Math.max(0, currentPageIndex - 1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-chevron-left"></i></button>
                  <span className="text-[10px] font-black whitespace-nowrap uppercase">Page {currentPageIndex + 1} / {project.pages.length}</span>
                  <button onClick={() => setCurrentPageIndex(Math.min(project.pages.length - 1, currentPageIndex + 1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-chevron-right"></i></button>
               </div>
               <button onClick={handleAddPage} className="ml-2 bg-[#E4002B] text-white w-8 h-8 rounded-full flex items-center justify-center hover:bg-[#c40024] transition-all shadow-lg"><i className="fas fa-plus text-xs"></i></button>
            </div>
          )}
        </main>

        {selectedElement && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-50 shadow-2xl overflow-hidden">
             <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
               <h3 className="text-[10px] font-black text-[#E4002B] uppercase tracking-widest">Editor Panel</h3>
               <span className="text-[9px] text-slate-400 font-bold uppercase">{selectedElement.type}</span>
             </div>
             <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide pb-32">
               {selectedElement.type === 'text' || selectedElement.type === 'button' ? (
                 <div className="space-y-3">
                   <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Content</label>
                   <textarea className="w-full bg-slate-50 border border-slate-200 rounded-xl text-xs py-4 px-4 text-slate-900 focus:ring-1 focus:ring-[#E4002B] focus:outline-none min-h-[100px] resize-none" value={selectedElement.content} onChange={(e) => handleUpdateElement(selectedElement.id, { content: e.target.value })} />
                 </div>
               ) : selectedElement.type === 'quiz' ? (
                 <div className="space-y-4">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Quiz Config (JSON)</label>
                    <textarea className="w-full bg-slate-50 border border-slate-200 rounded-xl text-[10px] font-mono py-4 px-4 h-48 focus:outline-none" value={selectedElement.content} onChange={(e) => handleUpdateElement(selectedElement.id, { content: e.target.value })} />
                    <p className="text-[8px] text-slate-400 italic">Format: {"{question, options:[], correct:index}"}</p>
                 </div>
               ) : null}

               <div className="space-y-4">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Actions & Interactivity</label>
                 <div className="space-y-3">
                    <select value={selectedElement.interactivity.type} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, type: e.target.value as any } })} className="w-full bg-slate-50 border border-slate-200 rounded-xl text-xs py-3 px-4 outline-none">
                      <option value={InteractivityType.NONE}>Standard Object</option>
                      <option value={InteractivityType.GOTO_PAGE}>Go to Page</option>
                      <option value={InteractivityType.TOOLTIP}>Quick Tip</option>
                      <option value={InteractivityType.EXTERNAL_LINK}>Link to URL</option>
                    </select>
                    {selectedElement.interactivity.type !== InteractivityType.NONE && (
                      <input type="text" placeholder={selectedElement.interactivity.type === InteractivityType.GOTO_PAGE ? "Page name or index..." : "Value..."} value={selectedElement.interactivity.value} onChange={(e) => handleUpdateElement(selectedElement.id, { interactivity: { ...selectedElement.interactivity, value: e.target.value } })} className="w-full bg-slate-50 border border-slate-200 rounded-xl text-xs py-3 px-4 outline-none" />
                    )}
                 </div>
               </div>

               <div className="space-y-4 pt-4 border-t border-slate-100">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Visual Style</label>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-200">
                       <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Bg Color</span>
                       <input type="color" value={selectedElement.styles.backgroundColor || '#E4002B'} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { backgroundColor: e.target.value } })} className="w-full h-8 p-0 border-0 bg-transparent cursor-pointer" />
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-200">
                       <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Border Radius</span>
                       <input type="number" value={selectedElement.styles.borderRadius} onChange={(e) => handleUpdateElement(selectedElement.id, { styles: { borderRadius: parseInt(e.target.value) } })} className="w-full bg-transparent border-none text-xs font-bold" />
                    </div>
                  </div>
               </div>
             </div>

             <div className="p-6 bg-slate-50 border-t border-slate-200 mt-auto">
               <button onClick={() => handleDeleteElement(selectedElement.id)} className="w-full py-4 bg-red-50 hover:bg-red-100 text-[#E4002B] text-[10px] font-black uppercase tracking-widest rounded-xl transition-all border border-red-200"><i className="fas fa-trash-alt mr-2"></i> Delete Element</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

