import React, { useState, useMemo } from 'react';
import { CanvasElement, InteractivityType, AnimationType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onResizeStart: (e: React.MouseEvent, handle: string) => void;
  isPreview?: boolean;
  onNavigate?: (target: string | number) => void;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ element, isSelected, onSelect, onResizeStart, isPreview, onNavigate }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [quizResult, setQuizResult] = useState<'none' | 'correct' | 'wrong'>('none');
  const [galleryIndex, setGalleryIndex] = useState(0);

  const style: React.CSSProperties = {
    position: 'absolute',
    left: element.x,
    top: element.y,
    width: element.width,
    height: element.height,
    zIndex: element.styles.zIndex,
    background: element.styles.gradient || element.styles.backgroundColor,
    color: element.styles.color,
    fontSize: element.styles.fontSize,
    borderRadius: `${element.styles.borderRadius || 0}px`,
    fontFamily: element.styles.fontFamily || 'Inter, sans-serif',
    textAlign: element.styles.textAlign,
    opacity: element.styles.opacity,
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
    overflow: 'visible',
    pointerEvents: 'auto',
    cursor: isPreview ? (element.interactivity.type !== InteractivityType.NONE ? 'pointer' : 'default') : 'move'
  };

  const handleInteraction = () => {
    if (!isPreview) return;
    switch (element.interactivity.type) {
      case InteractivityType.EXTERNAL_LINK: window.open(element.interactivity.value, '_blank'); break;
      case InteractivityType.GOTO_PAGE: onNavigate?.(element.interactivity.value); break;
      case InteractivityType.TOOLTIP: alert(element.interactivity.value); break;
    }
  };

  const renderContent = () => {
    switch(element.type) {
      case 'quiz': {
        try {
          const data = JSON.parse(element.content);
          return (
            <div className="w-full h-full bg-white p-8 flex flex-col gap-6 shadow-xl border border-slate-100 rounded-inherit">
               <h4 className="text-lg font-black text-slate-900 leading-tight">{data.question}</h4>
               <div className="space-y-2 flex-1">
                  {data.options.map((opt: string, idx: number) => (
                    <button 
                      key={idx}
                      onClick={(e) => {
                        if (!isPreview) return;
                        e.stopPropagation();
                        setQuizResult(idx === data.correct ? 'correct' : 'wrong');
                      }}
                      className={`w-full p-4 rounded-xl border-2 text-left text-xs font-bold transition-all flex items-center justify-between group ${quizResult === 'none' ? 'border-slate-100 hover:border-[#E4002B] hover:bg-red-50' : (idx === data.correct ? 'border-green-500 bg-green-50 text-green-700' : 'border-slate-100 opacity-50')}`}
                    >
                      {opt}
                      {quizResult === 'correct' && idx === data.correct && <i className="fas fa-check-circle"></i>}
                    </button>
                  ))}
               </div>
               {quizResult !== 'none' && (
                 <div className={`animate-in fade-in slide-in-from-bottom-2 duration-300 py-3 text-center rounded-lg text-[10px] font-black uppercase tracking-widest ${quizResult === 'correct' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {quizResult === 'correct' ? 'Brilliant! Correct' : 'Oops! Try again'}
                    {quizResult === 'wrong' && <button onClick={(e) => { e.stopPropagation(); setQuizResult('none'); }} className="ml-4 underline">Retry</button>}
                 </div>
               )}
            </div>
          );
        } catch(e) { return <div className="text-[10px] text-red-500 font-mono">Invalid Quiz JSON</div>; }
      }
      case 'gallery': {
        const images = element.content.split(',').map(s => s.trim()).filter(s => s);
        if (images.length === 0) return <div className="flex flex-col items-center gap-2 text-slate-300"><i className="fas fa-images text-4xl"></i><span className="text-[9px] font-black uppercase">No Images Set</span></div>;
        return (
          <div className="w-full h-full relative group/gallery bg-black rounded-inherit overflow-hidden shadow-2xl">
             <img src={images[galleryIndex]} className="w-full h-full object-cover transition-all duration-500" alt="" />
             <div className="absolute inset-x-0 bottom-0 p-6 bg-gradient-to-t from-black/80 to-transparent flex items-center justify-between">
                <span className="text-[9px] font-black text-white uppercase tracking-widest">{galleryIndex + 1} / {images.length}</span>
                <div className="flex gap-2">
                   <button onClick={(e) => { e.stopPropagation(); setGalleryIndex((galleryIndex - 1 + images.length) % images.length); }} className="w-8 h-8 rounded-full bg-white/20 backdrop-blur text-white flex items-center justify-center hover:bg-white/40"><i className="fas fa-chevron-left text-xs"></i></button>
                   <button onClick={(e) => { e.stopPropagation(); setGalleryIndex((galleryIndex + 1) % images.length); }} className="w-8 h-8 rounded-full bg-white/20 backdrop-blur text-white flex items-center justify-center hover:bg-white/40"><i className="fas fa-chevron-right text-xs"></i></button>
                </div>
             </div>
          </div>
        );
      }
      case 'image': return <img src={element.content} alt="" className="w-full h-full object-contain" />;
      case 'video': return <video src={element.content} controls={isPreview} className="w-full h-full object-cover rounded-inherit" />;
      case 'audio': return <div className="w-full h-full flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 gap-3"><i className="fas fa-music text-[#E4002B]"></i><audio src={element.content} controls={isPreview} className="w-full scale-90" /></div>;
      case 'button': return <button className="w-full h-full font-black uppercase tracking-widest text-xs px-6" style={{ background: 'inherit', color: 'inherit', borderRadius: 'inherit' }}>{element.content}</button>;
      default: return <span className="w-full px-4 whitespace-pre-wrap leading-relaxed">{element.content}</span>;
    }
  };

  return (
    <div
      style={style}
      onMouseDown={onSelect}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleInteraction}
      className={`
        ${isSelected && !isPreview ? 'ring-2 ring-[#E4002B] ring-offset-4 ring-offset-[#E5E5E5]' : ''} 
        ${isPreview && element.styles.hoverAnimation === 'pop' && isHovered ? 'scale-105 shadow-2xl' : ''}
        group/element
      `}
    >
      {renderContent()}

      {isSelected && !isPreview && ['tl', 'tr', 'bl', 'br'].map(h => (
        <div key={h} onMouseDown={(e) => { e.stopPropagation(); onResizeStart(e, h); }} className="absolute w-3 h-3 bg-white border-2 border-[#E4002B] rounded-full z-[120] hover:scale-125 transition-transform" style={getHandleStyle(h)} />
      ))}
    </div>
  );
};

function getHandleStyle(h: string): React.CSSProperties {
  const o = '-6px';
  switch (h) {
    case 'tl': return { top: o, left: o, cursor: 'nwse-resize' };
    case 'tr': return { top: o, right: o, cursor: 'nesw-resize' };
    case 'bl': return { bottom: o, left: o, cursor: 'nesw-resize' };
    case 'br': return { bottom: o, right: o, cursor: 'nwse-resize' };
    default: return {};
  }
}

export default ElementRenderer;

import JSZip from 'jszip';
import { Project } from '../types';

export const exportScorm = async (project: Project, version: '1.2' | '2004') => {
  const zip = new JSZip();
  const projectJson = JSON.stringify(project);
  zip.file('imsmanifest.xml', version === '1.2' ? getScorm12Manifest(project) : getScorm2004Manifest(project));
  zip.file('index.html', getPlayerHtml(projectJson, version));
  zip.file('scorm_wrapper.js', getScormWrapper());
  const content = await zip.generateAsync({ type: 'blob' });
  const fileName = `${project.title.replace(/\s+/g, '_')}_SCORM_${version}.zip`;
  const link = document.createElement('a');
  link.href = URL.createObjectURL(content);
  link.download = fileName;
  link.click();
};

const getScorm12Manifest = (p: Project) => `<?xml version="1.0" standalone="no" ?><manifest identifier="KFC_${p.id}" version="1" xmlns="http://www.imsproject.org/xsd/imscp_rootv1p1p2" xmlns:adlcp="http://www.adlnet.org/xsd/adlcp_rootv1p2" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><metadata><schema>ADL SCORM</schema><schemaversion>1.2</schemaversion></metadata><organizations default="KFC_Org"><organization identifier="KFC_Org"><title>${p.title}</title><item identifier="item_1" identifierref="res_1"><title>${p.title}</title></item></organization></organizations><resources><resource identifier="res_1" type="webcontent" adlcp:scormtype="sco" href="index.html"><file href="index.html"/><file href="scorm_wrapper.js"/></resource></resources></manifest>`;

const getScorm2004Manifest = (p: Project) => `<?xml version="1.0" standalone="no" ?><manifest identifier="KFC_${p.id}" version="1" xmlns="http://www.imsglobal.org/xsd/imscp_v1p1" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns:adlcp="http://www.adlnet.org/xsd/adlcp_v1p3"><metadata><schema>ADL SCORM</schema><schemaversion>2004 3rd Edition</schemaversion></metadata><organizations default="KFC_Org"><organization identifier="KFC_Org"><title>${p.title}</title><item identifier="item_1" identifierref="res_1"><title>${p.title}</title></item></organization></organizations><resources><resource identifier="res_1" type="webcontent" adlcp:scormtype="sco" href="index.html"><file href="index.html"/><file href="scorm_wrapper.js"/></resource></resources></manifest>`;

const getPlayerHtml = (json: string, ver: string) => `
<!DOCTYPE html>
<html>
<head>
    <title>Learning Player</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <script src="scorm_wrapper.js"></script>
    <style>
        body { margin: 0; background: #eee; font-family: sans-serif; height: 100vh; display: flex; flex-direction: column; }
        #canvas-wrap { flex: 1; display: flex; align-items: center; justify-content: center; position: relative; overflow: auto; padding: 40px; }
        .canvas { position: relative; background: white; box-shadow: 0 40px 100px rgba(0,0,0,0.1); }
        .element { position: absolute; transition: all 0.3s; box-sizing: border-box; }
        #nav-bar { height: 60px; background: #111; display: flex; align-items: center; justify-content: space-between; padding: 0 30px; color: white; border-top: 4px solid #E4002B; }
        #progress { position: fixed; top: 0; left: 0; height: 4px; background: #E4002B; transition: width 0.5s; z-index: 1000; }
    </style>
</head>
<body>
    <div id="progress"></div>
    <div id="canvas-wrap"><div id="canvas" class="canvas"></div></div>
    <div id="nav-bar">
        <span id="page-info" style="font-size: 10px; font-weight: 900; letter-spacing: 2px;">PAGE 1 / 1</span>
        <div style="display: flex; gap: 10px;">
            <button onclick="prev()" id="prev-btn" style="padding: 10px 20px; font-size: 10px; font-weight: 900; background: #333; border: none; color: white; border-radius: 4px;">PREV</button>
            <button onclick="next()" id="next-btn" style="padding: 10px 20px; font-size: 10px; font-weight: 900; background: #E4002B; border: none; color: white; border-radius: 4px;">NEXT</button>
        </div>
    </div>
    <script>
        const project = ${json};
        let currentIdx = 0;

        function render() {
            const page = project.pages[currentIdx];
            const canvas = document.getElementById('canvas');
            const dims = { presentation: { w: 960, h: 540 }, square: { w: 600, h: 600 }, vertical: { w: 400, h: 711 }, a4: { w: 595, h: 842 } }[project.canvasPreset];
            canvas.style.width = dims.w + 'px';
            canvas.style.height = dims.h + 'px';
            canvas.innerHTML = '';

            if(page.background) {
                if(page.background.type === 'image') canvas.style.backgroundImage = 'url('+page.background.value+')';
                else canvas.style.background = page.background.value;
                canvas.style.backgroundSize = 'cover';
            }

            page.elements.forEach(el => {
                const div = document.createElement('div');
                div.className = 'element';
                Object.assign(div.style, {
                    left: el.x + 'px', top: el.y + 'px', width: el.width + 'px', height: el.height + 'px', zIndex: el.styles.zIndex,
                    background: el.styles.gradient || el.styles.backgroundColor, color: el.styles.color, fontSize: el.styles.fontSize + 'px',
                    borderRadius: el.styles.borderRadius + 'px', textAlign: el.styles.textAlign, display: 'flex', alignItems: 'center', justifyContent: el.styles.textAlign === 'center' ? 'center' : 'flex-start'
                });

                if(el.type === 'text' || el.type === 'button') div.innerText = el.content;
                else if(el.type === 'image') div.innerHTML = '<img src="'+el.content+'" style="width:100%;height:100%;object-fit:contain">';
                else if(el.type === 'quiz') {
                    const d = JSON.parse(el.content);
                    div.innerHTML = '<div style="background:white;padding:20px;width:100%;height:100%;border-radius:inherit;display:flex;flex-direction:column;gap:10px;"><div style="font-weight:900;">'+d.question+'</div>' + d.options.map((o,i)=>'<button onclick="this.style.background= \\'#eee\\'; if('+i+'=='+d.correct+') alert(\\'Correct!\\'); else alert(\\'Wrong\\')" style="width:100%;padding:10px;border:1px solid #ddd;border-radius:8px;text-align:left;font-size:12px;">'+o+'</button>').join('') + '</div>';
                }

                if(el.interactivity && el.interactivity.type !== 'NONE') {
                    div.style.cursor = 'pointer';
                    div.onclick = () => {
                        if(el.interactivity.type === 'GOTO_PAGE') {
                            const tidx = project.pages.findIndex(p => p.name === el.interactivity.value || p.id === el.interactivity.value);
                            if(tidx !== -1) { currentIdx = tidx; render(); }
                        } else if(el.interactivity.type === 'EXTERNAL_LINK') window.open(el.interactivity.value);
                    };
                }
                canvas.appendChild(div);
            });

            document.getElementById('page-info').innerText = 'PAGE ' + (currentIdx+1) + ' / ' + project.pages.length;
            document.getElementById('progress').style.width = ((currentIdx+1)/project.pages.length)*100 + '%';
            document.getElementById('prev-btn').disabled = currentIdx === 0;
            if(currentIdx === project.pages.length - 1) {
                pipwerks.SCORM.set("cmi.core.lesson_status", "completed");
                pipwerks.SCORM.save();
            }
        }

        function next() { if(currentIdx < project.pages.length - 1) { currentIdx++; render(); } }
        function prev() { if(currentIdx > 0) { currentIdx--; render(); } }

        window.onload = () => { pipwerks.SCORM.init(); render(); };
    </script>
</body>
</html>`;

const getScormWrapper = () => `var pipwerks={};pipwerks.UTILS={handleError:function(m){console.error(m);return false}};pipwerks.SCORM={version:null,handle:null,isInit:false,init:function(){this.handle=this.getAPI();if(this.handle){var s=false;if(this.version==="1.2")s=this.handle.LMSInitialize("");else if(this.version==="2004")s=this.handle.Initialize("");this.isInit=(s==="true"||s===true);return this.isInit}return false},getAPI:function(){var w=window,f=function(w){if(w.API){pipwerks.SCORM.version="1.2";return w.API}if(w.API_1484_11){pipwerks.SCORM.version="2004";return w.API_1484_11}return null},a=f(w);if(!a&&w.parent&&w.parent!==w)a=f(w.parent);if(!a&&w.top&&w.top!==w)a=f(w.top);if(!a&&w.opener)a=f(w.opener);return a},set:function(p,v){if(this.isInit){if(this.version==="1.2")return this.handle.LMSSetValue(p,v);return this.handle.SetValue(p,v)}},save:function(){if(this.isInit){if(this.version==="1.2")return this.handle.LMSCommit("");return this.handle.Commit("")}},quit:function(){if(this.isInit){if(this.version==="1.2")this.handle.LMSFinish("");else this.handle.Terminate("");this.isInit=false}}};`;

export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'pop' | 'fade' | 'lift' | 'squeeze';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentation (16:9)' },
  square: { width: 600, height: 600, label: 'Square (1:1)' },
  vertical: { width: 400, height: 711, label: 'Mobile (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Portrait' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  groupId?: string;
  styles: {
    backgroundColor?: string;
    gradient?: string;
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    hoverAnimation?: AnimationType;
    clickAnimation?: AnimationType;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
  };
}

export interface GroupFolder {
  id: string;
  name: string;
  isOpen: boolean;
  elementIds: string[];
}

export interface PageBackground {
  type: 'color' | 'gradient' | 'image';
  value: string;
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
  groups: GroupFolder[];
  background?: PageBackground;
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
  canvasPreset: CanvasPreset;
}

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CanvasPreset, CANVAS_PRESETS, AnimationType, PageBackground, GroupFolder } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mastering KFC Culinary Arts',
  pages: [{ 
    id: 'page-1', 
    name: 'Introduction', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [clipboard, setClipboard] = useState<CanvasElement[] | null>(null);

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleUpdateBackground = useCallback((bg: PageBackground) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p)
    }));
  }, [currentPageIndex]);

  const handleDeleteSelected = useCallback(() => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    }));
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex]);

  const handleGroupSelected = useCallback(() => {
    if (selectedElementIds.length < 2) return;
    const groupId = `group-${Date.now()}`;
    const newGroup: GroupFolder = {
      id: groupId,
      name: `Group ${currentPage.groups.length + 1}`,
      isOpen: true,
      elementIds: [...selectedElementIds]
    };

    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        groups: [...p.groups, newGroup],
        elements: p.elements.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId } : el)
      }) : p)
    }));
  }, [selectedElementIds, currentPageIndex, currentPage.groups.length]);

  const handleCopy = useCallback(() => {
    if (selectedElements.length > 0) setClipboard(selectedElements.map(el => ({ ...el })));
  }, [selectedElements]);

  const handlePaste = useCallback(() => {
    if (clipboard) {
      const newEls = clipboard.map(el => ({ ...el, id: `el-${Math.random()}`, x: el.x + 20, y: el.y + 20 }));
      setProject(p => ({
        ...p,
        pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, ...newEls] }) : pg)
      }));
      setSelectedElementIds(newEls.map(el => el.id));
    }
  }, [clipboard, currentPageIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const activeTag = document.activeElement?.tagName;
      if (activeTag === 'INPUT' || activeTag === 'TEXTAREA') return;
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedElementIds.length > 0) handleDeleteSelected();
      else if ((e.ctrlKey || e.metaKey) && e.key === 'c') handleCopy();
      else if ((e.ctrlKey || e.metaKey) && e.key === 'v') handlePaste();
      else if ((e.ctrlKey || e.metaKey) && e.key === 'g') { e.preventDefault(); handleGroupSelected(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedElementIds, handleDeleteSelected, handleCopy, handlePaste, handleGroupSelected]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
      return;
    }
    if (!actionState) return;
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      // Resize only works for single selection in most Figma-like apps for simplicity
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;
      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { const cl = Math.min(dx, target.w - 10); newW = target.w - cl; newX = target.x + cl; }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { const cl = Math.min(dy, target.h - 10); newH = target.h - cl; newY = target.y + cl; }
      handleUpdateElement(target.id, { x: Math.round(newX), y: Math.round(newY), width: Math.round(newW), height: Math.round(newH) });
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: Math.round(init.x + dx), y: Math.round(init.y + dy) });
      });
    }
  }, [actionState, zoom, handleUpdateElement, marquee]);

  const onMouseUp = useCallback((e: MouseEvent) => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;

      const hitIds = currentPage.elements.filter(el => {
        return el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1;
      }).map(el => el.id);

      setSelectedElementIds(hitIds);
    }
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  const canvasBackgroundStyle: React.CSSProperties = useMemo(() => {
    const bg = currentPage.background;
    if (!bg) return { backgroundColor: '#FFFFFF' };
    if (bg.type === 'image') return { backgroundImage: `url(${bg.value})`, backgroundSize: 'cover', backgroundPosition: 'center' };
    if (bg.type === 'gradient') return { background: bg.value };
    return { backgroundColor: bg.value };
  }, [currentPage.background]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      <div className="h-1 w-full bg-slate-200 z-[300]">
         <div className="h-full bg-[#E4002B] transition-all duration-700 ease-out shadow-[0_0_10px_rgba(228,0,43,0.5)]" style={{ width: `${((currentPageIndex + 1) / project.pages.length) * 100}%` }} />
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, 
                x: 100, y: 100, width: 250, height: 60,
                content: content || (type === 'text' ? 'New Text' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#000000' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 20, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ ...p, pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) }));
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={handleUpdateBackground}
            pages={project.pages}
            currentPageIndex={currentPageIndex}
            onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Page ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              setProject(p => ({ ...p, pages: [...p.pages, newPage] }));
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-center items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) {
                setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
              }
            }
          }}
        >
          <div 
            ref={canvasRef}
            className={`shadow-[0_20px_60px_rgba(0,0,0,0.15)] relative flex-shrink-0 transition-transform duration-75 ease-out ${isPreview ? 'w-full h-full' : 'border border-slate-300 rounded-sm bg-white'}`}
            style={{ 
              ...canvasBackgroundStyle,
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(prev => prev.includes(el.id) ? prev.filter(id => id !== el.id) : [...prev, el.id]);
                  } else {
                    if (!selectedElementIds.includes(el.id)) {
                      setSelectedElementIds([el.id]);
                    }
                    const activeIds = e.shiftKey ? [...selectedElementIds, el.id] : (selectedElementIds.includes(el.id) ? selectedElementIds : [el.id]);
                    setActionState({ 
                      ids: activeIds, 
                      startX: e.clientX, 
                      startY: e.clientY, 
                      initials: currentPage.elements.filter(x => activeIds.includes(x.id)).map(x => ({ id: x.id, x: x.x, y: x.y, w: x.width, h: x.height }))
                    });
                  }
                }}
                onResizeStart={(e, handle) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ 
                    ids: [el.id], 
                    startX: e.clientX, 
                    startY: e.clientY, 
                    initials: [{ id: el.id, x: el.x, y: el.y, w: el.width, h: el.height }],
                    handle 
                  });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {/* Drag Marquee UI */}
            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{
                  left: Math.min(marquee.startX, marquee.currentX),
                  top: Math.min(marquee.startY, marquee.currentY),
                  width: Math.abs(marquee.startX - marquee.currentX),
                  height: Math.abs(marquee.startY - marquee.currentY)
                }}
              />
            )}
          </div>

          {!isPreview && (
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[110] flex items-center gap-2 bg-white/95 backdrop-blur border border-slate-200 px-5 py-3 rounded-full shadow-2xl">
               <div className="flex items-center gap-4 px-3 border-r border-slate-200">
                  <button onClick={() => setZoom(Math.max(0.1, zoom - 0.1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-search-minus"></i></button>
                  <span className="text-[10px] font-black min-w-[35px] text-center">{Math.round(zoom * 100)}%</span>
                  <button onClick={() => setZoom(Math.min(3, zoom + 0.1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-search-plus"></i></button>
               </div>
               <div className="flex items-center gap-4 px-3">
                  <button onClick={() => setCurrentPageIndex(Math.max(0, currentPageIndex - 1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-chevron-left"></i></button>
                  <span className="text-[10px] font-black whitespace-nowrap uppercase">Page {currentPageIndex + 1} / {project.pages.length}</span>
                  <button onClick={() => setCurrentPageIndex(Math.min(project.pages.length - 1, currentPageIndex + 1))} className="text-slate-400 hover:text-[#E4002B]"><i className="fas fa-chevron-right"></i></button>
               </div>
            </div>
          )}
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-50 shadow-2xl overflow-hidden animate-in slide-in-from-right duration-300">
             <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
               <h3 className="text-[10px] font-black text-[#E4002B] uppercase tracking-widest">Properties</h3>
               <span className="text-[9px] text-slate-400 font-bold uppercase">{selectedElements.length > 1 ? 'Multiple Selection' : selectedElements[0].type}</span>
             </div>
             <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-hide pb-32">
               {selectedElements.length === 1 && (
                 <>
                   {(selectedElements[0].type === 'text' || selectedElements[0].type === 'button') && (
                     <div className="space-y-3">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Content</label>
                       <textarea className="w-full bg-slate-50 border border-slate-200 rounded-xl text-xs py-4 px-4 text-slate-900 focus:ring-1 focus:ring-[#E4002B] outline-none min-h-[100px] resize-none" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                     </div>
                   )}
                   <div className="space-y-4">
                     <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Interactivity</label>
                     <select value={selectedElements[0].interactivity.type} onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { ...selectedElements[0].interactivity, type: e.target.value as any } })} className="w-full bg-slate-50 border border-slate-200 rounded-xl text-xs py-3 px-4 outline-none">
                       <option value={InteractivityType.NONE}>None</option>
                       <option value={InteractivityType.GOTO_PAGE}>Go to Page</option>
                       <option value={InteractivityType.EXTERNAL_LINK}>Link URL</option>
                       <option value={InteractivityType.TOOLTIP}>Tooltip</option>
                     </select>
                     {selectedElements[0].interactivity.type !== InteractivityType.NONE && (
                       <input type="text" placeholder="Value..." value={selectedElements[0].interactivity.value} onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { ...selectedElements[0].interactivity, value: e.target.value } })} className="w-full bg-slate-50 border border-slate-200 rounded-xl text-xs py-3 px-4 outline-none" />
                     )}
                   </div>
                 </>
               )}

               <div className="space-y-4 pt-4 border-t border-slate-100">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Visual Style</label>
                  <div className="space-y-4">
                     <div className="flex bg-slate-100 p-1 rounded-lg">
                        <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: undefined } }))} className={`flex-1 py-1.5 text-[9px] font-black rounded ${!selectedElements[0].styles.gradient ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Solid</button>
                        <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: 'linear-gradient(45deg, #E4002B 0%, #000000 100%)' } }))} className={`flex-1 py-1.5 text-[9px] font-black rounded ${selectedElements[0].styles.gradient ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Gradient</button>
                     </div>
                     {!selectedElements[0].styles.gradient ? (
                       <div className="bg-slate-50 p-3 rounded-xl border border-slate-200">
                          <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Bg Color</span>
                          <input type="color" value={selectedElements[0].styles.backgroundColor || '#E4002B'} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} className="w-full h-8 p-0 border-0 bg-transparent cursor-pointer" />
                       </div>
                     ) : (
                       <div className="space-y-2">
                          <span className="block text-[8px] font-bold text-slate-400 uppercase">Gradient CSS</span>
                          <input type="text" value={selectedElements[0].styles.gradient} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: e.target.value } }))} className="w-full bg-slate-50 border border-slate-200 rounded-xl text-[9px] font-mono py-2 px-3 outline-none" />
                       </div>
                     )}
                     <div className="bg-slate-50 p-3 rounded-xl border border-slate-200">
                        <span className="block text-[8px] font-bold text-slate-400 uppercase mb-2">Border Radius</span>
                        <input type="number" value={selectedElements[0].styles.borderRadius} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderRadius: parseInt(e.target.value) } }))} className="w-full bg-transparent border-none text-xs font-bold" />
                     </div>
                  </div>
               </div>
             </div>

             <div className="p-6 bg-slate-50 border-t border-slate-200 mt-auto flex flex-col gap-2">
               <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 hover:bg-red-100 text-[#E4002B] text-[10px] font-black uppercase tracking-widest rounded-xl transition-all border border-red-200"><i className="fas fa-trash-alt mr-2"></i> Delete ({selectedElements.length})</button>
               {selectedElements.length > 1 && (
                 <button onClick={handleGroupSelected} className="w-full py-4 bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest rounded-xl transition-all shadow-lg active:scale-95"><i className="fas fa-object-group mr-2"></i> Group Elements</button>
               )}
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ElementType, CanvasPreset, CANVAS_PRESETS, ProjectPage, PageBackground } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
  currentPage: ProjectPage;
  selectedElementIds: string[];
  onSelectElements: (ids: string[]) => void;
  onUpdateBackground: (bg: PageBackground) => void;
  pages: ProjectPage[];
  currentPageIndex: number;
  onNavigatePage: (index: number) => void;
  onAddPage: () => void;
}

const PREDEFINED_SHAPES = [
  { id: 'square', icon: 'fa-square' },
  { id: 'circle', icon: 'fa-circle' },
  { id: 'triangle', icon: 'fa-play fa-rotate-270' },
  { id: 'star', icon: 'fa-star' },
  { id: 'diamond', icon: 'fa-diamond' },
  { id: 'heart', icon: 'fa-heart' }
];

const Sidebar: React.FC<SidebarProps> = ({ 
  onAddElement, onBulkAdd, canvasPreset, onUpdatePreset, 
  currentPage, selectedElementIds, onSelectElements, onUpdateBackground,
  pages, currentPageIndex, onNavigatePage, onAddPage
}) => {
  const [activePanel, setActivePanel] = useState<'pages' | 'text' | 'resources' | 'objects' | 'insert' | 'bg'>('pages');
  const [pagesSubTab, setPagesSubTab] = useState<'outline' | 'layers'>('outline');
  const [insertMode, setInsertMode] = useState<'image' | 'audio' | 'video'>('image');

  return (
    <div className="flex h-full bg-[#111118] z-[100] shadow-2xl">
      {/* Primary Sidebar */}
      <div className="w-18 bg-black flex flex-col items-center py-8 gap-8 border-r border-white/5">
        <NavIcon active={activePanel === 'pages'} icon="fa-layer-group" onClick={() => setActivePanel('pages')} label="Pages" />
        <div className="h-px w-8 bg-white/10" />
        <NavIcon active={activePanel === 'text'} icon="fa-font" onClick={() => setActivePanel('text')} label="Text" />
        <NavIcon active={activePanel === 'resources'} icon="fa-shapes" onClick={() => setActivePanel('resources')} label="Shapes" />
        <NavIcon active={activePanel === 'objects'} icon="fa-cubes" onClick={() => setActivePanel('objects')} label="Widgets" />
        <NavIcon active={activePanel === 'insert'} icon="fa-plus-circle" onClick={() => setActivePanel('insert')} label="Insert" />
        <NavIcon active={activePanel === 'bg'} icon="fa-palette" onClick={() => setActivePanel('bg')} label="Theme" />
      </div>

      {/* Sub-Panel */}
      <div className="w-72 flex flex-col bg-white border-r border-slate-200">
        <div className="h-16 flex items-center px-6 border-b border-slate-100 bg-slate-50/50">
          <h2 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{activePanel}</h2>
        </div>

        <div className="flex-1 overflow-y-auto px-6 py-8 scrollbar-hide">
          {activePanel === 'pages' && (
            <div className="space-y-6">
               <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setPagesSubTab('outline')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'outline' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Pages</button>
                  <button onClick={() => setPagesSubTab('layers')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'layers' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Layers</button>
               </div>

               {pagesSubTab === 'outline' ? (
                 <div className="space-y-3">
                    {pages.map((p, idx) => (
                       <div key={p.id} onClick={() => onNavigatePage(idx)} className={`p-4 rounded-2xl border transition-all cursor-pointer ${currentPageIndex === idx ? 'border-[#E4002B] bg-red-50/50' : 'border-slate-100 bg-white hover:border-slate-300'}`}>
                          <span className={`text-[10px] font-black uppercase ${currentPageIndex === idx ? 'text-[#E4002B]' : 'text-slate-400'}`}>0{idx + 1}</span>
                          <div className="text-xs font-bold text-slate-900 mt-1">{p.name}</div>
                       </div>
                    ))}
                    <button onClick={onAddPage} className="w-full py-4 border-2 border-dashed border-slate-200 rounded-2xl text-[10px] font-black text-slate-400 hover:border-[#E4002B] hover:text-[#E4002B] transition-all uppercase">+ New Page</button>
                 </div>
               ) : (
                 <div className="space-y-2">
                    {currentPage.elements.length === 0 && <p className="text-[10px] text-slate-400 font-bold text-center py-10">No elements on this page</p>}
                    {[...currentPage.elements].reverse().map(el => (
                      <div 
                        key={el.id} 
                        onClick={(e) => {
                          if (e.shiftKey) onSelectElements([...selectedElementIds, el.id]);
                          else onSelectElements([el.id]);
                        }} 
                        className={`p-3 rounded-xl border flex items-center gap-3 cursor-pointer transition-all ${selectedElementIds.includes(el.id) ? 'bg-red-50 border-[#E4002B] text-[#E4002B]' : 'bg-white border-slate-100 hover:border-slate-300'}`}
                      >
                         <i className={`fas ${el.type === 'text' ? 'fa-font' : 'fa-square'} text-xs`}></i>
                         <span className="text-[10px] font-bold truncate flex-1 uppercase tracking-tighter">{el.type}</span>
                         {el.groupId && <i className="fas fa-layer-group text-[9px] text-slate-300"></i>}
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}

          {activePanel === 'resources' && (
             <div className="space-y-6">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Shapes</h3>
                <div className="grid grid-cols-3 gap-3">
                   {PREDEFINED_SHAPES.map(s => (
                      <button key={s.id} onClick={() => onAddElement('shape', s.id)} className="h-16 bg-slate-50 border border-slate-200 rounded-2xl flex items-center justify-center hover:border-[#E4002B] group transition-all">
                         <i className={`fas ${s.icon} text-lg text-slate-300 group-hover:text-[#E4002B]`}></i>
                      </button>
                   ))}
                </div>
             </div>
          )}

          {activePanel === 'bg' && (
            <div className="space-y-8">
               <div className="space-y-6">
                  <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Background Style</h3>
                  <div className="space-y-4">
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                       <span className="text-[8px] font-bold text-slate-400 uppercase block mb-3">Solid Color</span>
                       <input 
                          type="color" 
                          className="w-full h-10 border-none bg-transparent cursor-pointer"
                          value={currentPage.background?.type === 'color' ? currentPage.background.value : '#FFFFFF'}
                          onChange={(e) => onUpdateBackground({ type: 'color', value: e.target.value })}
                       />
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                       <span className="text-[8px] font-bold text-slate-400 uppercase block mb-3">Gradient</span>
                       <button 
                          onClick={() => onUpdateBackground({ type: 'gradient', value: 'linear-gradient(135deg, #E4002B 0%, #000000 100%)' })}
                          className="w-full h-10 rounded-lg shadow-sm border border-white"
                          style={{ background: 'linear-gradient(135deg, #E4002B 0%, #000000 100%)' }}
                       />
                       <input 
                          type="text" 
                          placeholder="linear-gradient(...)" 
                          className="w-full mt-3 bg-white border border-slate-200 rounded-lg py-2 px-3 text-[9px] font-mono outline-none"
                          value={currentPage.background?.type === 'gradient' ? currentPage.background.value : ''}
                          onChange={(e) => onUpdateBackground({ type: 'gradient', value: e.target.value })}
                       />
                    </div>
                  </div>
               </div>
            </div>
          )}

          {activePanel === 'text' && (
             <div className="space-y-4">
                <button onClick={() => onAddElement('text', 'Headline')} className="w-full py-6 px-5 bg-slate-50 border border-slate-100 rounded-2xl hover:border-[#E4002B] text-left transition-all group">
                   <span className="text-2xl font-black block group-hover:text-[#E4002B]">Heading</span>
                </button>
                <button onClick={() => onAddElement('text', 'Paragraph text content.')} className="w-full py-4 px-5 bg-slate-50 border border-slate-100 rounded-2xl hover:border-[#E4002B] text-left transition-all">
                   <span className="text-sm font-medium block">Body Copy</span>
                </button>
             </div>
          )}

          {activePanel === 'objects' && (
             <div className="space-y-4">
                <button onClick={() => onAddElement('quiz')} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl flex items-center gap-4 hover:border-[#E4002B] transition-all text-left">
                   <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-[#E4002B]"><i className="fas fa-tasks"></i></div>
                   <div className="text-[10px] font-black uppercase">Quiz Block</div>
                </button>
                <button onClick={() => onAddElement('gallery')} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl flex items-center gap-4 hover:border-[#E4002B] transition-all text-left">
                   <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-[#E4002B]"><i className="fas fa-photo-video"></i></div>
                   <div className="text-[10px] font-black uppercase">Gallery</div>
                </button>
             </div>
          )}

          {activePanel === 'insert' && (
             <div className="space-y-6">
                <div className="flex bg-slate-100 p-1.5 rounded-xl">
                   {['image', 'audio', 'video'].map(mode => (
                      <button key={mode} onClick={() => setInsertMode(mode as any)} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all uppercase ${insertMode === mode ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>{mode}</button>
                   ))}
                </div>
                <button 
                   onClick={() => {
                     const url = window.prompt(`Paste ${insertMode} URL:`);
                     if (url) onAddElement(insertMode, url);
                   }} 
                   className="w-full py-10 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center gap-3 hover:border-[#E4002B] group transition-all"
                >
                   <div className="w-12 h-12 rounded-full bg-slate-50 flex items-center justify-center text-slate-300 group-hover:text-[#E4002B] transition-all shadow-sm"><i className={`fas fa-plus`}></i></div>
                   <span className="text-[10px] font-black text-slate-400 group-hover:text-[#E4002B] uppercase">Link {insertMode}</span>
                </button>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

const NavIcon: React.FC<{ active: boolean; icon: string; onClick: () => void; label: string }> = ({ active, icon, onClick, label }) => (
  <button onClick={onClick} className={`group flex flex-col items-center gap-2 outline-none transition-all ${active ? 'text-white' : 'text-slate-600 hover:text-white'}`}>
    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${active ? 'bg-[#E4002B] shadow-xl shadow-red-900/40' : 'bg-white/5 hover:bg-white/10'}`}>
       <i className={`fas ${icon} text-lg`}></i>
    </div>
    <span className={`text-[8px] font-black uppercase tracking-tighter transition-all ${active ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-1 group-hover:opacity-40'}`}>{label}</span>
  </button>
);

export default Sidebar;

export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'fade' | 'slide' | 'zoom' | 'pop' | 'lift';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentación (16:9)' },
  square: { width: 600, height: 600, label: 'Cuadrado (1:1)' },
  vertical: { width: 400, height: 711, label: 'Móvil (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Vertical' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  groupId?: string;
  styles: {
    backgroundColor?: string;
    gradient?: {
      enabled: boolean;
      from: string;
      to: string;
      angle: number;
    };
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    // Efectos
    borderWidth?: number;
    borderColor?: string;
    shadowBlur?: number;
    shadowColor?: string;
    glowBlur?: number;
    glowColor?: string;
    // Animaciones
    hoverAnimation?: AnimationType;
    entranceAnimation?: AnimationType;
    exitAnimation?: AnimationType;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
  };
}

export interface GroupFolder {
  id: string;
  name: string;
  isOpen: boolean;
  elementIds: string[];
}

export interface PageBackground {
  type: 'color' | 'gradient' | 'image';
  value: string;
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
  groups: GroupFolder[];
  background?: PageBackground;
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
  canvasPreset: CanvasPreset;
}

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground, GroupFolder } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleDeleteSelected = useCallback(() => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    }));
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex]);

  const handleGroupSelected = useCallback(() => {
    if (selectedElementIds.length < 2) return;
    const groupId = `group-${Date.now()}`;
    const newGroup: GroupFolder = {
      id: groupId,
      name: `Grupo ${currentPage.groups.length + 1}`,
      isOpen: true,
      elementIds: [...selectedElementIds]
    };
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        groups: [...p.groups, newGroup],
        elements: p.elements.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId } : el)
      }) : p)
    }));
  }, [selectedElementIds, currentPageIndex, currentPage.groups.length]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
      return;
    }
    if (!actionState) return;
    const dx = (e.clientX - actionState.startX) / zoom;
    const dy = (e.clientY - actionState.startY) / zoom;

    if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;
      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { const cl = Math.min(dx, target.w - 10); newW = target.w - cl; newX = target.x + cl; }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { const cl = Math.min(dy, target.h - 10); newH = target.h - cl; newY = target.y + cl; }
      handleUpdateElement(target.id, { x: Math.round(newX), y: Math.round(newY), width: Math.round(newW), height: Math.round(newH) });
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: Math.round(init.x + dx), y: Math.round(init.y + dy) });
      });
    }
  }, [actionState, zoom, handleUpdateElement, marquee]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;

      const hitIds = currentPage.elements.filter(el => {
        return el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1;
      }).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, 
                type, x: 100, y: 100, 
                width: type === 'shape' ? 150 : 250, 
                height: type === 'shape' ? 150 : 60,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ ...p, pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) }));
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}}
            canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage}
            selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject(prev => ({ ...prev, pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) }))}
            pages={project.pages}
            currentPageIndex={currentPageIndex}
            onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Página ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              setProject(p => ({ ...p, pages: [...p.pages, newPage] }));
              setCurrentPageIndex(project.pages.length);
            }}
            onGroup={handleGroupSelected}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-center items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {/* Rulers Button */}
          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id}
                element={el}
                isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    if (!selectedElementIds.includes(el.id)) setSelectedElementIds([el.id]);
                    const activeIds = selectedElementIds.includes(el.id) ? selectedElementIds : [el.id];
                    setActionState({ 
                      ids: activeIds, 
                      startX: e.clientX, 
                      startY: e.clientY, 
                      initials: currentPage.elements.filter(x => activeIds.includes(x.id)).map(x => ({ id: x.id, x: x.x, y: x.y, w: x.width, h: x.height }))
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height}], handle:h });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{
                  left: Math.min(marquee.startX, marquee.currentX),
                  top: Math.min(marquee.startY, marquee.currentY),
                  width: Math.abs(marquee.startX - marquee.currentX),
                  height: Math.abs(marquee.startY - marquee.currentY)
                }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-50 shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="p-6 border-b bg-slate-50 flex items-center justify-between sticky top-0 z-10">
               <h3 className="text-xs font-black text-[#E4002B] uppercase tracking-widest">Propiedades</h3>
               <button onClick={() => setSelectedElementIds([])} className="text-slate-400 hover:text-slate-900"><i className="fas fa-times"></i></button>
             </div>
             <div className="p-6 space-y-8 pb-32">
               {selectedElements.length === 1 && (
                 <>
                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                   </section>

                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Tipografía</label>
                     <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Courier New">Mono</option>
                        <option value="Pacifico">Script</option>
                     </select>
                     <div className="flex gap-2">
                        <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                        <div className="flex flex-1 border rounded-xl overflow-hidden">
                           {['left', 'center', 'right'].map(a => (
                              <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs ${selectedElements[0].styles.textAlign === a ? 'bg-slate-200' : 'bg-white'}`}><i className={`fas fa-align-${a}`}></i></button>
                           ))}
                        </div>
                     </div>
                   </section>
                 </>
               )}

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo Visual</label>
                  <div className="space-y-4">
                    <div className="flex bg-slate-100 p-1 rounded-xl">
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                    </div>

                    {selectedElements[0].styles.gradient?.enabled ? (
                      <div className="grid grid-cols-2 gap-2">
                         <input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, from: e.target.value } } }))} className="w-full h-8 cursor-pointer" />
                         <input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, to: e.target.value } } }))} className="w-full h-8 cursor-pointer" />
                      </div>
                    ) : (
                      <input type="color" className="w-full h-10 border-none bg-transparent cursor-pointer" value={selectedElements[0].styles.backgroundColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} />
                    )}

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Radio Borde <span>{selectedElements[0].styles.borderRadius}px</span></label>
                       <input type="range" min="0" max="100" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.borderRadius} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderRadius: parseInt(e.target.value) } }))} />
                    </div>

                    <div className="space-y-3 pt-4 border-t">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Efectos</label>
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                          <span className="text-[8px] font-bold text-slate-400 uppercase">Sombra Blur</span>
                          <input type="number" className="w-full border rounded-lg p-2 text-xs" value={selectedElements[0].styles.shadowBlur || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { shadowBlur: parseInt(e.target.value) } }))} />
                        </div>
                        <div className="space-y-1">
                          <span className="text-[8px] font-bold text-slate-400 uppercase">Borde Ancho</span>
                          <input type="number" className="w-full border rounded-lg p-2 text-xs" value={selectedElements[0].styles.borderWidth || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderWidth: parseInt(e.target.value) } }))} />
                        </div>
                      </div>
                    </div>
                  </div>
               </section>

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones</label>
                  <div className="space-y-4">
                     <div>
                        <span className="text-[9px] font-bold text-slate-400 uppercase mb-2 block">Entrada</span>
                        <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.entranceAnimation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: e.target.value as any } }))}>
                           <option value="none">Ninguna</option>
                           <option value="fade">Desvanecer</option>
                           <option value="slide">Deslizar</option>
                           <option value="zoom">Zoom</option>
                        </select>
                     </div>
                     <div>
                        <span className="text-[9px] font-bold text-slate-400 uppercase mb-2 block">Ratón</span>
                        <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.hoverAnimation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { hoverAnimation: e.target.value as any } }))}>
                           <option value="none">Ninguna</option>
                           <option value="pop">Pop</option>
                           <option value="lift">Levantar</option>
                        </select>
                     </div>
                  </div>
               </section>
             </div>
             <div className="p-6 mt-auto bg-slate-50 border-t flex flex-col gap-2">
                <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 text-[#E4002B] text-[10px] font-black uppercase rounded-xl border border-red-200"><i className="fas fa-trash-alt mr-2"></i> Eliminar ({selectedElements.length})</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ElementType, CanvasPreset, ProjectPage, PageBackground } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
  currentPage: ProjectPage;
  selectedElementIds: string[];
  onSelectElements: (ids: string[]) => void;
  onUpdateBackground: (bg: PageBackground) => void;
  pages: ProjectPage[];
  currentPageIndex: number;
  onNavigatePage: (index: number) => void;
  onAddPage: () => void;
  onGroup?: () => void;
}

const PREDEFINED_SHAPES = [
  { id: 'square', icon: 'fa-square', label: 'Cuadrado' },
  { id: 'circle', icon: 'fa-circle', label: 'Círculo' },
  { id: 'triangle', icon: 'fa-play fa-rotate-270', label: 'Triángulo' },
  { id: 'star', icon: 'fa-star', label: 'Estrella' },
  { id: 'diamond', icon: 'fa-diamond', label: 'Diamante' },
  { id: 'heart', icon: 'fa-heart', label: 'Corazón' }
];

const Sidebar: React.FC<SidebarProps> = ({ 
  onAddElement, canvasPreset, currentPage, selectedElementIds, onSelectElements, onUpdateBackground,
  pages, currentPageIndex, onNavigatePage, onAddPage, onGroup
}) => {
  const [activePanel, setActivePanel] = useState<'pages' | 'text' | 'resources' | 'objects' | 'insert' | 'bg'>('pages');
  const [pagesSubTab, setPagesSubTab] = useState<'outline' | 'layers'>('outline');
  const [insertMode, setInsertMode] = useState<'image' | 'audio' | 'video'>('image');

  return (
    <div className="flex h-full bg-[#111118] z-[100] shadow-2xl">
      <div className="w-18 bg-black flex flex-col items-center py-8 gap-8 border-r border-white/5">
        <NavIcon active={activePanel === 'pages'} icon="fa-layer-group" onClick={() => setActivePanel('pages')} label="Páginas" />
        <div className="h-px w-8 bg-white/10" />
        <NavIcon active={activePanel === 'text'} icon="fa-font" onClick={() => setActivePanel('text')} label="Texto" />
        <NavIcon active={activePanel === 'resources'} icon="fa-shapes" onClick={() => setActivePanel('resources')} label="Formas" />
        <NavIcon active={activePanel === 'objects'} icon="fa-cubes" onClick={() => setActivePanel('objects')} label="Widgets" />
        <NavIcon active={activePanel === 'insert'} icon="fa-plus-circle" onClick={() => setActivePanel('insert')} label="Insertar" />
        <NavIcon active={activePanel === 'bg'} icon="fa-palette" onClick={() => setActivePanel('bg')} label="Tema" />
      </div>

      <div className="w-72 flex flex-col bg-white border-r border-slate-200">
        <div className="h-16 flex items-center px-6 border-b bg-slate-50/50">
          <h2 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{activePanel}</h2>
        </div>

        <div className="flex-1 overflow-y-auto px-6 py-8 scrollbar-hide">
          {activePanel === 'pages' && (
            <div className="space-y-6">
               <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setPagesSubTab('outline')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'outline' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Páginas</button>
                  <button onClick={() => setPagesSubTab('layers')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'layers' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Capas</button>
               </div>

               {pagesSubTab === 'outline' ? (
                 <div className="space-y-3">
                    {pages.map((p, idx) => (
                       <div key={p.id} onClick={() => onNavigatePage(idx)} className={`p-4 rounded-2xl border transition-all cursor-pointer ${currentPageIndex === idx ? 'border-[#E4002B] bg-red-50/50' : 'border-slate-100 bg-white hover:border-slate-300'}`}>
                          <span className={`text-[10px] font-black uppercase ${currentPageIndex === idx ? 'text-[#E4002B]' : 'text-slate-400'}`}>0{idx + 1}</span>
                          <div className="text-xs font-bold text-slate-900 mt-1">{p.name}</div>
