                         <span className="text-[10px] font-bold truncate flex-1 uppercase">{el.type === 'shape' ? el.content : el.type}</span>
                         {el.groupId && <i className="fas fa-layer-group text-[9px] text-slate-400"></i>}
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}

          {activePanel === 'resources' && (
             <div className="space-y-6">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Formas Geométricas</h3>
                <div className="grid grid-cols-2 gap-4">
                   {PREDEFINED_SHAPES.map(s => (
                      <button key={s.id} onClick={() => onAddElement('shape', s.id)} className="p-6 bg-slate-50 border border-slate-200 rounded-2xl flex flex-col items-center gap-2 hover:border-[#E4002B] group transition-all">
                         <i className={`fas ${s.icon} text-2xl text-slate-400 group-hover:text-[#E4002B]`}></i>
                         <span className="text-[8px] font-bold text-slate-400 group-hover:text-[#E4002B] uppercase">{s.label}</span>
                      </button>
                   ))}
                </div>
             </div>
          )}

          {activePanel === 'bg' && (
            <div className="space-y-6">
               <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Estilo de Fondo</h3>
               <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <span className="text-[8px] font-bold text-slate-400 uppercase block mb-3">Color Sólido</span>
                  <input type="color" className="w-full h-10 border-none bg-transparent cursor-pointer" value={currentPage.background?.value || '#FFFFFF'} onChange={(e) => onUpdateBackground({ type: 'color', value: e.target.value })} />
               </div>
            </div>
          )}

          {activePanel === 'text' && (
             <div className="space-y-4">
                <button onClick={() => onAddElement('text', 'Título Principal')} className="w-full py-6 px-5 bg-slate-50 border rounded-2xl hover:border-[#E4002B] text-left transition-all group">
                   <span className="text-2xl font-black block group-hover:text-[#E4002B]">Encabezado</span>
                </button>
                <button onClick={() => onAddElement('text', 'Escribe aquí tu texto.')} className="w-full py-4 px-5 bg-slate-50 border rounded-2xl hover:border-[#E4002B] text-left transition-all">
                   <span className="text-sm font-medium block">Párrafo</span>
