          {activePanel === 'objects' && (
             <div className="space-y-4">
                <button onClick={() => onAddElement('quiz')} className="w-full p-5 bg-slate-50 border rounded-2xl flex items-center gap-4 hover:border-[#E4002B] transition-all text-left group">
                   <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-slate-400 group-hover:text-[#E4002B]"><i className="fas fa-tasks"></i></div>
