  onAddElement, canvasPreset, currentPage, selectedElementIds, onSelectElements, onUpdateBackground,
  pages, currentPageIndex, onNavigatePage, onAddPage, onGroup
}) => {
  const [activePanel, setActivePanel] = useState<'pages' | 'text' | 'resources' | 'ai' | 'bg'>('pages');
  const [pagesSubTab, setPagesSubTab] = useState<'outline' | 'layers'>('outline');

  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleAiGeneration = async () => {
    if (!aiPrompt) return;
    setIsGenerating(true);
    try {
      const ideas = await generateContentIdeas(aiPrompt);
      onAddElement('text', ideas.title);
      ideas.points.forEach((p: any, i: number) => {
        setTimeout(() => {
          onAddElement('button', p.label);
        }, (i + 1) * 300);
      });
    } catch (e) {
      console.error(e);
      alert("Error generando ideas");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAiImage = async () => {
    if (!aiPrompt) return;
    setIsGenerating(true);
    try {
      const img = await generateAIImage(aiPrompt);
      if (img) onAddElement('image', img);
    } catch (e) {
      console.error(e);
      alert("Error generando imagen");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex h-full bg-[#111118] z-[100] shadow-2xl">
      <div className="w-18 bg-black flex flex-col items-center py-8 gap-8 border-r border-white/5">
        <NavIcon active={activePanel === 'pages'} icon="fa-layer-group" onClick={() => setActivePanel('pages')} label="Páginas" />
        <div className="h-px w-8 bg-white/10" />
        <NavIcon active={activePanel === 'text'} icon="fa-font" onClick={() => setActivePanel('text')} label="Texto" />
        <NavIcon active={activePanel === 'resources'} icon="fa-shapes" onClick={() => setActivePanel('resources')} label="Formas" />
        <NavIcon active={activePanel === 'ai'} icon="fa-wand-magic-sparkles" onClick={() => setActivePanel('ai')} label="IA Mágica" />
        <NavIcon active={activePanel === 'bg'} icon="fa-palette" onClick={() => setActivePanel('bg')} label="Tema" />
      </div>

      <div className="w-72 flex flex-col bg-white border-r border-slate-200">
        <div className="h-16 flex items-center px-6 border-b bg-slate-50/50">
          <h2 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">
            {activePanel === 'ai' ? 'Asistente de IA' : activePanel}
          </h2>
        </div>

        <div className="flex-1 overflow-y-auto px-6 py-8 scrollbar-hide">
          {activePanel === 'pages' && (
            <div className="space-y-6">
               <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setPagesSubTab('outline')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'outline' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Páginas</button>
                  <button onClick={() => setPagesSubTab('layers')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'layers' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Capas</button>
               </div>

               {pagesSubTab === 'outline' ? (
                 <div className="space-y-3">
                    {pages.map((p, idx) => (
                       <div key={p.id} onClick={() => onNavigatePage(idx)} className={`p-4 rounded-2xl border transition-all cursor-pointer ${currentPageIndex === idx ? 'border-[#E4002B] bg-red-50/50' : 'border-slate-100 bg-white hover:border-slate-300'}`}>
                          <span className={`text-[10px] font-black uppercase ${currentPageIndex === idx ? 'text-[#E4002B]' : 'text-slate-400'}`}>0{idx + 1}</span>
                          <div className="text-xs font-bold text-slate-900 mt-1">{p.name}</div>
                       </div>
                    ))}
                    <button onClick={onAddPage} className="w-full py-4 border-2 border-dashed border-slate-200 rounded-2xl text-[10px] font-black text-slate-400 hover:border-[#E4002B] hover:text-[#E4002B] transition-all uppercase">+ Nueva Página</button>
                 </div>
               ) : (
                 <div className="space-y-2">
                    {selectedElementIds.length > 1 && (
                      <button onClick={onGroup} className="w-full py-2 mb-4 bg-slate-900 text-white text-[10px] font-black rounded-lg uppercase"><i className="fas fa-object-group mr-2"></i> Agrupar Selección</button>
                    )}
                    {[...currentPage.elements].reverse().map(el => (
                      <div 
                        key={el.id} 
                        onClick={(e) => onSelectElements(e.shiftKey ? [...selectedElementIds, el.id] : [el.id])} 
                        className={`p-3 rounded-xl border flex items-center gap-3 cursor-pointer transition-all ${selectedElementIds.includes(el.id) ? 'bg-red-50 border-[#E4002B] text-[#E4002B]' : 'bg-white border-slate-100 hover:border-slate-300'}`}
                      >
                         <i className={`fas ${el.type === 'text' ? 'fa-font' : el.type === 'shape' ? 'fa-square' : 'fa-cube'} text-xs`}></i>
                         <span className="text-[10px] font-bold truncate flex-1 uppercase">{el.type === 'shape' ? el.content : el.type}</span>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}

          {activePanel === 'ai' && (
            <div className="space-y-6">
              <div className="p-4 bg-slate-900 rounded-2xl text-white shadow-xl">
                <label className="text-[9px] font-black uppercase tracking-widest text-slate-400 mb-2 block">¿Qué quieres crear?</label>
                <textarea 
                  className="w-full bg-white/10 border border-white/10 rounded-xl p-3 text-xs outline-none focus:ring-1 focus:ring-[#E4002B] min-h-[100px]"
                  placeholder="Ej: Una lección sobre el ciclo del agua..."
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                />
                <div className="grid grid-cols-2 gap-2 mt-4">
                  <button 
                    onClick={handleAiGeneration}
                    disabled={isGenerating}
                    className="py-3 bg-[#E4002B] rounded-xl text-[9px] font-black uppercase flex items-center justify-center gap-2 hover:bg-red-700 disabled:opacity-50"
                  >
                    {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-lightbulb"></i>}
                    Ideas
                  </button>
                  <button 
                    onClick={handleAiImage}
                    disabled={isGenerating}
                    className="py-3 bg-white/10 rounded-xl text-[9px] font-black uppercase flex items-center justify-center gap-2 hover:bg-white/20 disabled:opacity-50"
                  >
                    {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-image"></i>}
                    Imagen
                  </button>
                </div>
              </div>
              <div className="text-[9px] font-bold text-slate-400 uppercase leading-relaxed text-center px-4">
                Usa la IA para generar borradores rápidos de tus presentaciones.
              </div>
            </div>
          )}

          {activePanel === 'resources' && (
             <div className="space-y-6">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Formas Geométricas</h3>
                <div className="grid grid-cols-2 gap-4">
                   {PREDEFINED_SHAPES.map(s => (
                      <button key={s.id} onClick={() => onAddElement('shape', s.id)} className="p-6 bg-slate-50 border border-slate-200 rounded-2xl flex flex-col items-center gap-2 hover:border-[#E4002B] group transition-all">
                         <i className={`fas ${s.icon} text-2xl text-slate-400 group-hover:text-[#E4002B]`}></i>
                         <span className="text-[8px] font-bold text-slate-400 group-hover:text-[#E4002B] uppercase">{s.label}</span>
                      </button>
                   ))}
                </div>
             </div>
          )}

          {activePanel === 'text' && (
             <div className="space-y-4">
                <button onClick={() => onAddElement('text', 'Título Principal')} className="w-full py-6 px-5 bg-slate-50 border rounded-2xl hover:border-[#E4002B] text-left transition-all group">
                   <span className="text-2xl font-black block group-hover:text-[#E4002B]">Encabezado</span>
                </button>
                <button onClick={() => onAddElement('text', 'Escribe aquí tu texto.')} className="w-full py-4 px-5 bg-slate-50 border rounded-2xl hover:border-[#E4002B] text-left transition-all">
                   <span className="text-sm font-medium block">Párrafo</span>
                </button>
             </div>
          )}

          {activePanel === 'bg' && (
            <div className="space-y-6">
               <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Estilo de Fondo</h3>
               <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <span className="text-[8px] font-bold text-slate-400 uppercase block mb-3">Color Sólido</span>
                  <input type="color" className="w-full h-10 border-none bg-transparent cursor-pointer" value={currentPage.background?.value || '#FFFFFF'} onChange={(e) => onUpdateBackground({ type: 'color', value: e.target.value })} />
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const NavIcon: React.FC<{ active: boolean; icon: string; onClick: () => void; label: string }> = ({ active, icon, onClick, label }) => (
  <button onClick={onClick} className={`group flex flex-col items-center gap-2 outline-none transition-all ${active ? 'text-white' : 'text-slate-600 hover:text-white'}`}>
    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${active ? 'bg-[#E4002B] shadow-xl shadow-red-900/40' : 'bg-white/5 hover:bg-white/10'}`}>
       <i className={`fas ${icon} text-lg`}></i>
    </div>
    <span className={`text-[8px] font-black uppercase tracking-tighter transition-all ${active ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-1 group-hover:opacity-40'}`}>{label}</span>
  </button>
);

export default Sidebar;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground, GroupFolder } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30,
      y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newEls]
      }) : p)
    }));
    setSelectedElementIds(newEls.map(el => el.id));
  }, [selectedElements, currentPageIndex, currentPage.elements.length]);

  const handleDeleteSelected = useCallback(() => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    }));
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    const snap = (val: number) => showGrid ? Math.round(val / 10) * 10 : Math.round(val);

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;

      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;

      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      const finalAngle = Math.round((angle + 90) % 360);
      handleUpdateElement(target.id, { styles: { rotation: finalAngle } });
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { const cl = Math.min(dx, target.w - 10); newW = target.w - cl; newX = target.x + cl; }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { const cl = Math.min(dy, target.h - 10); newH = target.h - cl; newY = target.y + cl; }

      handleUpdateElement(target.id, { x: snap(newX), y: snap(newY), width: snap(newW), height: snap(newH) });
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: snap(init.x + dx), y: snap(init.y + dy) });
      });
    }
    requestRef.current = null;
  }, [actionState, zoom, handleUpdateElement, showGrid, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
      return;
    }
    if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = null;
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (isPreview) return;
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const scaleFactor = 1.1;
      const nextZoom = delta > 0 ? zoom * scaleFactor : zoom / scaleFactor;
      const clampedZoom = Math.min(Math.max(nextZoom, 0.1), 3);

      if (clampedZoom !== zoom && containerRef.current) {
        const container = containerRef.current;
        const rect = container.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        const scrollLeft = container.scrollLeft;
        const scrollTop = container.scrollTop;
        const worldX = (mouseX + scrollLeft) / zoom;
        const worldY = (mouseY + scrollTop) / zoom;
        const nextScrollLeft = (worldX * clampedZoom) - mouseX;
        const nextScrollTop = (worldY * clampedZoom) - mouseY;
        setZoom(clampedZoom);
        container.scrollLeft = nextScrollLeft;
        container.scrollTop = nextScrollTop;
      }
    }
  }, [zoom, isPreview]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  const rulerTicks = useMemo(() => {
    const ticks = [];
    for (let i = 0; i <= 2000; i += 50) ticks.push(i);
    return ticks;
  }, []);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 150, y: 150, width: type === 'shape' ? 150 : 250, height: type === 'shape' ? 150 : 60,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }, rotation: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ ...p, pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) }));
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}} canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage} selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject(prev => ({ ...prev, pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) }))}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              setProject(p => ({ ...p, pages: [...p.pages, newPage] }));
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-start items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef} onWheel={handleWheel}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {!isPreview && showRulers && (
            <>
              <div className="absolute top-0 left-16 right-0 h-6 bg-white border-b border-slate-200 z-[150] flex items-center overflow-hidden">
                <div className="flex" style={{ transform: `translateX(${-containerRef.current?.scrollLeft || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 w-[50px] border-l border-slate-300 h-full flex flex-col justify-end pb-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pl-1">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
              <div className="absolute top-16 left-0 bottom-0 w-6 bg-white border-r border-slate-200 z-[150] flex flex-col items-center overflow-hidden">
                <div className="flex flex-col" style={{ transform: `translateY(${-containerRef.current?.scrollTop || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 h-[50px] border-t border-slate-300 w-full flex flex-row justify-end pr-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pt-1 vertical-text rotate-90">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}

          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
               <div className="h-full w-px bg-slate-200 mx-1" />
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border shadow-sm">
                  <span className="text-[10px] font-black text-slate-400 uppercase">Zoom</span>
                  <span className="text-[10px] font-black text-slate-900 w-10 text-center">{Math.round(zoom * 100)}%</span>
               </div>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible transition-none ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    if (!selectedElementIds.includes(el.id)) setSelectedElementIds([el.id]);
                    const activeIds = selectedElementIds.includes(el.id) ? selectedElementIds : [el.id];
                    setActionState({ 
                      ids: activeIds, startX: e.clientX, startY: e.clientY, 
                      initials: currentPage.elements.filter(x => activeIds.includes(x.id)).map(x => ({ id: x.id, x: x.x, y: x.y, w: x.width, h: x.height, r: x.styles.rotation || 0 }))
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle:h });
                }}
                onRotateStart={(e) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle: 'rot' });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{ left: Math.min(marquee.startX, marquee.currentX), top: Math.min(marquee.startY, marquee.currentY), width: Math.abs(marquee.startX - marquee.currentX), height: Math.abs(marquee.startY - marquee.currentY) }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-50 shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="p-6 border-b bg-slate-50 flex items-center justify-between sticky top-0 z-10">
               <h3 className="text-xs font-black text-[#E4002B] uppercase tracking-widest">Propiedades</h3>
               <button onClick={() => setSelectedElementIds([])} className="text-slate-400 hover:text-slate-900 transition-colors"><i className="fas fa-times"></i></button>
             </div>
             <div className="p-6 space-y-8 pb-32">
               {selectedElements.length === 1 && (
                 <>
                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                   </section>

                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Tipografía</label>
                     <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Courier New">Mono</option>
                        <option value="Pacifico">Script</option>
                     </select>
                     <div className="flex gap-2">
                        <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                        <div className="flex flex-1 border rounded-xl overflow-hidden">
                           {['left', 'center', 'right'].map(a => (
                              <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs transition-colors ${selectedElements[0].styles.textAlign === a ? 'bg-[#E4002B] text-white' : 'bg-white text-slate-400'}`}><i className={`fas fa-align-${a}`}></i></button>
                           ))}
                        </div>
                     </div>
                   </section>
                 </>
               )}

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo y Rotación</label>
                  <div className="space-y-4">
                    <div className="flex bg-slate-100 p-1 rounded-xl">
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                    </div>

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Ángulo de Rotación <span>{selectedElements[0].styles.rotation}°</span></label>
                       <input type="range" min="0" max="360" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.rotation || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { rotation: parseInt(e.target.value) } }))} />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Opacidad <span>{Math.round((selectedElements[0].styles.opacity || 1) * 100)}%</span></label>
                       <input type="range" min="0" max="1" step="0.05" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.opacity || 1} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { opacity: parseFloat(e.target.value) } }))} />
                    </div>
                  </div>
               </section>

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones</label>
                  <div className="space-y-4">
                     <div>
                        <span className="text-[9px] font-bold text-slate-400 uppercase mb-2 block">Entrada</span>
                        <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.entranceAnimation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: e.target.value as any } }))}>
                           <option value="none">Ninguna</option>
                           <option value="fade">Desvanecer</option>
                           <option value="slide">Deslizar</option>
                           <option value="zoom">Zoom</option>
                        </select>
                     </div>
                  </div>
               </section>
             </div>
             <div className="p-6 mt-auto bg-slate-50 border-t flex flex-col gap-2">
                <button onClick={handleDuplicateSelected} className="w-full py-4 bg-white text-slate-800 text-[10px] font-black uppercase rounded-xl border border-slate-200 hover:bg-slate-100 transition-all shadow-sm"><i className="fas fa-copy mr-2"></i> Duplicar Selección</button>
                <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 text-[#E4002B] text-[10px] font-black uppercase rounded-xl border border-red-200 hover:bg-red-100 transition-all"><i className="fas fa-trash-alt mr-2"></i> Eliminar ({selectedElements.length})</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground, GroupFolder } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30,
      y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newEls]
      }) : p)
    }));
    setSelectedElementIds(newEls.map(el => el.id));
  }, [selectedElements, currentPageIndex, currentPage.elements.length]);

  const handleDeleteSelected = useCallback(() => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    }));
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    const snap = (val: number) => showGrid ? Math.round(val / 10) * 10 : Math.round(val);

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;

      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;

      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      const finalAngle = Math.round((angle + 90) % 360);
      handleUpdateElement(target.id, { styles: { rotation: finalAngle } });
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { const cl = Math.min(dx, target.w - 10); newW = target.w - cl; newX = target.x + cl; }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { const cl = Math.min(dy, target.h - 10); newH = target.h - cl; newY = target.y + cl; }

      handleUpdateElement(target.id, { x: snap(newX), y: snap(newY), width: snap(newW), height: snap(newH) });
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: snap(init.x + dx), y: snap(init.y + dy) });
      });
    }
    requestRef.current = null;
  }, [actionState, zoom, handleUpdateElement, showGrid, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
      return;
    }
    if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = null;
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (isPreview) return;
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const scaleFactor = 1.1;
      const nextZoom = delta > 0 ? zoom * scaleFactor : zoom / scaleFactor;
      const clampedZoom = Math.min(Math.max(nextZoom, 0.1), 3);

      if (clampedZoom !== zoom && containerRef.current) {
        const container = containerRef.current;
        const rect = container.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        const scrollLeft = container.scrollLeft;
        const scrollTop = container.scrollTop;
        const worldX = (mouseX + scrollLeft) / zoom;
        const worldY = (mouseY + scrollTop) / zoom;
        const nextScrollLeft = (worldX * clampedZoom) - mouseX;
        const nextScrollTop = (worldY * clampedZoom) - mouseY;
        setZoom(clampedZoom);
        container.scrollLeft = nextScrollLeft;
        container.scrollTop = nextScrollTop;
      }
    }
  }, [zoom, isPreview]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  const rulerTicks = useMemo(() => {
    const ticks = [];
    for (let i = 0; i <= 2000; i += 50) ticks.push(i);
    return ticks;
  }, []);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 150, y: 150, width: type === 'shape' ? 150 : 250, height: type === 'shape' ? 150 : 60,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }, rotation: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ ...p, pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) }));
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}} canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage} selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject(prev => ({ ...prev, pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) }))}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              setProject(p => ({ ...p, pages: [...p.pages, newPage] }));
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-start items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef} onWheel={handleWheel}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {!isPreview && showRulers && (
            <>
              <div className="absolute top-0 left-16 right-0 h-6 bg-white border-b border-slate-200 z-[150] flex items-center overflow-hidden">
                <div className="flex" style={{ transform: `translateX(${-containerRef.current?.scrollLeft || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 w-[50px] border-l border-slate-300 h-full flex flex-col justify-end pb-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pl-1">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
              <div className="absolute top-16 left-0 bottom-0 w-6 bg-white border-r border-slate-200 z-[150] flex flex-col items-center overflow-hidden">
                <div className="flex flex-col" style={{ transform: `translateY(${-containerRef.current?.scrollTop || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 h-[50px] border-t border-slate-300 w-full flex flex-row justify-end pr-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pt-1 vertical-text rotate-90">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}

          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
               <div className="h-full w-px bg-slate-200 mx-1" />
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border shadow-sm">
                  <span className="text-[10px] font-black text-slate-400 uppercase">Zoom</span>
                  <span className="text-[10px] font-black text-slate-900 w-10 text-center">{Math.round(zoom * 100)}%</span>
               </div>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible transition-none ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    if (!selectedElementIds.includes(el.id)) setSelectedElementIds([el.id]);
                    const activeIds = selectedElementIds.includes(el.id) ? selectedElementIds : [el.id];
                    setActionState({ 
                      ids: activeIds, startX: e.clientX, startY: e.clientY, 
                      initials: currentPage.elements.filter(x => activeIds.includes(x.id)).map(x => ({ id: x.id, x: x.x, y: x.y, w: x.width, h: x.height, r: x.styles.rotation || 0 }))
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle:h });
                }}
                onRotateStart={(e) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle: 'rot' });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{ left: Math.min(marquee.startX, marquee.currentX), top: Math.min(marquee.startY, marquee.currentY), width: Math.abs(marquee.startX - marquee.currentX), height: Math.abs(marquee.startY - marquee.currentY) }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-50 shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="p-6 border-b bg-slate-50 flex items-center justify-between sticky top-0 z-10">
               <h3 className="text-xs font-black text-[#E4002B] uppercase tracking-widest">Propiedades</h3>
               <button onClick={() => setSelectedElementIds([])} className="text-slate-400 hover:text-slate-900 transition-colors"><i className="fas fa-times"></i></button>
             </div>
             <div className="p-6 space-y-8 pb-32">
               {selectedElements.length === 1 && (
                 <>
                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                   </section>

                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Tipografía</label>
                     <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Courier New">Mono</option>
                        <option value="Pacifico">Script</option>
                     </select>
                     <div className="flex gap-2">
                        <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                        <div className="flex flex-1 border rounded-xl overflow-hidden">
                           {['left', 'center', 'right'].map(a => (
                              <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs transition-colors ${selectedElements[0].styles.textAlign === a ? 'bg-[#E4002B] text-white' : 'bg-white text-slate-400'}`}><i className={`fas fa-align-${a}`}></i></button>
                           ))}
                        </div>
                     </div>
                   </section>
                 </>
               )}

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo y Rotación</label>
                  <div className="space-y-4">
                    <div className="flex bg-slate-100 p-1 rounded-xl">
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                    </div>

                    {selectedElements[0].styles.gradient?.enabled ? (
                      <div className="space-y-4 mt-2">
                        <div className="grid grid-cols-2 gap-2">
                           <input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, from: e.target.value } } }))} className="w-full h-8 cursor-pointer rounded overflow-hidden" />
                           <input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, to: e.target.value } } }))} className="w-full h-8 cursor-pointer rounded overflow-hidden" />
                        </div>
                        <div className="space-y-2">
                           <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Ángulo Degradado <span>{selectedElements[0].styles.gradient.angle}°</span></label>
                           <input type="range" min="0" max="360" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.gradient.angle} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, angle: parseInt(e.target.value) } } }))} />
                        </div>
                      </div>
                    ) : (
                      <input type="color" className="w-full h-10 border-none bg-transparent cursor-pointer" value={selectedElements[0].styles.backgroundColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} />
                    )}

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Ángulo de Rotación <span>{selectedElements[0].styles.rotation}°</span></label>
                       <input type="range" min="0" max="360" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.rotation || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { rotation: parseInt(e.target.value) } }))} />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Opacidad <span>{Math.round((selectedElements[0].styles.opacity || 1) * 100)}%</span></label>
                       <input type="range" min="0" max="1" step="0.05" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.opacity || 1} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { opacity: parseFloat(e.target.value) } }))} />
                    </div>
                  </div>
               </section>

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones</label>
                  <div className="space-y-4">
                     <div>
                        <span className="text-[9px] font-bold text-slate-400 uppercase mb-2 block">Entrada</span>
                        <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.entranceAnimation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: e.target.value as any } }))}>
                           <option value="none">Ninguna</option>
                           <option value="fade">Desvanecer</option>
                           <option value="slide">Deslizar</option>
                           <option value="zoom">Zoom</option>
                        </select>
                     </div>
                  </div>
               </section>
             </div>
             <div className="p-6 mt-auto bg-slate-50 border-t flex flex-col gap-2">
                <button onClick={handleDuplicateSelected} className="w-full py-4 bg-white text-slate-800 text-[10px] font-black uppercase rounded-xl border border-slate-200 hover:bg-slate-100 transition-all shadow-sm"><i className="fas fa-copy mr-2"></i> Duplicar Selección</button>
                <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 text-[#E4002B] text-[10px] font-black uppercase rounded-xl border border-red-200 hover:bg-red-100 transition-all"><i className="fas fa-trash-alt mr-2"></i> Eliminar ({selectedElements.length})</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground, GroupFolder } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30,
      y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newEls]
      }) : p)
    }));
    setSelectedElementIds(newEls.map(el => el.id));
  }, [selectedElements, currentPageIndex, currentPage.elements.length]);

  const handleDeleteSelected = useCallback(() => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    }));
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    const snap = (val: number) => showGrid ? Math.round(val / 10) * 10 : Math.round(val);

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;

      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;

      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      const finalAngle = Math.round((angle + 90) % 360);
      handleUpdateElement(target.id, { styles: { rotation: finalAngle } });
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { const cl = Math.min(dx, target.w - 10); newW = target.w - cl; newX = target.x + cl; }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { const cl = Math.min(dy, target.h - 10); newH = target.h - cl; newY = target.y + cl; }

      handleUpdateElement(target.id, { x: snap(newX), y: snap(newY), width: snap(newW), height: snap(newH) });
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: snap(init.x + dx), y: snap(init.y + dy) });
      });
    }
    requestRef.current = null;
  }, [actionState, zoom, handleUpdateElement, showGrid, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
      return;
    }
    if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = null;
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (isPreview) return;
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const scaleFactor = 1.1;
      const nextZoom = delta > 0 ? zoom * scaleFactor : zoom / scaleFactor;
      const clampedZoom = Math.min(Math.max(nextZoom, 0.1), 3);

      if (clampedZoom !== zoom && containerRef.current) {
        const container = containerRef.current;
        const rect = container.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        const scrollLeft = container.scrollLeft;
        const scrollTop = container.scrollTop;
        const worldX = (mouseX + scrollLeft) / zoom;
        const worldY = (mouseY + scrollTop) / zoom;
        const nextScrollLeft = (worldX * clampedZoom) - mouseX;
        const nextScrollTop = (worldY * clampedZoom) - mouseY;
        setZoom(clampedZoom);
        container.scrollLeft = nextScrollLeft;
        container.scrollTop = nextScrollTop;
      }
    }
  }, [zoom, isPreview]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  const rulerTicks = useMemo(() => {
    const ticks = [];
    for (let i = 0; i <= 2000; i += 50) ticks.push(i);
    return ticks;
  }, []);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 150, y: 150, width: type === 'shape' ? 150 : 250, height: type === 'shape' ? 150 : 60,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }, rotation: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ ...p, pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) }));
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}} canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage} selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject(prev => ({ ...prev, pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) }))}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              setProject(p => ({ ...p, pages: [...p.pages, newPage] }));
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-start items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef} onWheel={handleWheel}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {!isPreview && showRulers && (
            <>
              <div className="absolute top-0 left-16 right-0 h-6 bg-white border-b border-slate-200 z-[150] flex items-center overflow-hidden">
                <div className="flex" style={{ transform: `translateX(${-containerRef.current?.scrollLeft || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 w-[50px] border-l border-slate-300 h-full flex flex-col justify-end pb-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pl-1">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
              <div className="absolute top-16 left-0 bottom-0 w-6 bg-white border-r border-slate-200 z-[150] flex flex-col items-center overflow-hidden">
                <div className="flex flex-col" style={{ transform: `translateY(${-containerRef.current?.scrollTop || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 h-[50px] border-t border-slate-300 w-full flex flex-row justify-end pr-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pt-1 vertical-text rotate-90">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}

          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
               <div className="h-full w-px bg-slate-200 mx-1" />
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border shadow-sm">
                  <span className="text-[10px] font-black text-slate-400 uppercase">Zoom</span>
                  <span className="text-[10px] font-black text-slate-900 w-10 text-center">{Math.round(zoom * 100)}%</span>
               </div>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible transition-none ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    if (!selectedElementIds.includes(el.id)) setSelectedElementIds([el.id]);
                    const activeIds = selectedElementIds.includes(el.id) ? selectedElementIds : [el.id];
                    setActionState({ 
                      ids: activeIds, startX: e.clientX, startY: e.clientY, 
                      initials: currentPage.elements.filter(x => activeIds.includes(x.id)).map(x => ({ id: x.id, x: x.x, y: x.y, w: x.width, h: x.height, r: x.styles.rotation || 0 }))
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle:h });
                }}
                onRotateStart={(e) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle: 'rot' });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{ left: Math.min(marquee.startX, marquee.currentX), top: Math.min(marquee.startY, marquee.currentY), width: Math.abs(marquee.startX - marquee.currentX), height: Math.abs(marquee.startY - marquee.currentY) }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-50 shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="p-6 border-b bg-slate-50 flex items-center justify-between sticky top-0 z-10">
               <h3 className="text-xs font-black text-[#E4002B] uppercase tracking-widest">Propiedades</h3>
               <button onClick={() => setSelectedElementIds([])} className="text-slate-400 hover:text-slate-900 transition-colors"><i className="fas fa-times"></i></button>
             </div>
             <div className="p-6 space-y-8 pb-32">
               {selectedElements.length === 1 && (
                 <>
                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                   </section>

                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Tipografía</label>
                     <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Courier New">Mono</option>
                        <option value="Pacifico">Script</option>
                     </select>
                     <div className="flex gap-2">
                        <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                        <div className="flex flex-1 border rounded-xl overflow-hidden">
                           {['left', 'center', 'right'].map(a => (
                              <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs transition-colors ${selectedElements[0].styles.textAlign === a ? 'bg-[#E4002B] text-white' : 'bg-white text-slate-400'}`}><i className={`fas fa-align-${a}`}></i></button>
                           ))}
                        </div>
                     </div>
                   </section>
                 </>
               )}

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo y Rotación</label>
                  <div className="space-y-4">
                    <div className="flex bg-slate-100 p-1 rounded-xl">
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                    </div>

                    {selectedElements[0].styles.gradient?.enabled ? (
                      <div className="space-y-4 mt-2">
                        <div className="grid grid-cols-2 gap-2">
                           <input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, from: e.target.value } } }))} className="w-full h-8 cursor-pointer rounded overflow-hidden" />
                           <input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, to: e.target.value } } }))} className="w-full h-8 cursor-pointer rounded overflow-hidden" />
                        </div>
                        <div className="space-y-2">
                           <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Ángulo Degradado <span>{selectedElements[0].styles.gradient.angle}°</span></label>
                           <input type="range" min="0" max="360" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.gradient.angle} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, angle: parseInt(e.target.value) } } }))} />
                        </div>
                      </div>
                    ) : (
                      <input type="color" className="w-full h-10 border-none bg-transparent cursor-pointer" value={selectedElements[0].styles.backgroundColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} />
                    )}

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Ángulo de Rotación <span>{selectedElements[0].styles.rotation}°</span></label>
                       <input type="range" min="0" max="360" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.rotation || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { rotation: parseInt(e.target.value) } }))} />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Radio Borde <span>{selectedElements[0].styles.borderRadius || 0}px</span></label>
                       <input type="range" min="0" max="200" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.borderRadius || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderRadius: parseInt(e.target.value) } }))} />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Opacidad <span>{Math.round((selectedElements[0].styles.opacity || 1) * 100)}%</span></label>
                       <input type="range" min="0" max="1" step="0.05" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.opacity || 1} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { opacity: parseFloat(e.target.value) } }))} />
                    </div>
                  </div>
               </section>

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones</label>
                  <div className="space-y-4">
                     <div>
                        <span className="text-[9px] font-bold text-slate-400 uppercase mb-2 block">Entrada</span>
                        <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.entranceAnimation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: e.target.value as any } }))}>
                           <option value="none">Ninguna</option>
                           <option value="fade">Desvanecer</option>
                           <option value="slide">Deslizar</option>
                           <option value="zoom">Zoom</option>
                        </select>
                     </div>
                  </div>
               </section>
             </div>
             <div className="p-6 mt-auto bg-slate-50 border-t flex flex-col gap-2">
                <button onClick={handleDuplicateSelected} className="w-full py-4 bg-white text-slate-800 text-[10px] font-black uppercase rounded-xl border border-slate-200 hover:bg-slate-100 transition-all shadow-sm"><i className="fas fa-copy mr-2"></i> Duplicar Selección</button>
                <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 text-[#E4002B] text-[10px] font-black uppercase rounded-xl border border-red-200 hover:bg-red-100 transition-all"><i className="fas fa-trash-alt mr-2"></i> Eliminar ({selectedElements.length})</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground, GroupFolder } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);
  const [clipboard, setClipboard] = useState<CanvasElement[]>([]);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']> }) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: p.elements.map(el => el.id === id ? ({ 
          ...el, 
          ...updates, 
          styles: { ...el.styles, ...(updates.styles || {}) } 
        } as CanvasElement) : el)
      }) : p)
    }));
  }, [currentPageIndex]);

  const handleDeleteSelected = useCallback(() => {
    setProject(prev => ({ 
      ...prev, 
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    }));
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex]);

  const handleCopy = useCallback(() => {
    if (selectedElements.length === 0) return;
    setClipboard(JSON.parse(JSON.stringify(selectedElements)));
  }, [selectedElements]);

  const handleCut = useCallback(() => {
    if (selectedElements.length === 0) return;
    handleCopy();
    handleDeleteSelected();
  }, [selectedElements, handleCopy, handleDeleteSelected]);

  const handlePaste = useCallback(() => {
    if (clipboard.length === 0) return;

    // Calculate center of current canvas
    const centerX = currentDimensions.width / 2;
    const centerY = currentDimensions.height / 2;

    // Find bounding box of clipboard elements
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    clipboard.forEach(el => {
      minX = Math.min(minX, el.x);
      minY = Math.min(minY, el.y);
      maxX = Math.max(maxX, el.x + el.width);
      maxY = Math.max(maxY, el.y + el.height);
    });

    const cbWidth = maxX - minX;
    const cbHeight = maxY - minY;
    const offsetX = centerX - (minX + cbWidth / 2);
    const offsetY = centerY - (minY + cbHeight / 2);

    const newElements = clipboard.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + offsetX,
      y: el.y + offsetY,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));

    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newElements]
      }) : p)
    }));
    setSelectedElementIds(newElements.map(el => el.id));
  }, [clipboard, currentDimensions, currentPageIndex, currentPage.elements.length]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30,
      y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newEls]
      }) : p)
    }));
    setSelectedElementIds(newEls.map(el => el.id));
  }, [selectedElements, currentPageIndex, currentPage.elements.length]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    const snap = (val: number) => showGrid ? Math.round(val / 10) * 10 : Math.round(val);

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;

      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;

      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      const finalAngle = Math.round((angle + 90) % 360);
      handleUpdateElement(target.id, { styles: { rotation: finalAngle } });
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { const cl = Math.min(dx, target.w - 10); newW = target.w - cl; newX = target.x + cl; }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { const cl = Math.min(dy, target.h - 10); newH = target.h - cl; newY = target.y + cl; }

      handleUpdateElement(target.id, { x: snap(newX), y: snap(newY), width: snap(newW), height: snap(newH) });
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: snap(init.x + dx), y: snap(init.y + dy) });
      });
    }
    requestRef.current = null;
  }, [actionState, zoom, handleUpdateElement, showGrid, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
      return;
    }
    if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = null;
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (isPreview) return;
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const scaleFactor = 1.1;
      const nextZoom = delta > 0 ? zoom * scaleFactor : zoom / scaleFactor;
      const clampedZoom = Math.min(Math.max(nextZoom, 0.1), 3);

      if (clampedZoom !== zoom && containerRef.current) {
        const container = containerRef.current;
        const rect = container.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        const scrollLeft = container.scrollLeft;
        const scrollTop = container.scrollTop;
        const worldX = (mouseX + scrollLeft) / zoom;
        const worldY = (mouseY + scrollTop) / zoom;
        const nextScrollLeft = (worldX * clampedZoom) - mouseX;
        const nextScrollTop = (worldY * clampedZoom) - mouseY;
        setZoom(clampedZoom);
        container.scrollLeft = nextScrollLeft;
        container.scrollTop = nextScrollTop;
      }
    }
  }, [zoom, isPreview]);

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isPreview) return;

      // Don't trigger if user is typing in an input or textarea
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') return;

      const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
      const cmdKey = isMac ? e.metaKey : e.ctrlKey;

      if (cmdKey && e.key.toLowerCase() === 'c') {
        e.preventDefault();
        handleCopy();
      } else if (cmdKey && e.key.toLowerCase() === 'v') {
        e.preventDefault();
        handlePaste();
      } else if (cmdKey && e.key.toLowerCase() === 'x') {
        e.preventDefault();
        handleCut();
      } else if (cmdKey && e.key.toLowerCase() === 'd') {
        e.preventDefault();
        handleDuplicateSelected();
      } else if (e.key === 'Delete' || e.key === 'Backspace') {
        handleDeleteSelected();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPreview, handleCopy, handlePaste, handleCut, handleDuplicateSelected, handleDeleteSelected]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  const rulerTicks = useMemo(() => {
    const ticks = [];
    for (let i = 0; i <= 2000; i += 50) ticks.push(i);
    return ticks;
  }, []);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => setProject(p => ({ ...p, title }))}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 150, y: 150, width: type === 'shape' ? 150 : 250, height: type === 'shape' ? 150 : 60,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }, rotation: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject(p => ({ ...p, pages: p.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) }));
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}} canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage} selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject(prev => ({ ...prev, pages: prev.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) }))}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              setProject(p => ({ ...p, pages: [...p.pages, newPage] }));
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-start items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef} onWheel={handleWheel}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {!isPreview && showRulers && (
            <>
              <div className="absolute top-0 left-16 right-0 h-6 bg-white border-b border-slate-200 z-[150] flex items-center overflow-hidden">
                <div className="flex" style={{ transform: `translateX(${-containerRef.current?.scrollLeft || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 w-[50px] border-l border-slate-300 h-full flex flex-col justify-end pb-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pl-1">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
              <div className="absolute top-16 left-0 bottom-0 w-6 bg-white border-r border-slate-200 z-[150] flex flex-col items-center overflow-hidden">
                <div className="flex flex-col" style={{ transform: `translateY(${-containerRef.current?.scrollTop || 0}px)` }}>
                  {rulerTicks.map(t => (
                    <div key={t} className="flex-shrink-0 h-[50px] border-t border-slate-300 w-full flex flex-row justify-end pr-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pt-1 vertical-text rotate-90">{t % 100 === 0 ? t : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}

          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
               <div className="h-full w-px bg-slate-200 mx-1" />
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border shadow-sm">
                  <span className="text-[10px] font-black text-slate-400 uppercase">Zoom</span>
                  <span className="text-[10px] font-black text-slate-900 w-10 text-center">{Math.round(zoom * 100)}%</span>
               </div>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible transition-none ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    if (!selectedElementIds.includes(el.id)) setSelectedElementIds([el.id]);
                    const activeIds = selectedElementIds.includes(el.id) ? selectedElementIds : [el.id];
                    setActionState({ 
                      ids: activeIds, startX: e.clientX, startY: e.clientY, 
                      initials: currentPage.elements.filter(x => activeIds.includes(x.id)).map(x => ({ id: x.id, x: x.x, y: x.y, w: x.width, h: x.height, r: x.styles.rotation || 0 }))
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle:h });
                }}
                onRotateStart={(e) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle: 'rot' });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{ left: Math.min(marquee.startX, marquee.currentX), top: Math.min(marquee.startY, marquee.currentY), width: Math.abs(marquee.startX - marquee.currentX), height: Math.abs(marquee.startY - marquee.currentY) }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-50 shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="p-6 border-b bg-slate-50 flex items-center justify-between sticky top-0 z-10">
               <h3 className="text-xs font-black text-[#E4002B] uppercase tracking-widest">Propiedades</h3>
               <button onClick={() => setSelectedElementIds([])} className="text-slate-400 hover:text-slate-900 transition-colors"><i className="fas fa-times"></i></button>
             </div>
             <div className="p-6 space-y-8 pb-32">
               {selectedElements.length === 1 && (
                 <>
                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                   </section>

                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Tipografía</label>
                     <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                        <option value="Inter">Inter</option>
                        <option value="Arial">Arial</option>
                        <option value="Georgia">Georgia</option>
                        <option value="Courier New">Mono</option>
                        <option value="Pacifico">Script</option>
                     </select>
                     <div className="flex gap-2">
                        <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                        <div className="flex flex-1 border rounded-xl overflow-hidden">
                           {['left', 'center', 'right'].map(a => (
                              <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs transition-colors ${selectedElements[0].styles.textAlign === a ? 'bg-[#E4002B] text-white' : 'bg-white text-slate-400'}`}><i className={`fas fa-align-${a}`}></i></button>
                           ))}
                        </div>
                     </div>
                   </section>
                 </>
               )}

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo y Rotación</label>
                  <div className="space-y-4">
                    <div className="flex bg-slate-100 p-1 rounded-xl">
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                      <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                    </div>

                    {selectedElements[0].styles.gradient?.enabled ? (
                      <div className="space-y-4 mt-2">
                        <div className="grid grid-cols-2 gap-2">
                           <input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, from: e.target.value } } }))} className="w-full h-8 cursor-pointer rounded overflow-hidden" />
                           <input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, to: e.target.value } } }))} className="w-full h-8 cursor-pointer rounded overflow-hidden" />
                        </div>
                        <div className="space-y-2">
                           <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Ángulo Degradado <span>{selectedElements[0].styles.gradient.angle}°</span></label>
                           <input type="range" min="0" max="360" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.gradient.angle} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, angle: parseInt(e.target.value) } } }))} />
                        </div>
                      </div>
                    ) : (
                      <input type="color" className="w-full h-10 border-none bg-transparent cursor-pointer" value={selectedElements[0].styles.backgroundColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} />
                    )}

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Ángulo de Rotación <span>{selectedElements[0].styles.rotation}°</span></label>
                       <input type="range" min="0" max="360" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.rotation || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { rotation: parseInt(e.target.value) } }))} />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Radio Borde <span>{selectedElements[0].styles.borderRadius || 0}px</span></label>
                       <input type="range" min="0" max="200" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.borderRadius || 0} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderRadius: parseInt(e.target.value) } }))} />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[9px] font-bold text-slate-400 uppercase flex justify-between">Opacidad <span>{Math.round((selectedElements[0].styles.opacity || 1) * 100)}%</span></label>
                       <input type="range" min="0" max="1" step="0.05" className="w-full accent-[#E4002B]" value={selectedElements[0].styles.opacity || 1} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { opacity: parseFloat(e.target.value) } }))} />
                    </div>
                  </div>
               </section>

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Acciones</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button onClick={handleCopy} className="py-2 bg-slate-100 text-[9px] font-black uppercase rounded-lg border hover:bg-slate-200 transition-all"><i className="fas fa-copy mr-2"></i> Copiar</button>
                    <button onClick={handleCut} className="py-2 bg-slate-100 text-[9px] font-black uppercase rounded-lg border hover:bg-slate-200 transition-all"><i className="fas fa-cut mr-2"></i> Cortar</button>
                    <button onClick={handleDuplicateSelected} className="py-2 bg-slate-100 text-[9px] font-black uppercase rounded-lg border hover:bg-slate-200 transition-all"><i className="fas fa-clone mr-2"></i> Duplicar</button>
                    <button onClick={handleDeleteSelected} className="py-2 bg-red-50 text-[9px] font-black uppercase rounded-lg border border-red-100 text-[#E4002B] hover:bg-red-100 transition-all"><i className="fas fa-trash mr-2"></i> Borrar</button>
                  </div>
                  {clipboard.length > 0 && (
                    <button onClick={handlePaste} className="w-full py-3 bg-[#E4002B] text-white text-[9px] font-black uppercase rounded-lg shadow-lg hover:bg-[#c40024] transition-all"><i className="fas fa-paste mr-2"></i> Pegar elementos ({clipboard.length})</button>
                  )}
               </section>

               <section className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones</label>
                  <div className="space-y-4">
                     <div>
                        <span className="text-[9px] font-bold text-slate-400 uppercase mb-2 block">Entrada</span>
                        <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.entranceAnimation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: e.target.value as any } }))}>
                           <option value="none">Ninguna</option>
                           <option value="fade">Desvanecer</option>
                           <option value="slide">Deslizar</option>
                           <option value="zoom">Zoom</option>
                        </select>
                     </div>
                  </div>
               </section>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [history, setHistory] = useState<Project[]>([INITIAL_PROJECT]);
  const [historyIndex, setHistoryIndex] = useState(0);

  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);
  const [clipboard, setClipboard] = useState<CanvasElement[]>([]);
  const [activePropertyTab, setActivePropertyTab] = useState<'design' | 'interact'>('design');

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const isInternalChange = useRef(false);

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  // History Management
  const pushToHistory = useCallback((newProject: Project) => {
    if (isInternalChange.current) return;
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newProject)));
    // Limit history size to 50
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  const undo = useCallback(() => {
    if (historyIndex > 0) {
      isInternalChange.current = true;
      const prevProject = history[historyIndex - 1];
      setProject(JSON.parse(JSON.stringify(prevProject)));
      setHistoryIndex(historyIndex - 1);
      setTimeout(() => isInternalChange.current = false, 50);
    }
  }, [history, historyIndex]);

  const redo = useCallback(() => {
    if (historyIndex < history.length - 1) {
      isInternalChange.current = true;
      const nextProject = history[historyIndex + 1];
      setProject(JSON.parse(JSON.stringify(nextProject)));
      setHistoryIndex(historyIndex + 1);
      setTimeout(() => isInternalChange.current = false, 50);
    }
  }, [history, historyIndex]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']>, interactivity?: Partial<CanvasElement['interactivity']> }, silent = false) => {
    setProject(prev => {
      const next = {
        ...prev,
        pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
          ...p,
          elements: p.elements.map(el => el.id === id ? ({ 
            ...el, 
            ...updates, 
            styles: { ...el.styles, ...(updates.styles || {}) },
            interactivity: { ...el.interactivity, ...(updates.interactivity || {}) }
          } as CanvasElement) : el)
        }) : p)
      };
      if (!silent) pushToHistory(next);
      return next;
    });
  }, [currentPageIndex, pushToHistory]);

  const handleDeleteSelected = useCallback(() => {
    const next = { 
      ...project, 
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex, project, pushToHistory]);

  const handleCopy = useCallback(() => {
    if (selectedElements.length === 0) return;
    setClipboard(JSON.parse(JSON.stringify(selectedElements)));
  }, [selectedElements]);

  const handleCut = useCallback(() => {
    if (selectedElements.length === 0) return;
    handleCopy();
    handleDeleteSelected();
  }, [selectedElements, handleCopy, handleDeleteSelected]);

  const handlePaste = useCallback(() => {
    if (clipboard.length === 0) return;
    const centerX = currentDimensions.width / 2;
    const centerY = currentDimensions.height / 2;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    clipboard.forEach(el => {
      minX = Math.min(minX, el.x); minY = Math.min(minY, el.y);
      maxX = Math.max(maxX, el.x + el.width); maxY = Math.max(maxY, el.y + el.height);
    });
    const offsetX = centerX - (minX + (maxX - minX) / 2);
    const offsetY = centerY - (minY + (maxY - minY) / 2);

    const newElements = clipboard.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + offsetX,
      y: el.y + offsetY,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));

    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newElements]
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newElements.map(el => el.id));
  }, [clipboard, currentDimensions, currentPageIndex, currentPage.elements.length, project, pushToHistory]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30,
      y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newEls]
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newEls.map(el => el.id));
  }, [selectedElements, currentPageIndex, currentPage.elements.length, project, pushToHistory]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;
    const snap = (val: number) => showGrid ? Math.round(val / 10) * 10 : Math.round(val);

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;
      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      const finalAngle = Math.round((angle + 90) % 360);
      handleUpdateElement(target.id, { styles: { rotation: finalAngle } }, true);
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;
      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { const cl = Math.min(dx, target.w - 10); newW = target.w - cl; newX = target.x + cl; }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { const cl = Math.min(dy, target.h - 10); newH = target.h - cl; newY = target.y + cl; }
      handleUpdateElement(target.id, { x: snap(newX), y: snap(newY), width: snap(newW), height: snap(newH) }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: snap(init.x + dx), y: snap(init.y + dy) }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, zoom, handleUpdateElement, showGrid, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    } else if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) {
      pushToHistory(project);
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = null;
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom, project, pushToHistory, actionState]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (isPreview) return;
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const nextZoom = delta > 0 ? zoom * 1.1 : zoom / 1.1;
      setZoom(Math.min(Math.max(nextZoom, 0.1), 3));
    }
  }, [zoom, isPreview]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isPreview) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') return;
      const cmd = navigator.platform.toUpperCase().indexOf('MAC') >= 0 ? e.metaKey : e.ctrlKey;

      if (cmd && e.key.toLowerCase() === 'z') { e.preventDefault(); e.shiftKey ? redo() : undo(); }
      else if (cmd && e.key.toLowerCase() === 'y') { e.preventDefault(); redo(); }
      else if (cmd && e.key.toLowerCase() === 'c') { e.preventDefault(); handleCopy(); }
      else if (cmd && e.key.toLowerCase() === 'v') { e.preventDefault(); handlePaste(); }
      else if (cmd && e.key.toLowerCase() === 'x') { e.preventDefault(); handleCut(); }
      else if (cmd && e.key.toLowerCase() === 'd') { e.preventDefault(); handleDuplicateSelected(); }
      else if (e.key === 'Delete' || e.key === 'Backspace') { e.preventDefault(); handleDeleteSelected(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPreview, handleCopy, handlePaste, handleCut, handleDuplicateSelected, handleDeleteSelected, undo, redo]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => {
          const next = { ...project, title };
          setProject(next);
          pushToHistory(next);
        }}
        onUndo={undo} onRedo={redo}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 150, y: 150, width: type === 'shape' ? 150 : 250, height: type === 'shape' ? 150 : 60,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }, rotation: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              const next = { ...project, pages: project.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) };
              setProject(next);
              pushToHistory(next);
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}} canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage} selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => {
              const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) };
              setProject(next);
              pushToHistory(next);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              const next = { ...project, pages: [...project.pages, newPage] };
              setProject(next);
              pushToHistory(next);
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-start items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef} onWheel={handleWheel}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {!isPreview && showRulers && (
             <div className="absolute top-0 left-16 right-0 h-6 bg-white border-b border-slate-200 z-[150] flex items-center overflow-hidden">
                <div className="flex" style={{ transform: `translateX(${-containerRef.current?.scrollLeft || 0}px)` }}>
                  {Array.from({length: 40}).map((_, i) => (
                    <div key={i} className="flex-shrink-0 w-[50px] border-l border-slate-300 h-full flex flex-col justify-end pb-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pl-1">{(i * 50) % 100 === 0 ? i * 50 : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
          )}

          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
               <div className="h-full w-px bg-slate-200 mx-1" />
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border shadow-sm">
                  <span className="text-[10px] font-black text-slate-400 uppercase">Zoom</span>
                  <span className="text-[10px] font-black text-slate-900 w-10 text-center">{Math.round(zoom * 100)}%</span>
               </div>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible transition-none ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    setSelectedElementIds([el.id]);
                    setActionState({ 
                      ids: [el.id], startX: e.clientX, startY: e.clientY, 
                      initials: [{ id: el.id, x: el.x, y: el.y, w: el.width, h: el.height, r: el.styles.rotation || 0 }]
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle:h });
                }}
                onRotateStart={(e) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle: 'rot' });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{ 
                  left: Math.min(marquee.startX, marquee.currentX), 
                  top: Math.min(marquee.startY, marquee.currentY), 
                  width: Math.abs(marquee.startX - marquee.currentX), 
                  height: Math.abs(marquee.startY - marquee.currentY) 
                }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-[300] shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="flex bg-slate-50 border-b">
                <button 
                  onClick={() => setActivePropertyTab('design')}
                  className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activePropertyTab === 'design' ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Diseño
                </button>
                <button 
                  onClick={() => setActivePropertyTab('interact')}
                  className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activePropertyTab === 'interact' ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Interacción
                </button>
             </div>

             <div className="p-6 space-y-8 pb-32">
               {activePropertyTab === 'design' ? (
                 <>
                   {selectedElements.length === 1 && (
                     <section className="space-y-3">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                       <textarea 
                        className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" 
                        value={selectedElements[0].content} 
                        onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} 
                       />
                       {selectedElements[0].type === 'text' && (
                         <div className="space-y-3 mt-3">
                           <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                              <option value="Inter">Inter</option>
                              <option value="Arial">Arial</option>
                              <option value="Pacifico">Pacifico (Script)</option>
                           </select>
                           <div className="flex gap-2">
                              <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                              <div className="flex flex-1 border rounded-xl overflow-hidden">
                                 {['left', 'center', 'right'].map(a => (
                                    <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs transition-colors ${selectedElements[0].styles.textAlign === a ? 'bg-[#E4002B] text-white' : 'bg-white text-slate-400'}`}><i className={`fas fa-align-${a}`}></i></button>
                                 ))}
                              </div>
                           </div>
                         </div>
                       )}
                     </section>
                   )}

                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo Visual</label>
                      <div className="space-y-4">
                        <div className="flex bg-slate-100 p-1 rounded-xl">
                          <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                          <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                        </div>

                        {selectedElements[0].styles.gradient?.enabled ? (
                          <div className="space-y-3">
                             <div className="flex gap-2">
                                <input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, from: e.target.value } } }))} className="flex-1 h-8 rounded border-none cursor-pointer" />
                                <input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, to: e.target.value } } }))} className="flex-1 h-8 rounded border-none cursor-pointer" />
                             </div>
                             <input type="range" min="0" max="360" value={selectedElements[0].styles.gradient.angle} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, angle: parseInt(e.target.value) } } }))} className="w-full accent-[#E4002B]" />
                          </div>
                        ) : (
                          <div className="flex items-center gap-4 bg-slate-50 p-3 rounded-xl border">
                             <input type="color" value={selectedElements[0].styles.backgroundColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} className="w-10 h-10 rounded-full border-2 border-white cursor-pointer shadow-sm" />
                             <span className="text-[10px] font-bold text-slate-500 uppercase">Color de fondo</span>
                          </div>
                        )}

                        <div className="grid grid-cols-2 gap-4">
                           <div className="space-y-1">
                              <label className="text-[9px] font-bold text-slate-400 uppercase">Radio ({selectedElements[0].styles.borderRadius}px)</label>
                              <input type="range" min="0" max="100" value={selectedElements[0].styles.borderRadius} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderRadius: parseInt(e.target.value) } }))} className="w-full accent-[#E4002B]" />
                           </div>
                           <div className="space-y-1">
                              <label className="text-[9px] font-bold text-slate-400 uppercase">Rotación ({selectedElements[0].styles.rotation}°)</label>
                              <input type="range" min="0" max="360" value={selectedElements[0].styles.rotation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { rotation: parseInt(e.target.value) } }))} className="w-full accent-[#E4002B]" />
                           </div>
                        </div>
                      </div>
                   </section>
                 </>
               ) : (
                 <>
                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Interactividad</label>
                      <div className="space-y-3">
                         <label className="text-[9px] font-bold text-slate-500 uppercase">Tipo de Acción</label>
                         <select 
                            className="w-full bg-slate-50 border rounded-xl text-xs py-2.5 px-3 outline-none focus:ring-1 focus:ring-[#E4002B]"
                            value={selectedElements[0].interactivity.type}
                            onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { type: e.target.value as InteractivityType } })}
                         >
                            <option value={InteractivityType.NONE}>Ninguna</option>
                            <option value={InteractivityType.EXTERNAL_LINK}>Abrir Enlace Externo</option>
                            <option value={InteractivityType.GOTO_PAGE}>Ir a Página</option>
                         </select>

                         {selectedElements[0].interactivity.type !== InteractivityType.NONE && (
                           <input 
                              placeholder={selectedElements[0].interactivity.type === InteractivityType.GOTO_PAGE ? "Nombre o ID de página" : "https://ejemplo.com"}
                              className="w-full bg-white border rounded-xl text-xs py-2.5 px-4 outline-none focus:border-[#E4002B]"
                              value={selectedElements[0].interactivity.value}
                              onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { value: e.target.value } })}
                           />
                         )}
                      </div>
                   </section>

                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones</label>
                      <div className="space-y-6">
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Entrada</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'fade', 'slide', 'zoom'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.entranceAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Al pasar el ratón (Hover)</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'pop', 'lift'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { hoverAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.hoverAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                      </div>
                   </section>
                 </>
               )}
             </div>

             <div className="p-6 mt-auto bg-slate-50 border-t flex flex-col gap-2">
                <div className="grid grid-cols-2 gap-2 mb-2">
                  <button onClick={handleCopy} className="py-2 bg-white text-[9px] font-black uppercase border rounded hover:bg-slate-50"><i className="fas fa-copy mr-1"></i> Copiar</button>
                  <button onClick={handlePaste} className="py-2 bg-white text-[9px] font-black uppercase border rounded hover:bg-slate-50 disabled:opacity-30" disabled={clipboard.length === 0}><i className="fas fa-paste mr-1"></i> Pegar</button>
                </div>
                <button onClick={handleDuplicateSelected} className="w-full py-4 bg-white text-slate-800 text-[10px] font-black uppercase rounded-xl border border-slate-200 hover:bg-slate-100 transition-all shadow-sm"><i className="fas fa-clone mr-2"></i> Duplicar Selección</button>
                <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 text-[#E4002B] text-[10px] font-black uppercase rounded-xl border border-red-200 hover:bg-red-100 transition-all"><i className="fas fa-trash-alt mr-2"></i> Eliminar ({selectedElements.length})</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React from 'react';
import { CanvasElement } from '../types';

interface ToolbarProps {
  selectedElement: CanvasElement | null;
  onPreview: () => void;
  onPublish: () => void;
  isPreview: boolean;
  projectTitle: string;
  onUpdateTitle: (title: string) => void;
  onUndo: () => void;
  onRedo: () => void;
  canUndo: boolean;
  canRedo: boolean;
}

