  onPreview, onPublish, isPreview, projectTitle, onUpdateTitle, onUndo, onRedo, canUndo, canRedo
}) => {
  return (
    <div className={`h-14 flex items-center justify-between px-6 transition-all duration-300 shadow-sm z-[200] ${isPreview ? 'bg-white border-b' : 'bg-[#1e1e28] border-b border-slate-800'}`}>
      <div className="flex items-center gap-6">
        <div className="flex items-center gap-4 pr-6 border-r border-white/10">
           <div className="w-8 h-8 flex items-center justify-center bg-[#E4002B] rounded-full text-white shadow-lg">
              <i className="fas fa-bolt text-xs"></i>
           </div>
           <div className="flex flex-col">
              <span className="text-[10px] font-black text-white uppercase tracking-widest leading-none mb-1">Creative Studio</span>
              <div className="flex items-center gap-2">
                 <input 
                    className="bg-transparent border-none text-[8px] font-black text-white hover:bg-white/5 rounded px-1 outline-none focus:ring-1 focus:ring-[#E4002B] w-40" 
                    value={projectTitle}
                    onChange={(e) => onUpdateTitle(e.target.value)}
                 />
              </div>
           </div>
        </div>

        {!isPreview && (
          <div className="flex items-center gap-1">
             <button 
              onClick={onUndo} 
              disabled={!canUndo}
              className={`w-8 h-8 rounded flex items-center justify-center transition-all ${canUndo ? 'text-white hover:bg-white/10' : 'text-slate-700 opacity-30 cursor-not-allowed'}`}
              title="Deshacer (Ctrl+Z)"
             >
                <i className="fas fa-undo text-xs"></i>
             </button>
             <button 
              onClick={onRedo} 
              disabled={!canRedo}
              className={`w-8 h-8 rounded flex items-center justify-center transition-all ${canRedo ? 'text-white hover:bg-white/10' : 'text-slate-700 opacity-30 cursor-not-allowed'}`}
              title="Rehacer (Ctrl+Y)"
             >
                <i className="fas fa-redo text-xs"></i>
             </button>
          </div>
        )}
      </div>

      <div className="flex items-center gap-3">
        <button 
          onClick={onPreview} 
          className={`flex items-center gap-2 px-5 py-2 rounded-full transition-all text-[9px] font-black uppercase tracking-widest ${isPreview ? 'bg-[#E4002B] text-white shadow-lg' : 'bg-white/5 text-slate-400 hover:text-white border border-white/10'}`}
        >
          <i className={`fas ${isPreview ? 'fa-pencil' : 'fa-play'}`}></i>
          {isPreview ? 'Volver al Editor' : 'Vista Previa'}
        </button>

        <button 
          onClick={onPublish}
          className="bg-[#E4002B] text-white px-6 py-2 rounded-full text-[9px] font-black uppercase tracking-widest hover:bg-[#c40024] shadow-lg transition-all flex items-center gap-2 active:scale-95"
        >
          Publicar <i className="fas fa-cloud-arrow-up text-[8px]"></i>
        </button>
      </div>
    </div>
  );
};

export default Toolbar;

export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'fade' | 'slide' | 'zoom' | 'pop' | 'lift' | 'back' | 'squish' | 'vibrate' | 'exit-fade' | 'exit-zoom';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentación (16:9)' },
  square: { width: 600, height: 600, label: 'Cuadrado (1:1)' },
  vertical: { width: 400, height: 711, label: 'Móvil (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Vertical' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  groupId?: string;
  styles: {
    backgroundColor?: string;
    gradient?: {
      enabled: boolean;
      from: string;
      to: string;
      angle: number;
    };
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    rotation?: number;
    borderWidth?: number;
    borderColor?: string;
    shadowBlur?: number;
    shadowColor?: string;
    glowBlur?: number;
    glowColor?: string;
    // Animaciones
    hoverAnimation?: AnimationType;
    entranceAnimation?: AnimationType;
    exitAnimation?: AnimationType;
    clickAnimation?: AnimationType;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
  };
}

export interface GroupFolder {
  id: string;
  name: string;
  isOpen: boolean;
  elementIds: string[];
}

export interface PageBackground {
  type: 'color' | 'gradient' | 'image';
  value: string;
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
  groups: GroupFolder[];
  background?: PageBackground;
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
  canvasPreset: CanvasPreset;
}

import React, { useState, useEffect, useMemo } from 'react';
import { CanvasElement, InteractivityType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onResizeStart: (e: React.MouseEvent, handle: string) => void;
  onRotateStart?: (e: React.MouseEvent) => void;
  isPreview?: boolean;
  onNavigate?: (target: string | number) => void;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ element, isSelected, onSelect, onResizeStart, onRotateStart, isPreview, onNavigate }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isClicked, setIsClicked] = useState(false);
  const [showEntrance, setShowEntrance] = useState(false);

  useEffect(() => {
    setShowEntrance(true);
  }, []);

  const getStyle = (): React.CSSProperties => {
    const s = element.styles;
    const background = s.gradient?.enabled 
      ? `linear-gradient(${s.gradient.angle}deg, ${s.gradient.from} 0%, ${s.gradient.to} 100%)` 
      : s.backgroundColor;

    const shadow = s.shadowBlur ? `0 ${s.shadowBlur / 2}px ${s.shadowBlur}px ${s.shadowColor || 'rgba(0,0,0,0.2)'}` : 'none';
    const glow = s.glowBlur ? `0 0 ${s.glowBlur}px ${s.glowColor || s.backgroundColor}` : 'none';

    return {
      position: 'absolute',
      left: element.x,
      top: element.y,
      width: element.width,
      height: element.height,
      zIndex: s.zIndex,
      background,
      color: s.color,
      fontSize: s.fontSize,
      borderRadius: `${s.borderRadius || 0}px`,
      fontFamily: s.fontFamily || 'Inter',
      textAlign: s.textAlign,
      opacity: s.opacity,
      border: s.borderWidth ? `${s.borderWidth}px solid ${s.borderColor || '#000'}` : 'none',
      boxShadow: `${shadow}${s.glowBlur ? ', ' + glow : ''}`,
      display: 'flex',
      alignItems: 'center',
      justifyContent: s.textAlign === 'center' ? 'center' : (s.textAlign === 'right' ? 'flex-end' : 'flex-start'),
      transition: isPreview ? 'transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275), opacity 0.3s' : 'none',
      transform: `rotate(${s.rotation || 0}deg) ${isPreview && isHovered && s.hoverAnimation === 'pop' ? 'scale(1.08)' : ''} ${isPreview && isHovered && s.hoverAnimation === 'lift' ? 'translateY(-8px)' : ''}`,
      clipPath: element.type === 'shape' ? getClipPath(element.content) : 'none',
      cursor: isPreview ? (element.interactivity.type !== InteractivityType.NONE ? 'pointer' : 'default') : 'move',
      pointerEvents: isPreview && element.interactivity.type === InteractivityType.NONE && !element.styles.hoverAnimation ? 'none' : 'auto'
    };
  };

  const animationClass = useMemo(() => {
    let classes = [];
    if (showEntrance) {
      if (element.styles.entranceAnimation && element.styles.entranceAnimation !== 'none') {
        classes.push(`anim-entrance-${element.styles.entranceAnimation}`);
      }
    } else {
      classes.push('opacity-0');
    }

    if (isClicked && element.styles.clickAnimation && element.styles.clickAnimation !== 'none') {
      classes.push(`anim-click-${element.styles.clickAnimation}`);
    }

    return classes.join(' ');
  }, [showEntrance, isClicked, element.styles.entranceAnimation, element.styles.clickAnimation]);

  const handleInteraction = (e: React.MouseEvent) => {
    if (!isPreview) return;

    // Activar animación de click
    setIsClicked(true);
    setTimeout(() => setIsClicked(false), 200);

    switch (element.interactivity.type) {
      case InteractivityType.EXTERNAL_LINK: 
        window.open(element.interactivity.value, '_blank'); 
        break;
      case InteractivityType.GOTO_PAGE: 
        onNavigate?.(element.interactivity.value); 
        break;
    }
  };

  const displayContent = () => {
    if (element.type === 'shape') {
      // No mostrar el nombre de la forma como texto
      return (element.content === 'square' || element.content === 'circle' || element.content === 'triangle' || element.content === 'star' || element.content === 'diamond' || element.content === 'heart') ? '' : element.content;
    }
    return element.content;
  };

  return (
    <div
      style={getStyle()}
      onMouseDown={(e) => {
        if (!isPreview) onSelect(e);
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleInteraction}
      className={`${isSelected && !isPreview ? 'ring-2 ring-[#E4002B] ring-offset-4' : ''} ${animationClass}`}
    >
      {element.type === 'image' ? (
        <img src={element.content} className="w-full h-full object-contain pointer-events-none" alt="" />
      ) : (
        <span className="w-full px-4 break-words pointer-events-none select-none">{displayContent()}</span>
      )}

      {isSelected && !isPreview && (
        <>
          {['tl', 'tr', 'bl', 'br'].map(h => (
            <div 
              key={h} 
              onMouseDown={(e) => { e.stopPropagation(); onResizeStart(e, h); }} 
              className="absolute w-3 h-3 bg-white border-2 border-[#E4002B] rounded-full z-[120] shadow-sm" 
              style={getHandleStyle(h)} 
            />
          ))}
          <div 
            onMouseDown={(e) => { e.stopPropagation(); onRotateStart?.(e); }} 
            className="absolute -top-10 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-2 border-[#E4002B] rounded-full z-[120] flex items-center justify-center cursor-alias shadow-lg hover:scale-110 transition-transform"
          >
             <i className="fas fa-redo text-[10px] text-[#E4002B]"></i>
             <div className="absolute top-6 left-1/2 -translate-x-1/2 w-px h-4 bg-[#E4002B]" />
          </div>
        </>
      )}
    </div>
  );
};

function getClipPath(shape: string) {
  switch (shape) {
    case 'circle': return 'circle(50% at 50% 50%)';
    case 'triangle': return 'polygon(50% 0%, 0% 100%, 100% 100%)';
    case 'star': return 'polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%)';
    case 'diamond': return 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)';
    case 'heart': return 'path("M 10,30 A 20,20 0,0,1 50,30 A 20,20 0,0,1 90,30 Q 90,60 50,90 Q 10,60 10,30 Z")';
    default: return 'none';
  }
}

function getHandleStyle(h: string): React.CSSProperties {
  const o = '-6px';
  switch (h) {
    case 'tl': return { top: o, left: o, cursor: 'nwse-resize' };
    case 'tr': return { top: o, right: o, cursor: 'nesw-resize' };
    case 'bl': return { bottom: o, left: o, cursor: 'nesw-resize' };
    case 'br': return { bottom: o, right: o, cursor: 'nwse-resize' };
    default: return {};
  }
}

export default ElementRenderer;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [history, setHistory] = useState<Project[]>([INITIAL_PROJECT]);
  const [historyIndex, setHistoryIndex] = useState(0);

  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);
  const [clipboard, setClipboard] = useState<CanvasElement[]>([]);
  const [activePropertyTab, setActivePropertyTab] = useState<'design' | 'interact'>('design');

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const isInternalChange = useRef(false);

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const pushToHistory = useCallback((newProject: Project) => {
    if (isInternalChange.current) return;
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newProject)));
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  const undo = useCallback(() => {
    if (historyIndex > 0) {
      isInternalChange.current = true;
      const prevProject = history[historyIndex - 1];
      setProject(JSON.parse(JSON.stringify(prevProject)));
      setHistoryIndex(historyIndex - 1);
      setTimeout(() => isInternalChange.current = false, 50);
    }
  }, [history, historyIndex]);

  const redo = useCallback(() => {
    if (historyIndex < history.length - 1) {
      isInternalChange.current = true;
      const nextProject = history[historyIndex + 1];
      setProject(JSON.parse(JSON.stringify(nextProject)));
      setHistoryIndex(historyIndex + 1);
      setTimeout(() => isInternalChange.current = false, 50);
    }
  }, [history, historyIndex]);

  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles'>> & { styles?: Partial<CanvasElement['styles']>, interactivity?: Partial<CanvasElement['interactivity']> }, silent = false) => {
    setProject(prev => {
      const next = {
        ...prev,
        pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
          ...p,
          elements: p.elements.map(el => el.id === id ? ({ 
            ...el, 
            ...updates, 
            styles: { ...el.styles, ...(updates.styles || {}) },
            interactivity: { ...el.interactivity, ...(updates.interactivity || {}) }
          } as CanvasElement) : el)
        }) : p)
      };
      if (!silent) pushToHistory(next);
      return next;
    });
  }, [currentPageIndex, pushToHistory]);

  const handleDeleteSelected = useCallback(() => {
    const next = { 
      ...project, 
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex, project, pushToHistory]);

  const handleCopy = useCallback(() => {
    if (selectedElements.length === 0) return;
    setClipboard(JSON.parse(JSON.stringify(selectedElements)));
  }, [selectedElements]);

  const handleCut = useCallback(() => {
    if (selectedElements.length === 0) return;
    handleCopy();
    handleDeleteSelected();
  }, [selectedElements, handleCopy, handleDeleteSelected]);

  const handlePaste = useCallback(() => {
    if (clipboard.length === 0) return;
    const centerX = currentDimensions.width / 2;
    const centerY = currentDimensions.height / 2;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    clipboard.forEach(el => {
      minX = Math.min(minX, el.x); minY = Math.min(minY, el.y);
      maxX = Math.max(maxX, el.x + el.width); maxY = Math.max(maxY, el.y + el.height);
    });
    const offsetX = centerX - (minX + (maxX - minX) / 2);
    const offsetY = centerY - (minY + (maxY - minY) / 2);

    const newElements = clipboard.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + offsetX,
      y: el.y + offsetY,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));

    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newElements]
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newElements.map(el => el.id));
  }, [clipboard, currentDimensions, currentPageIndex, currentPage.elements.length, project, pushToHistory]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30,
      y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newEls]
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newEls.map(el => el.id));
  }, [selectedElements, currentPageIndex, currentPage.elements.length, project, pushToHistory]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    // Snapping refinado: 5px con grid, 1px sin grid
    const snap = (val: number) => showGrid ? Math.round(val / 5) * 5 : Math.round(val);

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;
      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      const finalAngle = Math.round((angle + 90) % 360);
      handleUpdateElement(target.id, { styles: { rotation: finalAngle } }, true);
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { 
        const constrainedDx = Math.min(dx, target.w - 10);
        newW = target.w - constrainedDx; 
        newX = target.x + constrainedDx; 
      }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { 
        const constrainedDy = Math.min(dy, target.h - 10);
        newH = target.h - constrainedDy; 
        newY = target.y + constrainedDy; 
      }

      handleUpdateElement(target.id, { 
        x: snap(newX), 
        y: snap(newY), 
        width: snap(newW), 
        height: snap(newH) 
      }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { 
          x: snap(init.x + dx), 
          y: snap(init.y + dy) 
        }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, zoom, handleUpdateElement, showGrid, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    } else if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) {
      pushToHistory(project);
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = null;
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom, project, pushToHistory, actionState]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (isPreview) return;
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const nextZoom = delta > 0 ? zoom * 1.1 : zoom / 1.1;
      setZoom(Math.min(Math.max(nextZoom, 0.1), 3));
    }
  }, [zoom, isPreview]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isPreview) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') return;
      const cmd = navigator.platform.toUpperCase().indexOf('MAC') >= 0 ? e.metaKey : e.ctrlKey;

      if (cmd && e.key.toLowerCase() === 'z') { e.preventDefault(); e.shiftKey ? redo() : undo(); }
      else if (cmd && e.key.toLowerCase() === 'y') { e.preventDefault(); redo(); }
      else if (cmd && e.key.toLowerCase() === 'c') { e.preventDefault(); handleCopy(); }
      else if (cmd && e.key.toLowerCase() === 'v') { e.preventDefault(); handlePaste(); }
      else if (cmd && e.key.toLowerCase() === 'x') { e.preventDefault(); handleCut(); }
      else if (cmd && e.key.toLowerCase() === 'd') { e.preventDefault(); handleDuplicateSelected(); }
      else if (e.key === 'Delete' || e.key === 'Backspace') { e.preventDefault(); handleDeleteSelected(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPreview, handleCopy, handlePaste, handleCut, handleDuplicateSelected, handleDeleteSelected, undo, redo]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => {
          const next = { ...project, title };
          setProject(next);
          pushToHistory(next);
        }}
        onUndo={undo} onRedo={redo}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 150, y: 150, width: type === 'shape' ? 150 : 250, height: type === 'shape' ? 150 : 60,
                // Limpiar contenido por defecto para formas
                content: content || (type === 'text' ? 'Escribe aquí' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }, rotation: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              const next = { ...project, pages: project.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) };
              setProject(next);
              pushToHistory(next);
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}} canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage} selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => {
              const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) };
              setProject(next);
              pushToHistory(next);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              const newPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              const next = { ...project, pages: [...project.pages, newPage] };
              setProject(next);
              pushToHistory(next);
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-start items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef} onWheel={handleWheel}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {!isPreview && showRulers && (
             <div className="absolute top-0 left-16 right-0 h-6 bg-white border-b border-slate-200 z-[150] flex items-center overflow-hidden">
                <div className="flex" style={{ transform: `translateX(${-containerRef.current?.scrollLeft || 0}px)` }}>
                  {Array.from({length: 40}).map((_, i) => (
                    <div key={i} className="flex-shrink-0 w-[50px] border-l border-slate-300 h-full flex flex-col justify-end pb-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pl-1">{(i * 50) % 100 === 0 ? i * 50 : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
          )}

          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
               <div className="h-full w-px bg-slate-200 mx-1" />
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border shadow-sm">
                  <span className="text-[10px] font-black text-slate-400 uppercase">Zoom</span>
                  <span className="text-[10px] font-black text-slate-900 w-10 text-center">{Math.round(zoom * 100)}%</span>
               </div>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible transition-none ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    setSelectedElementIds([el.id]);
                    setActionState({ 
                      ids: [el.id], startX: e.clientX, startY: e.clientY, 
                      initials: [{ id: el.id, x: el.x, y: el.y, w: el.width, h: el.height, r: el.styles.rotation || 0 }]
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle:h });
                }}
                onRotateStart={(e) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle: 'rot' });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{ 
                  left: Math.min(marquee.startX, marquee.currentX), 
                  top: Math.min(marquee.startY, marquee.currentY), 
                  width: Math.abs(marquee.startX - marquee.currentX), 
                  height: Math.abs(marquee.startY - marquee.currentY) 
                }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-[300] shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="flex bg-slate-50 border-b">
                <button 
                  onClick={() => setActivePropertyTab('design')}
                  className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activePropertyTab === 'design' ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Diseño
                </button>
                <button 
                  onClick={() => setActivePropertyTab('interact')}
                  className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activePropertyTab === 'interact' ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Interacción
                </button>
             </div>

             <div className="p-6 space-y-8 pb-32">
               {activePropertyTab === 'design' ? (
                 <>
                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea 
                      className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" 
                      value={selectedElements[0].content} 
                      onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} 
                      placeholder="Escribe texto aquí..."
                     />
                     {selectedElements[0].type === 'text' && (
                       <div className="space-y-3 mt-3">
                         <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                            <option value="Inter">Inter</option>
                            <option value="Arial">Arial</option>
                            <option value="Pacifico">Pacifico (Script)</option>
                         </select>
                         <div className="flex gap-2">
                            <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                            <div className="flex flex-1 border rounded-xl overflow-hidden">
                               {['left', 'center', 'right'].map(a => (
                                  <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs transition-colors ${selectedElements[0].styles.textAlign === a ? 'bg-[#E4002B] text-white' : 'bg-white text-slate-400'}`}><i className={`fas fa-align-${a}`}></i></button>
                               ))}
                            </div>
                         </div>
                       </div>
                     )}
                   </section>

                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo Visual</label>
                      <div className="space-y-4">
                        <div className="flex bg-slate-100 p-1 rounded-xl">
                          <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                          <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                        </div>

                        {selectedElements[0].styles.gradient?.enabled ? (
                          <div className="space-y-3">
                             <div className="flex gap-2">
                                <input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, from: e.target.value } } }))} className="flex-1 h-8 rounded border-none cursor-pointer" />
                                <input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, to: e.target.value } } }))} className="flex-1 h-8 rounded border-none cursor-pointer" />
                             </div>
                             <input type="range" min="0" max="360" value={selectedElements[0].styles.gradient.angle} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, angle: parseInt(e.target.value) } } }))} className="w-full accent-[#E4002B]" />
                          </div>
                        ) : (
                          <div className="flex items-center gap-4 bg-slate-50 p-3 rounded-xl border">
                             <input type="color" value={selectedElements[0].styles.backgroundColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} className="w-10 h-10 rounded-full border-2 border-white cursor-pointer shadow-sm" />
                             <span className="text-[10px] font-bold text-slate-500 uppercase">Fondo</span>
                          </div>
                        )}

                        <div className="grid grid-cols-2 gap-4">
                           <div className="space-y-1">
                              <label className="text-[9px] font-bold text-slate-400 uppercase">Radio ({selectedElements[0].styles.borderRadius}px)</label>
                              <input type="range" min="0" max="100" value={selectedElements[0].styles.borderRadius} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderRadius: parseInt(e.target.value) } }))} className="w-full accent-[#E4002B]" />
                           </div>
                           <div className="space-y-1">
                              <label className="text-[9px] font-bold text-slate-400 uppercase">Rotación ({selectedElements[0].styles.rotation}°)</label>
                              <input type="range" min="0" max="360" value={selectedElements[0].styles.rotation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { rotation: parseInt(e.target.value) } }))} className="w-full accent-[#E4002B]" />
                           </div>
                        </div>
                      </div>
                   </section>
                 </>
               ) : (
                 <>
                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Interactividad</label>
                      <div className="space-y-3">
                         <label className="text-[9px] font-bold text-slate-500 uppercase">Tipo de Acción</label>
                         <select 
                            className="w-full bg-slate-50 border rounded-xl text-xs py-2.5 px-3 outline-none focus:ring-1 focus:ring-[#E4002B]"
                            value={selectedElements[0].interactivity.type}
                            onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { type: e.target.value as InteractivityType } })}
                         >
                            <option value={InteractivityType.NONE}>Ninguna</option>
                            <option value={InteractivityType.EXTERNAL_LINK}>Abrir Enlace Externo</option>
                            <option value={InteractivityType.GOTO_PAGE}>Ir a Página</option>
                         </select>

                         {selectedElements[0].interactivity.type !== InteractivityType.NONE && (
                           <input 
                              placeholder={selectedElements[0].interactivity.type === InteractivityType.GOTO_PAGE ? "Nombre o ID de página" : "https://ejemplo.com"}
                              className="w-full bg-white border rounded-xl text-xs py-2.5 px-4 outline-none focus:border-[#E4002B]"
                              value={selectedElements[0].interactivity.value}
                              onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { value: e.target.value } })}
                           />
                         )}
                      </div>
                   </section>

                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones de Comportamiento</label>
                      <div className="space-y-6">
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Entrada (Aparición)</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'fade', 'slide', 'zoom', 'back'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.entranceAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Al hacer Click (Tap)</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'squish', 'vibrate'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { clickAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.clickAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Hover (Ratón encima)</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'pop', 'lift'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { hoverAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.hoverAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                      </div>
                   </section>
                 </>
               )}
             </div>

             <div className="p-6 mt-auto bg-slate-50 border-t flex flex-col gap-2">
                <div className="grid grid-cols-2 gap-2 mb-2">
                  <button onClick={handleCopy} className="py-2 bg-white text-[9px] font-black uppercase border rounded hover:bg-slate-50"><i className="fas fa-copy mr-1"></i> Copiar</button>
                  <button onClick={handlePaste} className="py-2 bg-white text-[9px] font-black uppercase border rounded hover:bg-slate-50 disabled:opacity-30" disabled={clipboard.length === 0}><i className="fas fa-paste mr-1"></i> Pegar</button>
                </div>
                <button onClick={handleDuplicateSelected} className="w-full py-4 bg-white text-slate-800 text-[10px] font-black uppercase rounded-xl border border-slate-200 hover:bg-slate-100 transition-all shadow-sm"><i className="fas fa-clone mr-2"></i> Duplicar Selección</button>
                <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 text-[#E4002B] text-[10px] font-black uppercase rounded-xl border border-red-200 hover:bg-red-100 transition-all"><i className="fas fa-trash-alt mr-2"></i> Eliminar ({selectedElements.length})</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, AnimationType, PageBackground, ProjectPage } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [history, setHistory] = useState<Project[]>([INITIAL_PROJECT]);
  const [historyIndex, setHistoryIndex] = useState(0);

  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [zoom, setZoom] = useState(0.8);
  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);
  const [clipboard, setClipboard] = useState<CanvasElement[]>([]);
  const [activePropertyTab, setActivePropertyTab] = useState<'design' | 'interact'>('design');

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const isInternalChange = useRef(false);

  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];

  const selectedElements = useMemo(() => 
    currentPage.elements.filter(el => selectedElementIds.includes(el.id))
  , [currentPage.elements, selectedElementIds]);

  const pushToHistory = useCallback((newProject: Project) => {
    if (isInternalChange.current) return;
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newProject)));
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  const undo = useCallback(() => {
    if (historyIndex > 0) {
      isInternalChange.current = true;
      const prevProject = history[historyIndex - 1];
      setProject(JSON.parse(JSON.stringify(prevProject)));
      setHistoryIndex(historyIndex - 1);
      setTimeout(() => isInternalChange.current = false, 50);
    }
  }, [history, historyIndex]);

  const redo = useCallback(() => {
    if (historyIndex < history.length - 1) {
      isInternalChange.current = true;
      const nextProject = history[historyIndex + 1];
      setProject(JSON.parse(JSON.stringify(nextProject)));
      setHistoryIndex(historyIndex + 1);
      setTimeout(() => isInternalChange.current = false, 50);
    }
  }, [history, historyIndex]);

  // Fix: Refined update type by omitting 'interactivity' from the broad partial to avoid conflicts with custom partial interactivity
  const handleUpdateElement = useCallback((id: string, updates: Partial<Omit<CanvasElement, 'styles' | 'interactivity'>> & { styles?: Partial<CanvasElement['styles']>, interactivity?: Partial<CanvasElement['interactivity']> }, silent = false) => {
    setProject(prev => {
      const next = {
        ...prev,
        pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
          ...p,
          elements: p.elements.map(el => el.id === id ? ({ 
            ...el, 
            ...updates, 
            styles: { ...el.styles, ...(updates.styles || {}) },
            interactivity: { ...el.interactivity, ...(updates.interactivity || {}) }
          } as CanvasElement) : el)
        }) : p)
      };
      if (!silent) pushToHistory(next);
      return next;
    });
  }, [currentPageIndex, pushToHistory]);

  const handleDeleteSelected = useCallback(() => {
    const next = { 
      ...project, 
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({ 
        ...p, 
        elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) 
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds([]);
  }, [selectedElementIds, currentPageIndex, project, pushToHistory]);

  const handleCopy = useCallback(() => {
    if (selectedElements.length === 0) return;
    setClipboard(JSON.parse(JSON.stringify(selectedElements)));
  }, [selectedElements]);

  const handleCut = useCallback(() => {
    if (selectedElements.length === 0) return;
    handleCopy();
    handleDeleteSelected();
  }, [selectedElements, handleCopy, handleDeleteSelected]);

  const handlePaste = useCallback(() => {
    if (clipboard.length === 0) return;
    const centerX = currentDimensions.width / 2;
    const centerY = currentDimensions.height / 2;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    clipboard.forEach(el => {
      minX = Math.min(minX, el.x); minY = Math.min(minY, el.y);
      maxX = Math.max(maxX, el.x + el.width); maxY = Math.max(maxY, el.y + el.height);
    });
    const offsetX = centerX - (minX + (maxX - minX) / 2);
    const offsetY = centerY - (minY + (maxY - minY) / 2);

    const newElements = clipboard.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + offsetX,
      y: el.y + offsetY,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));

    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newElements]
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newElements.map(el => el.id));
  }, [clipboard, currentDimensions, currentPageIndex, currentPage.elements.length, project, pushToHistory]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30,
      y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? ({
        ...p,
        elements: [...p.elements, ...newEls]
      }) : p)
    };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newEls.map(el => el.id));
  }, [selectedElements, currentPageIndex, currentPage.elements.length, project, pushToHistory]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    // Snapping refinado: 5px con grid, 1px sin grid
    const snap = (val: number) => showGrid ? Math.round(val / 5) * 5 : Math.round(val);

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;
      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      const finalAngle = Math.round((angle + 90) % 360);
      handleUpdateElement(target.id, { styles: { rotation: finalAngle } }, true);
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x: newX, y: newY, w: newW, h: newH } = target;
      const h = actionState.handle;

      if (h.includes('r')) newW = Math.max(10, target.w + dx);
      if (h.includes('l')) { 
        const constrainedDx = Math.min(dx, target.w - 10);
        newW = target.w - constrainedDx; 
        newX = target.x + constrainedDx; 
      }
      if (h.includes('b')) newH = Math.max(10, target.h + dy);
      if (h.includes('t')) { 
        const constrainedDy = Math.min(dy, target.h - 10);
        newH = target.h - constrainedDy; 
        newY = target.y + constrainedDy; 
      }

      handleUpdateElement(target.id, { 
        x: snap(newX), 
        y: snap(newY), 
        width: snap(newW), 
        height: snap(newH) 
      }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { 
          x: snap(init.x + dx), 
          y: snap(init.y + dy) 
        }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, zoom, handleUpdateElement, showGrid, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    } else if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) {
      pushToHistory(project);
    }
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = null;
    setMarquee(null);
    setActionState(null);
  }, [marquee, currentPage.elements, zoom, project, pushToHistory, actionState]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (isPreview) return;
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const delta = -e.deltaY;
      const nextZoom = delta > 0 ? zoom * 1.1 : zoom / 1.1;
      setZoom(Math.min(Math.max(nextZoom, 0.1), 3));
    }
  }, [zoom, isPreview]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isPreview) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') return;
      const cmd = navigator.platform.toUpperCase().indexOf('MAC') >= 0 ? e.metaKey : e.ctrlKey;

      if (cmd && e.key.toLowerCase() === 'z') { e.preventDefault(); e.shiftKey ? redo() : undo(); }
      else if (cmd && e.key.toLowerCase() === 'y') { e.preventDefault(); redo(); }
      else if (cmd && e.key.toLowerCase() === 'c') { e.preventDefault(); handleCopy(); }
      else if (cmd && e.key.toLowerCase() === 'v') { e.preventDefault(); handlePaste(); }
      else if (cmd && e.key.toLowerCase() === 'x') { e.preventDefault(); handleCut(); }
      else if (cmd && e.key.toLowerCase() === 'd') { e.preventDefault(); handleDuplicateSelected(); }
      else if (e.key === 'Delete' || e.key === 'Backspace') { e.preventDefault(); handleDeleteSelected(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPreview, handleCopy, handlePaste, handleCut, handleDuplicateSelected, handleDeleteSelected, undo, redo]);

  useEffect(() => {
    if (actionState || marquee) {
      window.addEventListener('mousemove', onMouseMove, { passive: true });
      window.addEventListener('mouseup', onMouseUp);
    }
    return () => { 
      window.removeEventListener('mousemove', onMouseMove); 
      window.removeEventListener('mouseup', onMouseUp); 
    };
  }, [actionState, marquee, onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none">
      <Toolbar 
        selectedElement={selectedElements[0] || null}
        onPreview={() => { setIsPreview(!isPreview); setSelectedElementIds([]); }}
        onPublish={() => setShowPublishModal(true)}
        isPreview={isPreview}
        projectTitle={project.title}
        onUpdateTitle={(title) => {
          const next = { ...project, title };
          setProject(next);
          pushToHistory(next);
        }}
        onUndo={undo} onRedo={redo}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 150, y: 150, width: type === 'shape' ? 150 : 250, height: type === 'shape' ? 150 : 60,
                // Limpiar contenido por defecto para formas
                content: content || (type === 'text' ? 'Escribe aquí' : ''),
                styles: { 
                  backgroundColor: type === 'button' ? '#E4002B' : (type === 'shape' ? '#333333' : 'transparent'), 
                  color: type === 'button' ? '#ffffff' : '#000000', 
                  fontSize: 18, zIndex: currentPage.elements.length, opacity: 1, textAlign: 'center', fontFamily: 'Inter', borderRadius: 0,
                  gradient: { enabled: false, from: '#E4002B', to: '#000000', angle: 135 }, rotation: 0
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              const next = { ...project, pages: project.pages.map((pg, idx) => idx === currentPageIndex ? ({ ...pg, elements: [...pg.elements, el] }) : pg) };
              setProject(next);
              pushToHistory(next);
              setSelectedElementIds([el.id]);
            }} 
            onBulkAdd={() => {}} canvasPreset={project.canvasPreset}
            onUpdatePreset={(p) => setProject(pr => ({ ...pr, canvasPreset: p }))}
            currentPage={currentPage} selectedElementIds={selectedElementIds}
            onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => {
              const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, background: bg } : p) };
              setProject(next);
              pushToHistory(next);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => {
              // Fix: Added explicit ProjectPage type to prevent background.type being inferred as string
              const newPage: ProjectPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], background: { type: 'color', value: '#FFFFFF' } };
              const next = { ...project, pages: [...project.pages, newPage] };
              setProject(next);
              pushToHistory(next);
              setCurrentPageIndex(project.pages.length);
            }}
          />
        )}

        <main 
          className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-start items-start scrollbar-hide relative ${isPreview ? 'p-0' : 'pt-16 pl-16'}`}
          ref={containerRef} onWheel={handleWheel}
          onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}
        >
          {!isPreview && showRulers && (
             <div className="absolute top-0 left-16 right-0 h-6 bg-white border-b border-slate-200 z-[150] flex items-center overflow-hidden">
                <div className="flex" style={{ transform: `translateX(${-containerRef.current?.scrollLeft || 0}px)` }}>
                  {Array.from({length: 40}).map((_, i) => (
                    <div key={i} className="flex-shrink-0 w-[50px] border-l border-slate-300 h-full flex flex-col justify-end pb-0.5">
                      <span className="text-[8px] font-bold text-slate-400 pl-1">{(i * 50) % 100 === 0 ? i * 50 : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
          )}

          {!isPreview && (
            <div className="absolute top-4 right-8 flex gap-2 z-[200]">
               <button onClick={() => setShowRulers(!showRulers)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Reglas"><i className="fas fa-ruler"></i></button>
               <button onClick={() => setShowGrid(!showGrid)} className={`p-2 rounded-lg border bg-white shadow-sm hover:bg-slate-50 transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`} title="Cuadrícula"><i className="fas fa-th"></i></button>
               <div className="h-full w-px bg-slate-200 mx-1" />
               <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border shadow-sm">
                  <span className="text-[10px] font-black text-slate-400 uppercase">Zoom</span>
                  <span className="text-[10px] font-black text-slate-900 w-10 text-center">{Math.round(zoom * 100)}%</span>
               </div>
            </div>
          )}

          <div 
            ref={canvasRef}
            className={`relative flex-shrink-0 shadow-2xl overflow-visible transition-none ${isPreview ? 'w-full h-full' : 'border border-slate-300 bg-white'}`}
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`,
              height: isPreview ? '100%' : `${currentDimensions.height}px`,
              transform: isPreview ? 'none' : `scale(${zoom})`,
              transformOrigin: 'top left',
              backgroundImage: !isPreview && showGrid ? 'radial-gradient(circle, #ddd 1px, transparent 1px)' : 'none',
              backgroundSize: '20px 20px',
              backgroundColor: currentPage.background?.type === 'color' ? currentPage.background.value : '#FFF'
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)}
                onSelect={(e) => {
                  e.stopPropagation();
                  if (e.shiftKey) {
                    setSelectedElementIds(p => p.includes(el.id) ? p.filter(id => id !== el.id) : [...p, el.id]);
                  } else {
                    setSelectedElementIds([el.id]);
                    setActionState({ 
                      ids: [el.id], startX: e.clientX, startY: e.clientY, 
                      initials: [{ id: el.id, x: el.x, y: el.y, w: el.width, h: el.height, r: el.styles.rotation || 0 }]
                    });
                  }
                }}
                onResizeStart={(e, h) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle:h });
                }}
                onRotateStart={(e) => {
                  e.stopPropagation();
                  setSelectedElementIds([el.id]);
                  setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r: el.styles.rotation || 0}], handle: 'rot' });
                }}
                isPreview={isPreview}
                onNavigate={(t) => {
                  const idx = project.pages.findIndex(p => p.id === t || p.name === t);
                  if (idx !== -1) setCurrentPageIndex(idx);
                }}
              />
            ))}

            {marquee && (
              <div 
                className="fixed z-[1000] border border-[#E4002B] bg-[#E4002B]/10 pointer-events-none"
                style={{ 
                  left: Math.min(marquee.startX, marquee.currentX), 
                  top: Math.min(marquee.startY, marquee.currentY), 
                  width: Math.abs(marquee.startX - marquee.currentX), 
                  height: Math.abs(marquee.startY - marquee.currentY) 
                }}
              />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-[300] shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="flex bg-slate-50 border-b">
                <button 
                  onClick={() => setActivePropertyTab('design')}
                  className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activePropertyTab === 'design' ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Diseño
                </button>
                <button 
                  onClick={() => setActivePropertyTab('interact')}
                  className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${activePropertyTab === 'interact' ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Interacción
                </button>
             </div>

             <div className="p-6 space-y-8 pb-32">
               {activePropertyTab === 'design' ? (
                 <>
                   <section className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea 
                      className="w-full bg-slate-50 border rounded-xl text-xs py-3 px-4 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" 
                      value={selectedElements[0].content} 
                      onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} 
                      placeholder="Escribe texto aquí..."
                     />
                     {selectedElements[0].type === 'text' && (
                       <div className="space-y-3 mt-3">
                         <select className="w-full bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                            <option value="Inter">Inter</option>
                            <option value="Arial">Arial</option>
                            <option value="Pacifico">Pacifico (Script)</option>
                         </select>
                         <div className="flex gap-2">
                            <input type="number" className="w-20 bg-slate-50 border rounded-xl text-xs py-2 px-3 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                            <div className="flex flex-1 border rounded-xl overflow-hidden">
                               {['left', 'center', 'right'].map(a => (
                                  <button key={a} onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: a as any } })} className={`flex-1 py-2 text-xs transition-colors ${selectedElements[0].styles.textAlign === a ? 'bg-[#E4002B] text-white' : 'bg-white text-slate-400'}`}><i className={`fas fa-align-${a}`}></i></button>
                               ))}
                            </div>
                         </div>
                       </div>
                     )}
                   </section>

                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo Visual</label>
                      <div className="space-y-4">
                        <div className="flex bg-slate-100 p-1 rounded-xl">
                          <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: false } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${!selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Sólido</button>
                          <button onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, enabled: true } } }))} className={`flex-1 py-1.5 text-[10px] font-black rounded ${selectedElements[0].styles.gradient?.enabled ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Degradado</button>
                        </div>

                        {selectedElements[0].styles.gradient?.enabled ? (
                          <div className="space-y-3">
                             <div className="flex gap-2">
                                <input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, from: e.target.value } } }))} className="flex-1 h-8 rounded border-none cursor-pointer" />
                                <input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, to: e.target.value } } }))} className="flex-1 h-8 rounded border-none cursor-pointer" />
                             </div>
                             <input type="range" min="0" max="360" value={selectedElements[0].styles.gradient.angle} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { gradient: { ...el.styles.gradient!, angle: parseInt(e.target.value) } } }))} className="w-full accent-[#E4002B]" />
                          </div>
                        ) : (
                          <div className="flex items-center gap-4 bg-slate-50 p-3 rounded-xl border">
                             <input type="color" value={selectedElements[0].styles.backgroundColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { backgroundColor: e.target.value } }))} className="w-10 h-10 rounded-full border-2 border-white cursor-pointer shadow-sm" />
                             <span className="text-[10px] font-bold text-slate-500 uppercase">Fondo</span>
                          </div>
                        )}

                        <div className="grid grid-cols-2 gap-4">
                           <div className="space-y-1">
                              <label className="text-[9px] font-bold text-slate-400 uppercase">Radio ({selectedElements[0].styles.borderRadius}px)</label>
                              <input type="range" min="0" max="100" value={selectedElements[0].styles.borderRadius} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { borderRadius: parseInt(e.target.value) } }))} className="w-full accent-[#E4002B]" />
                           </div>
                           <div className="space-y-1">
                              <label className="text-[9px] font-bold text-slate-400 uppercase">Rotación ({selectedElements[0].styles.rotation}°)</label>
                              <input type="range" min="0" max="360" value={selectedElements[0].styles.rotation} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { rotation: parseInt(e.target.value) } }))} className="w-full accent-[#E4002B]" />
                           </div>
                        </div>
                      </div>
                   </section>
                 </>
               ) : (
                 <>
                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Interactividad</label>
                      <div className="space-y-3">
                         <label className="text-[9px] font-bold text-slate-500 uppercase">Tipo de Acción</label>
                         <select 
                            className="w-full bg-slate-50 border rounded-xl text-xs py-2.5 px-3 outline-none focus:ring-1 focus:ring-[#E4002B]"
                            value={selectedElements[0].interactivity.type}
                            onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { type: e.target.value as InteractivityType } })}
                         >
                            <option value={InteractivityType.NONE}>Ninguna</option>
                            <option value={InteractivityType.EXTERNAL_LINK}>Abrir Enlace Externo</option>
                            <option value={InteractivityType.GOTO_PAGE}>Ir a Página</option>
                         </select>

                         {selectedElements[0].interactivity.type !== InteractivityType.NONE && (
                           <input 
                              placeholder={selectedElements[0].interactivity.type === InteractivityType.GOTO_PAGE ? "Nombre o ID de página" : "https://ejemplo.com"}
                              className="w-full bg-white border rounded-xl text-xs py-2.5 px-4 outline-none focus:border-[#E4002B]"
                              value={selectedElements[0].interactivity.value}
                              onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { value: e.target.value } })}
                           />
                         )}
                      </div>
                   </section>

                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones de Comportamiento</label>
                      <div className="space-y-6">
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Entrada (Aparición)</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'fade', 'slide', 'zoom', 'back'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { entranceAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.entranceAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Al hacer Click (Tap)</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'squish', 'vibrate'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { clickAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.clickAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                         <div className="space-y-2">
                            <span className="text-[9px] font-bold text-slate-500 uppercase block">Hover (Ratón encima)</span>
                            <div className="grid grid-cols-2 gap-2">
                               {['none', 'pop', 'lift'].map(anim => (
                                 <button 
                                  key={anim} 
                                  onClick={() => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { hoverAnimation: anim as any } }))}
                                  className={`py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${selectedElements[0].styles.hoverAnimation === anim ? 'bg-[#E4002B] text-white border-[#E4002B]' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}
                                 >
                                    {anim}
                                 </button>
                               ))}
                            </div>
                         </div>
                      </div>
                   </section>
                 </>
               )}
             </div>

             <div className="p-6 mt-auto bg-slate-50 border-t flex flex-col gap-2">
                <div className="grid grid-cols-2 gap-2 mb-2">
                  <button onClick={handleCopy} className="py-2 bg-white text-[9px] font-black uppercase border rounded hover:bg-slate-50"><i className="fas fa-copy mr-1"></i> Copiar</button>
                  <button onClick={handlePaste} className="py-2 bg-white text-[9px] font-black uppercase border rounded hover:bg-slate-50 disabled:opacity-30" disabled={clipboard.length === 0}><i className="fas fa-paste mr-1"></i> Pegar</button>
                </div>
                <button onClick={handleDuplicateSelected} className="w-full py-4 bg-white text-slate-800 text-[10px] font-black uppercase rounded-xl border border-slate-200 hover:bg-slate-100 transition-all shadow-sm"><i className="fas fa-clone mr-2"></i> Duplicar Selección</button>
                <button onClick={handleDeleteSelected} className="w-full py-4 bg-red-50 text-[#E4002B] text-[10px] font-black uppercase rounded-xl border border-red-200 hover:bg-red-100 transition-all"><i className="fas fa-trash-alt mr-2"></i> Eliminar ({selectedElements.length})</button>
             </div>
          </aside>
        )}
      </div>

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'fade' | 'slide' | 'zoom' | 'pop' | 'lift' | 'back' | 'squish' | 'vibrate' | 'exit-fade' | 'exit-zoom';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentación (16:9)' },
  square: { width: 600, height: 600, label: 'Cuadrado (1:1)' },
  vertical: { width: 400, height: 711, label: 'Móvil (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Vertical' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  groupId?: string;
  styles: {
    backgroundColor?: string;
    gradient?: {
      enabled: boolean;
      from: string;
      to: string;
      angle: number;
    };
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    rotation?: number;
    borderWidth?: number;
    borderColor?: string;
    // Efectos Avanzados
    shadowBlur: number;
    shadowColor: string;
    shadowOffsetX: number;
    shadowOffsetY: number;
    glowBlur: number;
    glowColor: string;
    // Filtros de Imagen (Micro-Photoshop)
    brightness: number;
    contrast: number;
    saturate: number;
    // Animaciones
