import React, { useState, useEffect, useMemo } from 'react';
import { CanvasElement, InteractivityType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onResizeStart: (e: React.MouseEvent, handle: string) => void;
  onRotateStart?: (e: React.MouseEvent) => void;
  isPreview?: boolean;
  onNavigate?: (target: string | number) => void;
  onOpenContextMenu?: (e: React.MouseEvent) => void;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ 
  element, isSelected, onSelect, onResizeStart, onRotateStart, isPreview, onNavigate, onOpenContextMenu 
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isClicked, setIsClicked] = useState(false);
  const [showEntrance, setShowEntrance] = useState(false);

  useEffect(() => {
    setShowEntrance(true);
  }, []);

  const getStyle = (): React.CSSProperties => {
    const s = element.styles;
    const background = s.gradient?.enabled 
      ? `linear-gradient(${s.gradient.angle}deg, ${s.gradient.from} 0%, ${s.gradient.to} 100%)` 
      : s.backgroundColor;

    // Sombra y Resplandor
    const shadow = s.shadowBlur > 0 
      ? `${s.shadowOffsetX || 0}px ${s.shadowOffsetY || 0}px ${s.shadowBlur}px ${s.shadowColor || 'rgba(0,0,0,0.3)'}` 
      : 'none';
    const glow = s.glowBlur > 0 
      ? `0 0 ${s.glowBlur}px ${s.glowColor || s.backgroundColor || '#FFF'}` 
      : 'none';

    // Filtros (Micro-Photoshop)
    const filters = element.type === 'image' 
      ? `brightness(${s.brightness || 100}%) contrast(${s.contrast || 100}%) saturate(${s.saturate || 100}%)` 
      : 'none';

    return {
      position: 'absolute',
      left: element.x,
      top: element.y,
      width: element.width,
      height: element.height,
      zIndex: s.zIndex,
      background: element.type === 'image' ? 'transparent' : background,
      color: s.color,
      fontSize: s.fontSize,
      borderRadius: `${s.borderRadius || 0}px`,
      fontFamily: s.fontFamily || 'Inter',
      textAlign: s.textAlign,
      opacity: s.opacity,
      border: s.borderWidth ? `${s.borderWidth}px solid ${s.borderColor || '#000'}` : 'none',
      boxShadow: shadow !== 'none' || glow !== 'none' ? `${shadow}${shadow !== 'none' && glow !== 'none' ? ', ' : ''}${glow}` : 'none',
      display: 'flex',
      alignItems: 'center',
      justifyContent: s.textAlign === 'center' ? 'center' : (s.textAlign === 'right' ? 'flex-end' : 'flex-start'),
      transition: isPreview ? 'transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275), opacity 0.3s' : 'none',
      transform: `rotate(${s.rotation || 0}deg) ${isPreview && isHovered && s.hoverAnimation === 'pop' ? 'scale(1.08)' : ''} ${isPreview && isHovered && s.hoverAnimation === 'lift' ? 'translateY(-8px)' : ''}`,
      clipPath: element.type === 'shape' ? getClipPath(element.content) : 'none',
      filter: filters,
      cursor: isPreview ? (element.interactivity.type !== InteractivityType.NONE ? 'pointer' : 'default') : 'move',
      pointerEvents: isPreview && element.interactivity.type === InteractivityType.NONE && !element.styles.hoverAnimation ? 'none' : 'auto'
    };
  };

  const animationClass = useMemo(() => {
    let classes = [];
    if (showEntrance) {
      if (element.styles.entranceAnimation && element.styles.entranceAnimation !== 'none') {
        classes.push(`anim-entrance-${element.styles.entranceAnimation}`);
      }
    } else {
      classes.push('opacity-0');
    }

    if (isClicked && element.styles.clickAnimation && element.styles.clickAnimation !== 'none') {
      classes.push(`anim-click-${element.styles.clickAnimation}`);
    }

    return classes.join(' ');
  }, [showEntrance, isClicked, element.styles.entranceAnimation, element.styles.clickAnimation]);

  const handleInteraction = (e: React.MouseEvent) => {
    if (!isPreview) return;
    setIsClicked(true);
    setTimeout(() => setIsClicked(false), 200);

    switch (element.interactivity.type) {
      case InteractivityType.EXTERNAL_LINK: 
        window.open(element.interactivity.value, '_blank'); 
        break;
      case InteractivityType.GOTO_PAGE: 
        onNavigate?.(element.interactivity.value); 
        break;
    }
  };

  return (
    <div
      style={getStyle()}
      onMouseDown={(e) => {
        if (!isPreview) onSelect(e);
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleInteraction}
      onContextMenu={(e) => {
        if (!isPreview) {
          e.preventDefault();
          onOpenContextMenu?.(e);
        }
      }}
      className={`${isSelected && !isPreview ? 'ring-2 ring-[#E4002B] ring-offset-4' : ''} ${animationClass}`}
    >
      {element.type === 'image' ? (
        <img src={element.content} className="w-full h-full object-contain pointer-events-none" style={{ borderRadius: 'inherit' }} alt="" />
      ) : element.type === 'video' ? (
        <video src={element.content} className="w-full h-full object-cover" controls={isPreview} style={{ borderRadius: 'inherit' }} />
      ) : (
        <span className="w-full px-4 break-words pointer-events-none select-none">{element.type === 'shape' && ['square','circle','triangle','star','diamond','heart'].includes(element.content) ? '' : element.content}</span>
      )}

      {isSelected && !isPreview && (
        <>
          {['tl', 'tr', 'bl', 'br'].map(h => (
            <div 
              key={h} 
              onMouseDown={(e) => { e.stopPropagation(); onResizeStart(e, h); }} 
              className="absolute w-3 h-3 bg-white border-2 border-[#E4002B] rounded-full z-[120] shadow-sm" 
              style={getHandleStyle(h)} 
            />
          ))}
          <div 
            onMouseDown={(e) => { e.stopPropagation(); onRotateStart?.(e); }} 
            className="absolute -top-10 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-2 border-[#E4002B] rounded-full z-[120] flex items-center justify-center cursor-alias shadow-lg hover:scale-110 transition-transform"
          >
             <i className="fas fa-redo text-[10px] text-[#E4002B]"></i>
             <div className="absolute top-6 left-1/2 -translate-x-1/2 w-px h-4 bg-[#E4002B]" />
          </div>

          {/* Botón de Acciones Contextuales */}
          <button 
            onClick={(e) => { e.stopPropagation(); onOpenContextMenu?.(e); }}
            className="absolute -bottom-10 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-3 py-1.5 rounded-full text-[9px] font-black uppercase flex items-center gap-2 shadow-xl hover:bg-black transition-all"
          >
            Acciones <i className="fas fa-ellipsis-v"></i>
          </button>
        </>
      )}
    </div>
  );
};

function getClipPath(shape: string) {
  switch (shape) {
    case 'circle': return 'circle(50% at 50% 50%)';
    case 'triangle': return 'polygon(50% 0%, 0% 100%, 100% 100%)';
    case 'star': return 'polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%)';
    case 'diamond': return 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)';
    case 'heart': return 'path("M 10,30 A 20,20 0,0,1 50,30 A 20,20 0,0,1 90,30 Q 90,60 50,90 Q 10,60 10,30 Z")';
    default: return 'none';
  }
}

function getHandleStyle(h: string): React.CSSProperties {
  const o = '-6px';
  switch (h) {
    case 'tl': return { top: o, left: o, cursor: 'nwse-resize' };
    case 'tr': return { top: o, right: o, cursor: 'nesw-resize' };
    case 'bl': return { bottom: o, left: o, cursor: 'nesw-resize' };
    case 'br': return { bottom: o, right: o, cursor: 'nwse-resize' };
    default: return {};
  }
}

export default ElementRenderer;

import React, { useState, useRef } from 'react';
import { ElementType, CanvasPreset, ProjectPage, PageBackground } from '../types';
import { generateContentIdeas, generateAIImage } from '../services/geminiService';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
  currentPage: ProjectPage;
  selectedElementIds: string[];
  onSelectElements: (ids: string[]) => void;
  onUpdateBackground: (bg: PageBackground) => void;
  pages: ProjectPage[];
  currentPageIndex: number;
  onNavigatePage: (index: number) => void;
  onAddPage: () => void;
  onGroup?: () => void;
}

const PREDEFINED_SHAPES = [
  { id: 'square', icon: 'fa-square', label: 'Cuadrado' },
  { id: 'circle', icon: 'fa-circle', label: 'Círculo' },
  { id: 'triangle', icon: 'fa-play fa-rotate-270', label: 'Triángulo' },
  { id: 'star', icon: 'fa-star', label: 'Estrella' },
  { id: 'diamond', icon: 'fa-diamond', label: 'Diamante' },
  { id: 'heart', icon: 'fa-heart', label: 'Corazón' }
];

const Sidebar: React.FC<SidebarProps> = ({ 
  onAddElement, canvasPreset, currentPage, selectedElementIds, onSelectElements, onUpdateBackground,
  pages, currentPageIndex, onNavigatePage, onAddPage, onGroup
}) => {
  const [activePanel, setActivePanel] = useState<'pages' | 'text' | 'resources' | 'ai' | 'bg' | 'media'>('pages');
  const [pagesSubTab, setPagesSubTab] = useState<'outline' | 'layers'>('outline');

  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadType, setUploadType] = useState<ElementType>('image');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      onAddElement(uploadType, result);
    };
    reader.readAsDataURL(file);
    // Reset
    e.target.value = '';
  };

  const triggerUpload = (type: ElementType) => {
    setUploadType(type);
    fileInputRef.current?.click();
  };

  const handleAiGeneration = async () => {
    if (!aiPrompt) return;
    setIsGenerating(true);
    try {
      const ideas = await generateContentIdeas(aiPrompt);
      onAddElement('text', ideas.title);
      ideas.points.forEach((p: any, i: number) => {
        setTimeout(() => {
          onAddElement('button', p.label);
        }, (i + 1) * 300);
      });
    } catch (e) {
      console.error(e);
      alert("Error generando ideas");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAiImage = async () => {
    if (!aiPrompt) return;
    setIsGenerating(true);
    try {
      const img = await generateAIImage(aiPrompt);
      if (img) onAddElement('image', img);
