        <NavIcon active={activePanel === 'resources'} icon="fa-shapes" onClick={() => setActivePanel('resources')} label="Formas" />
        <NavIcon active={activePanel === 'media'} icon="fa-photo-film" onClick={() => setActivePanel('media')} label="Medios" />
        <NavIcon active={activePanel === 'ai'} icon="fa-wand-magic-sparkles" onClick={() => setActivePanel('ai')} label="IA Mágica" />
        <NavIcon active={activePanel === 'bg'} icon="fa-palette" onClick={() => setActivePanel('bg')} label="Tema" />
      </div>

      <div className="w-72 flex flex-col bg-white border-r border-slate-200">
