                            <input type="color" value={selectedElements[0].styles.shadowColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { shadowColor: e.target.value } }))} className="w-full h-6 rounded border-none cursor-pointer" />
