                            <input type="color" value={selectedElements[0].styles.glowColor} onChange={(e) => selectedElements.forEach(el => handleUpdateElement(el.id, { styles: { glowColor: e.target.value } }))} className="w-full h-6 rounded border-none cursor-pointer" />
