export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'fade' | 'slide' | 'zoom' | 'back' | 'bounce' | 'flip' | 'pop' | 'lift' | 'glow' | 'rotate' | 'exit-fade' | 'exit-zoom';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentación (16:9)' },
  square: { width: 600, height: 600, label: 'Cuadrado (1:1)' },
  vertical: { width: 400, height: 711, label: 'Móvil (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Vertical' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  isVisible: boolean;
  isLocked: boolean;
  styles: {
    backgroundColor?: string;
    gradient?: {
      enabled: boolean;
      from: string;
      to: string;
      angle: number;
    };
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    fontStyle?: 'normal' | 'italic';
    textTransform?: 'none' | 'uppercase';
    letterSpacing?: number;
    lineHeight?: number;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    rotation?: number;
    borderWidth?: number;
    borderColor?: string;
    // Efectos
    shadowBlur: number;
    shadowColor: string;
    shadowOffsetX: number;
    shadowOffsetY: number;
    glowBlur: number;
    glowColor: string;
    // Filtros
    brightness: number;
    contrast: number;
    saturate: number;
    // Animaciones
    hoverAnimation?: AnimationType;
    entranceAnimation?: AnimationType;
    exitAnimation?: AnimationType;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
  };
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
  groups: any[];
  background?: {
    type: 'color' | 'gradient' | 'image';
    value: string;
  };
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
  canvasPreset: CanvasPreset;
}

import React, { useState, useEffect, useMemo } from 'react';
import { CanvasElement, InteractivityType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onResizeStart: (e: React.MouseEvent, handle: string) => void;
  onRotateStart?: (e: React.MouseEvent) => void;
  isPreview?: boolean;
  onNavigate?: (target: string | number) => void;
  onOpenContextMenu?: (e: React.MouseEvent) => void;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ 
  element, isSelected, onSelect, onResizeStart, onRotateStart, isPreview, onNavigate, onOpenContextMenu 
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [showEntrance, setShowEntrance] = useState(false);

  useEffect(() => {
    setShowEntrance(true);
  }, []);

  if (!element.isVisible && !isPreview) return null;
  if (!element.isVisible && isPreview) return null;

  const getStyle = (): React.CSSProperties => {
    const s = element.styles;
    const background = s.gradient?.enabled 
      ? `linear-gradient(${s.gradient.angle}deg, ${s.gradient.from} 0%, ${s.gradient.to} 100%)` 
      : s.backgroundColor;

    // Sombra Inteligente: Box shadow para formas/botones, Text shadow para texto
    const shadowStr = s.shadowBlur > 0 
      ? `${s.shadowOffsetX}px ${s.shadowOffsetY}px ${s.shadowBlur}px ${s.shadowColor}` 
      : 'none';

    return {
      position: 'absolute',
      left: element.x,
      top: element.y,
      width: element.width,
      height: element.height,
      zIndex: s.zIndex,
      background: element.type === 'image' || element.type === 'text' ? 'transparent' : background,
      color: s.color,
      fontSize: s.fontSize,
      fontFamily: s.fontFamily || 'Inter',
      fontWeight: s.fontWeight || 'normal',
      fontStyle: s.fontStyle || 'normal',
      textTransform: s.textTransform || 'none',
      letterSpacing: `${s.letterSpacing || 0}px`,
      lineHeight: s.lineHeight || 1.2,
      textAlign: s.textAlign,
      borderRadius: `${s.borderRadius || 0}px`,
      opacity: s.opacity,
      border: s.borderWidth ? `${s.borderWidth}px solid ${s.borderColor || '#000'}` : 'none',
      boxShadow: element.type !== 'text' ? shadowStr : 'none',
      textShadow: element.type === 'text' ? shadowStr : 'none',
      display: 'flex',
      alignItems: 'center',
      justifyContent: s.textAlign === 'center' ? 'center' : (s.textAlign === 'right' ? 'flex-end' : 'flex-start'),
      transform: `rotate(${s.rotation || 0}deg) ${isPreview && isHovered && s.hoverAnimation === 'pop' ? 'scale(1.05)' : ''}`,
      filter: element.type === 'image' ? `brightness(${s.brightness}%) contrast(${s.contrast}%) saturate(${s.saturate}%)` : 'none',
      clipPath: element.type === 'shape' ? getClipPath(element.content) : 'none',
      cursor: isPreview ? (element.interactivity.type !== InteractivityType.NONE ? 'pointer' : 'default') : (element.isLocked ? 'not-allowed' : 'move'),
      pointerEvents: element.isLocked && !isPreview ? 'none' : 'auto',
      transition: 'all 0.2s ease-out'
    };
  };

  const animationClass = useMemo(() => {
    let cls = [];
    if (showEntrance && element.styles.entranceAnimation && element.styles.entranceAnimation !== 'none') {
      cls.push(`anim-entrance-${element.styles.entranceAnimation}`);
    }
    if (isPreview && isHovered) {
      if (element.styles.hoverAnimation === 'glow') cls.push('ring-4 ring-white/50');
      if (element.styles.hoverAnimation === 'lift') cls.push('-translate-y-2');
    }
    return cls.join(' ');
  }, [showEntrance, isHovered, element.styles.entranceAnimation, isPreview, element.styles.hoverAnimation]);

  return (
    <div
      style={getStyle()}
      className={`${isSelected && !isPreview ? 'ring-2 ring-[#E4002B] ring-offset-4' : ''} ${animationClass}`}
      onMouseDown={(e) => { if (!isPreview && !element.isLocked) onSelect(e); }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onContextMenu={(e) => { if (!isPreview) { e.preventDefault(); onOpenContextMenu?.(e); } }}
      onClick={() => {
        if (isPreview && element.interactivity.type === InteractivityType.GOTO_PAGE) onNavigate?.(element.interactivity.value);
        if (isPreview && element.interactivity.type === InteractivityType.EXTERNAL_LINK) window.open(element.interactivity.value, '_blank');
      }}
    >
      {element.type === 'image' ? (
        <img src={element.content} className="w-full h-full object-contain pointer-events-none" style={{ borderRadius: 'inherit' }} alt="" />
      ) : element.type === 'video' ? (
        <video src={element.content} className="w-full h-full object-cover" controls={isPreview} style={{ borderRadius: 'inherit' }} />
      ) : (
        <span className="w-full px-2 break-words select-none">{element.type === 'shape' ? '' : element.content}</span>
      )}

      {isSelected && !isPreview && !element.isLocked && (
        <>
          {['tl', 'tr', 'bl', 'br'].map(h => (
            <div 
              key={h} 
              onMouseDown={(e) => { e.stopPropagation(); onResizeStart(e, h); }} 
              className="absolute w-3 h-3 bg-white border-2 border-[#E4002B] rounded-full z-[120] shadow-sm" 
              style={getHandleStyle(h)} 
            />
          ))}
          <div onMouseDown={(e) => { e.stopPropagation(); onRotateStart?.(e); }} className="absolute -top-10 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-2 border-[#E4002B] rounded-full flex items-center justify-center cursor-alias shadow-lg"><i className="fas fa-redo text-[10px] text-[#E4002B]"></i></div>
          <button onClick={(e) => { e.stopPropagation(); onOpenContextMenu?.(e); }} className="absolute -bottom-10 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-3 py-1.5 rounded-full text-[9px] font-black uppercase flex items-center gap-2 shadow-xl hover:bg-black transition-all">Acciones <i className="fas fa-ellipsis-v"></i></button>
        </>
      )}
    </div>
  );
};

function getClipPath(shape: string) {
  switch (shape) {
    case 'circle': return 'circle(50% at 50% 50%)';
    case 'triangle': return 'polygon(50% 0%, 0% 100%, 100% 100%)';
    case 'star': return 'polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%)';
    case 'diamond': return 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)';
    case 'heart': return 'path("M 10,30 A 20,20 0,0,1 50,30 A 20,20 0,0,1 90,30 Q 90,60 50,90 Q 10,60 10,30 Z")';
    default: return 'none';
  }
}

function getHandleStyle(h: string): React.CSSProperties {
  const o = '-6px';
  switch (h) {
    case 'tl': return { top: o, left: o, cursor: 'nwse-resize' };
    case 'tr': return { top: o, right: o, cursor: 'nesw-resize' };
    case 'bl': return { bottom: o, left: o, cursor: 'nesw-resize' };
    case 'br': return { bottom: o, right: o, cursor: 'nwse-resize' };
    default: return {};
  }
}

export default ElementRenderer;

import React, { useState, useRef } from 'react';
import { ElementType, CanvasPreset, ProjectPage, CanvasElement } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
