                        className={`p-3 rounded-xl border flex items-center gap-3 transition-all ${selectedElementIds.includes(el.id) ? 'bg-red-50 border-[#E4002B]' : 'bg-white border-slate-100 hover:border-slate-300'}`}
                      >
                         <i className={`fas ${el.type === 'text' ? 'fa-font' : 'fa-square'} text-[10px] text-slate-400`}></i>
                         <span className="text-[10px] font-bold truncate flex-1 uppercase">{el.type}</span>
