                            <button onClick={(e) => { e.stopPropagation(); onUpdateElement(el.id, { isLocked: !el.isLocked }); }} className={`w-6 h-6 rounded flex items-center justify-center ${el.isLocked ? 'text-[#E4002B]' : 'text-slate-400 hover:text-slate-900'}`}>
