      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30, y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, ...newEls] } : p) };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newEls.map(e => e.id));
  }, [selectedElements, currentPageIndex, currentPage.elements, project, pushToHistory]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = mousePosRef.current.x - actionState.startX;
    const dy = mousePosRef.current.y - actionState.startY;

    if (actionState.handle === 'rot') {
