      if (han.includes('b')) h = Math.max(10, target.h + dy);
      if (han.includes('t')) { const diff = Math.min(dy, target.h - 10); h = target.h - diff; y = target.y + diff; }
      handleUpdateElement(target.id, { x, y, width: w, height: h }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: init.x + dx, y: init.y + dy }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, handleUpdateElement, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    } else if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = Math.min(marquee.startX, marquee.currentX) - rect.left;
      const y1 = Math.min(marquee.startY, marquee.currentY) - rect.top;
      const x2 = Math.max(marquee.startX, marquee.currentX) - rect.left;
      const y2 = Math.max(marquee.startY, marquee.currentY) - rect.top;
      const hitIds = currentPage.elements.filter(el => el.isVisible && !el.isLocked && el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) pushToHistory(project);
    setMarquee(null); setActionState(null);
  }, [marquee, currentPage.elements, project, pushToHistory, actionState]);

  useEffect(() => {
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => { window.removeEventListener('mousemove', onMouseMove); window.removeEventListener('mouseup', onMouseUp); };
  }, [onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none" onClick={() => setContextMenu(null)}>
      <Toolbar 
        selectedElement={selectedElements[0] || null} isPreview={isPreview} projectTitle={project.title}
        onPreview={() => setIsPreview(!isPreview)} onPublish={() => setShowPublishModal(true)}
        onUndo={() => { if (historyIndex > 0) { setProject(history[historyIndex - 1]); setHistoryIndex(historyIndex - 1); } }}
        onRedo={() => { if (historyIndex < history.length - 1) { setProject(history[historyIndex + 1]); setHistoryIndex(historyIndex + 1); } }}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1} onUpdateTitle={(t) => setProject({ ...project, title: t })}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 100, y: 100, width: 200, height: 100, isVisible: true, isLocked: false,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: '#E4002B', color: '#FFFFFF', fontSize: 24, zIndex: currentPage.elements.length, opacity: 1,
                  shadowBlur: 0, shadowColor: '#000000', shadowOffsetX: 0, shadowOffsetY: 0, glowBlur: 0, glowColor: '#FFFFFF',
                  brightness: 100, contrast: 100, saturate: 100, rotation: 0, borderRadius: 0, textAlign: 'center'
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, el] } : p) });
              pushToHistory(project);
              setSelectedElementIds([el.id]);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => { const np: ProjectPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [] }; setProject({ ...project, pages: [...project.pages, np] }); setCurrentPageIndex(project.pages.length); }}
            currentPage={currentPage} selectedElementIds={selectedElementIds} onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => handleUpdateElement(currentPage.id, bg)} onUpdateElement={handleUpdateElement}
            onUpdatePreset={() => {}} canvasPreset={project.canvasPreset} onBulkAdd={() => {}}
          />
        )}

        <main className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-center items-center relative ${isPreview ? 'p-0' : 'p-20'}`} ref={containerRef} onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}>
          <div ref={canvasRef} className={`relative bg-white shadow-2xl transition-all ${isPreview ? 'w-full h-full' : 'border border-slate-300'}`} style={{ width: isPreview ? '100%' : `${currentDimensions.width}px`, height: isPreview ? '100%' : `${currentDimensions.height}px`, backgroundColor: currentPage.background?.value || '#FFFFFF' }}>
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)} isPreview={isPreview}
                onSelect={(e) => { e.stopPropagation(); setSelectedElementIds(e.shiftKey ? [...selectedElementIds, el.id] : [el.id]); if (!e.shiftKey) setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}] }); }}
                onResizeStart={(e, h) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}], handle:h }); }}
                onRotateStart={(e) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}], handle:'rot' }); }}
                onOpenContextMenu={(e) => setContextMenu({ x: e.clientX, y: e.clientY })}
              />
            ))}
            {marquee && (
              <div className="fixed border border-[#E4002B] bg-[#E4002B]/10 z-[1000] pointer-events-none" style={{ left: Math.min(marquee.startX, marquee.currentX), top: Math.min(marquee.startY, marquee.currentY), width: Math.abs(marquee.startX - marquee.currentX), height: Math.abs(marquee.startY - marquee.currentY) }} />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-[300] shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="flex bg-slate-50 border-b">
                {['design', 'interact', 'effects'].map((tab) => (
                  <button key={tab} onClick={() => setActivePropertyTab(tab as any)} className={`flex-1 py-4 text-[9px] font-black uppercase tracking-widest ${activePropertyTab === tab ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}>
                    {tab}
                  </button>
                ))}
             </div>

             <div className="p-6 space-y-8 pb-32">
               {activePropertyTab === 'design' && (
                 <>
                   <section className="space-y-4">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs p-3 outline-none resize-none h-20" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                     {selectedElements[0].type === 'text' && (
                        <div className="grid grid-cols-2 gap-2">
                           <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { fontWeight: selectedElements[0].styles.fontWeight === 'bold' ? 'normal' : 'bold' } })} className={`p-2 border rounded-xl text-xs ${selectedElements[0].styles.fontWeight === 'bold' ? 'bg-[#E4002B] text-white' : ''}`}><i className="fas fa-bold"></i></button>
                           <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { fontStyle: selectedElements[0].styles.fontStyle === 'italic' ? 'normal' : 'italic' } })} className={`p-2 border rounded-xl text-xs ${selectedElements[0].styles.fontStyle === 'italic' ? 'bg-[#E4002B] text-white' : ''}`}><i className="fas fa-italic"></i></button>
                        </div>
                     )}
                   </section>

                   <section className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Estilo de Fondo</label>
                      <div className="flex items-center gap-4 bg-slate-50 p-3 rounded-xl border">
                        <input type="color" value={selectedElements[0].styles.backgroundColor} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { backgroundColor: e.target.value, gradient: { enabled: false, from: '', to: '', angle: 0 } } })} className="w-8 h-8 rounded-full border-none cursor-pointer" />
                        <span className="text-[10px] font-bold text-slate-500 uppercase">Sólido</span>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-xl border space-y-3">
                         <div className="flex justify-between items-center"><span className="text-[9px] font-black uppercase text-slate-400">Degradado</span><input type="checkbox" checked={selectedElements[0].styles.gradient?.enabled} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { gradient: { ...selectedElements[0].styles.gradient!, enabled: e.target.checked, from: '#E4002B', to: '#000000', angle: 135 } } })} /></div>
                         {selectedElements[0].styles.gradient?.enabled && (
                           <div className="flex gap-2"><input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { gradient: { ...selectedElements[0].styles.gradient!, from: e.target.value } } })} className="flex-1 h-6"/><input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { gradient: { ...selectedElements[0].styles.gradient!, to: e.target.value } } })} className="flex-1 h-6"/></div>
                         )}
                      </div>
                   </section>
                 </>
               )}

               {activePropertyTab === 'interact' && (
                 <section className="space-y-4">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Acción al Click</label>
                    <select className="w-full bg-slate-50 border rounded-xl text-xs p-3 outline-none" value={selectedElements[0].interactivity.type} onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { type: e.target.value as InteractivityType, value: '' } })}>
                       <option value={InteractivityType.NONE}>Ninguna</option>
                       <option value={InteractivityType.GOTO_PAGE}>Ir a Página</option>
                       <option value={InteractivityType.EXTERNAL_LINK}>Enlace Externo</option>
                    </select>
                    {selectedElements[0].interactivity.type === InteractivityType.GOTO_PAGE && (
                       <select className="w-full bg-white border rounded-xl text-xs p-3" value={selectedElements[0].interactivity.value} onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { value: e.target.value } })}>
                          <option value="">Seleccionar página...</option>
                          {project.pages.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                       </select>
                    )}
                 </section>
               )}

               {activePropertyTab === 'effects' && (
                 <section className="space-y-6">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Sombra (Shadow)</label>
                       <input type="range" min="0" max="50" value={selectedElements[0].styles.shadowBlur} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { shadowBlur: parseInt(e.target.value), shadowOffsetX: 0, shadowOffsetY: 5 } })} className="w-full accent-[#E4002B]" />
                       <input type="color" value={selectedElements[0].styles.shadowColor} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { shadowColor: e.target.value } })} className="w-full h-8 rounded border-none cursor-pointer" />
                    </div>
                    <div className="space-y-4 border-t pt-4">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones UX</label>
                       <div className="space-y-2">
                          <span className="text-[8px] font-bold text-slate-400 uppercase">Entrada</span>
                          <select className="w-full bg-slate-50 border rounded-xl text-xs p-2" value={selectedElements[0].styles.entranceAnimation} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { entranceAnimation: e.target.value as any } })}>
                             <option value="none">Ninguna</option><option value="fade">Fade</option><option value="slide">Slide</option><option value="zoom">Zoom</option><option value="back">Back</option>
                          </select>
                       </div>
                    </div>
                 </section>
               )}
             </div>
          </aside>
        )}
      </div>

      {contextMenu && (
        <div className="fixed bg-white border shadow-2xl z-[1000] rounded-xl py-2 w-48" style={{ left: contextMenu.x, top: contextMenu.y }}>
           <button onClick={handleDuplicateSelected} className="w-full px-4 py-2 text-left text-xs hover:bg-slate-50"><i className="fas fa-clone mr-2"></i> Duplicar</button>
           <button onClick={() => { handleUpdateElement(selectedElementIds[0], { isLocked: true }); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-xs hover:bg-slate-50"><i className="fas fa-lock mr-2"></i> Bloquear</button>
           <div className="h-px bg-slate-100 my-1"/>
           <button onClick={() => { setProject({ ...project, pages: project.pages.map(p => ({ ...p, elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) })) }); setSelectedElementIds([]); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-xs hover:bg-red-50 text-[#E4002B]"><i className="fas fa-trash mr-2"></i> Eliminar</button>
        </div>
      )}

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'fade' | 'slide' | 'zoom' | 'back' | 'bounce' | 'flip' | 'pop' | 'lift' | 'glow' | 'rotate' | 'exit-fade' | 'exit-zoom';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentación (16:9)' },
  square: { width: 600, height: 600, label: 'Cuadrado (1:1)' },
  vertical: { width: 400, height: 711, label: 'Móvil (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Vertical' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  isVisible: boolean;
  isLocked: boolean;
  styles: {
    backgroundColor?: string;
    gradient?: {
      enabled: boolean;
      from: string;
      to: string;
      angle: number;
    };
    color?: string;
    fontSize?: number;
    borderRadius?: number;
    fontWeight?: string;
    fontStyle?: 'normal' | 'italic';
    textTransform?: 'none' | 'uppercase';
    letterSpacing?: number;
    lineHeight?: number;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    rotation?: number;
    borderWidth?: number;
    borderColor?: string;
    // Efectos
    shadowBlur: number;
    shadowColor: string;
    shadowOffsetX: number;
    shadowOffsetY: number;
    glowBlur: number;
    glowColor: string;
    // Filtros
    brightness: number;
    contrast: number;
    saturate: number;
    // Animaciones
    hoverAnimation?: AnimationType;
    entranceAnimation?: AnimationType;
    exitAnimation?: AnimationType;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
  };
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
  groups: any[];
  background?: {
    type: 'color' | 'gradient' | 'image';
    value: string;
  };
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
  canvasPreset: CanvasPreset;
}

import React, { useState, useEffect, useMemo } from 'react';
import { CanvasElement, InteractivityType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onResizeStart: (e: React.MouseEvent, handle: string) => void;
  onRotateStart?: (e: React.MouseEvent) => void;
  isPreview?: boolean;
  onNavigate?: (target: string | number) => void;
  onOpenContextMenu?: (e: React.MouseEvent) => void;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ 
  element, isSelected, onSelect, onResizeStart, onRotateStart, isPreview, onNavigate, onOpenContextMenu 
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [showEntrance, setShowEntrance] = useState(false);

  useEffect(() => {
    setShowEntrance(true);
  }, []);

  if (!element.isVisible && !isPreview) return null;
  if (!element.isVisible && isPreview) return null;

  const getStyle = (): React.CSSProperties => {
    const s = element.styles;
    const background = s.gradient?.enabled 
      ? `linear-gradient(${s.gradient.angle}deg, ${s.gradient.from} 0%, ${s.gradient.to} 100%)` 
      : s.backgroundColor;

    // Sombra Inteligente: Box shadow para formas/botones, Text shadow para texto
    const shadowStr = s.shadowBlur > 0 
      ? `${s.shadowOffsetX}px ${s.shadowOffsetY}px ${s.shadowBlur}px ${s.shadowColor}` 
      : 'none';

    // Resplandor (Glow)
    const glowStr = s.glowBlur > 0 
      ? `0 0 ${s.glowBlur}px ${s.glowColor}` 
      : '';

    const combinedShadow = [shadowStr, glowStr].filter(Boolean).join(', ');

    return {
      position: 'absolute',
      left: element.x,
      top: element.y,
      width: element.width,
      height: element.height,
      zIndex: s.zIndex,
      background: element.type === 'image' || element.type === 'text' ? 'transparent' : background,
      color: s.color,
      fontSize: s.fontSize,
      fontFamily: s.fontFamily || 'Inter',
      fontWeight: s.fontWeight || 'normal',
      fontStyle: s.fontStyle || 'normal',
      textTransform: s.textTransform || 'none',
      letterSpacing: `${s.letterSpacing || 0}px`,
      lineHeight: s.lineHeight || 1.2,
      textAlign: s.textAlign,
      borderRadius: `${s.borderRadius || 0}px`,
      opacity: s.opacity,
      border: s.borderWidth ? `${s.borderWidth}px solid ${s.borderColor || '#000'}` : 'none',
      boxShadow: element.type !== 'text' ? combinedShadow : 'none',
      textShadow: element.type === 'text' ? shadowStr : 'none',
      display: 'flex',
      alignItems: 'center',
      justifyContent: s.textAlign === 'center' ? 'center' : (s.textAlign === 'right' ? 'flex-end' : 'flex-start'),
      transform: `rotate(${s.rotation || 0}deg) ${isPreview && isHovered && s.hoverAnimation === 'pop' ? 'scale(1.05)' : ''}`,
      filter: element.type === 'image' ? `brightness(${s.brightness}%) contrast(${s.contrast}%) saturate(${s.saturate}%)` : 'none',
      clipPath: element.type === 'shape' ? getClipPath(element.content) : 'none',
      cursor: isPreview ? (element.interactivity.type !== InteractivityType.NONE ? 'pointer' : 'default') : (element.isLocked ? 'not-allowed' : 'move'),
      pointerEvents: element.isLocked && !isPreview ? 'none' : 'auto',
      transition: 'all 0.2s ease-out'
    };
  };

  const animationClass = useMemo(() => {
    let cls = [];
    if (showEntrance && element.styles.entranceAnimation && element.styles.entranceAnimation !== 'none') {
      cls.push(`anim-entrance-${element.styles.entranceAnimation}`);
    }
    if (isPreview && isHovered) {
      if (element.styles.hoverAnimation === 'glow') cls.push('ring-4 ring-white/50');
      if (element.styles.hoverAnimation === 'lift') cls.push('-translate-y-2');
    }
    return cls.join(' ');
  }, [showEntrance, isHovered, element.styles.entranceAnimation, isPreview, element.styles.hoverAnimation]);

  return (
    <div
      style={getStyle()}
      className={`${isSelected && !isPreview ? 'ring-2 ring-[#E4002B] ring-offset-4' : ''} ${animationClass}`}
      onMouseDown={(e) => { if (!isPreview && !element.isLocked) onSelect(e); }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onContextMenu={(e) => { if (!isPreview) { e.preventDefault(); onOpenContextMenu?.(e); } }}
      onClick={() => {
        if (isPreview && element.interactivity.type === InteractivityType.GOTO_PAGE) onNavigate?.(element.interactivity.value);
        if (isPreview && element.interactivity.type === InteractivityType.EXTERNAL_LINK) window.open(element.interactivity.value, '_blank');
      }}
    >
      {element.type === 'image' ? (
        <img src={element.content} className="w-full h-full object-contain pointer-events-none" style={{ borderRadius: 'inherit' }} alt="" />
      ) : element.type === 'video' ? (
        <video src={element.content} className="w-full h-full object-cover" controls={isPreview} style={{ borderRadius: 'inherit' }} />
      ) : (
        <span className="w-full px-2 break-words select-none pointer-events-none">{element.type === 'shape' ? '' : element.content}</span>
      )}

      {isSelected && !isPreview && !element.isLocked && (
        <>
          {['tl', 'tr', 'bl', 'br'].map(h => (
            <div 
              key={h} 
              onMouseDown={(e) => { e.stopPropagation(); onResizeStart(e, h); }} 
              className="absolute w-3 h-3 bg-white border-2 border-[#E4002B] rounded-full z-[120] shadow-sm" 
              style={getHandleStyle(h)} 
            />
          ))}
          <div onMouseDown={(e) => { e.stopPropagation(); onRotateStart?.(e); }} className="absolute -top-10 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-2 border-[#E4002B] rounded-full flex items-center justify-center cursor-alias shadow-lg"><i className="fas fa-redo text-[10px] text-[#E4002B]"></i></div>
          <button onClick={(e) => { e.stopPropagation(); onOpenContextMenu?.(e); }} className="absolute -bottom-10 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-3 py-1.5 rounded-full text-[9px] font-black uppercase flex items-center gap-2 shadow-xl hover:bg-black transition-all">Acciones <i className="fas fa-ellipsis-v"></i></button>
        </>
      )}
    </div>
  );
};

function getClipPath(shape: string) {
  switch (shape) {
    case 'circle': return 'circle(50% at 50% 50%)';
    case 'triangle': return 'polygon(50% 0%, 0% 100%, 100% 100%)';
    case 'star': return 'polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%)';
    case 'diamond': return 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)';
    case 'heart': return 'path("M 10,30 A 20,20 0,0,1 50,30 A 20,20 0,0,1 90,30 Q 90,60 50,90 Q 10,60 10,30 Z")';
    default: return 'none';
  }
}

function getHandleStyle(h: string): React.CSSProperties {
  const o = '-6px';
  switch (h) {
    case 'tl': return { top: o, left: o, cursor: 'nwse-resize' };
    case 'tr': return { top: o, right: o, cursor: 'nesw-resize' };
    case 'bl': return { bottom: o, left: o, cursor: 'nesw-resize' };
    case 'br': return { bottom: o, right: o, cursor: 'nwse-resize' };
    default: return {};
  }
}

export default ElementRenderer;

import React, { useState, useRef } from 'react';
import { ElementType, CanvasPreset, ProjectPage, CanvasElement } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
  currentPage: ProjectPage;
  selectedElementIds: string[];
  onSelectElements: (ids: string[]) => void;
  onUpdateBackground: (bg: any) => void;
  pages: ProjectPage[];
  currentPageIndex: number;
  onNavigatePage: (index: number) => void;
  onAddPage: () => void;
  onUpdateElement: (id: string, updates: Partial<CanvasElement>) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  onAddElement, currentPage, selectedElementIds, onSelectElements, onUpdateBackground,
  pages, currentPageIndex, onNavigatePage, onAddPage, onUpdateElement
}) => {
  const [activePanel, setActivePanel] = useState<'pages' | 'text' | 'resources' | 'ai' | 'bg' | 'media'>('pages');
  const [pagesSubTab, setPagesSubTab] = useState<'outline' | 'layers'>('outline');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadType, setUploadType] = useState<ElementType>('image');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => onAddElement(uploadType, event.target?.result as string);
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  const triggerUpload = (type: ElementType) => {
    setUploadType(type);
    fileInputRef.current?.click();
  };

  return (
    <div className="flex h-full bg-[#111118] z-[100] shadow-2xl">
      <div className="w-18 bg-black flex flex-col items-center py-8 gap-8 border-r border-white/5">
        <NavIcon active={activePanel === 'pages'} icon="fa-layer-group" onClick={() => setActivePanel('pages')} label="Capas" />
        <NavIcon active={activePanel === 'text'} icon="fa-font" onClick={() => setActivePanel('text')} label="Texto" />
        <NavIcon active={activePanel === 'resources'} icon="fa-shapes" onClick={() => setActivePanel('resources')} label="Formas" />
        <NavIcon active={activePanel === 'media'} icon="fa-photo-film" onClick={() => setActivePanel('media')} label="Medios" />
        <NavIcon active={activePanel === 'bg'} icon="fa-palette" onClick={() => setActivePanel('bg')} label="Tema" />
      </div>

      <div className="w-72 flex flex-col bg-white border-r border-slate-200">
        <div className="h-16 flex items-center px-6 border-b bg-slate-50/50">
          <h2 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{activePanel}</h2>
        </div>

        <div className="flex-1 overflow-y-auto px-6 py-8 scrollbar-hide">
          <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileUpload} accept={uploadType === 'image' ? 'image/*' : uploadType === 'audio' ? 'audio/*' : 'video/*'} />

          {activePanel === 'media' && (
            <div className="space-y-4">
              <button onClick={() => triggerUpload('image')} className="w-full p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl flex items-center gap-4 hover:border-[#E4002B] transition-all group">
                <i className="fas fa-image text-slate-400 group-hover:text-[#E4002B]"></i>
                <span className="text-[10px] font-black uppercase text-slate-800">Subir Imagen</span>
              </button>
              <button onClick={() => triggerUpload('video')} className="w-full p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl flex items-center gap-4 hover:border-[#E4002B] transition-all group">
                <i className="fas fa-video text-slate-400 group-hover:text-[#E4002B]"></i>
                <span className="text-[10px] font-black uppercase text-slate-800">Subir Video</span>
              </button>
            </div>
          )}

          {activePanel === 'pages' && (
            <div className="space-y-6">
               <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setPagesSubTab('outline')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'outline' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Páginas</button>
                  <button onClick={() => setPagesSubTab('layers')} className={`flex-1 py-1.5 text-[10px] font-black rounded transition-all ${pagesSubTab === 'layers' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400'}`}>Capas</button>
               </div>

               {pagesSubTab === 'outline' ? (
                 <div className="space-y-3">
                    {pages.map((p, idx) => (
                       <div key={p.id} onClick={() => onNavigatePage(idx)} className={`p-4 rounded-2xl border transition-all cursor-pointer ${currentPageIndex === idx ? 'border-[#E4002B] bg-red-50/50' : 'border-slate-100 bg-white hover:border-slate-300'}`}>
                          <div className="text-xs font-bold text-slate-900">{p.name}</div>
                       </div>
                    ))}
                    <button onClick={onAddPage} className="w-full py-3 border-2 border-dashed border-slate-200 rounded-2xl text-[10px] font-black text-slate-400 hover:border-[#E4002B] hover:text-[#E4002B] uppercase">+ Nueva Página</button>
                 </div>
               ) : (
                 <div className="space-y-2">
                    {[...currentPage.elements].reverse().map(el => (
                      <div 
                        key={el.id} 
                        onClick={() => onSelectElements([el.id])}
                        className={`p-3 rounded-xl border flex items-center gap-3 transition-all ${selectedElementIds.includes(el.id) ? 'bg-red-50 border-[#E4002B]' : 'bg-white border-slate-100 hover:border-slate-300'}`}
                      >
                         <i className={`fas ${el.type === 'text' ? 'fa-font' : 'fa-square'} text-[10px] text-slate-400`}></i>
                         <span className="text-[10px] font-bold truncate flex-1 uppercase">{el.type}</span>
                         <div className="flex gap-2">
                            <button onClick={(e) => { e.stopPropagation(); onUpdateElement(el.id, { isVisible: !el.isVisible }); }} className={`w-6 h-6 rounded flex items-center justify-center transition-colors ${el.isVisible ? 'text-slate-400 hover:text-slate-900' : 'text-[#E4002B]'}`}>
                               <i className={`fas ${el.isVisible ? 'fa-eye' : 'fa-eye-slash'}`}></i>
                            </button>
                            <button onClick={(e) => { e.stopPropagation(); onUpdateElement(el.id, { isLocked: !el.isLocked }); }} className={`w-6 h-6 rounded flex items-center justify-center transition-colors ${el.isLocked ? 'text-[#E4002B]' : 'text-slate-400 hover:text-slate-900'}`}>
                               <i className={`fas ${el.isLocked ? 'fa-lock' : 'fa-lock-open'}`}></i>
                            </button>
                         </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}

          {activePanel === 'resources' && (
             <div className="grid grid-cols-2 gap-4">
                {['square', 'circle', 'triangle', 'star', 'diamond', 'heart'].map(s => (
                   <button key={s} onClick={() => onAddElement('shape', s)} className="p-4 bg-slate-50 border border-slate-200 rounded-2xl flex flex-col items-center gap-2 hover:border-[#E4002B] transition-all">
                      <i className={`fas fa-${s === 'triangle' ? 'play fa-rotate-270' : s} text-xl text-slate-400`}></i>
                      <span className="text-[8px] font-bold uppercase text-slate-400">{s}</span>
                   </button>
                ))}
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

const NavIcon: React.FC<{ active: boolean; icon: string; onClick: () => void; label: string }> = ({ active, icon, onClick, label }) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-2 transition-all ${active ? 'text-white' : 'text-slate-600 hover:text-white'}`}>
    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${active ? 'bg-[#E4002B]' : 'bg-white/5'}`}>
       <i className={`fas ${icon} text-lg`}></i>
    </div>
    <span className="text-[8px] font-black uppercase">{label}</span>
  </button>
);

export default Sidebar;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, ProjectPage } from './types';
import { generateAIImage } from './services/geminiService';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [history, setHistory] = useState<Project[]>([INITIAL_PROJECT]);
  const [historyIndex, setHistoryIndex] = useState(0);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [clipboard, setClipboard] = useState<CanvasElement[]>([]);
  const [activePropertyTab, setActivePropertyTab] = useState<'design' | 'interact' | 'effects'>('design');
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number } | null>(null);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElements = useMemo(() => currentPage.elements.filter(el => selectedElementIds.includes(el.id)), [currentPage.elements, selectedElementIds]);

  const pushToHistory = useCallback((newProject: Project) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newProject)));
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  const handleUpdateElement = useCallback((id: string, updates: any, silent = false) => {
    setProject(prev => {
      const next = {
        ...prev,
        pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
          ...p,
          elements: p.elements.map(el => el.id === id ? ({ 
            ...el, 
            ...updates, 
            styles: { ...el.styles, ...(updates.styles || {}) },
            interactivity: { ...el.interactivity, ...(updates.interactivity || {}) }
          } as CanvasElement) : el)
        }) : p)
      };
      if (!silent) pushToHistory(next);
      return next;
    });
  }, [currentPageIndex, pushToHistory]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30, y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, ...newEls] } : p) };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newEls.map(e => e.id));
    setContextMenu(null);
  }, [selectedElements, currentPageIndex, currentPage.elements, project, pushToHistory]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = mousePosRef.current.x - actionState.startX;
    const dy = mousePosRef.current.y - actionState.startY;

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2);
      const centerY = rect.top + (el.y + el.height / 2);
      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      handleUpdateElement(target.id, { styles: { rotation: Math.round(angle + 90) } }, true);
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x, y, w, h } = target;
      const han = actionState.handle;
      if (han.includes('r')) w = Math.max(10, target.w + dx);
      if (han.includes('l')) { const diff = Math.min(dx, target.w - 10); w = target.w - diff; x = target.x + diff; }
      if (han.includes('b')) h = Math.max(10, target.h + dy);
      if (han.includes('t')) { const diff = Math.min(dy, target.h - 10); h = target.h - diff; y = target.y + diff; }
      handleUpdateElement(target.id, { x, y, width: w, height: h }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: init.x + dx, y: init.y + dy }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, handleUpdateElement, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    } else if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = Math.min(marquee.startX, marquee.currentX) - rect.left;
      const y1 = Math.min(marquee.startY, marquee.currentY) - rect.top;
      const x2 = Math.max(marquee.startX, marquee.currentX) - rect.left;
      const y2 = Math.max(marquee.startY, marquee.currentY) - rect.top;
      const hitIds = currentPage.elements.filter(el => el.isVisible && !el.isLocked && el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) pushToHistory(project);
    setMarquee(null); setActionState(null);
  }, [marquee, currentPage.elements, project, pushToHistory, actionState]);

  useEffect(() => {
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => { window.removeEventListener('mousemove', onMouseMove); window.removeEventListener('mouseup', onMouseUp); };
  }, [onMouseMove, onMouseUp]);

  const handleCopy = () => {
    if (selectedElements.length > 0) {
      setClipboard(JSON.parse(JSON.stringify(selectedElements)));
      setContextMenu(null);
    }
  };

  const handlePaste = () => {
    if (clipboard.length > 0) {
      const newEls = clipboard.map(el => ({
        ...el,
        id: `el-${Date.now()}-${Math.random()}`,
        x: el.x + 40, y: el.y + 40,
        styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
      }));
      setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, ...newEls] } : p) });
      pushToHistory(project);
      setSelectedElementIds(newEls.map(e => e.id));
      setContextMenu(null);
    }
  };

  const handleDelete = () => {
    setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) } : p) });
    setSelectedElementIds([]);
    setContextMenu(null);
  };

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none" onClick={() => setContextMenu(null)}>
      <Toolbar 
        selectedElement={selectedElements[0] || null} isPreview={isPreview} projectTitle={project.title}
        onPreview={() => setIsPreview(!isPreview)} onPublish={() => setShowPublishModal(true)}
        onUndo={() => { if (historyIndex > 0) { setProject(history[historyIndex - 1]); setHistoryIndex(historyIndex - 1); } }}
        onRedo={() => { if (historyIndex < history.length - 1) { setProject(history[historyIndex + 1]); setHistoryIndex(historyIndex + 1); } }}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1} onUpdateTitle={(t) => setProject({ ...project, title: t })}
      />

      <div className="flex flex-1 overflow-hidden">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 100, y: 100, width: type === 'text' ? 300 : 200, height: type === 'text' ? 80 : 200, isVisible: true, isLocked: false,
                content: content || (type === 'text' ? 'Nuevo Texto' : ''),
                styles: { 
                  backgroundColor: type === 'shape' ? '#E4002B' : 'transparent', color: type === 'text' ? '#000000' : '#FFFFFF', fontSize: 24, zIndex: currentPage.elements.length, opacity: 1,
                  shadowBlur: 0, shadowColor: 'rgba(0,0,0,0.3)', shadowOffsetX: 0, shadowOffsetY: 0, glowBlur: 0, glowColor: '#FFFFFF',
                  brightness: 100, contrast: 100, saturate: 100, rotation: 0, borderRadius: 0, textAlign: 'center',
                  fontFamily: 'Inter', fontWeight: 'normal', fontStyle: 'normal', textTransform: 'none', letterSpacing: 0, lineHeight: 1.2,
                  entranceAnimation: 'fade', hoverAnimation: 'none'
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, el] } : p) });
              pushToHistory(project);
              setSelectedElementIds([el.id]);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => { const np: ProjectPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [] }; setProject({ ...project, pages: [...project.pages, np] }); setCurrentPageIndex(project.pages.length); }}
            currentPage={currentPage} selectedElementIds={selectedElementIds} onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject({...project, pages: project.pages.map((p, i) => i === currentPageIndex ? {...p, background: bg} : p)})} onUpdateElement={handleUpdateElement}
            onUpdatePreset={() => {}} canvasPreset={project.canvasPreset} onBulkAdd={() => {}}
          />
        )}

        <main className={`flex-1 overflow-auto bg-[#E5E5E5] flex justify-center items-center relative ${isPreview ? 'p-0' : 'p-20'}`} ref={containerRef} onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}>
          <div ref={canvasRef} className={`relative bg-white shadow-2xl transition-all ${isPreview ? 'w-full h-full' : 'border border-slate-300'}`} style={{ width: isPreview ? '100%' : `${currentDimensions.width}px`, height: isPreview ? '100%' : `${currentDimensions.height}px`, backgroundColor: currentPage.background?.value || '#FFFFFF' }}>
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)} isPreview={isPreview}
                onSelect={(e) => { 
                  e.stopPropagation(); 
                  setSelectedElementIds(e.shiftKey ? [...selectedElementIds, el.id] : [el.id]); 
                  if (!e.shiftKey) setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}] }); 
                }}
                onResizeStart={(e, h) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}], handle:h }); }}
                onRotateStart={(e) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}], handle:'rot' }); }}
                onOpenContextMenu={(e) => setContextMenu({ x: e.clientX, y: e.clientY })}
              />
            ))}
            {marquee && (
              <div className="fixed border border-[#E4002B] bg-[#E4002B]/10 z-[1000] pointer-events-none" style={{ left: Math.min(marquee.startX, marquee.currentX), top: Math.min(marquee.startY, marquee.currentY), width: Math.abs(marquee.startX - marquee.currentX), height: Math.abs(marquee.startY - marquee.currentY) }} />
            )}
          </div>
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-[300] shadow-2xl overflow-y-auto scrollbar-hide">
             <div className="flex bg-slate-50 border-b">
                {['design', 'interact', 'effects'].map((tab) => (
                  <button key={tab} onClick={() => setActivePropertyTab(tab as any)} className={`flex-1 py-4 text-[9px] font-black uppercase tracking-widest transition-all ${activePropertyTab === tab ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}>
                    {tab === 'design' ? 'Diseño' : tab === 'interact' ? 'Interacción' : 'Efectos'}
                  </button>
                ))}
             </div>

             <div className="p-6 space-y-8 pb-32">
               {activePropertyTab === 'design' && (
                 <>
                   <section className="space-y-4">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs p-3 outline-none resize-none h-20 focus:ring-1 focus:ring-[#E4002B]" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />
                     {selectedElements[0].type === 'text' && (
                        <div className="space-y-3">
                           <div className="grid grid-cols-4 gap-2">
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { fontWeight: selectedElements[0].styles.fontWeight === 'bold' ? 'normal' : 'bold' } })} className={`p-2 border rounded-xl text-xs ${selectedElements[0].styles.fontWeight === 'bold' ? 'bg-[#E4002B] text-white' : 'bg-white'}`}><i className="fas fa-bold"></i></button>
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { fontStyle: selectedElements[0].styles.fontStyle === 'italic' ? 'normal' : 'italic' } })} className={`p-2 border rounded-xl text-xs ${selectedElements[0].styles.fontStyle === 'italic' ? 'bg-[#E4002B] text-white' : 'bg-white'}`}><i className="fas fa-italic"></i></button>
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textTransform: selectedElements[0].styles.textTransform === 'uppercase' ? 'none' : 'uppercase' } })} className={`p-2 border rounded-xl text-xs ${selectedElements[0].styles.textTransform === 'uppercase' ? 'bg-[#E4002B] text-white' : 'bg-white'}`}><i className="fas fa-font"></i></button>
                              <input type="color" value={selectedElements[0].styles.color} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { color: e.target.value } })} className="w-full h-full rounded-xl border cursor-pointer" />
                           </div>
                           <div className="grid grid-cols-2 gap-4">
                              <div className="space-y-1">
                                 <label className="text-[8px] font-black text-slate-400 uppercase">Interlineado</label>
                                 <input type="range" min="0.5" max="3" step="0.1" value={selectedElements[0].styles.lineHeight} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { lineHeight: parseFloat(e.target.value) } })} className="w-full accent-[#E4002B]" />
                              </div>
                              <div className="space-y-1">
                                 <label className="text-[8px] font-black text-slate-400 uppercase">Espaciado</label>
                                 <input type="range" min="-5" max="20" step="1" value={selectedElements[0].styles.letterSpacing} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { letterSpacing: parseInt(e.target.value) } })} className="w-full accent-[#E4002B]" />
                              </div>
                           </div>
