                             <select className="w-full bg-slate-50 border rounded-xl text-xs p-2 outline-none" value={selectedElements[0].styles.hoverAnimation} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { hoverAnimation: e.target.value as any } })}>
