                content: content || (type === 'text' ? 'Escribe aquí' : ''),
                styles: { 
                  backgroundColor: type === 'shape' ? '#E4002B' : 'transparent', color: type === 'text' ? '#000000' : '#FFFFFF', fontSize: 24, zIndex: currentPage.elements.length, opacity: 1,
                  shadowBlur: 0, shadowColor: 'rgba(0,0,0,0.3)', shadowOffsetX: 0, shadowOffsetY: 0, glowBlur: 0, glowColor: '#FFFFFF',
                  brightness: 100, contrast: 100, saturate: 100, rotation: 0, borderRadius: 0, textAlign: 'center',
                  fontFamily: 'Inter', fontWeight: 'normal', fontStyle: 'normal', textTransform: 'none', letterSpacing: 0, lineHeight: 1.2,
                  entranceAnimation: 'fade', hoverAnimation: 'none'
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, el] } : p) });
              pushToHistory(project);
              setSelectedElementIds([el.id]);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => { const np: ProjectPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [] }; setProject({ ...project, pages: [...project.pages, np] }); setCurrentPageIndex(project.pages.length); }}
            currentPage={currentPage} selectedElementIds={selectedElementIds} onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject({...project, pages: project.pages.map((p, i) => i === currentPageIndex ? {...p, background: bg} : p)})} onUpdateElement={handleUpdateElement}
            onUpdatePreset={() => {}} canvasPreset={project.canvasPreset} onBulkAdd={() => {}}
          />
