  const [contextMenu, setContextMenu] = useState<{ x: number, y: number } | null>(null);

  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElements = useMemo(() => currentPage.elements.filter(el => selectedElementIds.includes(el.id)), [currentPage.elements, selectedElementIds]);

  const pushToHistory = useCallback((newProject: Project) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newProject)));
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  const handleUpdateElement = useCallback((id: string, updates: any, silent = false) => {
    setProject(prev => {
      const next = {
        ...prev,
        pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
          ...p,
          elements: p.elements.map(el => el.id === id ? ({ 
            ...el, 
            ...updates, 
            styles: { ...el.styles, ...(updates.styles || {}) },
            interactivity: { ...el.interactivity, ...(updates.interactivity || {}) }
          } as CanvasElement) : el)
        }) : p)
      };
      if (!silent) pushToHistory(next);
      return next;
    });
  }, [currentPageIndex, pushToHistory]);

  const handleGroupSelected = useCallback(() => {
    if (selectedElementIds.length < 2) return;
    const groupId = `group-${Date.now()}`;
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? {
        ...p,
        elements: p.elements.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId } : el),
        groups: [...p.groups, { id: groupId, name: `Grupo ${p.groups.length + 1}` }]
      } : p)
    }));
    pushToHistory(project);
    setContextMenu(null);
  }, [selectedElementIds, currentPageIndex, project, pushToHistory]);

  const handleUngroupSelected = useCallback(() => {
    if (selectedElementIds.length === 0) return;
    const groupIdsToClear = Array.from(new Set(selectedElements.map(el => el.groupId).filter(Boolean)));
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map((p, idx) => idx === currentPageIndex ? {
        ...p,
        elements: p.elements.map(el => el.groupId && groupIdsToClear.includes(el.groupId) ? { ...el, groupId: undefined } : el),
        groups: p.groups.filter(g => !groupIdsToClear.includes(g.id))
      } : p)
    }));
    pushToHistory(project);
    setContextMenu(null);
  }, [selectedElements, selectedElementIds, currentPageIndex, project, pushToHistory]);

  const handleDuplicateSelected = useCallback(() => {
    if (selectedElements.length === 0) return;
    const newEls = selectedElements.map(el => ({
      ...el,
      id: `el-${Date.now()}-${Math.random()}`,
      x: el.x + 30, y: el.y + 30,
      styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
    }));
    const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, ...newEls] } : p) };
    setProject(next);
    pushToHistory(next);
    setSelectedElementIds(newEls.map(e => e.id));
    setContextMenu(null);
  }, [selectedElements, currentPageIndex, currentPage.elements, project, pushToHistory]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = mousePosRef.current.x - actionState.startX;
    const dy = mousePosRef.current.y - actionState.startY;

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2);
      const centerY = rect.top + (el.y + el.height / 2);
      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      handleUpdateElement(target.id, { styles: { rotation: Math.round(angle + 90) } }, true);
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x, y, w, h } = target;
      const han = actionState.handle;
      if (han.includes('r')) w = Math.max(10, target.w + dx);
      if (han.includes('l')) { const diff = Math.min(dx, target.w - 10); w = target.w - diff; x = target.x + diff; }
      if (han.includes('b')) h = Math.max(10, target.h + dy);
      if (han.includes('t')) { const diff = Math.min(dy, target.h - 10); h = target.h - diff; y = target.y + diff; }
      handleUpdateElement(target.id, { x, y, width: w, height: h }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: init.x + dx, y: init.y + dy }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, handleUpdateElement, currentPage.elements]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) {
      setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    } else if (actionState && !requestRef.current) {
      requestRef.current = requestAnimationFrame(animateMove);
    }
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = Math.min(marquee.startX, marquee.currentX) - rect.left;
      const y1 = Math.min(marquee.startY, marquee.currentY) - rect.top;
      const x2 = Math.max(marquee.startX, marquee.currentX) - rect.left;
      const y2 = Math.max(marquee.startY, marquee.currentY) - rect.top;

      const hitIds = currentPage.elements.filter(el => 
        el.isVisible && !el.isLocked && 
        el.x < x2 && el.x + el.width > x1 && 
        el.y < y2 && el.y + el.height > y1
      ).map(el => el.id);

      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) pushToHistory(project);
    setMarquee(null); setActionState(null);
  }, [marquee, currentPage.elements, project, pushToHistory, actionState]);

  useEffect(() => {
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => { window.removeEventListener('mousemove', onMouseMove); window.removeEventListener('mouseup', onMouseUp); };
  }, [onMouseMove, onMouseUp]);

  const handleCopy = () => {
    if (selectedElements.length > 0) {
      setClipboard(JSON.parse(JSON.stringify(selectedElements)));
      setContextMenu(null);
    }
  };

  const handlePaste = () => {
    if (clipboard.length > 0) {
      const newEls = clipboard.map(el => ({
        ...el,
        id: `el-${Date.now()}-${Math.random()}`,
        x: el.x + 40, y: el.y + 40,
        styles: { ...el.styles, zIndex: currentPage.elements.length + 1 }
      }));
      setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, ...newEls] } : p) });
      pushToHistory(project);
      setSelectedElementIds(newEls.map(e => e.id));
      setContextMenu(null);
    }
  };

  const handleDelete = () => {
    setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) } : p) });
    setSelectedElementIds([]);
    setContextMenu(null);
  };

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none" onClick={() => setContextMenu(null)}>
      <Toolbar 
        selectedElement={selectedElements[0] || null} isPreview={isPreview} projectTitle={project.title}
        onPreview={() => setIsPreview(!isPreview)} onPublish={() => setShowPublishModal(true)}
        onUndo={() => { if (historyIndex > 0) { setProject(history[historyIndex - 1]); setHistoryIndex(historyIndex - 1); } }}
        onRedo={() => { if (historyIndex < history.length - 1) { setProject(history[historyIndex + 1]); setHistoryIndex(historyIndex + 1); } }}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1} onUpdateTitle={(t) => setProject({ ...project, title: t })}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 100, y: 100, width: type === 'text' ? 300 : 200, height: type === 'text' ? 60 : 200, isVisible: true, isLocked: false,
                content: content || (type === 'text' ? 'Escribe aquí' : ''),
                styles: { 
                  backgroundColor: type === 'shape' ? '#E4002B' : 'transparent', color: type === 'text' ? '#000000' : '#FFFFFF', fontSize: 24, zIndex: currentPage.elements.length, opacity: 1,
                  shadowBlur: 0, shadowColor: 'rgba(0,0,0,0.3)', shadowOffsetX: 0, shadowOffsetY: 0, glowBlur: 0, glowColor: '#FFFFFF',
                  brightness: 100, contrast: 100, saturate: 100, rotation: 0, borderRadius: 0, textAlign: 'center',
                  fontFamily: 'Inter', fontWeight: 'normal', fontStyle: 'normal', textTransform: 'none', letterSpacing: 0, lineHeight: 1.2,
                  entranceAnimation: 'fade', hoverAnimation: 'none'
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, el] } : p) });
              pushToHistory(project);
              setSelectedElementIds([el.id]);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={setCurrentPageIndex}
            onAddPage={() => { const np: ProjectPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [] }; setProject({ ...project, pages: [...project.pages, np] }); setCurrentPageIndex(project.pages.length); }}
            currentPage={currentPage} selectedElementIds={selectedElementIds} onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject({...project, pages: project.pages.map((p, i) => i === currentPageIndex ? {...p, background: bg} : p)})} onUpdateElement={handleUpdateElement}
            onUpdatePreset={() => {}} canvasPreset={project.canvasPreset} onBulkAdd={() => {}}
          />
        )}

        <main className={`flex-1 overflow-auto bg-[#f8f9fa] flex justify-center items-center relative transition-all duration-300 ${isPreview ? 'p-0' : 'p-16'}`} ref={containerRef} onMouseDown={(e) => {
            if (e.target === containerRef.current || e.target === canvasRef.current) {
              setSelectedElementIds([]);
              if (!isPreview) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY });
            }
          }}>

          {!isPreview && showRulers && (
            <>
              <div className="ruler-corner"></div>
              <div className="ruler ruler-h">
                 <div className="flex h-full items-center">
                    {Array.from({length: 40}).map((_, i) => <div key={i} className="w-10 border-l border-slate-300 h-2 pl-0.5">{i*100}</div>)}
                 </div>
              </div>
              <div className="ruler ruler-v">
                 <div className="flex flex-col w-full">
                    {Array.from({length: 40}).map((_, i) => <div key={i} className="h-10 border-t border-slate-300 w-2 pt-0.5 pl-0.5">{i*100}</div>)}
                 </div>
              </div>
            </>
          )}

          <div 
            ref={canvasRef} 
            className={`relative bg-white shadow-2xl transition-all ${showGrid && !isPreview ? 'canvas-grid' : ''} ${isPreview ? 'w-full h-full' : 'border border-slate-300'}`} 
            style={{ 
              width: isPreview ? '100%' : `${currentDimensions.width}px`, 
              height: isPreview ? '100%' : `${currentDimensions.height}px`, 
              backgroundColor: currentPage.background?.value || '#FFFFFF',
              minWidth: isPreview ? 'none' : `${currentDimensions.width}px`,
              minHeight: isPreview ? 'none' : `${currentDimensions.height}px`
            }}
          >
            {currentPage.elements.map(el => (
              <ElementRenderer 
                key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)} isPreview={isPreview}
                onSelect={(e) => { 
                  e.stopPropagation(); 
                  const targetIds = el.groupId 
                    ? currentPage.elements.filter(e => e.groupId === el.groupId).map(e => e.id)
                    : [el.id];

                  setSelectedElementIds(e.shiftKey ? Array.from(new Set([...selectedElementIds, ...targetIds])) : targetIds); 

                  if (!e.shiftKey) {
                    const initials = (el.groupId ? currentPage.elements.filter(e => e.groupId === el.groupId) : [el])
                      .map(item => ({ id: item.id, x: item.x, y: item.y, w: item.width, h: item.height, r: item.styles.rotation || 0 }));
                    setActionState({ ids: targetIds, startX: e.clientX, startY: e.clientY, initials }); 
                  }
                }}
                onResizeStart={(e, h) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}], handle:h }); }}
                onRotateStart={(e) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0}], handle:'rot' }); }}
                onOpenContextMenu={(e) => setContextMenu({ x: e.clientX, y: e.clientY })}
              />
            ))}
            {marquee && (
              <div className="fixed border border-[#E4002B] bg-[#E4002B]/10 z-[1000] pointer-events-none" style={{ left: Math.min(marquee.startX, marquee.currentX), top: Math.min(marquee.startY, marquee.currentY), width: Math.abs(marquee.startX - marquee.currentX), height: Math.abs(marquee.startY - marquee.currentY) }} />
            )}
          </div>

          {!isPreview && (
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur rounded-full shadow-2xl px-6 py-2 flex items-center gap-6 border border-slate-200 z-[400]">
               <button onClick={() => setShowGrid(!showGrid)} className={`flex items-center gap-2 text-[9px] font-black uppercase tracking-widest ${showGrid ? 'text-[#E4002B]' : 'text-slate-400'}`}>
                  <i className="fas fa-th"></i> Cuadrícula
               </button>
               <button onClick={() => setShowRulers(!showRulers)} className={`flex items-center gap-2 text-[9px] font-black uppercase tracking-widest ${showRulers ? 'text-[#E4002B]' : 'text-slate-400'}`}>
                  <i className="fas fa-ruler-combined"></i> Reglas
               </button>
               <div className="h-4 w-px bg-slate-200"></div>
               <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">
                  Canvas: {currentDimensions.width}x{currentDimensions.height}
               </div>
            </div>
          )}
        </main>

        {selectedElements.length > 0 && !isPreview && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-[300] shadow-2xl overflow-y-auto scrollbar-hide shrink-0">
             <div className="flex bg-slate-50 border-b">
                {['design', 'interact', 'effects'].map((tab) => (
                  <button key={tab} onClick={() => setActivePropertyTab(tab as any)} className={`flex-1 py-4 text-[9px] font-black uppercase tracking-widest transition-all ${activePropertyTab === tab ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}>
                    {tab === 'design' ? 'Diseño' : tab === 'interact' ? 'Interact & Anim' : 'Efectos'}
                  </button>
                ))}
             </div>

             <div className="p-6 space-y-8 pb-32">
               {activePropertyTab === 'design' && (
                 <>
                   <section className="space-y-4">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs p-3 outline-none resize-none h-20 focus:ring-1 focus:ring-[#E4002B]" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />

                     {(selectedElements[0].type === 'text' || selectedElements[0].type === 'shape') && (
                        <div className="space-y-4">
                           <div className="space-y-2">
                              <label className="text-[9px] font-black text-slate-400 uppercase">Tipografía</label>
                              <select 
                                className="w-full bg-slate-50 border rounded-xl text-xs p-2 outline-none" 
                                value={selectedElements[0].styles.fontFamily}
                                onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}
                              >
                                {FONT_FAMILIES.map(f => <option key={f} value={f}>{f}</option>)}
                              </select>
                           </div>

                           <div className="grid grid-cols-2 gap-2">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-400 uppercase">Peso</label>
                                <select 
                                  className="w-full bg-slate-50 border rounded-xl text-xs p-2 outline-none" 
                                  value={selectedElements[0].styles.fontWeight}
                                  onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontWeight: e.target.value } })}
                                >
                                  {FONT_WEIGHTS.map(w => <option key={w} value={w}>{w}</option>)}
                                </select>
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-400 uppercase">Estilo</label>
                                <div className="flex gap-1 h-9">
                                   <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { fontStyle: selectedElements[0].styles.fontStyle === 'italic' ? 'normal' : 'italic' } })} className={`flex-1 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.fontStyle === 'italic' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-italic"></i></button>
                                   <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textTransform: selectedElements[0].styles.textTransform === 'uppercase' ? 'none' : 'uppercase' } })} className={`flex-1 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textTransform === 'uppercase' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-font"></i></button>
                                </div>
                              </div>
                           </div>

                           <div className="grid grid-cols-4 gap-1">
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: 'left' } })} className={`p-2 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textAlign === 'left' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-align-left"></i></button>
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: 'center' } })} className={`p-2 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textAlign === 'center' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-align-center"></i></button>
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: 'right' } })} className={`p-2 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textAlign === 'right' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-align-right"></i></button>
                              <input type="color" value={selectedElements[0].styles.color} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { color: e.target.value } })} className="w-full h-full rounded-xl border border-slate-200 cursor-pointer overflow-hidden" />
                           </div>
                        </div>
                     )}
                   </section>

                   <section className="space-y-4 border-t pt-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Geometría</label>
                      <div className="space-y-4 p-4 bg-slate-50 rounded-xl border border-slate-200 shadow-sm">
                         <div className="space-y-1">
                            <div className="flex justify-between items-center"><span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Redondeado</span><span className="text-[9px] font-bold text-[#E4002B]">{selectedElements[0].styles.borderRadius}px</span></div>
                            <input type="range" min="0" max="200" value={selectedElements[0].styles.borderRadius} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { borderRadius: parseInt(e.target.value) } })} className="w-full accent-[#E4002B]" />
                         </div>
                      </div>
                   </section>
                 </>
               )}

               {activePropertyTab === 'interact' && (
                 <section className="space-y-8">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Interactividad</label>
                       <select className="w-full bg-slate-50 border rounded-xl text-xs p-3 outline-none focus:border-[#E4002B]" value={selectedElements[0].interactivity.type} onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { type: e.target.value as InteractivityType, value: '' } })}>
                          <option value={InteractivityType.NONE}>Ninguna (Estático)</option>
                          <option value={InteractivityType.GOTO_PAGE}>Saltar a Página</option>
                          <option value={InteractivityType.EXTERNAL_LINK}>Abrir Enlace Externo</option>
                       </select>

                       {selectedElements[0].interactivity.type === InteractivityType.GOTO_PAGE && (
                          <div className="space-y-2 animate-in slide-in-from-left-2 duration-300">
                             <select className="w-full bg-white border rounded-xl text-xs p-3 focus:ring-1 focus:ring-[#E4002B] outline-none" value={selectedElements[0].interactivity.value} onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { value: e.target.value } })}>
                                <option value="">-- Elige una página --</option>
                                {project.pages.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                             </select>
                          </div>
                       )}

                       {selectedElements[0].interactivity.type === InteractivityType.EXTERNAL_LINK && (
                          <input placeholder="https://ejemplo.com" className="w-full bg-white border rounded-xl text-xs p-3 outline-none focus:border-[#E4002B]" value={selectedElements[0].interactivity.value} onChange={(e) => handleUpdateElement(selectedElements[0].id, { interactivity: { value: e.target.value } })} />
                       )}
                    </div>

                    <div className="space-y-4 border-t pt-4">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Animaciones</label>
                       <div className="space-y-4">
                          <div className="space-y-1">
                             <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-1">Entrada</span>
                             <select className="w-full bg-slate-50 border rounded-xl text-xs p-3 focus:border-[#E4002B] outline-none" value={selectedElements[0].styles.entranceAnimation} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { entranceAnimation: e.target.value as any } })}>
                                <option value="none">Ninguna</option>
                                <option value="fade">Desvanecer</option>
                                <option value="zoom">Zoom</option>
                                <option value="bounce">Rebotar</option>
                                <option value="flip">Giro 3D</option>
                             </select>
                          </div>
                          <div className="space-y-1">
                             <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-1">Hover</span>
