           <button onClick={handleCopy} className="w-full px-4 py-2.5 text-left text-xs font-black uppercase tracking-tight hover:bg-slate-50 flex items-center gap-3 transition-colors"><i className="fas fa-copy text-slate-400"></i> Copiar</button>
