  const [isPagesView, setIsPagesView] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [clipboard, setClipboard] = useState<CanvasElement[]>([]);
  const [activePropertyTab, setActivePropertyTab] = useState<'design' | 'interact' | 'effects'>('design');
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number } | null>(null);

  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);
  const [zoom, setZoom] = useState(1);
  const [activeModalContent, setActiveModalContent] = useState<string | null>(null);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number, fs: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElements = useMemo(() => currentPage.elements.filter(el => selectedElementIds.includes(el.id)), [currentPage.elements, selectedElementIds]);

  const pushToHistory = useCallback((newProject: Project) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newProject)));
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  const handleUpdateElement = useCallback((id: string, updates: any, silent = false) => {
    setProject(prev => {
      const next = {
        ...prev,
        pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
          ...p,
          elements: p.elements.map(el => el.id === id ? ({ 
            ...el, 
            ...updates, 
            styles: { ...el.styles, ...(updates.styles || {}) },
            interactivity: { ...el.interactivity, ...(updates.interactivity || {}) }
          } as CanvasElement) : el)
        }) : p)
      };
      if (!silent) pushToHistory(next);
      return next;
    });
  }, [currentPageIndex, pushToHistory]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;
      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      handleUpdateElement(target.id, { styles: { rotation: Math.round(angle + 90) } }, true);
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x, y, w, h, fs } = target;
      const han = actionState.handle;
      if (han.includes('r')) w = Math.max(10, target.w + dx);
      if (han.includes('l')) { const diff = Math.min(dx, target.w - 10); w = target.w - diff; x = target.x + diff; }
      if (han.includes('b')) h = Math.max(10, target.h + dy);
      if (han.includes('t')) { const diff = Math.min(dy, target.h - 10); h = target.h - diff; y = target.y + diff; }

      // Scaling font size on resize
      const el = currentPage.elements.find(e => e.id === target.id);
      if (el && el.type === 'text') {
        const scaleX = w / target.w;
        const scaleY = h / target.h;
        const avgScale = (scaleX + scaleY) / 2;
        fs = Math.max(6, Math.round(target.fs * avgScale));
      }

      handleUpdateElement(target.id, { x, y, width: w, height: h, styles: { fontSize: fs } }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: init.x + dx, y: init.y + dy }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, handleUpdateElement, currentPage.elements, zoom]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    else if (actionState && !requestRef.current) requestRef.current = requestAnimationFrame(animateMove);
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const hitIds = currentPage.elements.filter(el => el.isVisible && !el.isLocked && el.x < x2 && el.x + el.width > x1 && el.y < y2 && el.y + el.height > y1).map(el => el.id);
      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) pushToHistory(project);
    setMarquee(null); setActionState(null);
  }, [marquee, currentPage.elements, project, pushToHistory, actionState, zoom]);

  useEffect(() => {
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => { window.removeEventListener('mousemove', onMouseMove); window.removeEventListener('mouseup', onMouseUp); };
  }, [onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none" onClick={() => setContextMenu(null)}>
      <Toolbar 
        selectedElement={selectedElements[0] || null} isPreview={isPreview} projectTitle={project.title}
        onPreview={() => setIsPreview(!isPreview)} onPublish={() => setShowPublishModal(true)}
        onUndo={() => { if (historyIndex > 0) { setProject(history[historyIndex - 1]); setHistoryIndex(historyIndex - 1); } }}
        onRedo={() => { if (historyIndex < history.length - 1) { setProject(history[historyIndex + 1]); setHistoryIndex(historyIndex + 1); } }}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1} onUpdateTitle={(t) => setProject({ ...project, title: t })}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            activePanel={isPagesView ? 'pages' : undefined}
            onActivePanelChange={(panel) => { if(panel === 'pages') setIsPagesView(true); else setIsPagesView(false); }}
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 100, y: 100, width: type === 'text' ? 300 : 200, height: type === 'text' ? 60 : 200, isVisible: true, isLocked: false,
                content: content || (type === 'text' ? 'Escribe aquí' : ''),
                styles: { 
                    backgroundColor: type === 'shape' ? '#E4002B' : 'transparent', color: type === 'text' ? '#000000' : '#FFFFFF', fontSize: 24, zIndex: currentPage.elements.length, opacity: 1, 
                    shadow: { enabled: false, blur: 10, color: 'rgba(0,0,0,0.3)', offsetX: 4, offsetY: 4, opacity: 0.5 },
                    glow: { enabled: false, blur: 15, color: '#E4002B', spread: 2, opacity: 0.5 },
                    border: { enabled: false, width: 2, color: '#000000', style: 'solid' },
                    brightness: 100, contrast: 100, saturate: 100, rotation: 0, borderRadius: 0, textAlign: 'center', fontFamily: 'Inter', fontWeight: 'normal', fontStyle: 'normal', textTransform: 'none', letterSpacing: 0, lineHeight: 1.2, entranceAnimation: 'fade', hoverAnimation: 'none' 
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
              };
              setProject({ ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, el] } : p) });
              pushToHistory(project); setSelectedElementIds([el.id]);
            }}
            pages={project.pages} currentPageIndex={currentPageIndex} onNavigatePage={(i) => { setCurrentPageIndex(i); setIsPagesView(false); }}
            onAddPage={() => { const np: ProjectPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], transition: 'fade' }; setProject({ ...project, pages: [...project.pages, np] }); setCurrentPageIndex(project.pages.length); }}
            currentPage={currentPage} selectedElementIds={selectedElementIds} onSelectElements={setSelectedElementIds}
            onUpdateBackground={(bg) => setProject({...project, pages: project.pages.map((p, i) => i === currentPageIndex ? {...p, background: bg} : p)})} onUpdateElement={handleUpdateElement}
            onUpdatePreset={() => {}} canvasPreset={project.canvasPreset} onBulkAdd={() => {}}
          />
        )}

        <main className={`flex-1 overflow-hidden bg-[#e2e8f0] flex flex-col items-center justify-center relative transition-all duration-300`} 
              ref={containerRef} 
              onMouseDown={(e) => {
                if (e.target === containerRef.current || e.target === canvasRef.current) { 
                  setSelectedElementIds([]); 
                  if (!isPreview && !isPagesView) setMarquee({ startX: e.clientX, startY: e.clientY, currentX: e.clientX, currentY: e.clientY }); 
                }
              }}>

          {isPagesView ? (
            <div className="w-full h-full overflow-y-auto p-12 bg-slate-50 animate-in fade-in duration-500">
               <div className="max-w-7xl mx-auto space-y-12">
                  <div className="flex items-center justify-between border-b pb-6">
                     <h2 className="text-3xl font-black text-slate-800 uppercase tracking-widest">Gestión de Páginas</h2>
                     <button onClick={() => setIsPagesView(false)} className="px-8 py-3 bg-slate-900 text-white rounded-full text-[10px] font-black uppercase tracking-widest hover:bg-black transition-all shadow-xl">Cerrar Vista</button>
                  </div>
                  <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-10">
                    {project.pages.map((p, idx) => (
                      <div key={p.id} className="space-y-4 group">
                         <div 
                           onClick={() => { setCurrentPageIndex(idx); setIsPagesView(false); }}
                           className={`aspect-video rounded-3xl border-4 transition-all cursor-pointer overflow-hidden shadow-2xl relative ${currentPageIndex === idx ? 'border-[#E4002B] scale-105' : 'border-white hover:border-slate-300 hover:scale-105'}`}
                           style={{ backgroundColor: p.background?.value || '#fff' }}
                         >
                            <div className="absolute inset-0 flex items-center justify-center bg-black/5 group-hover:bg-transparent transition-all">
                               <span className="text-4xl font-black text-slate-200">{idx + 1}</span>
                            </div>
                         </div>
                         <div className="flex items-center justify-between px-2">
                            <span className="text-xs font-black text-slate-600 uppercase tracking-widest">{p.name}</span>
                            <select 
                              className="text-[9px] font-black uppercase bg-slate-100 border-none rounded-lg p-2 outline-none"
                              value={p.transition}
                              onChange={(e) => {
                                const newP = { ...project, pages: project.pages.map((pg, i) => i === idx ? { ...pg, transition: e.target.value as PageTransition } : pg) };
                                setProject(newP); pushToHistory(newP);
                              }}
                            >
                               <option value="none">Sin Transición</option>
                               <option value="fade">Fundido</option>
                               <option value="push-h">Empuje Lateral</option>
                               <option value="push-v">Empuje Vertical</option>
                               <option value="zoom">Zoom</option>
                               <option value="slide-up">Deslizar Arriba</option>
                            </select>
                         </div>
                      </div>
                    ))}
                    <button onClick={() => { const np: ProjectPage = { id: `pg-${Date.now()}`, name: `Pág. ${project.pages.length + 1}`, elements: [], groups: [], transition: 'fade' }; setProject({ ...project, pages: [...project.pages, np] }); }} className="aspect-video rounded-3xl border-4 border-dashed border-slate-200 flex flex-col items-center justify-center gap-4 text-slate-300 hover:border-[#E4002B] hover:text-[#E4002B] transition-all group">
                       <i className="fas fa-plus text-3xl group-hover:scale-110 transition-transform"></i>
                       <span className="text-[10px] font-black uppercase tracking-widest">Añadir Página</span>
                    </button>
                  </div>
               </div>
            </div>
          ) : (
            <div className="w-full h-full overflow-auto flex items-center justify-center p-20" style={{ perspective: '1000px' }}>
              <div 
                ref={canvasRef} 
                className={`relative bg-white shadow-2xl transition-transform duration-75 origin-center ${showGrid && !isPreview ? 'canvas-grid' : ''} ${isPreview ? 'w-full h-full' : 'border border-slate-300'}`} 
                style={{ 
                  width: isPreview ? '100%' : `${currentDimensions.width}px`, 
                  height: isPreview ? '100%' : `${currentDimensions.height}px`, 
                  backgroundColor: currentPage.background?.value || '#FFFFFF',
                  transform: isPreview ? 'none' : `scale(${zoom})`,
                }}
              >
                {currentPage.elements.map(el => (
                  <ElementRenderer 
                    key={el.id} element={el} isSelected={selectedElementIds.includes(el.id)} isPreview={isPreview}
                    onSelect={(e) => { 
                      e.stopPropagation(); 
                      const targetIds = el.groupId ? currentPage.elements.filter(e => e.groupId === el.groupId).map(e => e.id) : [el.id];
                      setSelectedElementIds(e.shiftKey ? Array.from(new Set([...selectedElementIds, ...targetIds])) : targetIds); 
                      if (!e.shiftKey) {
                        const initials = (el.groupId ? currentPage.elements.filter(e => e.groupId === el.groupId) : [el])
                          .map(item => ({ id: item.id, x: item.x, y: item.y, w: item.width, h: item.height, r: item.styles.rotation || 0, fs: item.styles.fontSize }));
                        setActionState({ ids: targetIds, startX: e.clientX, startY: e.clientY, initials }); 
                      }
                    }}
                    onResizeStart={(e, h) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0, fs: el.styles.fontSize}], handle:h }); }}
                    onRotateStart={(e) => { e.stopPropagation(); setActionState({ ids:[el.id], startX:e.clientX, startY:e.clientY, initials:[{id:el.id, x:el.x, y:el.y, w:el.width, h:el.height, r:el.styles.rotation || 0, fs: el.styles.fontSize}], handle:'rot' }); }}
                    onOpenContextMenu={(e) => setContextMenu({ x: e.clientX, y: e.clientY })}
                    onNavigate={(targetId) => {
                      const idx = project.pages.findIndex(p => p.id === targetId || p.name === targetId);
                      if (idx !== -1) setCurrentPageIndex(idx);
                    }}
                    onShowModal={(content) => setActiveModalContent(content)}
                  />
                ))}
                {marquee && (
                  <div className="fixed border border-[#E4002B] bg-[#E4002B]/10 z-[1000] pointer-events-none" 
                       style={{ 
                         left: Math.min(marquee.startX, marquee.currentX), 
                         top: Math.min(marquee.startY, marquee.currentY), 
                         width: Math.abs(marquee.startX - marquee.currentX), 
                         height: Math.abs(marquee.startY - marquee.currentY) 
                       }} />
                )}
              </div>
            </div>
          )}

          {!isPreview && !isPagesView && (
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md rounded-full shadow-2xl px-8 py-3 flex items-center gap-8 border border-slate-200 z-[400] ring-1 ring-black/5">
               <button onClick={() => setShowGrid(!showGrid)} className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all ${showGrid ? 'text-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}><i className="fas fa-th"></i> Cuadrícula</button>
               <button onClick={() => setShowRulers(!showRulers)} className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all ${showRulers ? 'text-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}><i className="fas fa-ruler-combined"></i> Reglas</button>
               <div className="h-4 w-px bg-slate-200"></div>
               <div className="flex items-center gap-3">
                  <button onClick={() => setZoom(z => Math.max(0.1, z - 0.1))} className="w-8 h-8 flex items-center justify-center bg-slate-100 hover:bg-slate-200 rounded-full text-slate-400 hover:text-slate-900 transition-colors"><i className="fas fa-minus text-[8px]"></i></button>
                  <span className="text-[10px] font-black text-slate-900 w-12 text-center">{Math.round(zoom * 100)}%</span>
                  <button onClick={() => setZoom(z => Math.min(5, z + 0.1))} className="w-8 h-8 flex items-center justify-center bg-slate-100 hover:bg-slate-200 rounded-full text-slate-400 hover:text-slate-900 transition-colors"><i className="fas fa-plus text-[8px]"></i></button>
               </div>
            </div>
          )}
        </main>

        {selectedElements.length > 0 && !isPreview && !isPagesView && (
          <aside className="w-80 bg-white border-l border-slate-200 flex flex-col z-[300] shadow-2xl overflow-y-auto scrollbar-hide shrink-0 animate-in slide-in-from-right-4 duration-300">
             <div className="flex bg-slate-50 border-b sticky top-0 z-10">
                {['design', 'interact', 'effects'].map((tab) => (
                  <button key={tab} onClick={() => setActivePropertyTab(tab as any)} className={`flex-1 py-4 text-[9px] font-black uppercase tracking-widest transition-all ${activePropertyTab === tab ? 'bg-white text-[#E4002B] border-b-2 border-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}>
                    {tab === 'design' ? 'DISEÑO' : tab === 'interact' ? 'INTERACCIONES' : 'EFECTOS'}
                  </button>
                ))}
             </div>

             <div className="p-6 space-y-8 pb-32">
               {activePropertyTab === 'design' && (
                 <>
                   <section className="space-y-4">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contenido</label>
                     <textarea className="w-full bg-slate-50 border rounded-xl text-xs p-3 outline-none resize-none h-24 focus:ring-1 focus:ring-[#E4002B]" value={selectedElements[0].content} onChange={(e) => handleUpdateElement(selectedElements[0].id, { content: e.target.value })} />

                     {(selectedElements[0].type === 'text' || selectedElements[0].type === 'shape') && (
                        <div className="space-y-4 animate-in fade-in duration-300">
                           <div className="grid grid-cols-2 gap-2">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-400 uppercase">Tipografía</label>
                                <select className="w-full bg-slate-50 border rounded-xl text-xs p-2 outline-none" value={selectedElements[0].styles.fontFamily} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontFamily: e.target.value } })}>
                                  {FONT_FAMILIES.map(f => <option key={f} value={f}>{f}</option>)}
                                </select>
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-400 uppercase">Tamaño</label>
                                <input type="number" min="1" className="w-full bg-slate-50 border rounded-xl text-xs p-2 outline-none" value={selectedElements[0].styles.fontSize} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontSize: parseInt(e.target.value) } })} />
                              </div>
                           </div>
                           <div className="grid grid-cols-2 gap-2">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-400 uppercase">Peso</label>
                                <select className="w-full bg-slate-50 border rounded-xl text-xs p-2 outline-none" value={selectedElements[0].styles.fontWeight} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { fontWeight: e.target.value } })}>
                                  {FONT_WEIGHTS.map(w => <option key={w} value={w}>{w}</option>)}
                                </select>
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-400 uppercase">Estilo</label>
                                <div className="flex gap-1 h-9">
                                   <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { fontStyle: selectedElements[0].styles.fontStyle === 'italic' ? 'normal' : 'italic' } })} className={`flex-1 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.fontStyle === 'italic' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-italic"></i></button>
                                   <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textTransform: selectedElements[0].styles.textTransform === 'uppercase' ? 'none' : 'uppercase' } })} className={`flex-1 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textTransform === 'uppercase' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-font"></i></button>
                                </div>
                              </div>
                           </div>
                           <div className="grid grid-cols-4 gap-1">
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: 'left' } })} className={`p-2 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textAlign === 'left' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-align-left"></i></button>
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: 'center' } })} className={`p-2 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textAlign === 'center' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-align-center"></i></button>
                              <button onClick={() => handleUpdateElement(selectedElements[0].id, { styles: { textAlign: 'right' } })} className={`p-2 border rounded-xl text-xs flex items-center justify-center transition-all ${selectedElements[0].styles.textAlign === 'right' ? 'bg-slate-900 text-white' : 'bg-white'}`}><i className="fas fa-align-right"></i></button>
                              <input type="color" value={selectedElements[0].styles.color} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { color: e.target.value } })} className="w-full h-full rounded-xl border border-slate-200 cursor-pointer overflow-hidden" />
                           </div>
                        </div>
                     )}

                     {selectedElements[0].type === 'image' && (
                       <div className="space-y-4 animate-in fade-in duration-300 border-t pt-4">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Edición de Imagen</label>
                          <div className="space-y-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                             <div className="space-y-1">
                                <div className="flex justify-between items-center"><span className="text-[9px] font-black text-slate-500 uppercase">Brillo</span><span className="text-[9px] font-bold text-[#E4002B]">{selectedElements[0].styles.brightness}%</span></div>
                                <input type="range" min="0" max="200" value={selectedElements[0].styles.brightness} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { brightness: parseInt(e.target.value) } })} className="w-full accent-[#E4002B]" />
                             </div>
                             <div className="space-y-1">
                                <div className="flex justify-between items-center"><span className="text-[9px] font-black text-slate-500 uppercase">Contraste</span><span className="text-[9px] font-bold text-[#E4002B]">{selectedElements[0].styles.contrast}%</span></div>
                                <input type="range" min="0" max="200" value={selectedElements[0].styles.contrast} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { contrast: parseInt(e.target.value) } })} className="w-full accent-[#E4002B]" />
                             </div>
                             <div className="space-y-1">
                                <div className="flex justify-between items-center"><span className="text-[9px] font-black text-slate-500 uppercase">Saturación</span><span className="text-[9px] font-bold text-[#E4002B]">{selectedElements[0].styles.saturate}%</span></div>
                                <input type="range" min="0" max="200" value={selectedElements[0].styles.saturate} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { saturate: parseInt(e.target.value) } })} className="w-full accent-[#E4002B]" />
                             </div>
                          </div>
                       </div>
                     )}
                   </section>

                   <section className="space-y-4 border-t pt-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Geometría</label>
                      <div className="space-y-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                         <div className="space-y-1">
                            <div className="flex justify-between items-center"><span className="text-[9px] font-black text-slate-500 uppercase">Redondeado</span><span className="text-[9px] font-bold text-[#E4002B]">{selectedElements[0].styles.borderRadius}px</span></div>
                            <input type="range" min="0" max="200" value={selectedElements[0].styles.borderRadius} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { borderRadius: parseInt(e.target.value) } })} className="w-full accent-[#E4002B]" />
                         </div>
                         <div className="space-y-1">
                            <div className="flex justify-between items-center"><span className="text-[9px] font-black text-slate-500 uppercase">Opacidad</span><span className="text-[9px] font-bold text-[#E4002B]">{Math.round((selectedElements[0].styles.opacity || 1) * 100)}%</span></div>
                            <input type="range" min="0" max="1" step="0.01" value={selectedElements[0].styles.opacity || 1} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { opacity: parseFloat(e.target.value) } })} className="w-full accent-[#E4002B]" />
                         </div>
                      </div>
                   </section>

                   <section className="space-y-4 border-t pt-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Fondo / Degradado</label>
                      <div className="p-4 bg-slate-50 rounded-xl border space-y-4">
                         <div className="flex items-center gap-3">
                           <input type="color" value={selectedElements[0].styles.backgroundColor} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { backgroundColor: e.target.value, gradient: { ...selectedElements[0].styles.gradient!, enabled: false } } })} className="w-10 h-10 rounded-full border-none cursor-pointer" />
                           <div className="flex flex-col"><span className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Color Base</span><span className="text-[8px] font-bold text-slate-400">{selectedElements[0].styles.backgroundColor}</span></div>
                         </div>
                         <div className="border-t border-slate-200 pt-3 flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Habilitar Degradado</span>
                            <input type="checkbox" className="w-5 h-5 accent-[#E4002B] cursor-pointer" checked={selectedElements[0].styles.gradient?.enabled} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { gradient: { enabled: e.target.checked, from: selectedElements[0].styles.backgroundColor || '#E4002B', to: '#111111', angle: 135 } } })} />
                         </div>
                         {selectedElements[0].styles.gradient?.enabled && (
                           <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-300">
                              <div className="flex gap-2">
                                 <div className="flex-1 space-y-1"><span className="text-[8px] font-black text-slate-400 uppercase">Inicio</span><input type="color" value={selectedElements[0].styles.gradient.from} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { gradient: { ...selectedElements[0].styles.gradient!, from: e.target.value } } })} className="w-full h-8 rounded-lg border-none cursor-pointer" /></div>
                                 <div className="flex-1 space-y-1"><span className="text-[8px] font-black text-slate-400 uppercase">Fin</span><input type="color" value={selectedElements[0].styles.gradient.to} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { gradient: { ...selectedElements[0].styles.gradient!, to: e.target.value } } })} className="w-full h-8 rounded-lg border-none cursor-pointer" /></div>
                              </div>
                              <div className="space-y-1"><div className="flex justify-between"><span className="text-[8px] font-black text-slate-400 uppercase">Ángulo</span><span className="text-[8px] font-bold text-[#E4002B]">{selectedElements[0].styles.gradient.angle}°</span></div><input type="range" min="0" max="360" value={selectedElements[0].styles.gradient.angle} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { gradient: { ...selectedElements[0].styles.gradient!, angle: parseInt(e.target.value) } } })} className="w-full accent-[#E4002B]" /></div>
                           </div>
                         )}
                      </div>
                   </section>
                 </>
               )}

               {activePropertyTab === 'effects' && (
                 <section className="space-y-8 animate-in slide-in-from-right-2 duration-300">
                    <div className="space-y-4">
                       <div className="flex items-center justify-between">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sombra</label>
                         <input type="checkbox" className="w-4 h-4 accent-[#E4002B]" checked={selectedElements[0].styles.shadow.enabled} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { shadow: { ...selectedElements[0].styles.shadow, enabled: e.target.checked } } })} />
                       </div>
                       {selectedElements[0].styles.shadow.enabled && (
                          <div className="space-y-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                             <div className="grid grid-cols-2 gap-4">
                               <div className="space-y-1"><span className="text-[8px] font-black text-slate-400 uppercase">Offset X</span><input type="number" value={selectedElements[0].styles.shadow.offsetX} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { shadow: { ...selectedElements[0].styles.shadow, offsetX: parseInt(e.target.value) } } })} className="w-full bg-white border rounded p-1 text-xs" /></div>
                               <div className="space-y-1"><span className="text-[8px] font-black text-slate-400 uppercase">Offset Y</span><input type="number" value={selectedElements[0].styles.shadow.offsetY} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { shadow: { ...selectedElements[0].styles.shadow, offsetY: parseInt(e.target.value) } } })} className="w-full bg-white border rounded p-1 text-xs" /></div>
                             </div>
                             <div className="space-y-1"><div className="flex justify-between"><span className="text-[8px] font-black text-slate-400 uppercase">Difuminado</span><span className="text-[8px] font-bold text-[#E4002B]">{selectedElements[0].styles.shadow.blur}px</span></div><input type="range" min="0" max="50" value={selectedElements[0].styles.shadow.blur} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { shadow: { ...selectedElements[0].styles.shadow, blur: parseInt(e.target.value) } } })} className="w-full accent-[#E4002B]" /></div>
                             <div className="space-y-1"><span className="text-[8px] font-black text-slate-400 uppercase">Color Sombra</span><input type="color" value={selectedElements[0].styles.shadow.color} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { shadow: { ...selectedElements[0].styles.shadow, color: e.target.value } } })} className="w-full h-8 rounded border-none cursor-pointer" /></div>
                          </div>
                       )}
                    </div>

                    <div className="space-y-4 border-t pt-4">
                       <div className="flex items-center justify-between">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resplandor (Glow)</label>
                         <input type="checkbox" className="w-4 h-4 accent-[#E4002B]" checked={selectedElements[0].styles.glow.enabled} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { glow: { ...selectedElements[0].styles.glow, enabled: e.target.checked } } })} />
                       </div>
                       {selectedElements[0].styles.glow.enabled && (
                          <div className="space-y-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                             <div className="space-y-1"><div className="flex justify-between"><span className="text-[8px] font-black text-slate-400 uppercase">Extensión</span><span className="text-[8px] font-bold text-[#E4002B]">{selectedElements[0].styles.glow.spread}px</span></div><input type="range" min="0" max="30" value={selectedElements[0].styles.glow.spread} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { glow: { ...selectedElements[0].styles.glow, spread: parseInt(e.target.value) } } })} className="w-full accent-[#E4002B]" /></div>
                             <div className="space-y-1"><div className="flex justify-between"><span className="text-[8px] font-black text-slate-400 uppercase">Difuminado</span><span className="text-[8px] font-bold text-[#E4002B]">{selectedElements[0].styles.glow.blur}px</span></div><input type="range" min="0" max="100" value={selectedElements[0].styles.glow.blur} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { glow: { ...selectedElements[0].styles.glow, blur: parseInt(e.target.value) } } })} className="w-full accent-[#E4002B]" /></div>
                             <input type="color" value={selectedElements[0].styles.glow.color} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { glow: { ...selectedElements[0].styles.glow, color: e.target.value } } })} className="w-full h-8 rounded border-none cursor-pointer" />
                          </div>
                       )}
                    </div>

                    <div className="space-y-4 border-t pt-4">
                       <div className="flex items-center justify-between">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Borde</label>
                         <input type="checkbox" className="w-4 h-4 accent-[#E4002B]" checked={selectedElements[0].styles.border.enabled} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { border: { ...selectedElements[0].styles.border, enabled: e.target.checked } } })} />
                       </div>
                       {selectedElements[0].styles.border.enabled && (
                          <div className="space-y-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                             <div className="space-y-1"><div className="flex justify-between"><span className="text-[8px] font-black text-slate-400 uppercase">Grosor</span><span className="text-[8px] font-bold text-[#E4002B]">{selectedElements[0].styles.border.width}px</span></div><input type="range" min="0" max="20" value={selectedElements[0].styles.border.width} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { border: { ...selectedElements[0].styles.border, width: parseInt(e.target.value) } } })} className="w-full accent-[#E4002B]" /></div>
                             <div className="space-y-1"><span className="text-[8px] font-black text-slate-400 uppercase">Estilo</span><select value={selectedElements[0].styles.border.style} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { border: { ...selectedElements[0].styles.border, style: e.target.value as any } } })} className="w-full bg-white border rounded p-1 text-xs"><option value="solid">Sólido</option><option value="dashed">Guiones</option><option value="dotted">Puntos</option></select></div>
                             <input type="color" value={selectedElements[0].styles.border.color} onChange={(e) => handleUpdateElement(selectedElements[0].id, { styles: { border: { ...selectedElements[0].styles.border, color: e.target.value } } })} className="w-full h-8 rounded border-none cursor-pointer" />
                          </div>
                       )}
                    </div>
                 </section>
               )}
             </div>
          </aside>
        )}
      </div>

      {activeModalContent && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-black/70 backdrop-blur-md p-10 animate-in fade-in duration-300">
          <div className="bg-white max-w-2xl w-full rounded-3xl shadow-2xl overflow-hidden relative p-12 animate-in zoom-in-95 duration-500">
             <button onClick={() => setActiveModalContent(null)} className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center bg-slate-100 hover:bg-[#E4002B] hover:text-white rounded-full transition-all group">
                <i className="fas fa-times"></i>
             </button>
             <div className="prose prose-slate max-w-none"><p className="text-lg leading-relaxed text-slate-700 whitespace-pre-wrap">{activeModalContent}</p></div>
          </div>
        </div>
      )}

      {showPublishModal && <PublishModal project={project} onClose={() => setShowPublishModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { ElementType, CanvasPreset, ProjectPage, CanvasElement } from '../types';

interface SidebarProps {
  onAddElement: (type: ElementType, content?: string) => void;
  onBulkAdd: (data: any) => void;
  canvasPreset: CanvasPreset;
  onUpdatePreset: (preset: CanvasPreset) => void;
  currentPage: ProjectPage;
  selectedElementIds: string[];
  onSelectElements: (ids: string[]) => void;
  onUpdateBackground: (bg: any) => void;
  pages: ProjectPage[];
  currentPageIndex: number;
  onNavigatePage: (index: number) => void;
  onAddPage: () => void;
  onUpdateElement: (id: string, updates: Partial<CanvasElement>) => void;
  onActivePanelChange?: (panel: string) => void;
  activePanel?: string;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  onAddElement, currentPage, selectedElementIds, onSelectElements, onUpdateBackground,
  pages, currentPageIndex, onNavigatePage, onAddPage, onUpdateElement, onActivePanelChange, activePanel: externalActivePanel
}) => {
  const [internalActivePanel, setInternalActivePanel] = useState<'pages' | 'text' | 'resources' | 'bg' | 'media'>('pages');
  const activePanel = externalActivePanel || internalActivePanel;

  const [pagesSubTab, setPagesSubTab] = useState<'outline' | 'layers'>('outline');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadType, setUploadType] = useState<ElementType>('image');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => onAddElement(uploadType, event.target?.result as string);
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  const triggerUpload = (type: ElementType) => {
    setUploadType(type);
    fileInputRef.current?.click();
  };

  const switchPanel = (panel: any) => {
    setInternalActivePanel(panel);
    onActivePanelChange?.(panel);
  };

  return (
    <div className="flex h-full bg-[#111118] z-[100] shadow-2xl shrink-0">
      <div className="w-18 bg-black flex flex-col items-center py-8 gap-8 border-r border-white/5">
        <NavIcon active={activePanel === 'pages'} icon="fa-layer-group" onClick={() => switchPanel('pages')} label="Páginas" />
        <NavIcon active={activePanel === 'text'} icon="fa-font" onClick={() => switchPanel('text')} label="Texto" />
        <NavIcon active={activePanel === 'resources'} icon="fa-shapes" onClick={() => switchPanel('resources')} label="Formas" />
        <NavIcon active={activePanel === 'media'} icon="fa-photo-film" onClick={() => switchPanel('media')} label="Medios" />
        <NavIcon active={activePanel === 'bg'} icon="fa-palette" onClick={() => switchPanel('bg')} label="Tema" />
      </div>

      <div className="w-72 flex flex-col bg-white border-r border-slate-200 shadow-inner">
        <div className="h-16 flex items-center px-6 border-b bg-slate-50/50">
          <h2 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{activePanel}</h2>
        </div>

        <div className="flex-1 overflow-y-auto px-6 py-8 scrollbar-hide">
          <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileUpload} accept={uploadType === 'image' ? 'image/*' : uploadType === 'audio' ? 'audio/*' : 'video/*'} />

          {activePanel === 'text' && (
            <div className="space-y-4 animate-in fade-in slide-in-from-left-4 duration-300">
              <button onClick={() => onAddElement('text', 'Añadir un título')} className="w-full p-6 bg-slate-50 border border-slate-200 rounded-2xl hover:border-[#E4002B] hover:bg-white hover:shadow-xl transition-all text-left group">
                <span className="text-2xl font-black block text-slate-900 group-hover:text-[#E4002B]">Título</span>
                <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest mt-1 block">Click para añadir</span>
              </button>
              <button onClick={() => onAddElement('text', 'Añadir un subtítulo')} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl hover:border-[#E4002B] hover:bg-white hover:shadow-xl transition-all text-left group">
                <span className="text-lg font-bold block text-slate-800 group-hover:text-[#E4002B]">Subtítulo</span>
                <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest mt-1 block">Click para añadir</span>
              </button>
              <button onClick={() => onAddElement('text', 'Cuerpo de texto')} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl hover:border-[#E4002B] hover:bg-white hover:shadow-xl transition-all text-left group">
                <span className="text-sm font-medium block text-slate-700 group-hover:text-[#E4002B]">Texto de cuerpo</span>
                <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest mt-1 block">Click para añadir</span>
              </button>
            </div>
          )}

          {activePanel === 'media' && (
            <div className="space-y-4 animate-in fade-in slide-in-from-left-4 duration-300">
              <div className="grid grid-cols-2 gap-3">
                 <button onClick={() => triggerUpload('image')} className="p-6 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center gap-3 hover:border-[#E4002B] hover:bg-white hover:shadow-xl transition-all group">
                    <i className="fas fa-image text-xl text-slate-400 group-hover:text-[#E4002B]"></i>
                    <span className="text-[8px] font-black uppercase text-slate-600">Imagen</span>
                 </button>
                 <button onClick={() => triggerUpload('video')} className="p-6 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center gap-3 hover:border-[#E4002B] hover:bg-white hover:shadow-xl transition-all group">
                    <i className="fas fa-video text-xl text-slate-400 group-hover:text-[#E4002B]"></i>
                    <span className="text-[8px] font-black uppercase text-slate-600">Video</span>
                 </button>
              </div>
            </div>
          )}

          {activePanel === 'pages' && (
            <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
               <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setPagesSubTab('outline')} className={`flex-1 py-2 text-[9px] font-black rounded-lg transition-all ${pagesSubTab === 'outline' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}>ESQUEMA</button>
                  <button onClick={() => setPagesSubTab('layers')} className={`flex-1 py-2 text-[9px] font-black rounded-lg transition-all ${pagesSubTab === 'layers' ? 'bg-white shadow-sm text-[#E4002B]' : 'text-slate-400 hover:text-slate-600'}`}>CAPAS</button>
               </div>

               {pagesSubTab === 'outline' ? (
                 <div className="space-y-3">
                    {pages.map((p, idx) => (
                       <div key={p.id} onClick={() => onNavigatePage(idx)} className={`p-4 rounded-2xl border transition-all cursor-pointer group ${currentPageIndex === idx ? 'border-[#E4002B] bg-red-50/50' : 'border-slate-100 bg-white hover:border-slate-300'}`}>
                          <div className="flex items-center justify-between">
                             <div className="text-[10px] font-black text-slate-900 uppercase tracking-tight">{p.name}</div>
                             <div className="text-[8px] font-bold text-slate-300 group-hover:text-[#E4002B]">{idx + 1}</div>
                          </div>
                       </div>
                    ))}
                    <button onClick={onAddPage} className="w-full py-4 border-2 border-dashed border-slate-200 rounded-2xl text-[9px] font-black text-slate-400 hover:border-[#E4002B] hover:text-[#E4002B] hover:bg-white uppercase tracking-widest transition-all">+ Añadir Página</button>
                 </div>
               ) : (
                 <div className="space-y-2">
                    {[...currentPage.elements].reverse().map(el => (
                      <div 
                        key={el.id} 
                        onClick={() => onSelectElements([el.id])}
                        className={`p-3 rounded-xl border flex items-center gap-3 transition-all cursor-pointer ${selectedElementIds.includes(el.id) ? 'bg-red-50 border-[#E4002B]' : 'bg-white border-slate-100 hover:border-slate-300'}`}
                      >
                         <i className={`fas ${el.type === 'text' ? 'fa-font' : (el.type === 'image' ? 'fa-image' : 'fa-square')} text-[10px] text-slate-400`}></i>
                         <span className="text-[9px] font-black truncate flex-1 uppercase tracking-tight text-slate-600">{el.type}</span>
                         <div className="flex gap-1">
                            <button onClick={(e) => { e.stopPropagation(); onUpdateElement(el.id, { isVisible: !el.isVisible }); }} className={`w-7 h-7 rounded-lg flex items-center justify-center transition-all ${el.isVisible ? 'text-slate-400 hover:bg-slate-100' : 'bg-red-100 text-[#E4002B]'}`}>
                               <i className={`fas ${el.isVisible ? 'fa-eye' : 'fa-eye-slash'} text-[10px]`}></i>
                            </button>
                            <button onClick={(e) => { e.stopPropagation(); onUpdateElement(el.id, { isLocked: !el.isLocked }); }} className={`w-7 h-7 rounded-lg flex items-center justify-center transition-all ${el.isLocked ? 'bg-slate-900 text-white' : 'text-slate-400 hover:bg-slate-100'}`}>
                               <i className={`fas ${el.isLocked ? 'fa-lock' : 'fa-lock-open'} text-[10px]`}></i>
                            </button>
                         </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}

          {activePanel === 'resources' && (
             <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-left-4 duration-300">
                {['square', 'circle', 'triangle', 'star', 'diamond', 'heart'].map(s => (
                   <button key={s} onClick={() => onAddElement('shape', s)} className="p-6 bg-slate-50 border border-slate-200 rounded-2xl flex flex-col items-center gap-3 hover:border-[#E4002B] hover:bg-white hover:shadow-xl transition-all group">
                      <i className={`fas fa-${s === 'triangle' ? 'play fa-rotate-270' : s} text-2xl text-slate-400 group-hover:text-[#E4002B]`}></i>
                      <span className="text-[8px] font-black uppercase text-slate-500 group-hover:text-[#E4002B] tracking-widest">{s}</span>
                   </button>
                ))}
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

const NavIcon: React.FC<{ active: boolean; icon: string; onClick: () => void; label: string }> = ({ active, icon, onClick, label }) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-2 transition-all group ${active ? 'text-white' : 'text-slate-600 hover:text-white'}`}>
    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${active ? 'bg-[#E4002B] shadow-xl shadow-red-900/40 ring-2 ring-white/10' : 'bg-white/5 hover:bg-white/10 group-hover:scale-110'}`}>
       <i className={`fas ${icon} text-lg`}></i>
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter opacity-70 group-hover:opacity-100">{label}</span>
  </button>
);

export default Sidebar;

export type ElementType = 'text' | 'image' | 'shape' | 'button' | 'audio' | 'video' | 'quiz' | 'gallery';

export enum InteractivityType {
  NONE = 'NONE',
  TOOLTIP = 'TOOLTIP',
  MODAL = 'MODAL',
  GOTO_PAGE = 'GOTO_PAGE',
  EXTERNAL_LINK = 'EXTERNAL_LINK'
}

export type AnimationType = 'none' | 'fade' | 'slide' | 'zoom' | 'back' | 'bounce' | 'flip' | 'pop' | 'lift' | 'glow' | 'rotate';
export type PageTransition = 'none' | 'fade' | 'push-h' | 'push-v' | 'wipe' | 'zoom' | 'slide-up';

export type CanvasPreset = 'presentation' | 'square' | 'vertical' | 'a4';

export interface CanvasDimensions {
  width: number;
  height: number;
  label: string;
}

export const CANVAS_PRESETS: Record<CanvasPreset, CanvasDimensions> = {
  presentation: { width: 960, height: 540, label: 'Presentación (16:9)' },
  square: { width: 600, height: 600, label: 'Cuadrado (1:1)' },
  vertical: { width: 400, height: 711, label: 'Móvil (9:16)' },
  a4: { width: 595, height: 842, label: 'A4 Vertical' }
};

export interface CanvasElement {
  id: string;
  type: ElementType;
  x: number;
  y: number;
  width: number;
  height: number;
  content: string;
  isVisible: boolean;
  isLocked: boolean;
  groupId?: string;
  styles: {
    backgroundColor?: string;
    gradient?: {
      enabled: boolean;
      from: string;
      to: string;
      angle: number;
    };
    color?: string;
    fontSize: number;
    borderRadius?: number;
    fontWeight?: string;
    fontStyle?: 'normal' | 'italic';
    textTransform?: 'none' | 'uppercase';
    letterSpacing?: number;
    lineHeight?: number;
    fontFamily?: string;
    textAlign?: 'left' | 'center' | 'right';
    opacity?: number;
    zIndex: number;
    rotation?: number;

    // Detailed Effects
    shadow: {
      enabled: boolean;
      blur: number;
      color: string;
      offsetX: number;
      offsetY: number;
      opacity: number;
    };
    glow: {
      enabled: boolean;
      blur: number;
      color: string;
      spread: number;
      opacity: number;
    };
    border: {
      enabled: boolean;
      width: number;
      color: string;
      style: 'solid' | 'dashed' | 'dotted';
      opacity: number;
    };

    textStrokeWidth?: number;
    textStrokeColor?: string;
    brightness: number;
    contrast: number;
    saturate: number;
    hoverAnimation?: AnimationType;
    entranceAnimation?: AnimationType;
    exitAnimation?: AnimationType;
  };
  interactivity: {
    type: InteractivityType;
    value: string;
    title?: string;
    modalContent?: string;
  };
}

export interface ElementGroup {
  id: string;
  name: string;
}

export interface ProjectPage {
  id: string;
  name: string;
  elements: CanvasElement[];
  groups: ElementGroup[];
  transition: PageTransition;
  background?: {
    type: 'color' | 'gradient' | 'image';
    value: string;
  };
}

export interface Project {
  id: string;
  title: string;
  pages: ProjectPage[];
  canvasPreset: CanvasPreset;
}

import React, { useState, useEffect, useMemo } from 'react';
import { CanvasElement, InteractivityType } from '../types';

interface ElementRendererProps {
  element: CanvasElement;
  isSelected: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onResizeStart: (e: React.MouseEvent, handle: string) => void;
  onRotateStart?: (e: React.MouseEvent) => void;
  isPreview?: boolean;
  onNavigate?: (targetId: string) => void;
  onOpenContextMenu?: (e: React.MouseEvent) => void;
  onShowModal?: (content: string) => void;
}

const ElementRenderer: React.FC<ElementRendererProps> = ({ 
  element, isSelected, onSelect, onResizeStart, onRotateStart, isPreview, onNavigate, onOpenContextMenu, onShowModal 
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [showEntrance, setShowEntrance] = useState(false);

  useEffect(() => {
    setShowEntrance(true);
  }, []);

  const style: React.CSSProperties = useMemo(() => {
    const s = element.styles;
    const background = s.gradient?.enabled 
      ? `linear-gradient(${s.gradient.angle}deg, ${s.gradient.from} 0%, ${s.gradient.to} 100%)` 
      : s.backgroundColor;

    const shadowParts = [];
    if (s.shadow.enabled) {
      // Simple hex to rgba conversion or just use opacity if supported
      shadowParts.push(`${s.shadow.offsetX}px ${s.shadow.offsetY}px ${s.shadow.blur}px ${s.shadow.color}`);
    }
    if (s.glow.enabled) {
      shadowParts.push(`0 0 ${s.glow.blur}px ${s.glow.spread}px ${s.glow.color}`);
    }
    const shadowStr = shadowParts.length > 0 ? shadowParts.join(', ') : 'none';

    const weightMap: Record<string, string> = {
      'light': '300',
      'normal': '400',
      'medium': '500',
      'bold': '700',
      'black': '900'
    };

    return {
      position: 'absolute',
      left: element.x,
      top: element.y,
      width: element.width,
      height: element.height,
      zIndex: s.zIndex,
      background: (element.type === 'image' || element.type === 'text') ? 'transparent' : background,
      color: s.color,
      fontSize: `${s.fontSize}px`,
      fontFamily: s.fontFamily || 'Inter',
      fontWeight: weightMap[s.fontWeight || 'normal'] || s.fontWeight,
      fontStyle: s.fontStyle || 'normal',
      textTransform: s.textTransform || 'none',
      letterSpacing: `${s.letterSpacing || 0}px`,
      lineHeight: s.lineHeight || 1.2,
      textAlign: s.textAlign,
      borderRadius: `${s.borderRadius || 0}px`,
      opacity: s.opacity,
      border: (element.type !== 'text' && s.border.enabled) ? `${s.border.width}px ${s.border.style} ${s.border.color}` : 'none',
      boxShadow: (element.type !== 'text' && element.type !== 'image') ? shadowStr : 'none',
      textShadow: element.type === 'text' && s.shadow.enabled ? `${s.shadow.offsetX}px ${s.shadow.offsetY}px ${s.shadow.blur}px ${s.shadow.color}` : 'none',
      display: 'flex',
      alignItems: 'center',
      justifyContent: s.textAlign === 'center' ? 'center' : (s.textAlign === 'right' ? 'flex-end' : 'flex-start'),
      transform: `rotate(${s.rotation || 0}deg)`,
      filter: (element.type === 'image') ? `brightness(${s.brightness}%) contrast(${s.contrast}%) saturate(${s.saturate}%)` : 'none',
      clipPath: element.type === 'shape' && !['square', 'text'].includes(element.content) && !element.content.includes(' ') ? getClipPath(element.content) : 'none',
      cursor: isPreview ? 'pointer' : (element.isLocked ? 'not-allowed' : 'move'),
      pointerEvents: !element.isVisible ? 'none' : (element.isLocked && !isPreview ? 'none' : 'auto'),
      transition: isPreview ? 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)' : 'none',
      visibility: element.isVisible ? 'visible' : 'hidden',
      WebkitTextStroke: element.type === 'text' && s.textStrokeWidth ? `${s.textStrokeWidth}px ${s.textStrokeColor || '#000'}` : undefined,
      overflow: 'visible'
    };
  }, [element, isPreview]);

  const handleInteraction = () => {
    if (!isPreview) return;
    const { type, value, modalContent } = element.interactivity;
    switch (type) {
      case InteractivityType.GOTO_PAGE:
        if (onNavigate) onNavigate(value);
        break;
      case InteractivityType.EXTERNAL_LINK:
        window.open(value, '_blank');
        break;
      case InteractivityType.MODAL:
        if (onShowModal && modalContent) onShowModal(modalContent);
        break;
    }
  };

  if (!element.isVisible && !isPreview) return null;

  return (
    <div
      style={style}
      className={`group-element`}
      onMouseDown={(e) => { if (!isPreview && !element.isLocked) onSelect(e); }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onContextMenu={(e) => { if (!isPreview) { e.preventDefault(); onOpenContextMenu?.(e); } }}
      onClick={handleInteraction}
    >
      {/* Selection Box Line */}
      {isSelected && !isPreview && (
        <div className="absolute inset-0 border-2 border-[#E4002B] pointer-events-none rounded-[inherit] z-[50]" style={{ margin: '-2px' }} />
      )}

      {element.groupId && isSelected && !isPreview && (
        <div className="absolute -inset-2 border border-blue-400 border-dashed pointer-events-none rounded-lg" />
      )}

      {element.type === 'image' ? (
        <img src={element.content} className="w-full h-full object-contain pointer-events-none" style={{ borderRadius: 'inherit' }} alt="" />
      ) : element.type === 'video' ? (
        <video src={element.content} className="w-full h-full object-cover" controls={isPreview} style={{ borderRadius: 'inherit' }} />
      ) : (
        <span className="w-full px-2 break-words select-none pointer-events-none z-10">
          {element.type === 'shape' ? (element.content.includes(' ') || element.content.length > 15 || !['circle','square','triangle','star','diamond','heart'].includes(element.content) ? element.content : '') : element.content}
        </span>
      )}

      {isSelected && !isPreview && !element.isLocked && (
        <>
          {['tl', 'tr', 'bl', 'br', 'tc', 'bc', 'ml', 'mr'].map(h => (
            <div 
              key={h} 
              onMouseDown={(e) => { e.stopPropagation(); onResizeStart(e, h); }} 
              className="absolute w-2.5 h-2.5 bg-white border-2 border-[#E4002B] rounded-full z-[120] shadow-md hover:scale-125 transition-transform" 
              style={getHandleStyle(h)} 
            />
          ))}
          <div onMouseDown={(e) => { e.stopPropagation(); onRotateStart?.(e); }} className="absolute -top-12 left-1/2 -translate-x-1/2 w-8 h-8 bg-white border-2 border-slate-200 rounded-full flex items-center justify-center cursor-alias shadow-xl hover:border-[#E4002B] transition-all"><i className="fas fa-redo text-xs text-[#E4002B]"></i></div>
        </>
      )}
    </div>
  );
};

function getClipPath(shape: string) {
  switch (shape) {
    case 'circle': return 'circle(50% at 50% 50%)';
    case 'triangle': return 'polygon(50% 0%, 0% 100%, 100% 100%)';
    case 'star': return 'polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%)';
    case 'diamond': return 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)';
    case 'heart': return 'path("M 10,30 A 20,20 0,0,1 50,30 A 20,20 0,0,1 90,30 Q 90,60 50,90 Q 10,60 10,30 Z")';
    default: return 'none';
  }
}

function getHandleStyle(h: string): React.CSSProperties {
  const o = '-6px';
  const mid = 'calc(50% - 5px)';
  switch (h) {
    case 'tl': return { top: o, left: o, cursor: 'nwse-resize' };
    case 'tr': return { top: o, right: o, cursor: 'nesw-resize' };
    case 'bl': return { bottom: o, left: o, cursor: 'nesw-resize' };
    case 'br': return { bottom: o, right: o, cursor: 'nwse-resize' };
    case 'tc': return { top: o, left: mid, cursor: 'ns-resize' };
    case 'bc': return { bottom: o, left: mid, cursor: 'ns-resize' };
    case 'ml': return { left: o, top: mid, cursor: 'ew-resize' };
    case 'mr': return { right: o, top: mid, cursor: 'ew-resize' };
    default: return {};
  }
}

export default ElementRenderer;

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Toolbar from './components/Toolbar';
import ElementRenderer from './components/ElementRenderer';
import PublishModal from './components/PublishModal';
import { CanvasElement, Project, ElementType, InteractivityType, CANVAS_PRESETS, ProjectPage, PageTransition } from './types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  title: 'Mi Proyecto Interactivo',
  pages: [{ 
    id: 'page-1', 
    name: 'Introducción', 
    elements: [], 
    groups: [],
    transition: 'fade',
    background: { type: 'color', value: '#FFFFFF' }
  }],
  canvasPreset: 'presentation'
};

const FONT_FAMILIES = ['Inter', 'Montserrat', 'Playfair Display', 'Roboto Mono', 'Arial', 'Times New Roman'];
const FONT_WEIGHTS = ['light', 'normal', 'medium', 'bold', 'black'];

const App: React.FC = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [history, setHistory] = useState<Project[]>([INITIAL_PROJECT]);
  const [historyIndex, setHistoryIndex] = useState(0);
  const [currentPageIndex, setCurrentPageIndex] = useState(0);
  const [selectedElementIds, setSelectedElementIds] = useState<string[]>([]);
  const [isPreview, setIsPreview] = useState(false);
  const [isPagesView, setIsPagesView] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [clipboard, setClipboard] = useState<CanvasElement[]>([]);
  const [activePropertyTab, setActivePropertyTab] = useState<'design' | 'interact' | 'effects'>('design');
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number } | null>(null);

  const [showGrid, setShowGrid] = useState(true);
  const [showRulers, setShowRulers] = useState(true);
  const [zoom, setZoom] = useState(1);
  const [activeModalContent, setActiveModalContent] = useState<string | null>(null);

  const requestRef = useRef<number | null>(null);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const [actionState, setActionState] = useState<{ 
    ids: string[]; 
    startX: number; 
    startY: number; 
    initials: { id: string, x: number, y: number, w: number, h: number, r: number, fs: number }[];
    handle?: string 
  } | null>(null);

  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const currentPage = project.pages[currentPageIndex] || project.pages[0];
  const currentDimensions = CANVAS_PRESETS[project.canvasPreset];
  const selectedElements = useMemo(() => currentPage.elements.filter(el => selectedElementIds.includes(el.id)), [currentPage.elements, selectedElementIds]);

  const pushToHistory = useCallback((newProject: Project) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newProject)));
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  const handleUpdateElement = useCallback((id: string, updates: any, silent = false) => {
    setProject(prev => {
      const next = {
        ...prev,
        pages: prev.pages.map((p, idx) => idx === currentPageIndex ? ({
          ...p,
          elements: p.elements.map(el => el.id === id ? ({ 
            ...el, 
            ...updates, 
            styles: { ...el.styles, ...(updates.styles || {}) },
            interactivity: { ...el.interactivity, ...(updates.interactivity || {}) }
          } as CanvasElement) : el)
        }) : p)
      };
      if (!silent) pushToHistory(next);
      return next;
    });
  }, [currentPageIndex, pushToHistory]);

  const handleGroupSelected = useCallback(() => {
    if (selectedElementIds.length < 2) return;
    const groupId = `group-${Date.now()}`;
    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? {
        ...p,
        elements: p.elements.map(el => selectedElementIds.includes(el.id) ? { ...el, groupId } : el),
        groups: [...p.groups, { id: groupId, name: `Grupo ${p.groups.length + 1}` }]
      } : p)
    };
    setProject(next);
    pushToHistory(next);
  }, [selectedElementIds, currentPageIndex, project, pushToHistory]);

  const handleUngroupSelected = useCallback(() => {
    const groupIdsToClear = Array.from(new Set(selectedElements.map(el => el.groupId).filter(Boolean)));
    if (groupIdsToClear.length === 0) return;
    const next = {
      ...project,
      pages: project.pages.map((p, idx) => idx === currentPageIndex ? {
        ...p,
        elements: p.elements.map(el => el.groupId && groupIdsToClear.includes(el.groupId) ? { ...el, groupId: undefined } : el),
        groups: p.groups.filter(g => !groupIdsToClear.includes(g.id))
      } : p)
    };
    setProject(next);
    pushToHistory(next);
  }, [selectedElements, currentPageIndex, project, pushToHistory]);

  const handleCopy = useCallback(() => { if (selectedElements.length > 0) setClipboard(JSON.parse(JSON.stringify(selectedElements))); setContextMenu(null); }, [selectedElements]);
  const handlePaste = useCallback(() => {
    if (clipboard.length > 0) {
      const newEls = clipboard.map(el => ({ ...el, id: `el-${Date.now()}-${Math.random()}`, x: el.x + 40, y: el.y + 40, styles: { ...el.styles, zIndex: currentPage.elements.length + 1 } }));
      const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: [...p.elements, ...newEls] } : p) };
      setProject(next);
      pushToHistory(next); setSelectedElementIds(newEls.map(e => e.id)); setContextMenu(null);
    }
  }, [clipboard, project, currentPageIndex, currentPage.elements.length, pushToHistory]);

  const handleDelete = useCallback(() => { 
    const next = { ...project, pages: project.pages.map((p, idx) => idx === currentPageIndex ? { ...p, elements: p.elements.filter(el => !selectedElementIds.includes(el.id)) } : p) };
    setProject(next); 
    pushToHistory(next);
    setSelectedElementIds([]); 
    setContextMenu(null); 
  }, [project, currentPageIndex, selectedElementIds, pushToHistory]);

  // Keyboard Shortcuts Fix
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isPreview) return;
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      const ctrl = e.ctrlKey || e.metaKey;

      if (ctrl && e.key.toLowerCase() === 'z') { e.preventDefault(); if (historyIndex > 0) { setProject(history[historyIndex - 1]); setHistoryIndex(historyIndex - 1); } }
      if (ctrl && e.key.toLowerCase() === 'y') { e.preventDefault(); if (historyIndex < history.length - 1) { setProject(history[historyIndex + 1]); setHistoryIndex(historyIndex + 1); } }
      if (ctrl && e.key.toLowerCase() === 'c') { e.preventDefault(); handleCopy(); }
      if (ctrl && e.key.toLowerCase() === 'v') { e.preventDefault(); handlePaste(); }
      if (ctrl && e.key.toLowerCase() === 'g') { e.preventDefault(); e.shiftKey ? handleUngroupSelected() : handleGroupSelected(); }
      if (e.key === 'Delete' || e.key === 'Backspace') { e.preventDefault(); handleDelete(); }
    };

    const handleWheel = (e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const delta = e.deltaY > 0 ? -0.1 : 0.1;
        setZoom(z => Math.max(0.1, Math.min(5, z + delta)));
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('wheel', handleWheel, { passive: false });
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('wheel', handleWheel);
    };
  }, [historyIndex, history, selectedElementIds, clipboard, isPreview, handleCopy, handlePaste, handleGroupSelected, handleUngroupSelected, handleDelete]);

  const animateMove = useCallback(() => {
    if (!actionState) return;
    const dx = (mousePosRef.current.x - actionState.startX) / zoom;
    const dy = (mousePosRef.current.y - actionState.startY) / zoom;

    if (actionState.handle === 'rot') {
      const target = actionState.initials[0];
      const el = currentPage.elements.find(e => e.id === target.id);
      if (!el || !canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const centerX = rect.left + (el.x + el.width / 2) * zoom;
      const centerY = rect.top + (el.y + el.height / 2) * zoom;
      const angle = Math.atan2(mousePosRef.current.y - centerY, mousePosRef.current.x - centerX) * (180 / Math.PI);
      handleUpdateElement(target.id, { styles: { rotation: Math.round(angle + 90) } }, true);
    } else if (actionState.handle) {
      const target = actionState.initials[0];
      let { x, y, w, h, fs } = target;
      const han = actionState.handle;

      if (han.includes('r')) w = Math.max(10, target.w + dx);
      if (han.includes('l')) { const diff = Math.min(dx, target.w - 10); w = target.w - diff; x = target.x + diff; }
      if (han.includes('b')) h = Math.max(10, target.h + dy);
      if (han.includes('t')) { const diff = Math.min(dy, target.h - 10); h = target.h - diff; y = target.y + diff; }

      // Scaling font size on resize - Requested
      const el = currentPage.elements.find(e => e.id === target.id);
      if (el && el.type === 'text') {
        const scaleX = w / target.w;
        const scaleY = h / target.h;
        const scale = Math.min(scaleX, scaleY); // Scale based on smaller ratio to fit
        fs = Math.max(1, Math.round(target.fs * scale));
      }

      handleUpdateElement(target.id, { x, y, width: w, height: h, styles: { fontSize: fs } }, true);
    } else {
      actionState.initials.forEach(init => {
        handleUpdateElement(init.id, { x: init.x + dx, y: init.y + dy }, true);
      });
    }
    requestRef.current = null;
  }, [actionState, handleUpdateElement, currentPage.elements, zoom]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    mousePosRef.current = { x: e.clientX, y: e.clientY };
    if (marquee) setMarquee(m => m ? { ...m, currentX: e.clientX, currentY: e.clientY } : null);
    else if (actionState && !requestRef.current) requestRef.current = requestAnimationFrame(animateMove);
  }, [marquee, actionState, animateMove]);

  const onMouseUp = useCallback(() => {
    if (marquee && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      // Adjust coordinates based on zoom and scroll position
      const x1 = (Math.min(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y1 = (Math.min(marquee.startY, marquee.currentY) - rect.top) / zoom;
      const x2 = (Math.max(marquee.startX, marquee.currentX) - rect.left) / zoom;
      const y2 = (Math.max(marquee.startY, marquee.currentY) - rect.top) / zoom;

      const hitIds = currentPage.elements.filter(el => 
        el.isVisible && !el.isLocked && 
        el.x < x2 && el.x + el.width > x1 && 
        el.y < y2 && el.y + el.height > y1
      ).map(el => el.id);

      setSelectedElementIds(hitIds);
    }
    if (actionState || marquee) pushToHistory(project);
    setMarquee(null); setActionState(null);
  }, [marquee, currentPage.elements, project, pushToHistory, actionState, zoom]);

  useEffect(() => {
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => { window.removeEventListener('mousemove', onMouseMove); window.removeEventListener('mouseup', onMouseUp); };
  }, [onMouseMove, onMouseUp]);

  return (
    <div className="flex flex-col h-screen bg-[#F4F4F4] text-slate-900 overflow-hidden font-sans select-none" onClick={() => setContextMenu(null)}>
      <Toolbar 
        selectedElement={selectedElements[0] || null} isPreview={isPreview} projectTitle={project.title}
        onPreview={() => setIsPreview(!isPreview)} onPublish={() => setShowPublishModal(true)}
        onUndo={() => { if (historyIndex > 0) { setProject(history[historyIndex - 1]); setHistoryIndex(historyIndex - 1); } }}
        onRedo={() => { if (historyIndex < history.length - 1) { setProject(history[historyIndex + 1]); setHistoryIndex(historyIndex + 1); } }}
        canUndo={historyIndex > 0} canRedo={historyIndex < history.length - 1} onUpdateTitle={(t) => setProject({ ...project, title: t })}
      />

      <div className="flex flex-1 overflow-hidden relative">
        {!isPreview && (
          <Sidebar 
            activePanel={isPagesView ? 'pages' : undefined}
            onActivePanelChange={(panel) => { if(panel === 'pages') setIsPagesView(true); else setIsPagesView(false); }}
            onAddElement={(type, content) => {
              const el: CanvasElement = {
                id: `el-${Date.now()}`, type, x: 100, y: 100, width: type === 'text' ? 300 : 200, height: type === 'text' ? 60 : 200, isVisible: true, isLocked: false,
                content: content || (type === 'text' ? 'Escribe aquí' : ''),
                styles: { 
                    backgroundColor: type === 'shape' ? '#E4002B' : 'transparent', color: type === 'text' ? '#000000' : '#FFFFFF', fontSize: 24, zIndex: currentPage.elements.length, opacity: 1, 
                    shadow: { enabled: false, blur: 10, color: '#000000', offsetX: 4, offsetY: 4, opacity: 0.5 },
                    glow: { enabled: false, blur: 15, color: '#E4002B', spread: 2, opacity: 0.5 },
                    border: { enabled: false, width: 2, color: '#000000', style: 'solid', opacity: 1 },
                    brightness: 100, contrast: 100, saturate: 100, rotation: 0, borderRadius: 0, textAlign: 'center', fontFamily: 'Inter', fontWeight: 'normal', fontStyle: 'normal', textTransform: 'none', letterSpacing: 0, lineHeight: 1.2, entranceAnimation: 'fade', hoverAnimation: 'none' 
                },
                interactivity: { type: InteractivityType.NONE, value: '' }
