import React, { useState, useMemo } from 'react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData, Restaurant } from '../types';
import * as XLSX from 'xlsx';
import { 
  Shield, 
  AlertCircle, 
  CheckCircle2, 
  X, 
  FileSpreadsheet, 
  Network, 
  UserPlus, 
  Trash2, 
  Key,
  Download,
  MapPin,
  Store,
  Layers,
  ChevronDown,
  Check,
  RefreshCw,
  Globe
} from 'lucide-react';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);
  const [isClearing, setIsClearing] = useState(false);
  const [isCreatingUser, setIsCreatingUser] = useState(false);
  const [showSelectorDropdown, setShowSelectorDropdown] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: [],
    assignedRegions: []
  });

  const availableRegions = useMemo(() => {
    return hierarchy.regions.map(r => r.name).sort();
  }, [hierarchy]);

  const availableZones = useMemo(() => {
    const zones = new Set<string>();
    hierarchy.regions.forEach(r => r.zones.forEach(z => zones.add(z.name)));
    return Array.from(zones).sort();
  }, [hierarchy]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) {
      alert("Por favor, ingresa usuario y contraseña.");
      return;
    }

    setIsCreatingUser(true);
    const userId = `user_${Date.now()}`;
    const userToSave: User = { 
      id: userId, 
      username: newUser.username!, 
      password: newUser.password!, 
      role: newUser.role!, 
      assignedZones: newUser.assignedZones || [], 
      assignedRestaurants: newUser.assignedRestaurants || [],
      assignedRegions: newUser.assignedRegions || []
    };

    try {
      const updatedUsersList = [...users, userToSave];
      await dataService.saveUsers(updatedUsersList);
      setUsers(updatedUsersList);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [], assignedRegions: [] });
      setImportStatus({ message: `Usuario @${userToSave.username} creado exitosamente.`, isError: false });
    } catch (e: any) { 
      console.error("Error al crear usuario:", e);
      alert(`Error crítico al guardar usuario: ${e.message}`); 
    } finally {
      setIsCreatingUser(false);
    }
  };

  const toggleSelection = (val: string, field: 'assignedZones' | 'assignedRegions') => {
    const current = (newUser as any)[field] || [];
    if (current.includes(val)) {
      setNewUser({ ...newUser, [field]: current.filter((v: string) => v !== val) });
    } else {
      setNewUser({ ...newUser, [field]: [...current, val] });
    }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { 
        await dataService.deleteUser(id); 
        setUsers(users.filter(u => u.id !== id)); 
        setImportStatus({ message: "Usuario eliminado correctamente.", isError: false });
      } catch (e) { 
        alert("Error al eliminar usuario del servidor."); 
      }
    }
  };

  const allRestaurants = dataService.getRestaurants();

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <button onClick={() => { 
                setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [], assignedRegions: [] });
                setShowUserModal(true); 
              }} 
              className="p-6 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:bg-slate-50 transition-colors"
            >
              <UserPlus className="w-6 h-6 mb-2" />
              <span className="text-[9px] font-black uppercase">Nuevo Usuario Acceso</span>
            </button>
            {users.map(u => (
              <div key={u.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm group hover:border-red-200 transition-all relative">
                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  {u.username !== 'admin' && <button onClick={() => handleDeleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 bg-slate-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>}
                </div>
                <div className="min-w-0">
                  <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center mb-3 text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-all"><Key className="w-5 h-5" /></div>
                  <p className="text-xs font-black text-slate-800 uppercase truncate italic">{u.username}</p>
                  <p className="text-[8px] font-black text-slate-400 uppercase mt-1 tracking-widest">{u.role}</p>
                  {u.role === UserRole.COORDINATOR && u.assignedRegions && u.assignedRegions.length > 0 && (
                    <div className="mt-3 flex flex-wrap gap-1">
                      {u.assignedRegions.map(r => (
                        <span key={r} className="text-[7px] font-black bg-blue-50 px-1.5 py-0.5 rounded border border-blue-100 uppercase text-blue-500">{r}</span>
                      ))}
                    </div>
                  )}
                  {u.role === UserRole.SPECIALIST && u.assignedZones && u.assignedZones.length > 0 && (
                    <div className="mt-3 flex flex-wrap gap-1">
                      {u.assignedZones.map(z => (
                        <span key={z} className="text-[7px] font-black bg-slate-50 px-1.5 py-0.5 rounded border border-slate-100 uppercase text-slate-400">{z}</span>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg flex flex-col overflow-hidden border-2 border-white/20">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                  <UserPlus className="w-6 h-6 text-white" />
                </div>
                <h3 className="font-black uppercase italic tracking-tighter text-xl">Creación de Usuario</h3>
              </div>
              <button onClick={() => { setShowUserModal(false); setShowSelectorDropdown(false); }} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-all">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="p-8 space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nombre Usuario</label>
                  <input type="text" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black outline-none focus:border-red-500" placeholder="ID Usuario" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Clave</label>
                  <input type="text" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black outline-none focus:border-red-500" placeholder="Clave" />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Perfil</label>
                <div className="grid grid-cols-2 gap-2">
                  <button onClick={() => setNewUser({...newUser, role: UserRole.SPECIALIST})} className={`py-3 rounded-xl text-[10px] font-black uppercase border-2 transition-all ${newUser.role === UserRole.SPECIALIST ? 'bg-red-50 border-red-500 text-red-600' : 'bg-slate-50 border-transparent text-slate-400'}`}>Especialista</button>
                  <button onClick={() => setNewUser({...newUser, role: UserRole.COORDINATOR})} className={`py-3 rounded-xl text-[10px] font-black uppercase border-2 transition-all ${newUser.role === UserRole.COORDINATOR ? 'bg-blue-50 border-blue-500 text-blue-600' : 'bg-slate-50 border-transparent text-slate-400'}`}>Coordinador</button>
                </div>
              </div>

              <div className="space-y-2 relative">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-1.5">
                  {newUser.role === UserRole.COORDINATOR ? <Globe className="w-3 h-3" /> : <Layers className="w-3 h-3" />}
                  {newUser.role === UserRole.COORDINATOR ? 'Regiones Asignadas' : 'Zonas Asignadas'}
                </label>
                <div className="relative">
                  <button type="button" onClick={() => setShowSelectorDropdown(!showSelectorDropdown)} className="w-full flex items-center justify-between px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-[11px] font-black uppercase text-slate-900 shadow-sm transition-all hover:border-slate-300">
                    <span className="truncate">
                      {newUser.role === UserRole.COORDINATOR 
                        ? (newUser.assignedRegions?.length ? `${newUser.assignedRegions.length} regiones` : 'Seleccionar regiones...')
                        : (newUser.assignedZones?.length ? `${newUser.assignedZones.length} zonas` : 'Seleccionar zonas...')}
                    </span>
                    <ChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${showSelectorDropdown ? 'rotate-180' : ''}`} />
                  </button>

                  {showSelectorDropdown && (
                    <div className="absolute bottom-full mb-2 left-0 right-0 bg-white border-2 border-slate-100 rounded-2xl shadow-2xl z-[210] overflow-hidden animate-in slide-in-from-bottom-2">
                      <div className="max-h-[180px] overflow-y-auto p-2 no-scrollbar">
                        {(newUser.role === UserRole.COORDINATOR ? availableRegions : availableZones).map(item => {
                          const isSelected = newUser.role === UserRole.COORDINATOR ? newUser.assignedRegions?.includes(item) : newUser.assignedZones?.includes(item);
                          return (
                            <button key={item} type="button" onClick={() => toggleSelection(item, newUser.role === UserRole.COORDINATOR ? 'assignedRegions' : 'assignedZones')} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${isSelected ? 'bg-red-50 text-red-600' : 'text-slate-500 hover:bg-slate-50'}`}>
                              <span>{item}</span>
                              {isSelected && <Check className="w-4 h-4" />}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <button onClick={handleCreateUser} disabled={isCreatingUser} className="w-full py-5 bg-red-600 text-white font-black rounded-full shadow-xl hover:bg-red-700 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3">
                {isCreatingUser ? <RefreshCw className="w-4 h-4 animate-spin" /> : <CheckCircle2 className="w-4 h-4" />}
                Crear Acceso
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Download, X, Check, FileText } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const [showExportModal, setShowExportModal] = useState(false);
  const [exportConfig, setExportConfig] = useState({
    groups: Object.keys(EVALUATION_GROUPS),
    includeDetails: false
  });

  const allGrades = useMemo(() => dataService.getGrades(), []);

  const dynamicRegions = useMemo(() => {
    let regions = Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort();
    if (user.role === UserRole.COORDINATOR) {
      regions = regions.filter(r => user.assignedRegions.includes(r));
    }
    return regions;
  }, [restaurants, user]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    else if (user.role === UserRole.COORDINATOR) baseStores = baseStores.filter(r => user.assignedRegions.includes(r.region));

    let zones = Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    else if (user.role === UserRole.COORDINATOR) baseStores = baseStores.filter(r => user.assignedRegions.includes(r.region));

    if (filterZone !== 'all') baseStores = baseStores.filter(r => r.zone === filterZone);
    if (user.role === UserRole.SPECIALIST) baseStores = baseStores.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const employeesWithEffectiveGrades = useMemo(() => {
    return initialEmployees.map(emp => {
      const effectiveGrades = dataService.getEffectiveGrades(emp.id, selectedMonth);
      const exactMonthGrades = effectiveGrades.filter(g => g.month === selectedMonth);
      const storeIdAtPeriod = exactMonthGrades.length > 0 ? exactMonthGrades[0].restaurantId : emp.restaurant_id;
      const sum = effectiveGrades.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? Math.round(sum / TOTAL_CATEGORIES_COUNT) : 0;
      const isApproved = effectiveGrades.length > 0 && avg >= APPROVAL_THRESHOLD;
      const isPending = effectiveGrades.length === 0;

      return {
        ...emp,
        effectiveGrades,
        storeIdAtPeriod,
        avg,
        isApproved,
        isPending
      };
    });
  }, [initialEmployees, selectedMonth, allGrades]);

  const filteredData = useMemo(() => {
    return employeesWithEffectiveGrades.filter(e => {
      const store = restaurants.find(r => r.id === e.storeIdAtPeriod);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchRegion = filterRegion === 'all' ? (user.role === UserRole.COORDINATOR ? user.assignedRegions.includes(store?.region || '') : true) : store?.region === filterRegion;
      const matchZone = filterZone === 'all' ? true : store?.zone === filterZone;
      const matchStore = filterStore === 'all' ? true : e.storeIdAtPeriod === filterStore;

      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [employeesWithEffectiveGrades, searchPerson, filterStore, filterZone, filterRegion, restaurants, user]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    const approvedCount = filteredData.filter(e => e.isApproved).length;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      let totalScores = 0;
      let totalCatsPossible = filteredData.length * groupData.categories.length;

      filteredData.forEach(e => {
        const groupGrades = e.effectiveGrades.filter(g => g.group === groupId);
        totalScores += groupGrades.reduce((s, g) => s + g.score, 0);
      });

      const avg = totalCatsPossible > 0 ? totalScores / totalCatsPossible : 0;
      return { id: groupId, name: groupData.name, avg: Math.round(avg) };
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData]);

  const handleExportFinal = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.storeIdAtPeriod);
      const dynamicColumns: any = {};

      exportConfig.groups.forEach(gid => {
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const gGrades = emp.effectiveGrades.filter(g => g.group === gid);
        const sum = gGrades.reduce((s, g) => s + g.score, 0);
        const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
        dynamicColumns[`${gConfig.name} %`] = `${avg}%`;

        if (exportConfig.includeDetails) {
          gConfig.categories.forEach((cat: string) => {
            const grade = gGrades.find(g => g.category === cat);
            dynamicColumns[`[${gConfig.name}] ${cat}`] = grade ? `${grade.score}%` : '0%';
          });
        }
      });

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Cargo": emp.title,
        "Tienda Reportada": empStore?.name || emp.storeIdAtPeriod,
        "Ceco": emp.storeIdAtPeriod,
        "Jefe de area": empStore?.zone || emp.zone,
        "Mes Reporte": selectedMonth,
        "Promedio General": `${emp.avg}%`,
        "Certificación": emp.isPending ? 'Pendiente' : (emp.isApproved ? 'Aprobado' : 'No Cumple'),
        "Origen Nota": emp.isPending ? 'N/A' : (emp.effectiveGrades.some(g => g.month === selectedMonth) ? 'Mes Actual' : 'Heredada'),
        ...dynamicColumns
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
    setShowExportModal(false);
  };

  const selectClasses = "w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><MapPin className="w-3 h-3 mr-1 inline" /> Región</label>
            <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses}>
              <option value="all">{user.role === UserRole.COORDINATOR ? 'Mis Regiones' : 'Todas'}</option>
              {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
        )}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Tienda</label>
          <select value={filterStore} onChange={(e) => setFilterStore(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Search className="w-3 h-3 mr-1 inline" /> Persona</label>
          <input type="text" placeholder="ID o Nombre..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)} className="w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800" />
        </div>
        <button onClick={() => setShowExportModal(true)} className="w-full flex items-center justify-center space-x-2 px-4 py-3.5 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-lg">
          <Download className="w-4 h-4" /> <span>Exportar Excel</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.totalEmployees} subValue={`Trabajadores en alcance`} />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Nivel de Excelencia" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Promedio" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="General" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Pendientes" value={filteredData.filter(e => e.isPending).length} subValue="Sin ninguna nota" color="red" />
      </div>

      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
        <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center mb-8"><TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={stats.groupAvgs} margin={{ top: 20, right: 0, left: -25, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <Tooltip cursor={{ fill: '#f8fafc' }} />
              <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                <LabelList dataKey="avg" position="top" formatter={(v: any) => `${v}%`} style={{ fontSize: '10px', fontWeight: '900', fill: '#64748b' }} />
                {stats.groupAvgs.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {showExportModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden border-2 border-white/20">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <FileText className="w-6 h-6 text-red-500" />
                <h3 className="font-black uppercase italic tracking-tighter text-xl">Configurar Exportación</h3>
              </div>
              <button onClick={() => setShowExportModal(false)}><X className="w-6 h-6"/></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Grupos a incluir</label>
                <div className="grid grid-cols-2 gap-2">
                  {Object.entries(EVALUATION_GROUPS).map(([id, group]) => (
                    <button key={id} onClick={() => {
