      </div>

      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 z-40 lg:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab) => { setActiveTab(tab as any); setIsSidebarOpen(false); }} 
        role={auth.user!.role}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          user={auth.user!} 
          selectedMonth={selectedMonth} 
          onMonthChange={setSelectedMonth} 
          onMenuClick={() => setIsSidebarOpen(true)}
          onLogout={handleLogout}
        />
        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-6">
          {activeTab === 'dashboard' && <Dashboard employees={filteredEmployees} restaurants={restaurants} selectedMonth={selectedMonth} user={auth.user!} />}
          {activeTab === 'my-stores' && <MyStores user={auth.user!} restaurants={restaurants} employees={employees} selectedMonth={selectedMonth} onUpdate={refreshData} />}
          {activeTab === 'entries-exits' && (auth.user?.role === UserRole.ADMIN || auth.user?.role === UserRole.COORDINATOR) && <EntriesExitsReport employees={filteredEmployees} restaurants={restaurants} />}
          {activeTab === 'admin' && auth.user?.role === UserRole.ADMIN && <AdminPanel onEmployeesImported={refreshData} />}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData, Restaurant } from '../types';
import * as XLSX from 'xlsx';
import { 
  Shield, 
  AlertCircle, 
  CheckCircle2, 
  X, 
  FileSpreadsheet, 
  Network, 
  UserPlus, 
  Trash2, 
  Key,
  Download,
  MapPin,
  Store,
  Layers,
  ChevronDown,
  Check,
  RefreshCw,
  Globe,
  UploadCloud,
  Settings
} from 'lucide-react';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);
  const [isCreatingUser, setIsCreatingUser] = useState(false);
  const [showSelectorDropdown, setShowSelectorDropdown] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: [],
    assignedRegions: []
  });

  const availableRegions = useMemo(() => {
    return hierarchy.regions.map(r => r.name).sort();
  }, [hierarchy]);

  const availableZones = useMemo(() => {
    const zones = new Set<string>();
    hierarchy.regions.forEach(r => r.zones.forEach(z => zones.add(z.name)));
    return Array.from(zones).sort();
  }, [hierarchy]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) {
      alert("Por favor, ingresa usuario y contraseña.");
      return;
    }

    setIsCreatingUser(true);
    const userId = `user_${Date.now()}`;
    const userToSave: User = { 
      id: userId, 
      username: newUser.username!, 
      password: newUser.password!, 
      role: newUser.role!, 
      assignedZones: newUser.assignedZones || [], 
      assignedRestaurants: newUser.assignedRestaurants || [],
      assignedRegions: newUser.assignedRegions || []
    };

    try {
      const updatedUsersList = [...users, userToSave];
      await dataService.saveUsers(updatedUsersList);
      setUsers(updatedUsersList);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [], assignedRegions: [] });
      setImportStatus({ message: `Usuario @${userToSave.username} creado exitosamente.`, isError: false });
    } catch (e: any) { 
      console.error("Error al crear usuario:", e);
      alert(`Error crítico al guardar usuario: ${e.message}`); 
    } finally {
      setIsCreatingUser(false);
    }
  };

  const toggleSelection = (val: string, field: 'assignedZones' | 'assignedRegions') => {
    const current = (newUser as any)[field] || [];
    if (current.includes(val)) {
      setNewUser({ ...newUser, [field]: current.filter((v: string) => v !== val) });
    } else {
      setNewUser({ ...newUser, [field]: [...current, val] });
    }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { 
        await dataService.deleteUser(id); 
        setUsers(users.filter(u => u.id !== id)); 
        setImportStatus({ message: "Usuario eliminado correctamente.", isError: false });
      } catch (e) { 
        alert("Error al eliminar usuario del servidor."); 
      }
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {/* CONTENIDO TAB: CARGA EXCEL */}
        {activeSubTab === 'import' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in duration-300">
            <div className="p-8 bg-slate-50 rounded-[32px] border-2 border-dashed border-slate-200 flex flex-col items-center text-center space-y-4">
               <div className="w-16 h-16 bg-white rounded-2xl shadow-sm flex items-center justify-center text-red-600"><FileSpreadsheet className="w-8 h-8" /></div>
               <h3 className="text-sm font-black uppercase italic tracking-tight">Plantilla Personal Mensual</h3>
               <p className="text-[10px] text-slate-400 font-bold leading-relaxed">Sincroniza el listado de trabajadores activos, cargos y CECOs desde el archivo de nómina.</p>
               <label className="cursor-pointer bg-red-600 text-white px-8 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg flex items-center gap-2">
                 <UploadCloud className="w-4 h-4" /> Seleccionar Excel
                 <input type="file" accept=".xlsx, .xls" className="hidden" onChange={(e) => handleFileUpload(e, 'employees')} />
               </label>
            </div>
            <div className="p-8 bg-slate-50 rounded-[32px] border-2 border-dashed border-slate-200 flex flex-col items-center text-center space-y-4">
               <div className="w-16 h-16 bg-white rounded-2xl shadow-sm flex items-center justify-center text-slate-600"><Network className="w-8 h-8" /></div>
               <h3 className="text-sm font-black uppercase italic tracking-tight">Maestro Estructura (CECOs)</h3>
               <p className="text-[10px] text-slate-400 font-bold leading-relaxed">Define la relación entre Regiones, Zonas y Tiendas para los filtros de visualización.</p>
               <label className="cursor-pointer bg-slate-900 text-white px-8 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-black transition-all shadow-lg flex items-center gap-2">
                 <UploadCloud className="w-4 h-4" /> Cargar Estructura
                 <input type="file" accept=".xlsx, .xls" className="hidden" onChange={(e) => handleFileUpload(e, 'hierarchy')} />
               </label>
            </div>
          </div>
        )}

        {/* CONTENIDO TAB: ESTRUCTURA */}
        {activeSubTab === 'hierarchy' && (
          <div className="space-y-4 animate-in fade-in duration-300">
            <div className="flex items-center justify-between px-2">
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Mapa de Regiones y Zonas</p>
              <span className="text-[10px] font-black bg-slate-100 px-3 py-1 rounded-full uppercase">{availableRegions.length} Regiones</span>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {hierarchy.regions.map(region => (
                <div key={region.name} className="p-6 bg-white border border-slate-100 rounded-[28px] shadow-sm space-y-4">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-red-50 text-red-600 rounded-lg"><Globe className="w-4 h-4" /></div>
                    <p className="text-xs font-black uppercase italic tracking-tight">{region.name}</p>
                  </div>
                  <div className="space-y-2">
                    {region.zones.map(zone => (
                      <div key={zone.name} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                         <span className="text-[10px] font-black text-slate-600 uppercase">{zone.name}</span>
                         <span className="text-[9px] font-bold text-slate-400">{zone.restaurantIds.length} Tiendas</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
              {hierarchy.regions.length === 0 && (
                <div className="col-span-full py-20 text-center bg-slate-50 rounded-[32px] border-2 border-dashed border-slate-200">
                  <p className="text-xs font-black text-slate-300 uppercase tracking-widest italic">No hay estructura cargada. Sube el maestro de CECOs.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {/* CONTENIDO TAB: ESPECIALISTAS */}
        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in duration-300">
            <button onClick={() => { 
                setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [], assignedRegions: [] });
                setShowUserModal(true); 
              }} 
              className="p-6 border-2 border-dashed border-slate-200 rounded-[32px] flex flex-col items-center justify-center text-slate-400 hover:bg-slate-50 transition-colors group"
            >
              <div className="p-4 bg-slate-50 rounded-full mb-3 group-hover:bg-red-50 group-hover:text-red-600 transition-colors">
                <UserPlus className="w-6 h-6" />
              </div>
              <span className="text-[9px] font-black uppercase tracking-widest">Nuevo Usuario Acceso</span>
            </button>
            {users.map(u => (
              <div key={u.id} className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm group hover:border-red-200 transition-all relative">
                <div className="absolute top-6 right-6 opacity-0 group-hover:opacity-100 transition-opacity">
                  {u.username !== 'admin' && <button onClick={() => handleDeleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 bg-slate-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>}
                </div>
                <div className="min-w-0">
                  <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center mb-4 text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-all"><Key className="w-5 h-5" /></div>
                  <p className="text-sm font-black text-slate-800 uppercase truncate italic tracking-tight leading-none">{u.username}</p>
                  <p className={`text-[8px] font-black uppercase mt-2 tracking-widest inline-block px-2 py-0.5 rounded ${u.role === UserRole.ADMIN ? 'bg-slate-900 text-white' : u.role === UserRole.COORDINATOR ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
