                  <button onClick={() => setNewUser({...newUser, role: UserRole.COORDINATOR})} className={`py-3 rounded-xl text-[10px] font-black uppercase border-2 transition-all ${newUser.role === UserRole.COORDINATOR ? 'bg-blue-50 border-blue-500 text-blue-600' : 'bg-slate-50 border-transparent text-slate-400'}`}>Coordinador</button>
                </div>
              </div>

              <div className="space-y-2 relative">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-1.5">
                  {newUser.role === UserRole.COORDINATOR ? <Globe className="w-3 h-3" /> : <Layers className="w-3 h-3" />}
                  {newUser.role === UserRole.COORDINATOR ? 'Regiones Asignadas' : 'Zonas Asignadas'}
                </label>
                <div className="relative">
                  <button type="button" onClick={() => setShowSelectorDropdown(!showSelectorDropdown)} className="w-full flex items-center justify-between px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-[11px] font-black uppercase text-slate-900 shadow-sm transition-all hover:border-slate-300">
                    <span className="truncate">
                      {newUser.role === UserRole.COORDINATOR 
                        ? (newUser.assignedRegions?.length ? `${newUser.assignedRegions.length} regiones` : 'Seleccionar regiones...')
                        : (newUser.assignedZones?.length ? `${newUser.assignedZones.length} zonas` : 'Seleccionar zonas...')}
                    </span>
                    <ChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${showSelectorDropdown ? 'rotate-180' : ''}`} />
                  </button>

                  {showSelectorDropdown && (
                    <div className="absolute bottom-full mb-2 left-0 right-0 bg-white border-2 border-slate-100 rounded-2xl shadow-2xl z-[210] overflow-hidden animate-in slide-in-from-bottom-2">
                      <div className="max-h-[180px] overflow-y-auto p-2 no-scrollbar">
                        {(newUser.role === UserRole.COORDINATOR ? availableRegions : availableZones).map(item => {
                          const isSelected = newUser.role === UserRole.COORDINATOR ? newUser.assignedRegions?.includes(item) : newUser.assignedZones?.includes(item);
                          return (
                            <button key={item} type="button" onClick={() => toggleSelection(item, newUser.role === UserRole.COORDINATOR ? 'assignedRegions' : 'assignedZones')} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${isSelected ? 'bg-red-50 text-red-600' : 'text-slate-500 hover:bg-slate-50'}`}>
                              <span>{item}</span>
                              {isSelected && <Check className="w-4 h-4" />}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <button onClick={handleCreateUser} disabled={isCreatingUser} className="w-full py-5 bg-red-600 text-white font-black rounded-full shadow-xl hover:bg-red-700 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3">
                {isCreatingUser ? <RefreshCw className="w-4 h-4 animate-spin" /> : <CheckCircle2 className="w-4 h-4" />}
                Crear Acceso
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

