export default MyStores;

import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, Clock, GraduationCap, Star, Trophy, ClipboardCheck, Vault, ChevronRight, CheckCircle2, MapPin, Cloud, History, ArrowRight, Lock, RefreshCw, BookOpen, ArrowUp, ArrowDown, Repeat } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'AK': <BookOpen className="w-5 h-5" />,
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
  'C': <Trophy className="w-5 h-5" />,
  'D': <ClipboardCheck className="w-5 h-5" />,
  'E': <Vault className="w-5 h-5" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('AK');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  // Lógica de bloqueo Manual: El mes se bloquea si está en el array lockedMonths de la jerarquía
  const isPeriodLocked = useMemo(() => {
    const hierarchy = dataService.getHierarchy();
    return hierarchy.lockedMonths.includes(month);
  }, [month]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    if (existing.length > 0) {
      setFormGrades(existing);
    } else {
      const effective = dataService.getEffectiveGrades(employee.id, month);
      setFormGrades(effective.map(g => ({ ...g, month })));
    }
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (isPeriodLocked) return;
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { 
        const next = [...prev]; 
        next[idx] = { ...next[idx], score }; 
        return next; 
      }
      return [...prev, { employeeId: employee.id, month, group, category, score, restaurantId: employee.restaurant_id }];
    });
  };

  const saveGrades = async () => {
    if (isPeriodLocked) return;
    setIsSaving(true);
    try {
      await dataService.saveEmployeeGrades(employee.id, month, formGrades);
      onClose();
    } catch (err: any) {
      alert(`Error al guardar notas: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-white h-full w-full md:h-[92vh] md:max-w-6xl md:rounded-[48px] flex flex-col overflow-hidden relative shadow-2xl">

        <div className="p-5 md:p-8 bg-slate-900 text-white shrink-0 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center space-x-4 md:space-x-6">
            <div className="w-12 h-12 md:w-16 md:h-16 bg-red-600 rounded-2xl md:rounded-3xl flex items-center justify-center shadow-lg border-4 border-white/10">
              <User className="w-6 h-6 md:w-9 md:h-9 text-white" />
            </div>
            <div>
              <div className="flex wrap items-center gap-2 md:gap-4">
                 <h2 className="text-lg md:text-2xl font-black uppercase italic truncate max-w-[200px] md:max-w-none">{employee.name}</h2>
                 <span className="px-3 py-1 bg-red-600 text-[8px] md:text-[10px] font-black rounded-full uppercase tracking-widest">{employee.title}</span>
              </div>
              <div className="flex wrap gap-x-4 gap-y-1 mt-1 text-[9px] font-black uppercase tracking-widest opacity-60">
                <span className="flex items-center gap-1"><Calendar className="w-3 h-3" /> Periodo: {month}</span>
                <span className="flex items-center gap-1"><MapPin className="w-3 h-3" /> Tienda: {employee.restaurant_id}</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2 self-end md:self-auto">
             <button onClick={onClose} className="p-2 bg-white/10 hover:bg-red-600 rounded-xl transition-all shadow-md"><X className="w-6 h-6"/></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-200 flex md:flex-col overflow-x-auto md:overflow-y-auto p-4 gap-3 no-scrollbar shrink-0 sticky top-0 z-10">
            <p className="hidden md:block text-[9px] font-black uppercase tracking-widest text-slate-400 mb-2 px-2">Categorías</p>
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const isActive = activeGroup === id;
              const groupGrades = formGrades.filter(g => g.group === id);
              const groupAvg = groupGrades.length > 0 ? Math.round(groupGrades.reduce((s, g) => s + g.score, 0) / (group as any).categories.length) : 0;

              return (
                <button 
                  key={id} 
                  onClick={() => setActiveGroup(id)} 
                  className={`p-3 md:p-5 rounded-2xl md:rounded-3xl text-left border-2 transition-all flex items-center gap-3 shrink-0 md:shrink ${isActive ? 'bg-white border-red-600 shadow-lg' : 'bg-transparent border-transparent opacity-50'}`}
                >
                  <div className={`p-2 rounded-xl ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{GroupIcons[id]}</div>
                  <div className="hidden md:block flex-1 min-w-0">
                    <p className={`text-[10px] font-black uppercase tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>{group.name}</p>
                    <div className="mt-2 flex items-center gap-2">
                       <div className="flex-1 h-1 bg-slate-200 rounded-full overflow-hidden">
                          <div className={`h-full ${groupAvg >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${groupAvg}%`}} />
                       </div>
                       <span className="text-[9px] font-black text-slate-400">{groupAvg}%</span>
                    </div>
                  </div>
                </button>
              );
            })}

            <div className="hidden md:block mt-6 pt-6 border-t border-slate-200">
               <p className="text-[9px] font-black uppercase tracking-widest text-slate-400 mb-4 px-2">Historial de Movimientos</p>
               <div className="space-y-4 px-2">
                  {employee.history?.map((h, i) => (
                    <div key={i} className="flex gap-3 items-start relative pb-4 last:pb-0">
                       {i < (employee.history?.length || 0) - 1 && <div className="absolute left-3 top-6 bottom-0 w-0.5 bg-slate-100" />}
                       <div className={`w-6 h-6 rounded-full flex items-center justify-center shrink-0 ${h.action === 'INGRESO' ? 'bg-emerald-100 text-emerald-600' : h.action === 'RETIRO' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                          {h.action === 'INGRESO' ? <ArrowUp className="w-3 h-3" /> : h.action === 'RETIRO' ? <ArrowDown className="w-3 h-3" /> : <Repeat className="w-3 h-3" />}
                       </div>
                       <div className="min-w-0">
                          <p className="text-[8px] font-black uppercase text-slate-800 leading-tight">{h.action}</p>
                          <p className="text-[7px] font-bold text-slate-400 uppercase truncate tracking-widest mt-0.5">{h.restaurantName}</p>
                          <p className="text-[7px] font-bold text-slate-300 mt-0.5">{h.date}</p>
                       </div>
                    </div>
                  ))}
                  {(!employee.history || employee.history.length === 0) && (
                    <p className="text-[8px] text-slate-300 uppercase font-black italic">Sin historial registrado</p>
                  )}
               </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 md:p-12 bg-white no-scrollbar">
            <div className="max-w-2xl mx-auto">
              <div className="space-y-6">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-lg font-black uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                  {isPeriodLocked && <div className="flex items-center gap-1.5 bg-red-100 text-red-600 px-3 py-1 rounded-full text-[9px] font-black uppercase"><Lock className="w-3 h-3"/> Lectura</div>}
                </div>

                <div className="space-y-4">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                    const grade = formGrades.find(g => g.group === activeGroup && g.category === cat);
                    const score = grade?.score ?? 0;
                    const isInherited = grade && grade.month !== month;

                    return (
                      <div key={cat} className="bg-slate-50/50 border-2 border-transparent rounded-[24px] p-5 flex items-center justify-between gap-6 transition-all hover:bg-white hover:border-slate-100">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-3">
                            <label className="text-[10px] font-black text-slate-900 uppercase block">{cat}</label>
                            {isInherited && <span className="text-[8px] bg-slate-900 text-white px-2 py-0.5 rounded uppercase font-black">Heredado</span>}
                          </div>
                          <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                            <div className={`h-full ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                          </div>
                        </div>
                        <div className="relative">
                          <input 
                            type="number" 
                            disabled={isPeriodLocked}
                            value={score === 0 ? '' : score} 
                            onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                            className={`w-16 md:w-20 px-2 py-3 bg-white border-2 rounded-xl text-lg font-black text-center shadow-md outline-none ${isPeriodLocked ? 'text-slate-300' : score >= 90 ? 'border-emerald-100 text-emerald-700' : 'border-slate-200 text-slate-800 focus:border-red-500'}`} 
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 md:p-8 border-t border-slate-100 bg-slate-50 flex flex-col sm:flex-row gap-4 justify-between items-center shrink-0">
          <div className="hidden sm:block">
            <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-relaxed italic">
              {isPeriodLocked ? '* Este periodo ha sido ASENTADO por el Administrador. No se permiten cambios.' : '* El periodo puede ser asentado manualmente por el Administrador.'}<br/>
              * Las notas se heredan automáticamente si no se modifican.
            </div>
          </div>
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <button onClick={onClose} className="flex-1 sm:flex-none px-8 py-4 bg-white text-slate-400 font-black rounded-2xl border-2 border-slate-200 text-[10px] uppercase transition-all">Regresar</button>
            {!isPeriodLocked && (
              <button onClick={saveGrades} disabled={isSaving} className="flex-1 sm:flex-none px-10 py-4 bg-red-600 text-white text-[10px] font-black rounded-2xl shadow-xl hover:bg-red-700 transition-all uppercase flex items-center justify-center gap-2">
                {isSaving ? <RefreshCw className="w-4 h-4 animate-spin"/> : <Save className="w-4 h-4"/>}
                {isSaving ? 'Sincronizando...' : 'Guardar y Certificar'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy, JobTitle } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, TrendingUp, Search, Edit3, LineChart, Download, X, Calendar, RefreshCw, BarChart3, ChevronRight, Activity, BookOpen, GraduationCap, Star, Trophy, ClipboardCheck, Vault } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'AK': <BookOpen className="w-4 h-4" />,
  'A': <GraduationCap className="w-4 h-4" />,
  'B': <Star className="w-4 h-4" />,
  'C': <Trophy className="w-4 h-4" />,
  'D': <ClipboardCheck className="w-4 h-4" />,
  'E': <Vault className="w-4 h-4" />,
};

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => {
    const all = Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort();
    if (user.role === UserRole.COORDINATOR) {
      return all.filter(r => user.assignedRegions?.includes(r));
    }
    return all;
  }, [restaurants, user]);

  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') {
      base = base.filter(r => r.region === filterRegion);
    } else if (user.role === UserRole.COORDINATOR) {
      base = base.filter(r => user.assignedRegions?.includes(r.region));
    }

    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) {
      zones = zones.filter(z => user.assignedZones.includes(z));
    }
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = restaurants;
    if (user.role === UserRole.COORDINATOR) {
      base = restaurants.filter(r => user.assignedRegions?.includes(r.region));
    } else if (user.role === UserRole.SPECIALIST) {
      base = restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
    }

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStatsForMonth = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupStats: {} as Record<string, {avg: number, approvalRate: number}>, cargoCounts: {} as Record<string, number> };

    let storeApprovedCount = 0;
    const groupData: Record<string, { scores: number[], passed: number }> = {};
    const cargoCounts: Record<string, number> = {};

    Object.keys(EVALUATION_GROUPS).forEach(gid => {
      groupData[gid] = { scores: [], passed: 0 };
    });

    storeEmps.forEach(emp => {
      cargoCounts[emp.title] = (cargoCounts[emp.title] || 0) + 1;
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const totalAvg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && totalAvg >= APPROVAL_THRESHOLD) storeApprovedCount++;

      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        const gAvg = gSum / gconfig.categories.length;
        groupData[gid].scores.push(gAvg);
        if (gAvg >= APPROVAL_THRESHOLD) groupData[gid].passed++;
      });
    });

    const groupStats: Record<string, {avg: number, approvalRate: number}> = {};
    Object.keys(EVALUATION_GROUPS).forEach(gid => {
      const avg = groupData[gid].scores.length > 0 ? groupData[gid].scores.reduce((a,b)=>a+b, 0) / groupData[gid].scores.length : 0;
      const rate = storeEmps.length > 0 ? (groupData[gid].passed / storeEmps.length) * 100 : 0;
      groupStats[gid] = { avg: Math.round(avg), approvalRate: Math.round(rate) };
    });

    return { 
      total: storeEmps.length, 
      approved: storeApprovedCount, 
      percent: Math.round((storeApprovedCount / storeEmps.length) * 100), 
      groupStats, 
      cargoCounts 
    };
  };

  const handleGeneratePDF = async () => {
    if (!selectedStore || isGeneratingPdf) return;
    setIsGeneratingPdf(true);

    setTimeout(async () => {
      try {
        const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
        const stats = getStoreStatsForMonth(selectedStore.id, pdfMonth);
        const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

        const colors = {
          kfcRed: [227, 24, 55],
          dark: [26, 32, 44],
          emerald: [16, 185, 129]
        };

        doc.setFillColor(colors.kfcRed[0], colors.kfcRed[1], colors.kfcRed[2]);
        doc.rect(0, 0, 210, 50, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(9);
        doc.text('REPORTE DE CERTIFICACIÓN - GENERAR CURVAS', 20, 15);
        doc.setFontSize(26);
        doc.text(selectedStore.name.toUpperCase(), 20, 30);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        doc.text(`CECO: ${selectedStore.id} | REGIÓN: ${selectedStore.region} | PERIODO: ${pdfMonth}`, 20, 38);

        doc.setFillColor(255, 255, 255);
        doc.circle(170, 25, 18, 'F');
        doc.setTextColor(colors.kfcRed[0], colors.kfcRed[1], colors.kfcRed[2]);
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(14);
        doc.text(`${stats.percent}%`, 170, 27, { align: 'center' });
        doc.setFontSize(6);
        doc.text('CURVA TOTAL', 170, 32, { align: 'center' });

        doc.setTextColor(colors.dark[0], colors.dark[1], colors.dark[2]);
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.text('CENSO DE EQUIPO (ESTRUCTURA DE MANDO)', 20, 65);

        const roleData = [
          [JobTitle.GERENTE.toUpperCase(), stats.cargoCounts[JobTitle.GERENTE] || 0],
          [JobTitle.SUBGERENTE.toUpperCase(), stats.cargoCounts[JobTitle.SUBGERENTE] || 0],
          [JobTitle.LIDER_TURNO.toUpperCase(), stats.cargoCounts[JobTitle.LIDER_TURNO] || 0],
          [JobTitle.ENTRENADOR.toUpperCase(), stats.cargoCounts[JobTitle.ENTRENADOR] || 0],
          [JobTitle.MIEMBRO_EQUIPO_FULL.toUpperCase(), stats.cargoCounts[JobTitle.MIEMBRO_EQUIPO_FULL] || 0],
          [JobTitle.MIEMBRO_EQUIPO_ROLEX.toUpperCase(), stats.cargoCounts[JobTitle.MIEMBRO_EQUIPO_ROLEX] || 0],
          [JobTitle.DOMICILIARIO.toUpperCase(), stats.cargoCounts[JobTitle.DOMICILIARIO] || 0],
          [{ content: 'TOTAL PERSONAL ACTIVO', styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }, { content: stats.total, styles: { fontStyle: 'bold', fillColor: colors.kfcRed, textColor: 255 } }]
        ];

        autoTable(doc, {
          startY: 70,
          head: [['CARGO EN TIENDA', 'CANTIDAD']],
          body: roleData,
          theme: 'grid',
          styles: { fontSize: 8, cellPadding: 2, halign: 'center' },
          headStyles: { fillColor: colors.dark, textColor: 255 },
          margin: { left: 20, right: 110 }
        });

        doc.setTextColor(colors.dark[0], colors.dark[1], colors.dark[2]);
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.text('PORCENTAJE DE APROBACIÓN POR CURVA', 110, 65);

        let barY = 70;
        Object.entries(EVALUATION_GROUPS).forEach(([gid, config]) => {
          const rate = stats.groupStats[gid]?.approvalRate || 0;
          doc.setFontSize(7);
          doc.setTextColor(100);
          doc.text(config.name.toUpperCase(), 110, barY + 4);
          doc.setFillColor(240, 240, 240);
          doc.roundedRect(110, barY + 6, 80, 4, 1, 1, 'F');
          const barColor = rate >= 90 ? colors.emerald : colors.kfcRed;
          doc.setFillColor(barColor[0], barColor[1], barColor[2]);
          doc.roundedRect(110, barY + 6, (rate / 100) * 80, 4, 1, 1, 'F');
          doc.setTextColor(barColor[0], barColor[1], barColor[2]);
          doc.setFont('helvetica', 'bold');
          doc.text(`${rate}%`, 192, barY + 9.5);
          barY += 15;
        });

        doc.addPage();
        doc.setFillColor(colors.dark[0], colors.dark[1], colors.dark[2]);
        doc.rect(0, 0, 210, 15, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(9);
        doc.text(`DESGLOSE DETALLADO DE CALIFICACIONES - ${pdfMonth}`, 15, 10);

        const tableData = storeEmps
          .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99))
          .map(emp => {
            const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
            const sum = effective.reduce((s, g) => s + g.score, 0);
            const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
            const isCert = avg >= APPROVAL_THRESHOLD;
            const getScore = (gid: string) => {
              const gGrades = effective.filter(g => g.group === gid);
              const gConf = (EVALUATION_GROUPS as any)[gid];
              return gGrades.length > 0 ? `${Math.round(gGrades.reduce((s,g)=>s+g.score,0) / gConf.categories.length)}%` : '0%';
            };
            return [
              emp.id,
              emp.name.toUpperCase(),
              emp.join_date,
              emp.title.toUpperCase(),
              { content: `${avg}%`, styles: { fontStyle: 'bold', textColor: isCert ? colors.emerald : colors.kfcRed } },
              getScore('A'), getScore('B'), getScore('C'), getScore('D'), getScore('E')
            ];
          });

        autoTable(doc, {
          startY: 20,
          head: [['ID', 'NOMBRE', 'INGRESO', 'CARGO', 'PROM.', 'BAS.', 'STAR', 'ALLS.', 'SST', 'VAUL.']],
          body: tableData,
          theme: 'grid',
          styles: { fontSize: 7, halign: 'center', cellPadding: 2 },
          headStyles: { fillColor: colors.kfcRed, textColor: 255 },
          columnStyles: {
            1: { halign: 'left', cellWidth: 35 },
            2: { halign: 'center', cellWidth: 20 },
            3: { halign: 'left', cellWidth: 30 }
          }
        });

        doc.save(`Curvas_Certificacion_${selectedStore.id}_${pdfMonth}.pdf`);
        setShowPdfModal(false);
      } catch (err) {
        console.error(err);
        alert("Error al generar el reporte PDF.");
      } finally {
        setIsGeneratingPdf(false);
      }
    }, 200);
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStatsForMonth(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.SPECIALIST ? e.active : true))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button type="button" onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm relative z-20"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              type="button"
              onClick={() => { setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg"
            >
              <LineChart className="w-4 h-4" /> <span>Generar Curvas</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <input 
                type="text" 
                placeholder="Buscar personal..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Estructura Total" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Curva Global" value={`${stats.percent}%`} color="red" />
        </div>

        {/* Widgets de Cumplimiento por Grupo */}
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-4">
           {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const groupAvg = stats.groupStats[id]?.avg || 0;
              return (
                <div key={id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex flex-col items-center text-center">
                   <div className={`p-2 rounded-xl mb-2 ${groupAvg >= 90 ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                      {GroupIcons[id]}
                   </div>
                   <p className="text-[8px] font-black uppercase text-slate-400 tracking-tighter mb-1 truncate w-full">{group.name}</p>
                   <p className={`text-lg font-black tracking-tighter ${groupAvg >= 90 ? 'text-emerald-700' : 'text-red-700'}`}>{groupAvg}%</p>
                </div>
              );
           })}
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Activity className="w-4 h-4 mr-2 text-red-600" /> Registro de Notas
             </h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Score</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');
                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button type="button" onClick={() => setEditingEmployee(emp)} className="w-9 h-9 bg-slate-900 text-white rounded-xl hover:bg-red-600 transition-all flex items-center justify-center mx-auto shadow-md"><Edit3 className="w-4 h-4" /></button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <p className="font-black text-slate-800 text-[12px] uppercase italic">{emp.name}</p>
                        <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest">{emp.title} | ID: {emp.id}</p>
                      </td>
                      <td className="px-4 md:px-8 py-4 text-center">
                        <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-md ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>{status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Cumple' : 'S/N'}</span>
                        {status !== 'PENDING' && <p className="text-[12px] font-black text-slate-900">{avg}%</p>}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-950/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-sm overflow-hidden border-2 border-white/20 relative">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center relative z-10">
                <div className="flex items-center gap-4">
                  <LineChart className="w-6 h-6 text-red-500" />
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button type="button" onClick={() => setShowPdfModal(false)} className="p-2 hover:bg-white/10 rounded-xl transition-all"><X className="w-5 h-5"/></button>
              </div>

              <div className="p-10 space-y-8 bg-white relative z-10">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Periodo a Consultar</label>
                  <div className="relative group">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 z-10 pointer-events-none text-red-600"><Calendar className="w-4 h-4" /></div>
                    <input 
                      type="month" 
                      value={pdfMonth} 
                      onChange={e => setPdfMonth(e.target.value)}
                      className="w-full pl-12 pr-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all shadow-inner cursor-pointer" 
                    />
                  </div>
                </div>

                <button onClick={handleGeneratePDF} disabled={isGeneratingPdf} className="w-full py-6 bg-red-600 text-white font-black rounded-[32px] hover:bg-red-700 shadow-2xl transition-all uppercase tracking-[0.2em] text-[11px] flex items-center justify-center gap-4 disabled:opacity-50">
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Calculando...' : 'Descargar Curvas'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas las Regiones</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas las Zonas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <div className="relative">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input type="text" placeholder="Nombre o CECO..." value={storeSearch} onChange={e => setStoreSearch(e.target.value)} className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStatsForMonth(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl transition-all group cursor-pointer flex flex-col p-8 relative">
              <div className="absolute top-6 right-6 text-slate-100 group-hover:text-red-50 transition-colors"><ChevronRight className="w-10 h-10" /></div>
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white shadow-sm"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white shadow-sm"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Aprobación</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

