            };
            return [
              emp.id,
              emp.name.toUpperCase(),
              emp.join_date,
              emp.title.toUpperCase(),
              { content: `${avg}%`, styles: { fontStyle: 'bold', textColor: isCert ? colors.emerald : colors.kfcRed } },
              getScore('A'), getScore('B'), getScore('C'), getScore('D'), getScore('E')
