const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

export const dataService = {
  supabaseFetch: async (table: string, method: string = 'GET', body?: any, queryParams: string = '') => {
    const url = `${SUPABASE_URL}/rest/v1/${table}${queryParams}`;
    const isUpsert = queryParams.includes('on_conflict');

    const options: any = {
      method,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': isUpsert ? 'return=representation,resolution=merge-duplicates' : 'return=representation'
      }
    };

    if (body) options.body = JSON.stringify(body, (k, v) => v === undefined ? null : v);

    try {
      const res = await fetch(url, options);
      if (!res.ok) {
        const errorText = await res.text();
        console.error(`Error detallado de Supabase en tabla [${table}]:`, errorText);
        throw new Error(`Supabase Error [${table}]: ${errorText}`);
      }

      if (res.status === 204) return true;
      const text = await res.text();
      return text ? JSON.parse(text) : true;
    } catch (err) {
      console.error("Fallo de red o servidor al conectar con Supabase:", err);
      throw err;
    }
  },

  supabaseFetchAll: async (table: string): Promise<any[]> => {
    let allData: any[] = [];
    let from = 0;
    const step = 1000;
    let hasMore = true;
    while (hasMore) {
      const url = `${SUPABASE_URL}/rest/v1/${table}?select=*&offset=${from}&limit=${step}`;
      try {
        const res = await fetch(url, { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } });
        if (!res.ok) {
           const errText = await res.text();
           throw new Error(errText);
        }
        const data = await res.json();
        allData = [...allData, ...data];
        if (data.length < step) hasMore = false; else from += step;
      } catch (e) {
        console.warn(`No se pudieron cargar datos de la tabla ${table}. ¿Existe en Supabase?`, e);
        hasMore = false;
      }
    }
    return allData;
  },

  loadAllFromCloud: async () => {
    try {
      const [employees, restaurants, rawGrades, hierarchy, users] = await Promise.all([
        dataService.supabaseFetchAll('employees'),
        dataService.supabaseFetchAll('restaurants'),
        dataService.supabaseFetchAll('grades'),
        dataService.supabaseFetch('hierarchy').catch(() => []),
        dataService.supabaseFetchAll('users').catch(() => [])
      ]);

      const grades: GradeEntry[] = (rawGrades || []).map((g: any) => ({
        employeeId: g.employee_id,
        restaurantId: g.restaurant_id || '',
        month: g.month,
        group: g.group,
        category: g.category,
        score: g.score
      }));

      localStorage.setItem('la_akademia_employees', JSON.stringify(employees || []));
      localStorage.setItem('la_akademia_stores', JSON.stringify(restaurants || []));
      localStorage.setItem('la_akademia_grades', JSON.stringify(grades || []));
      localStorage.setItem('la_akademia_users', JSON.stringify(users || []));

      const defaultHierarchy = { lockedMonths: [], regions: [] };
      const cloudHierarchy = (hierarchy && hierarchy[0]?.data) ? hierarchy[0].data : defaultHierarchy;
      localStorage.setItem('la_akademia_hierarchy', JSON.stringify(cloudHierarchy));
      return true;
    } catch (e) {
      console.error("Error crítico al cargar desde la nube:", e);
      return false;
    }
  },

  getEmployees: (): Employee[] => JSON.parse(localStorage.getItem('la_akademia_employees') || '[]'),
  getRestaurants: (): Restaurant[] => JSON.parse(localStorage.getItem('la_akademia_stores') || '[]'),
  getGrades: (): GradeEntry[] => JSON.parse(localStorage.getItem('la_akademia_grades') || '[]'),

  getEffectiveGrades: (employeeId: string, upToMonth: string): GradeEntry[] => {
    const allGrades = dataService.getGrades();

    // Filtrar grados: 
    // 1. Pertenecen al empleado.
    // 2. Mes es menor o igual al consultado.
    // 3. EXCEPCIÓN REGLA SST (Grupo D): Solo se permite el mes EXACTO, no se arrastra de meses previos.
    const empGrades = allGrades.filter(g => {
      if (g.employeeId !== employeeId) return false;
      if (g.month > upToMonth) return false;

      // Regla de NO arrastre para Grupo D (SST / Plan Capacitación)
      if (g.group === 'D' && g.month !== upToMonth) return false;

      return true;
    });

    const latestMap = new Map<string, GradeEntry>();
    empGrades.forEach(g => {
      const key = `${g.group}-${g.category}`;
      const existing = latestMap.get(key);
      if (!existing || g.month > existing.month) {
        latestMap.set(key, g);
      }
    });

    return Array.from(latestMap.values());
  },

  getHierarchy: (): HierarchyData => JSON.parse(localStorage.getItem('la_akademia_hierarchy') || '{"lockedMonths":[], "regions":[]}'),
  getUsers: (): User[] => {
    const local = JSON.parse(localStorage.getItem('la_akademia_users') || '[]');
    const adminExists = local.some((u: any) => u.username === 'admin');
    if (!adminExists) {
      const admin = { id: 'admin-master', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [], assignedRegions: [] };
      return [admin, ...local];
    }
    return local;
  },

  saveEmployees: async (employees: Employee[]) => {
    localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
    // Normalizar para evitar error PGRST102 (llaves faltantes en objetos del array)
    const normalized = employees.map(e => ({
      id: e.id,
      name: e.name,
      join_date: e.join_date,
      exit_date: e.exit_date || null,
      title: e.title,
      restaurant_id: e.restaurant_id,
      zone: e.zone,
      active: e.active,
      history: e.history || []
    }));
    const chunkSize = 100;
    for (let i = 0; i < normalized.length; i += chunkSize) {
      await dataService.supabaseFetch('employees', 'POST', normalized.slice(i, i + chunkSize), '?on_conflict=id');
    }
  },

  saveRestaurants: async (restaurants: Restaurant[]) => {
    localStorage.setItem('la_akademia_stores', JSON.stringify(restaurants));
    await dataService.supabaseFetch('restaurants', 'POST', restaurants, '?on_conflict=id');
  },

  clearAllDataInCloud: async () => {
    // IMPORTANTE: Primero borrar notas (hijas) y luego empleados (padres) por integridad referencial
    await dataService.supabaseFetch('grades', 'DELETE', null, '?employee_id=not.is.null');
    await dataService.supabaseFetch('employees', 'DELETE', null, '?id=not.is.null');
    localStorage.setItem('la_akademia_employees', '[]');
    localStorage.setItem('la_akademia_grades', '[]');
  },

  saveEmployeeGrades: async (employeeId: string, month: string, grades: GradeEntry[]) => {
    const employees = dataService.getEmployees();
    const emp = employees.find(e => e.id === employeeId);
    const currentCeco = emp?.restaurant_id || 'SIN_CECO';

    const deleteUrl = `${SUPABASE_URL}/rest/v1/grades?employee_id=eq.${employeeId}&month=eq.${month}`;
    await fetch(deleteUrl, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });

    if (grades.length > 0) {
      const payload = grades.map(g => ({
        employee_id: g.employeeId,
        restaurant_id: currentCeco,
        month: month, 
        group: g.group,
        category: g.category,
        score: g.score
      }));
      await dataService.supabaseFetch('grades', 'POST', payload);
    }

    const allGrades = dataService.getGrades().filter(g => !(g.employeeId === employeeId && g.month === month));
    const gradesWithContext = grades.map(g => ({ ...g, month, restaurantId: currentCeco }));
    const updated = [...allGrades, ...gradesWithContext];
    localStorage.setItem('la_akademia_grades', JSON.stringify(updated));
  },

  saveHierarchy: async (hierarchy: HierarchyData) => {
    localStorage.setItem('la_akademia_hierarchy', JSON.stringify(hierarchy));
    await dataService.supabaseFetch('hierarchy', 'POST', { id: 1, data: hierarchy }, '?on_conflict=id');
  },

  deleteUser: async (userId: string) => {
    const url = `${SUPABASE_URL}/rest/v1/users?id=eq.${userId}`;
    const res = await fetch(url, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    if (!res.ok) throw new Error('No se pudo eliminar el usuario');
    const current = dataService.getUsers().filter(u => u.id !== userId);
    localStorage.setItem('la_akademia_users', JSON.stringify(current));
  },

  importHierarchyExcel: async (rawData: any[]) => {
    const restaurants: Restaurant[] = [];
    const regionMap = new Map<string, Map<string, Set<string>>>();

    rawData.forEach(item => {
      const id = String(item.Nombre_Ceco || item.nombre_ceco || item.Ceco || item.ceco || item.CECO || '').trim().toUpperCase();
      const name = String(item.Nombre || item.nombre || item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      const zone = String(item.Zona || item.zona || item.ZONA || item["Jefe de area"] || 'Sin Zona').trim();
      const region = String(item.Regional || item.regional || item.Region || item.REGION || 'Sin Region').trim();

      if (!id || id === 'SIN_CECO') return;
      restaurants.push({ id, name, zone, region });

      if (!regionMap.has(region)) regionMap.set(region, new Map());
      const zonesInRegion = regionMap.get(region)!;
      if (!zonesInRegion.has(zone)) zonesInRegion.set(zone, new Set());
      zonesInRegion.get(zone)!.add(id);
    });

    await dataService.saveRestaurants(restaurants);
    const currentHierarchy = dataService.getHierarchy();
    const hierarchy: HierarchyData = {
      lockedMonths: currentHierarchy.lockedMonths || [],
      groupDConfig: currentHierarchy.groupDConfig || {},
      regions: Array.from(regionMap.entries()).map(([regionName, zonesMap]) => ({
        name: regionName,
        zones: Array.from(zonesMap.entries()).map(([zoneName, storeIds]) => ({
          name: zoneName,
          restaurantIds: Array.from(storeIds)
        }))
      }))
    };
    await dataService.saveHierarchy(hierarchy);
    return restaurants.length;
  },

  importMonthlyExcel: async (rawData: any[]) => {
    await dataService.loadAllFromCloud();
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const importedIds = new Set();
    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      return storeId !== '' && !storeId.startsWith('H');
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim().toUpperCase();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;
      importedIds.add(docId);

      const existing = currentEmployees.find(e => e.id === docId);

      const rawFechaFin = item["Fecha fin"] || item.fecha_fin || item["Fecha retiro"] || item.fecha_retiro || item.FECHA_FIN;
      const parsedFechaFin = rawFechaFin ? parseExcelDate(rawFechaFin) : null;

      const isActiveInExcel = !parsedFechaFin;

      // Lógica de transformación de Cargos
      const rawCargo = String(item.Cargo || item.cargo || '').trim().toUpperCase();
      let finalTitle: JobTitle = rawCargo as JobTitle;

      if (rawCargo.includes('MIEMBRO DE EQUIPO')) {
        if (rawCargo.includes('OF. VARIOS')) {
          finalTitle = JobTitle.MIEMBRO_EQUIPO_FULL;
        } else {
          // Captura FDS, HRS y cualquier otra variación
          finalTitle = JobTitle.MIEMBRO_EQUIPO_ROLEX;
        }
      }

      const emp: Employee = {
        id: docId,
        name: String(item["Nombre completo"] || item.nombre || 'Sin Nombre').trim(),
        join_date: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: finalTitle,
        restaurant_id: storeId,
        zone: currentStores.find(s => s.id === storeId)?.zone || (existing?.zone || 'Sin Clasificar'),
        active: isActiveInExcel,
        history: existing?.history || [],
        exit_date: parsedFechaFin || existing?.exit_date
      };

      if (existing) {
        if (existing.restaurant_id !== storeId && existing.restaurant_id !== 'SIN_CECO') {
           emp.history!.push({ date: today, restaurantName: existing.restaurant_id, action: 'TRASLADO' });
        }
        if (existing.active && !isActiveInExcel && parsedFechaFin) {
           emp.history!.push({ date: parsedFechaFin, restaurantName: storeId, action: 'RETIRO' });
        }
        if (!existing.active && isActiveInExcel) {
           emp.exit_date = undefined;
           emp.history!.push({ date: today, restaurantName: storeId, action: 'INGRESO' });
        }
      } else {
        emp.history = [{ date: emp.join_date || today, restaurantName: storeId, action: 'INGRESO' }];
        if (!isActiveInExcel && parsedFechaFin) {
          emp.history.push({ date: parsedFechaFin, restaurantName: storeId, action: 'RETIRO' });
        }
      }
      return emp;
    }).filter(e => e !== null) as Employee[];

    const uniqueStoresInExcel = new Set(filteredRawData.map(item => String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase()));

    const implicitRetires = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active && uniqueStoresInExcel.has(e.restaurant_id))
      .map(e => ({
        ...e, 
        active: false, 
        exit_date: today,
        history: [...(e.history || []), { date: today, restaurantName: e.restaurant_id, action: 'RETIRO' as const }]
      }));

    const allProcessedMap = new Map<string, Employee>();
    importedEmployees.forEach(e => allProcessedMap.set(e.id, e));
    implicitRetires.forEach(e => allProcessedMap.set(e.id, e));
    currentEmployees.forEach(old => {
      if (!allProcessedMap.has(old.id)) {
        allProcessedMap.set(old.id, old);
      }
    });

    const finalEmployees = Array.from(allProcessedMap.values());
    await dataService.saveEmployees(finalEmployees);
    return { count: importedEmployees.length };
  }
};

import React, { useState, useMemo } from 'react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData, Restaurant } from '../types';
import * as XLSX from 'xlsx';
import { 
  Shield, 
  AlertCircle, 
  CheckCircle2, 
  X, 
  FileSpreadsheet, 
  Network, 
  UserPlus, 
  Trash2, 
  Key,
  Layers,
  ChevronDown,
  Check,
  RefreshCw,
  Globe,
  UploadCloud,
  FileDown,
  Search,
  Users,
  Lock,
  Unlock,
  Calendar,
  Store,
  BookOpen,
  Save,
  Activity
} from 'lucide-react';

interface AdminPanelProps {
  currentUser: User;
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ currentUser, onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy' | 'settlement' | 'sst-config'>(
    currentUser.role === UserRole.ADMIN ? 'import' : 'users'
  );
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [restaurants, setRestaurants] = useState<Restaurant[]>(dataService.getRestaurants());

  const [showUserModal, setShowUserModal] = useState(false);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [regionSearchTerm, setRegionSearchTerm] = useState('');

  // Estado para configuración de SST
  const [sstMonth, setSstMonth] = useState<string>(new Date().toISOString().slice(0, 7));
  const [sstCat1, setSstCat1] = useState('');
  const [sstCat2, setSstCat2] = useState('');

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: [],
    assignedRegions: []
  });

  const availableRegions = useMemo(() => {
    const all = hierarchy.regions.map(r => r.name).sort();
    if (currentUser.role === UserRole.COORDINATOR) {
      return all.filter(r => currentUser.assignedRegions?.includes(r));
    }
    return all;
  }, [hierarchy, currentUser]);

  const filteredRegions = useMemo(() => {
    if (!regionSearchTerm) return availableRegions;
    return availableRegions.filter(r => r.toLowerCase().includes(regionSearchTerm.toLowerCase()));
  }, [availableRegions, regionSearchTerm]);

  const availableZones = useMemo(() => {
    const zonesSet = new Set<string>();
    hierarchy.regions.forEach(r => {
      if (currentUser.role === UserRole.ADMIN || currentUser.assignedRegions?.includes(r.name)) {
        r.zones.forEach(z => zonesSet.add(z.name));
      }
    });
    return Array.from(zonesSet).sort();
  }, [hierarchy, currentUser]);

  const visibleUsers = useMemo(() => {
    if (currentUser.role === UserRole.ADMIN) return users;
    return users.filter(u => {
      if (u.role !== UserRole.SPECIALIST) return false;
      const coordRegions = hierarchy.regions.filter(r => currentUser.assignedRegions?.includes(r.name));
      const coordZones = coordRegions.flatMap(r => r.zones.map(z => z.name));
      return (u.assignedZones || []).some(z => coordZones.includes(z)) || 
             (u.assignedRestaurants || []).some(rid => {
               const rest = restaurants.find(r => r.id === rid);
               return rest && currentUser.assignedRegions?.includes(rest.region);
             });
    });
  }, [users, currentUser, hierarchy, restaurants]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
          setRestaurants(dataService.getRestaurants());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleSaveSstConfig = async () => {
    setIsSaving(true);
    try {
      const newHierarchy = { ...hierarchy };
      if (!newHierarchy.groupDConfig) newHierarchy.groupDConfig = {};
      newHierarchy.groupDConfig[sstMonth] = { cat1: sstCat1, cat2: sstCat2 };

      await dataService.saveHierarchy(newHierarchy);
      setHierarchy(newHierarchy);
      setImportStatus({ message: `Temas de SST para ${sstMonth} actualizados correctamente.`, isError: false });
    } catch (e) {
      alert("Error al guardar la configuración.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleMonthChangeSst = (m: string) => {
    setSstMonth(m);
    const cfg = hierarchy.groupDConfig?.[m];
    setSstCat1(cfg?.cat1 || '');
    setSstCat2(cfg?.cat2 || '');
  };

  const handleSaveUser = async () => {
    if (!newUser.username || (!selectedUser && !newUser.password)) {
      alert("Por favor, completa los campos obligatorios.");
      return;
    }
    setIsSaving(true);
    try {
      const userToSave: User = selectedUser 
        ? { ...selectedUser, ...newUser as User }
        : { 
            id: `user_${Date.now()}`, 
            username: newUser.username!, 
            password: newUser.password!, 
            role: currentUser.role === UserRole.COORDINATOR ? UserRole.SPECIALIST : newUser.role!, 
            assignedZones: newUser.assignedZones || [], 
            assignedRestaurants: newUser.assignedRestaurants || [],
            assignedRegions: newUser.assignedRegions || []
          };

      const updatedUsersList = selectedUser 
        ? users.map(u => u.id === userToSave.id ? userToSave : u)
        : [...users, userToSave];

      await dataService.saveUsers(updatedUsersList);
      setUsers(updatedUsersList);
      setShowUserModal(false);
      setSelectedUser(null);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [], assignedRegions: [] });
      setImportStatus({ message: `Especialista @${userToSave.username} guardado exitosamente.`, isError: false });
    } catch (e: any) { 
      alert(`Error al guardar: ${e.message}`); 
    } finally {
      setIsSaving(false);
    }
  };

  const handleDeleteUser = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm("¿Estás seguro de que deseas eliminar este usuario?")) {
      try { 
        await dataService.deleteUser(id); 
        setUsers(prev => prev.filter(u => u.id !== id));
        setImportStatus({ message: "Usuario eliminado correctamente.", isError: false });
      } catch (e: any) { 
        alert(`No se pudo eliminar el usuario.`); 
      }
    }
  };

  const toggleMonthLock = async (month: string) => {
    const isLocked = hierarchy.lockedMonths.includes(month);
    let newLockedMonths;
    if (isLocked) {
      newLockedMonths = hierarchy.lockedMonths.filter(m => m !== month);
    } else {
      newLockedMonths = [...hierarchy.lockedMonths, month];
    }

    const newHierarchy = { ...hierarchy, lockedMonths: newLockedMonths };
    setIsSaving(true);
    try {
      await dataService.saveHierarchy(newHierarchy);
      setHierarchy(newHierarchy);
      setImportStatus({ 
        message: isLocked ? `Periodo ${month} abierto para edición.` : `Periodo ${month} cerrado (Asentado).`, 
        isError: false 
      });
    } catch (e) {
      alert("Error al actualizar el estado del periodo.");
    } finally {
      setIsSaving(false);
    }
  };

  const monthsToManage = useMemo(() => {
    const dates = [];
    const now = new Date();
    for (let i = 0; i < 4; i++) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      dates.push(d.toISOString().slice(0, 7));
    }
    return dates;
  }, []);

  const toggleItem = (val: string, field: 'assignedZones' | 'assignedRegions' | 'assignedRestaurants') => {
    const current = (newUser as any)[field] || [];
    if (current.includes(val)) {
      setNewUser({ ...newUser, [field]: current.filter((v: string) => v !== val) });
    } else {
      setNewUser({ ...newUser, [field]: [...current, val] });
    }
  };

  const filteredStores = useMemo(() => {
    let base = restaurants;
    if (currentUser.role === UserRole.COORDINATOR) {
      base = base.filter(r => currentUser.assignedRegions?.includes(r.region));
    }
    if (!searchTerm) return [];
    return base.filter(r => 
      r.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      r.id.toLowerCase().includes(searchTerm.toLowerCase())
    ).slice(0, 10);
  }, [restaurants, searchTerm, currentUser]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg">
              {currentUser.role === UserRole.ADMIN ? <Shield className="w-6 h-6" /> : <Users className="w-6 h-6" />}
            </div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic leading-none">
                {currentUser.role === UserRole.ADMIN ? 'Panel Administración' : 'Gestión de Equipo'}
              </h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {currentUser.role === UserRole.ADMIN && (
                  <>
                    <button onClick={() => setActiveSubTab('import')} className={`text-[9px] font-black uppercase tracking-widest px-4 py-2 rounded-full transition ${activeSubTab === 'import' ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>Carga Excel</button>
                    <button onClick={() => setActiveSubTab('sst-config')} className={`text-[9px] font-black uppercase tracking-widest px-4 py-2 rounded-full transition ${activeSubTab === 'sst-config' ? 'bg-red-600 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>Configuración SST</button>
                    <button onClick={() => setActiveSubTab('settlement')} className={`text-[9px] font-black uppercase tracking-widest px-4 py-2 rounded-full transition ${activeSubTab === 'settlement' ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>Asentar Notas</button>
                    <button onClick={() => setActiveSubTab('hierarchy')} className={`text-[9px] font-black uppercase tracking-widest px-4 py-2 rounded-full transition ${activeSubTab === 'hierarchy' ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>Estructura</button>
                  </>
                )}
                <button onClick={() => setActiveSubTab('users')} className={`text-[9px] font-black uppercase tracking-widest px-4 py-2 rounded-full transition ${activeSubTab === 'users' ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>Gestión de Usuarios</button>
              </div>
            </div>
          </div>
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'import' && currentUser.role === UserRole.ADMIN && (
          <div className="space-y-8 animate-in fade-in duration-300">
            <div className="flex justify-end">
              <button 
                onClick={() => {
                  const templateData = [{"Documento": "12345678", "Nombre completo": "JUAN PEREZ", "Fecha de ingreso": "2023-01-15", "Cargo": "Miembro de equipo", "Nombre_Ceco": "CECO001", "Fecha fin": ""}];
                  const ws = XLSX.utils.json_to_sheet(templateData);
                  const wb = XLSX.utils.book_new();
                  XLSX.utils.book_append_sheet(wb, ws, "Plantilla");
                  XLSX.writeFile(wb, "Plantilla_Nomina_KFC.xlsx");
                }}
                className="flex items-center gap-2 px-6 py-3 bg-white border-2 border-slate-100 text-slate-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:border-red-500 hover:text-red-600 transition-all shadow-sm"
              >
                <FileDown className="w-4 h-4" />
                Descargar Plantilla
              </button>
            </div>
