import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
// Added MapPin to the imports from lucide-react
import { X, Save, User, Calendar, GraduationCap, Star, Trophy, ClipboardCheck, Vault, Lock, RefreshCw, BookOpen, ArrowUp, ArrowDown, Repeat, History, Clock, MapPin } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'AK': <BookOpen className="w-5 h-5" />,
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
  'C': <Trophy className="w-5 h-5" />,
  'D': <ClipboardCheck className="w-5 h-5" />,
  'E': <Vault className="w-5 h-5" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('AK');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  const hierarchy = useMemo(() => dataService.getHierarchy(), []);

  const isPeriodLocked = useMemo(() => {
    return hierarchy.lockedMonths.includes(month);
  }, [hierarchy, month]);

  const seniorityMonths = useMemo(() => {
    if (!employee.join_date) return 0;
    const start = new Date(employee.join_date);
    const end = new Date(month + "-01");
    const diff = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
    return Math.max(0, diff);
  }, [employee, month]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    if (existing.length > 0) {
      setFormGrades(existing);
    } else {
      const effective = dataService.getEffectiveGrades(employee.id, month);
      setFormGrades(effective.map(g => ({ ...g, month })));
    }
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (isPeriodLocked) return;
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { 
        const next = [...prev]; 
        next[idx] = { ...next[idx], score }; 
        return next; 
      }
      return [...prev, { employeeId: employee.id, month, group, category, score, restaurantId: employee.restaurant_id }];
    });
  };

  const saveGrades = async () => {
    if (isPeriodLocked) return;
    setIsSaving(true);
    try {
      await dataService.saveEmployeeGrades(employee.id, month, formGrades);
      onClose();
    } catch (err: any) {
      alert(`Error al guardar notas: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  // Función para obtener nombres dinámicos de categorías del Grupo D
  const getCategoryName = (groupId: string, defaultName: string, index: number) => {
    if (groupId === 'D') {
      const cfg = hierarchy.groupDConfig?.[month];
      if (index === 0) return cfg?.cat1 || "Guías Plan de Capacitación";
      if (index === 1) return cfg?.cat2 || "Guías de SST";
    }
    return defaultName;
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-white h-full w-full md:h-[92vh] md:max-w-6xl md:rounded-[48px] flex flex-col overflow-hidden relative shadow-2xl">

        <div className="p-5 md:p-8 bg-slate-900 text-white shrink-0 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center space-x-4 md:space-x-6">
            <div className="w-12 h-12 md:w-16 md:h-16 bg-red-600 rounded-2xl md:rounded-3xl flex items-center justify-center shadow-lg border-4 border-white/10 relative">
              <User className="w-6 h-6 md:w-9 md:h-9 text-white" />
            </div>
            <div className="min-w-0">
              <div className="flex items-center gap-4">
                 <h2 className="text-lg md:text-2xl font-black uppercase italic truncate max-w-[150px] md:max-w-none">{employee.name}</h2>
                 <button onClick={() => setShowHistory(true)} className="flex items-center gap-1.5 px-3 py-1 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all group shrink-0">
                   <History className="w-3 h-3 group-hover:rotate-[-45deg] transition-transform" />
                   <span className="text-[8px] font-black uppercase tracking-widest">Historial</span>
                 </button>
              </div>
              <div className="flex flex-wrap gap-x-6 gap-y-2 mt-2 text-[10px] font-black uppercase tracking-widest">
                <span className="flex items-center gap-1.5 text-slate-400"><Calendar className="w-3.5 h-3.5 text-red-500" /> {month}</span>
                <span className="flex items-center gap-1.5 text-slate-400"><MapPin className="w-3.5 h-3.5 text-red-500" /> {employee.restaurant_id}</span>
                <span className="flex items-center gap-1.5 bg-white text-slate-900 px-3 py-1 rounded-full shadow-lg border border-white/10">
                  <Clock className="w-3.5 h-3.5 text-red-600" /> 
                  Antigüedad: {seniorityMonths} Meses
                </span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2 self-end md:self-auto">
             <button onClick={onClose} className="p-2 bg-white/10 hover:bg-red-600 rounded-xl transition-all shadow-md"><X className="w-6 h-6"/></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-200 flex md:flex-col overflow-x-auto md:overflow-y-auto p-4 gap-3 no-scrollbar shrink-0 sticky top-0 z-10">
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const isActive = activeGroup === id;
              const groupGrades = formGrades.filter(g => g.group === id);
              const groupAvg = groupGrades.length > 0 ? Math.round(groupGrades.reduce((s, g) => s + g.score, 0) / (group as any).categories.length) : 0;

              return (
                <button 
                  key={id} 
                  onClick={() => setActiveGroup(id)} 
                  className={`p-3 md:p-5 rounded-2xl md:rounded-3xl text-left border-2 transition-all flex items-center gap-3 shrink-0 md:shrink ${isActive ? 'bg-white border-red-600 shadow-lg' : 'bg-transparent border-transparent opacity-50'}`}
                >
                  <div className={`p-2 rounded-xl ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{GroupIcons[id]}</div>
                  <div className="hidden md:block flex-1 min-w-0">
                    <p className={`text-[10px] font-black uppercase tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>{group.name}</p>
                    <div className="mt-2 flex items-center gap-2">
                       <div className="flex-1 h-1 bg-slate-200 rounded-full overflow-hidden">
                          <div className={`h-full ${groupAvg >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${groupAvg}%`}} />
                       </div>
                       <span className="text-[9px] font-black text-slate-400">{groupAvg}%</span>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>

          <div className="flex-1 overflow-y-auto p-4 md:p-12 bg-white no-scrollbar">
            <div className="max-w-2xl mx-auto">
              <div className="space-y-6">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-lg font-black uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                  {isPeriodLocked && <div className="flex items-center gap-1.5 bg-red-100 text-red-600 px-3 py-1 rounded-full text-[9px] font-black uppercase"><Lock className="w-3 h-3"/> Lectura</div>}
                </div>

                <div className="space-y-4">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string, index: number) => {
                    const dynamicCatName = getCategoryName(activeGroup, cat, index);
                    const grade = formGrades.find(g => g.group === activeGroup && g.category === cat);
                    const score = grade?.score ?? 0;
                    const isInherited = grade && grade.month !== month;

                    return (
                      <div key={cat} className="bg-slate-50/50 border-2 border-transparent rounded-[24px] p-5 flex items-center justify-between gap-6 transition-all hover:bg-white hover:border-slate-100">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-3">
                            <label className="text-[10px] font-black text-slate-900 uppercase block">{dynamicCatName}</label>
                            {isInherited && <span className="text-[8px] bg-slate-900 text-white px-2 py-0.5 rounded uppercase font-black">Heredado</span>}
                          </div>
                          <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                            <div className={`h-full ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                          </div>
                        </div>
                        <div className="relative">
                          <input 
                            type="number" 
                            disabled={isPeriodLocked}
                            value={score === 0 ? '' : score} 
                            onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                            className={`w-16 md:w-20 px-2 py-3 bg-white border-2 rounded-xl text-lg font-black text-center shadow-md outline-none ${isPeriodLocked ? 'text-slate-300' : score >= 90 ? 'border-emerald-100 text-emerald-700' : 'border-slate-200 text-slate-800 focus:border-red-500'}`} 
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 md:p-8 border-t border-slate-100 bg-slate-50 flex justify-end items-center shrink-0">
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <button onClick={onClose} className="flex-1 sm:flex-none px-8 py-4 bg-white text-slate-400 font-black rounded-2xl border-2 border-slate-200 text-[10px] uppercase transition-all">Regresar</button>
            {!isPeriodLocked && (
              <button onClick={saveGrades} disabled={isSaving} className="flex-1 sm:flex-none px-10 py-4 bg-red-600 text-white text-[10px] font-black rounded-2xl shadow-xl hover:bg-red-700 transition-all uppercase flex items-center justify-center gap-2">
                {isSaving ? <RefreshCw className="w-4 h-4 animate-spin"/> : <Save className="w-4 h-4"/>}
                {isSaving ? 'Sincronizando...' : 'Guardar y Certificar'}
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Modal de Historial de Movimientos */}
      {showHistory && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center bg-slate-950/80 backdrop-blur-md p-4 animate-in fade-in duration-300">
           <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden border-2 border-white/20">
              <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
                 <div className="flex items-center gap-3">
                    <History className="w-5 h-5 text-red-500" />
                    <h3 className="font-black uppercase italic tracking-tighter text-lg">Historial de Movimientos</h3>
                 </div>
                 <button onClick={() => setShowHistory(false)} className="p-2 hover:bg-white/10 rounded-xl transition-all"><X className="w-5 h-5"/></button>
              </div>
              <div className="p-8 max-h-[60vh] overflow-y-auto no-scrollbar">
                 <div className="space-y-6">
                    {employee.history?.map((h, i) => (
                      <div key={i} className="flex gap-4 items-start relative pb-6 last:pb-0">
                         {i < (employee.history?.length || 0) - 1 && <div className="absolute left-4 top-8 bottom-0 w-0.5 bg-slate-100" />}
                         <div className={`w-8 h-8 rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${h.action === 'INGRESO' ? 'bg-emerald-50 text-emerald-600' : h.action === 'RETIRO' ? 'bg-red-50 text-red-600' : 'bg-blue-50 text-blue-600'}`}>
                            {h.action === 'INGRESO' ? <ArrowUp className="w-4 h-4" /> : h.action === 'RETIRO' ? <ArrowDown className="w-4 h-4" /> : <Repeat className="w-4 h-4" />}
                         </div>
                         <div className="min-w-0 bg-slate-50 p-4 rounded-3xl flex-1 border border-slate-100">
                            <p className="text-[9px] font-black uppercase text-slate-800 tracking-widest">{h.action}</p>
                            <p className="text-[11px] font-black text-slate-500 uppercase italic mt-1">{h.restaurantName}</p>
                            <p className="text-[9px] font-bold text-slate-400 mt-2 flex items-center gap-1.5"><Calendar className="w-3 h-3" /> {h.date}</p>
                         </div>
                      </div>
                    ))}
                    {(!employee.history || employee.history.length === 0) && (
                      <div className="text-center py-10">
                         <p className="text-[10px] text-slate-300 uppercase font-black italic tracking-widest">Sin historial registrado en el sistema</p>
                      </div>
                    )}
                 </div>
              </div>
              <div className="p-6 bg-slate-50 text-center">
                 <button onClick={() => setShowHistory(false)} className="px-8 py-3 bg-white border-2 border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-red-600 transition-colors">Cerrar Historial</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default GradeEditor;

import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Download, X, Check, FileText } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const [showExportModal, setShowExportModal] = useState(false);
  const [exportConfig, setExportConfig] = useState({
    groups: Object.keys(EVALUATION_GROUPS),
    includeDetails: false
  });

  const allGrades = useMemo(() => dataService.getGrades(), []);
  const hierarchy = useMemo(() => dataService.getHierarchy(), []);

  const dynamicRegions = useMemo(() => {
    let regions = Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort();
    if (user.role === UserRole.COORDINATOR) {
      regions = regions.filter(r => user.assignedRegions.includes(r));
    }
    return regions;
  }, [restaurants, user]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    else if (user.role === UserRole.COORDINATOR) baseStores = baseStores.filter(r => user.assignedRegions.includes(r.region));

    let zones = Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    else if (user.role === UserRole.COORDINATOR) baseStores = baseStores.filter(r => user.assignedRegions.includes(r.region));

    if (filterZone !== 'all') baseStores = baseStores.filter(r => r.zone === filterZone);
    if (user.role === UserRole.SPECIALIST) baseStores = baseStores.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const employeesWithEffectiveGrades = useMemo(() => {
    return initialEmployees.map(emp => {
      const effectiveGrades = dataService.getEffectiveGrades(emp.id, selectedMonth);
      const exactMonthGrades = effectiveGrades.filter(g => g.month === selectedMonth);
      const storeIdAtPeriod = exactMonthGrades.length > 0 ? exactMonthGrades[0].restaurantId : emp.restaurant_id;
      const sum = effectiveGrades.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? Math.round(sum / TOTAL_CATEGORIES_COUNT) : 0;
      const isApproved = effectiveGrades.length > 0 && avg >= APPROVAL_THRESHOLD;
      const isPending = effectiveGrades.length === 0;

      return {
        ...emp,
        effectiveGrades,
        storeIdAtPeriod,
        avg,
        isApproved,
        isPending
      };
    });
  }, [initialEmployees, selectedMonth, allGrades]);

  const filteredData = useMemo(() => {
    return employeesWithEffectiveGrades.filter(e => {
      const store = restaurants.find(r => r.id === e.storeIdAtPeriod);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchRegion = filterRegion === 'all' ? (user.role === UserRole.COORDINATOR ? user.assignedRegions.includes(store?.region || '') : true) : store?.region === filterRegion;
      const matchZone = filterZone === 'all' ? true : store?.zone === filterZone;
      const matchStore = filterStore === 'all' ? true : e.storeIdAtPeriod === filterStore;

      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [employeesWithEffectiveGrades, searchPerson, filterStore, filterZone, filterRegion, restaurants, user]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    const approvedCount = filteredData.filter(e => e.isApproved).length;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      let totalScores = 0;
      let totalCatsPossible = filteredData.length * groupData.categories.length;

      filteredData.forEach(e => {
        const groupGrades = e.effectiveGrades.filter(g => g.group === groupId);
        totalScores += groupGrades.reduce((s, g) => s + g.score, 0);
      });

      const avg = totalCatsPossible > 0 ? totalScores / totalCatsPossible : 0;
      return { id: groupId, name: groupData.name, avg: Math.round(avg) };
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData]);

  const handleExportFinal = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.storeIdAtPeriod);
      const dynamicColumns: any = {};

      exportConfig.groups.forEach(gid => {
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const gGrades = emp.effectiveGrades.filter(g => g.group === gid);
        const sum = gGrades.reduce((s, g) => s + g.score, 0);
        const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
        dynamicColumns[`${gConfig.name} %`] = `${avg}%`;

        if (exportConfig.includeDetails) {
          gConfig.categories.forEach((cat: string, index: number) => {
            let catName = cat;
            if (gid === 'D') {
              const cfg = hierarchy.groupDConfig?.[selectedMonth];
              if (index === 0) catName = cfg?.cat1 || "Guías Plan de Capacitación";
              if (index === 1) catName = cfg?.cat2 || "Guías de SST";
            }
            const grade = gGrades.find(g => g.category === cat);
            dynamicColumns[`[${gConfig.name}] ${catName}`] = grade ? `${grade.score}%` : '0%';
          });
        }
      });

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Cargo": emp.title,
        "Tienda Reportada": empStore?.name || emp.storeIdAtPeriod,
        "Ceco": emp.storeIdAtPeriod,
        "Jefe de area": empStore?.zone || emp.zone,
        "Mes Reporte": selectedMonth,
        "Promedio General": `${emp.avg}%`,
        "Certificación": emp.isPending ? 'Pendiente' : (emp.isApproved ? 'Aprobado' : 'No Cumple'),
        "Origen Nota": emp.isPending ? 'N/A' : (emp.effectiveGrades.some(g => g.month === selectedMonth) ? 'Mes Actual' : 'Heredada'),
        ...dynamicColumns
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
    setShowExportModal(false);
  };

  const selectClasses = "w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><MapPin className="w-3 h-3 mr-1 inline" /> Región</label>
            <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses}>
              <option value="all">{user.role === UserRole.COORDINATOR ? 'Mis Regiones' : 'Todas'}</option>
              {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
        )}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Tienda</label>
          <select value={filterStore} onChange={(e) => setFilterStore(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Search className="w-3 h-3 mr-1 inline" /> Persona</label>
          <input type="text" placeholder="ID o Nombre..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)} className="w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800" />
        </div>
        <button onClick={() => setShowExportModal(true)} className="w-full flex items-center justify-center space-x-2 px-4 py-3.5 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-lg">
          <Download className="w-4 h-4" /> <span>Exportar Excel</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.totalEmployees} subValue={`Trabajadores en alcance`} />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Nivel de Excelencia" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Promedio" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="General" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Pendientes" value={filteredData.filter(e => e.isPending).length} subValue="Sin ninguna nota" color="red" />
      </div>

      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
        <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center mb-8"><TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={stats.groupAvgs} margin={{ top: 20, right: 0, left: -25, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <Tooltip cursor={{ fill: '#f8fafc' }} />
              <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                <LabelList dataKey="avg" position="top" formatter={(v: any) => `${v}%`} style={{ fontSize: '10px', fontWeight: '900', fill: '#64748b' }} />
                {stats.groupAvgs.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {showExportModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-lg overflow-hidden border-2 border-white/20">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <FileText className="w-6 h-6 text-red-500" />
                <h3 className="font-black uppercase italic tracking-tighter text-xl">Configurar Exportación</h3>
              </div>
              <button onClick={() => setShowExportModal(false)}><X className="w-6 h-6"/></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Grupos a incluir</label>
                <div className="grid grid-cols-2 gap-2">
                  {Object.entries(EVALUATION_GROUPS).map(([id, group]) => (
                    <button key={id} onClick={() => {
                        setExportConfig(prev => ({
                          ...prev,
                          groups: prev.groups.includes(id) ? prev.groups.filter(gid => gid !== id) : [...prev.groups, id]
                        }));
                      }}
                      className={`flex items-center gap-3 p-3 rounded-2xl text-[10px] font-black uppercase transition-all ${exportConfig.groups.includes(id) ? 'bg-red-50 border-2 border-red-500 text-red-600' : 'bg-slate-50 border-2 border-transparent text-slate-400'}`}
                    >
                      <div className={`w-4 h-4 rounded flex items-center justify-center ${exportConfig.groups.includes(id) ? 'bg-red-600 text-white' : 'bg-slate-200'}`}>
                        {exportConfig.groups.includes(id) && <Check className="w-3 h-3" />}
                      </div>
                      {group.name}
                    </button>
                  ))}
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-2xl flex items-center justify-between">
                <div>
                  <p className="text-[10px] font-black uppercase text-slate-900">Incluir detalle por categoría</p>
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Saca notas individuales por item</p>
                </div>
                <button onClick={() => setExportConfig(prev => ({ ...prev, includeDetails: !prev.includeDetails }))}
                  className={`w-12 h-6 rounded-full transition-all relative ${exportConfig.includeDetails ? 'bg-emerald-500' : 'bg-slate-300'}`}
                >
                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${exportConfig.includeDetails ? 'left-7' : 'left-1'}`} />
                </button>
              </div>

              <button onClick={handleExportFinal} className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl transition-all uppercase tracking-widest text-xs">Generar Reporte Excel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = { red: 'bg-red-50 text-red-600', green: 'bg-emerald-50 text-emerald-600', blue: 'bg-blue-50 text-blue-600', gray: 'bg-slate-50 text-slate-600' };
  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
      <div className="flex items-center space-x-5">
        <div className={`p-4 rounded-2xl ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">{label}</p>
          <h4 className="text-3xl font-black text-slate-800 tracking-tighter leading-none">{value}</h4>
          <p className="text-[10px] text-slate-400 font-bold mt-2">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
